window.HADITH_CACHE["abu-dawud_4"] = {"2001":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا وَهْبٌ حَدَّثَنَا مُوسَى بْنُ عَلِيٍّ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ مُوسَى بْنِ عَلِيٍّ وَالْإِخْبَارُ فِي حَدِيثِ وَهْبٍ قَالَ سَمِعْتُ أَبِي أَنَّهُ سَمِعَ عُقْبَةَ بْنَ عَامِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمُ عَرَفَةَ وَيَوْمُ النَّحْرِ وَأَيَّامُ التَّشْرِيقِ عِيدُنَا أَهْلَ الْإِسْلَامِ وَهِيَ أَيَّامُ أَكْلٍ وَشُرْبٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], Telah menceritakan kepada kami [Wahb] telah menceritakan kepada kami [Musa bin Ali], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Waki'] dari [Musa bin Ali], dan bentuk pengabaran ada dalam hadits Wahb, ia berkata; saya mendengar [ayahku] bahwa ia mendengar [Uqbah bin 'Amir] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hari 'Arafah dan Hari Kurban, serta hari-hari Tasyriq adalah hari raya kita, orang-orang Islam. Hari-hari tersebut adalah hari-hari makan dan minum.\""},"2002":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَصُمْ أَحَدُكُمْ يَوْمَ الْجُمُعَةِ إِلَّا أَنْ يَصُومَ قَبْلَهُ بِيَوْمٍ أَوْ بَعْدَهُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu wa'alaihi wa sallam bersabda: \"Janganlah salah seorang diantara kalian berpuasa pada Hari Jum'at, kecuali ia berpuasa sebelumnya atau setelahnya.\""},"2003":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا سُفْيَانُ بْنُ حَبِيبٍ ح و حَدَّثَنَا يَزِيدُ بْنُ قُبَيْسٍ مِنْ أَهْلِ جَبَلَةَ حَدَّثَنَا الْوَلِيدُ جَمِيعًا عَنْ ثَوْرِ بْنِ يَزِيدَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍ السُّلَمِيِّ عَنْ أُخْتِهِ وَقَالَ يَزِيدُ الصَّمَّاءِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصُومُوا يَوْمَ السَّبْتِ إِلَّا فِي مَا افْتُرِضَ عَلَيْكُمْ وَإِنْ لَمْ يَجِدْ أَحَدُكُمْ إِلَّا لِحَاءَ عِنَبَةٍ أَوْ عُودَ شَجَرَةٍ فَلْيَمْضَغْهُ قَالَ أَبُو دَاوُد وَهَذَا حَدِيثٌ مَنْسُوخٌ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah], telah menceritakan kepada kami [Sufyan bin Habib], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Yazid bin Qubais] dari penduduk Jabalah, telah menceritakan kepada kami [Al Walid], seluruhnya dari [Tsaur bin Yazid] dari [Khalid bin Ma'dan] dari [Abdullah bin Busr As Sulami], dari [saudarinya], Yazid berkata; Shama`, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian berpuasa pada hari Sabtu kecuali yang diwajibkan atas kalian, dan apabila salah seorang diantara kalian tidak mendapatkan sesuatu kecuali kulit pohon anggur atau ranting pohon maka hendaknya ia mengunyahnya.\" Abu Daud berkata; hadits ini adalah hadits yang telah di naskh (yang hukumnya telah diganti dengan ayat atau hadits yang lain). "},"2004":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ ح و حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي أَيُّوبَ قَالَ حَفْصٌ الْعَتَكِيُّ عَنْ جُوَيْرِيَةَ بِنْتِ الْحَارِثِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا يَوْمَ الْجُمُعَةِ وَهِيَ صَائِمَةٌ فَقَالَ أَصُمْتِ أَمْسِ قَالَتْ لَا قَالَ تُرِيدِينَ أَنْ تَصُومِي غَدًا قَالَتْ لَا قَالَ فَأَفْطِرِي","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah menceritakan kepada kami [Hammam], dari [Qatadah], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Hafsh bin Umar], telah menceritakan kepada kami [Hammam], telah menceritakan kepada kami [Qatadah], dari [Abu Ayyub], Hafsh Al 'Ataki dari [Juwairiyah binti Al Harits], bahwa Nabi shallallahu 'alaihi wasallam menemuinya pada Hari Jum'at dalam keadaan sedang berpuasa, kemudian beliau berkata; apakah engkau berpuasa kemarin? Ia berkata; tidak. Beliau berkata: \"Apakah engkau ingin berpuasa besok?\" Ia berkata; tidak. Beliau berkata; \"Berbukalah!\""},"2005":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبٍ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ سَمِعْتُ اللَّيْثَ يُحَدِّثُ عَنْ ابْنِ شِهَابٍأَنَّهُ كَانَ إِذَا ذَكَرَ لَهُ أَنَّهُ نَهَى عَنْ صِيَامِ يَوْمِ السَّبْتِ يَقُولُ ابْنُ شِهَابٍ هَذَا حَدِيثٌ حِمْصِيٌّحَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ بْنِ سُفْيَانَ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ قَالَ مَا زِلْتُ لَهُ كَاتِمًا حَتَّى رَأَيْتُهُ انْتَشَرَ يَعْنِي حَدِيثَ عَبْدِ اللَّهِ بْنِ بُسْرٍ هَذَا فِي صَوْمِ يَوْمِ السَّبْتِ قَالَ أَبُو دَاوُد قَالَ مَالِكٌ هَذَا كَذِبٌ","id":"Telah menceritakan kepada kami [Abdul Malik bin Syu'aib], telah menceritakan kepada kami [Ibnu Wahb], ia berkata; saya mendengar [Al Laits] menceritakan dari [Ibnu Syihab] bahwa ia apabila menyebutkan kepadanya bahwa beliau melarang dari berpuasa pada Hari Sabtu Ibnu Syihab berkata; ini adalah hadits orang Himshi. Telah menceritakan kepada kami [Muhammad bin Ash Shabah bin Sufyan], telah menceritakan kepada kami [Al Walid] dari [Al Auza'i], ia berkata; aku masih menyembunyikannya hingga aku melihatnya telah menyebar. Yang ia maksud adalah hadits Abdullah bin Busr ini yang berbicara mengenai puasa pada Hari Sabtu. Abu Daud berkata; Malik berkata; ini adalah dusta. "},"2006":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَمُسَدَّدٌ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ مَعْبَدٍ الزِّمَّانِيِّ عَنْ أَبِي قَتَادَةَأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ تَصُومُ فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ قَوْلِهِ فَلَمَّا رَأَى ذَلِكَ عُمَرُ قَالَ رَضِينَا بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ نَبِيًّا نَعُوذُ بِاللَّهِ مِنْ غَضَبِ اللَّهِ وَمِنْ غَضَبِ رَسُولِهِ فَلَمْ يَزَلْ عُمَرُ يُرَدِّدُهَا حَتَّى سَكَنَ غَضَبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ بِمَنْ يَصُومُ الدَّهْرَ كُلَّهُ قَالَ لَا صَامَ وَلَا أَفْطَرَ قَالَ مُسَدَّدٌ لَمْ يَصُمْ وَلَمْ يُفْطِرْ أَوْ مَا صَامَ وَلَا أَفْطَرَ شَكَّ غَيْلَانُ قَالَ يَا رَسُولَ اللَّهِ كَيْفَ بِمَنْ يَصُومُ يَوْمَيْنِ وَيُفْطِرُ يَوْمًا قَالَ أَوَ يُطِيقُ ذَلِكَ أَحَدٌ قَالَ يَا رَسُولَ اللَّهِ فَكَيْفَ بِمَنْ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا قَالَ ذَلِكَ صَوْمُ دَاوُدَ قَالَ يَا رَسُولَ اللَّهِ فَكَيْفَ بِمَنْ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمَيْنِ قَالَ وَدِدْتُ أَنِّي طُوِّقْتُ ذَلِكَ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثٌ مِنْ كُلِّ شَهْرٍ وَرَمَضَانُ إِلَى رَمَضَانَ فَهَذَا صِيَامُ الدَّهْرِ كُلِّهِ وَصِيَامُ عَرَفَةَ إِنِّي أَحْتَسِبُ عَلَى اللَّهِ أَنْ يُكَفِّرَ السَّنَةَ الَّتِي قَبْلَهُ وَالسَّنَةَ الَّتِي بَعْدَهُ وَصَوْمُ يَوْمِ عَاشُورَاءَ إِنِّي أَحْتَسِبُ عَلَى اللَّهِ أَنْ يُكَفِّرَ السَّنَةَ الَّتِي قَبْلَهُحَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا مَهْدِيٌّ حَدَّثَنَا غَيْلَانُ عَنْ عَبْدِ اللَّهِ بْنِ مَعْبَدٍ الزِّمَّانِيِّ عَنْ أَبِي قَتَادَةَ بِهَذَا الْحَدِيثِ زَادَ قَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ صَوْمَ يَوْمِ الِاثْنَيْنِ وَيَوْمِ الْخَمِيسِ قَالَ فِيهِ وُلِدْتُ وَفِيهِ أُنْزِلَ عَلَيَّ الْقُرْآنُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], dan [Musaddad] mereka berdua berkata; telah menceritakan kepada kami [Hammad bin Zaid], dari [Ghailan bin Jarir], dari [Abdullah bin Ma'bad Az Zimmani] dari [Abu Qatadah], bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, bagaimana anda berpuasa? Kemudian Rasulullah shallallahu 'alaihi wasallam marah karena ucapannya tersebut. Kemudian tatkala Umar melihat hal tersebut ia berkata; kami ridha kepada Allah sebagai Tuhan, dan Islam sebagai agama, serta Muhammad sebagai nabi. Kami berlindung kepada Allah dari kemurkaanNya dan kemarahan rasulNya. Umar terus mengulangi ucapan tersebut hingga berhenti kemarahan Rasulullah shallallahu wa'alaihi wa sallam. Kemudian ia berkata; wahai Rasulullah, bagaimana dengan orang yang berpuasa setahun penuh? Beliau berkata; ia tidak berpuasa dan tidak berbuka. Musaddad berkata; Musaddad berkata; maka ia belum berpuasa dan belum berbuka, atau tidak berpuasa dan tidak berbuka. Ghailan merasa ragu. Umar berkata; wahai Rasulullah, bagaimana dengan orang yang berpuasa dua hari dan berbuka satu hari? Beliau berkata: \"Apakah ada orang yang mampu melakukan hal tersebut?\" Ia berkata; wahai Rasulullah, bagaimana dengan orang yang berpuasa satu hari dan berbuka satu hari? Beliau berkata: \"Itu adalah puasa Daud.\" Ia berkata; wahai Rasulullah, bagaimana dengan orang yang berpuasa satu hari dan berbuka dua hari? Beliau berkata: \"Aku ingin diberikan kemampuan melakukan hal tersebut.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Puasa tiga hari setiap hari setiap bulan, dan Ramadhan hingga Ramadhan yang lain ini adalah puasa setahun penuh. Dan puasa Hari 'Arafah aku berharap kepada Allah agar menggugurkan dosa satu tahun yang sebelumnya, serta satu tahun setelahnya, dan puasa Hari 'Asyura` aku berharap kepada Allah agar menghapuskan dosa sebelumnya.\" Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Mahdi] telah menceritakan kepada kami [Ghailan] dari [Abdullah bin Ma'bad Az Zimmani] dari [Abu Qatadah] dengan hadits ini. Ia menambahkan; Umar berkata; wahai Rasulullah, bagaimana pendapat anda mengenai puasa hari Senin dan hari Kamis? Beliau berkata; padanya aku dilahirkan dan padanya Al Qur'an di turunkan kepadaku. "},"2007":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ قَالَلَقِيَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَمْ أُحَدَّثْ أَنَّكَ تَقُولُ لَأَقُومَنَّ اللَّيْلَ وَلَأَصُومَنَّ النَّهَارَ قَالَ أَحْسَبُهُ قَالَ نَعَمْ يَا رَسُولَ اللَّهِ قَدْ قُلْتُ ذَاكَ قَالَ قُمْ وَنَمْ وَصُمْ وَأَفْطِرْ وَصُمْ مِنْ كُلِّ شَهْرٍ ثَلَاثَةَ أَيَّامٍ وَذَاكَ مِثْلُ صِيَامِ الدَّهْرِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ قَالَ فَصُمْ يَوْمًا وَأَفْطِرْ يَوْمَيْنِ قَالَ فَقُلْتُ إِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ قَالَ فَصُمْ يَوْمًا وَأَفْطِرْ يَوْمًا وَهُوَ أَعْدَلُ الصِّيَامِ وَهُوَ صِيَامُ دَاوُدَ قُلْتُ إِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَفْضَلَ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdurrazzaq], telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Al Musayyab], dan [Abu Salamah], dari [Abdullah bin 'Amr bin Al 'Ash], ia berkata; Rasulullah shallallahu 'alaihi wasallam bertemu denganku dan berkata; bukankah aku telah diberitahu bahwa engkau mengatakan; sungguh aku akan melakukan shalat malam dan melakukan puasa pada siang hari? Al Hasan berkata; aku mengira bahwa Abdullah bin 'Amr berkata; ya wahai Rasulullah, saya telah mengatakan hal tersebut. Beliau berkata: \"Berdiri dan tidurlah, berpuasalah, berbukalah serta berpuasalah tiga hari setiap bulan. Dan hal itu seperti puasa satu tahun.\" Abdullah berkata; aku katakan; wahai Rasulullah, aku mampu untuk melakukan yang lebih dari hal tersebut. Beliau berkata: \"Berpuasalah satu hari dan berbukalah dua hari.\" Ia berkata; lalu aku katakan; aku mampu melakukan lebih dari hal tersebut. Beliau berkata: \"Berpuasalah satu hari dan berbukalah satu hari, dan hal itu adalah puasa yang paling adil, dan puasa tersebut adalah puasa Daud.\" Aku katakan; aku mampu melakukan lebih dari hal tersebut. Rasulullah shallallahu wa'alaihi wa sallam berkata: \"Tidak ada yang lebih baik daripada hal tersebut.\""},"2008":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ أَبِي السَّلِيلِ عَنْ مُجِيبَةَ الْبَاهِلِيَّةِ عَنْ أَبِيهَا أَوْ عَمِّهَاأَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ انْطَلَقَ فَأَتَاهُ بَعْدَ سَنَةٍ وَقَدْ تَغَيَّرَتْ حَالُهُ وَهَيْئَتُهُ فَقَالَ يَا رَسُولَ اللَّهِ أَمَا تَعْرِفُنِي قَالَ وَمَنْ أَنْتَ قَالَ أَنَا الْبَاهِلِيُّ الَّذِي جِئْتُكَ عَامَ الْأَوَّلِ قَالَ فَمَا غَيَّرَكَ وَقَدْ كُنْتَ حَسَنَ الْهَيْئَةِ قَالَ مَا أَكَلْتُ طَعَامًا إِلَّا بِلَيْلٍ مُنْذُ فَارَقْتُكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمَ عَذَّبْتَ نَفْسَكَ ثُمَّ قَالَ صُمْ شَهْرَ الصَّبْرِ وَيَوْمًا مِنْ كُلِّ شَهْرٍ قَالَ زِدْنِي فَإِنَّ بِي قُوَّةً قَالَ صُمْ يَوْمَيْنِ قَالَ زِدْنِي قَالَ صُمْ ثَلَاثَةَ أَيَّامٍ قَالَ زِدْنِي قَالَ صُمْ مِنْ الْحُرُمِ وَاتْرُكْ صُمْ مِنْ الْحُرُمِ وَاتْرُكْ صُمْ مِنْ الْحُرُمِ وَاتْرُكْ وَقَالَ بِأَصَابِعِهِ الثَّلَاثَةِ فَضَمَّهَا ثُمَّ أَرْسَلَهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il], Telah menceritakan kepada kami [Hammad] dari [Sa'id Al Jurairi], dari [Abu As Salil] dari [Mujibah Al Bahili], dari [ayahnya] atau pamannya bahwa ia datang kepada Rasulullah shallallahu 'alaihi wasallam kemudian pergi, kemudian ia datang kepada beliau setelah satu tahun, dan keadaan serta penampilannya telah berubah. Kemudian ia berkata; wahai Rasulullah, apakah engkau mengenalku? Beliau berkata: \"Siapa kamu?\" Ia berkata; saya adalah Al Bahili yang telah datang kepada engkau pada tahun pertama. Beliau berkata: \"Apakah yang telah mengubahmu? Dahulu penampilanmu baik.\" Ia berkata; saya tidak makan kecuali pada malam hari semenjak saya berpisah dengan engkau. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kenapa engkau menyiksa dirimu?\" kemudian beliau berkata: \"Berpuasalah pada bulan yang penuh kesabaran (Bulan Ramadhan), dan satu hari setiap bulan.\" Ia berkata; tambahkan untukku, karena sesungguhnya saya kuat. Beliau berkata: \"Berpuasalah dua hari!\" Ia berkata; tambahkan untukku! Beliau berkata: \"Berpuasalah tiga hari!\" Ia berkata; tambahkan untukku! Beliau berkata: \"Berpuasalah sebagian dari bulan hurum (Rajab, Dzul Qa'dah, Dzul Hijjah dan Al Muharram).\" Beliau mengatakannya dengan memberi isyarat menggunakan ketiga jari-jarinya, beliau menggenggamnya kemudian membukanya. "},"2009":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَقُتَيْبَةُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ الصِّيَامِ بَعْدَ شَهْرِ رَمَضَانَ شَهْرُ اللَّهِ الْمُحَرَّمُ وَإِنَّ أَفْضَلَ الصَّلَاةِ بَعْدَ الْمَفْرُوضَةِ صَلَاةٌ مِنْ اللَّيْلِ لَمْ يَقُلْ قُتَيْبَةُ شَهْرٌ قَالَ رَمَضَانُ","id":"Telah menceritakan kepada kami [Musaddad] serta [Qutaibah bin Sa'id], mereka berkata; telah menceritakan kepada kami [Abu 'Awanah], dari [Abu Bisyr], dari [Humaid bin Abdurrahman], dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam puasa yang paling baik setelah Bulan Ramadhan adalah bulan Allah Al Muharram, dan sesungguhnya shalat terbaik setelah shalat wajib adalah shalat pada malam hari. Qutaibah tidak mengatakan; bulan. Ia mengatakan; Ramadhan. "},"2010":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا عِيسَى حَدَّثَنَا عُثْمَانُ يَعْنِي ابْنَ حَكِيمٍ قَالَ سَأَلْتُ سَعِيدَ بْنَ جُبَيْرٍ عَنْ صِيَامِ رَجَبٍ فَقَالَ أَخْبَرَنِي ابْنُ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَصُومُ حَتَّى نَقُولَ لَا يُفْطِرُ وَيُفْطِرُ حَتَّى نَقُولَ لَا يَصُومُ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa], telah menceritakan kepada kami [Isa], telah menceritakan kepada kami [Utsman bin Hakim], ia beraka; saya bertanya kepada [Sa'id bin Jubair], mengenai puasa Rajab. Ia berkata; telah mengabarkan kepadaku [Ibnu Abbas], bahwa Rasulullah shallallahu 'alaihi wasallam pernah berpuasa hingga kami mengatakan; beliau tidak berbuka. Dan beliau berbuka hingga kami mengatakan; beliau tidak berpuasa. "},"2011":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَيْسٍ سَمِعَ عَائِشَةَ تَقُولُ كَانَ أَحَبَّ الشُّهُورِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَصُومَهُ شَعْبَانُ ثُمَّ يَصِلُهُ بِرَمَضَانَ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrahman bin Mahdi], dari [Mu'awiyah bin Shalih] dari [Abdullah bin Abu Qais], ia mendengar [Aisyah] berkata; bulan yang paling Rasulullah shallallahu 'alaihi wasallam sukai untuk berpuasa adalah Bulan Sya'ban, kemudian beliau menyambungnya dengan Ramadhan. "},"2012":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ الْعِجْلِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ مُوسَى عَنْ هَارُونَ بْنِ سَلْمَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ مُسْلِمٍ الْقُرَشِيِّ عَنْ أَبِيهِ قَالَ سَأَلْتُ أَوْ سُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صِيَامِ الدَّهْرِ فَقَالَ إِنَّ لِأَهْلِكَ عَلَيْكَ حَقًّا صُمْ رَمَضَانَ وَالَّذِي يَلِيهِ وَكُلَّ أَرْبِعَاءَ وَخَمِيسٍ فَإِذَا أَنْتَ قَدْ صُمْتَ الدَّهْرَ قَالَ أَبُو دَاوُد وَافَقَهُ زَيْدٌ الْعُكْلِيُّ وَخَالَفَهُ أَبُو نُعَيْمٍ قَالَ مُسْلِمُ بْنُ عُبَيْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Utsman Al 'Ajli], telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Harun bin Salman], dari ['Ubaidullah bin Muslim Al Qurasyi], dari [ayahnya], ia berkata; saya bertanya atau Nabi shallallahu 'alaihi wasallam ditanya mengenai puasa setahun, lalu beliau berkata; sesungguhnya keluargamu memiliki hak atasmu. Berpuasalah pada Bulan Ramadhan dan setelahnya, serta setiap hari Rabu dan Kamis, maka engkau telah melakukan puasa setahun. Abu Daud berkata; hal tersebut disepakati oleh Zaid Al 'Ukli, sedangkan Ummu Nu'aim menyelisihinya, ia mengatakan; Muslim bin 'Ubaidullah. "},"2013":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ وَسَعْدِ بْنِ سَعِيدٍ عَنْ عُمَرَ بْنِ ثَابِتٍ الْأَنْصَارِيِّ عَنْ أَبِي أَيُّوبَ صَاحِبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ رَمَضَانَ ثُمَّ أَتْبَعَهُ بِسِتٍّ مِنْ شَوَّالٍ فَكَأَنَّمَا صَامَ الدَّهْرَ","id":"Telah menceritakan kepada kami [An Nufaili], Telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Shafwan bin Sulaim] serta [Sa'd bin Sa'id], dari [Umar bin Tsabit Al Anshari], dari [Abu Ayyub] sahabat nabi shallallahu 'alaihi wasallam, dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Barangsiapa yang melakukan puasa pada Bulan Ramadhan kemudian ia ikutkan dengan puasa enam hari pada Bulan Syawal, maka seolah-olah ia berpuasa satu tahun.\""},"2014":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ حَتَّى نَقُولَ لَا يُفْطِرُ وَيُفْطِرُ حَتَّى نَقُولَ لَا يَصُومُ وَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَكْمَلَ صِيَامَ شَهْرٍ قَطُّ إِلَّا رَمَضَانَ وَمَا رَأَيْتُهُ فِي شَهْرٍ أَكْثَرَ صِيَامًا مِنْهُ فِي شَعْبَانَحَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ زَادَ كَانَ يَصُومُهُ إِلَّا قَلِيلًا بَلْ كَانَ يَصُومُهُ كُلَّهُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah], dari [Malik], dari [Abu An Nadhr] mantan budak Umar bin 'Ubaidullah, dari [Abu Salamah bin Abdurrahman] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam bahwa ia berkata; Rasulullah shallallahu 'alaihi wasallam berpuasa hingga kami mengatakan; beliau tidak berbuka, dan beliau berbuka hingga kami mengatakan; beliau tidak berpuasa. Dan tidaklah aku melihat Rasulullah shallallahu 'alaihi wasallam menyempurnakan puasa satu bulan sama sekali kecuali pada Bulan Ramadhan, dan tidaklah aku melihat beliau dalam satu bulan lebih banyak melakukan puasa daripada berpuasa pada Bulan Sya'ban. Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Muhammad bin 'Amr] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dengan maknanya. Ia menambahkan; beliau melakukan puasa padanya kecuali sedikit, bahkan beliau pernah berpuasa pada bulan tersebut secara penuh."},"2015":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى عَنْ عُمَرَ بْنِ أَبِي الْحَكَمِ بْنِ ثَوْبَانَ عَنْ مَوْلَى قُدَامَةَ بْنِ مَظْعُونٍ عَنْ مَوْلَى أُسَامَةَ بْنِ زَيْدٍأَنَّهُ انْطَلَقَ مَعَ أُسَامَةَ إِلَى وَادِي الْقُرَى فِي طَلَبِ مَالٍ لَهُ فَكَانَ يَصُومُ يَوْمَ الِاثْنَيْنِ وَيَوْمَ الْخَمِيسِ فَقَالَ لَهُ مَوْلَاهُ لِمَ تَصُومُ يَوْمَ الِاثْنَيْنِ وَيَوْمَ الْخَمِيسِ وَأَنْتَ شَيْخٌ كَبِيرٌ فَقَالَ إِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَصُومُ يَوْمَ الِاثْنَيْنِ وَيَوْمَ الْخَمِيسِ وَسُئِلَ عَنْ ذَلِكَ فَقَالَ إِنَّ أَعْمَالَ الْعِبَادِ تُعْرَضُ يَوْمَ الِاثْنَيْنِ وَيَوْمَ الْخَمِيسِقَالَ أَبُو دَاوُد كَذَا قَالَ هِشَامٌ الدَّسْتُوَائِيُّ عَنْ يَحْيَى عَنْ عُمَرَ بْنِ أَبِي الْحَكَمِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Aban], telah menceritakan kepada kami [Yahya] dari [Umar bin Abu Al Hakam bin Tsauban] dari [mantan budak Qudamah bin Mazh'un] dari [mantan budak Usamah bin Zaid], bahwa ia pernah pergi bersama Usamah menuju bukit Al Qura untuk mencari hartanya, ia berpuasa pada hari Senin dan Kamis. Kemudian mantan budaknya berkata; kenapa engkau berpuasa pada Hari Senin dan Kamis? Dan ia ditanya mengeani hal tersebut, lalu ia berkata; sesungguhnya Nabi shallallahu 'alaihi wasallam berkata: \"Sesungguhnya amalan para hamba disampaikan pada hari Senin dan Kamis.\" Abu Daud berkata; demikianlah yang dikatakan oleh Hisyam Ad Dastuwai dari Yahya dari Umar bin Abu Al Hakam. "},"2016":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْحُرِّ بْنِ الصَّبَّاحِ عَنْ هُنَيْدَةَ بْنِ خَالِدٍ عَنْ امْرَأَتِهِ عَنْ بَعْضِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ تِسْعَ ذِي الْحِجَّةِ وَيَوْمَ عَاشُورَاءَ وَثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ أَوَّلَ اثْنَيْنِ مِنْ الشَّهْرِ وَالْخَمِيسَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu 'Awanah] dari [Al Hurr bin Ash Shabbah], dari [Hunaidah bin Khalid] dari [Seorang wanita] dari [sebagian isteri Nabi shallallahu 'alaihi wasallam] ia berkata; Rasulullah shallallahu 'alaihi wasallam berpuasa pada tanggal sembilan Bulan Dzul Hijjah, serta pada Hari 'Asyura` serta tiga hari dari setiap bulan, dan hari Senin serta Kamis pada setiap bulan. "},"2017":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ وَمُجَاهِدٍ وَمُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ أَيَّامٍ الْعَمَلُ الصَّالِحُ فِيهَا أَحَبُّ إِلَى اللَّهِ مِنْ هَذِهِ الْأَيَّامِ يَعْنِي أَيَّامَ الْعَشْرِ قَالُوا يَا رَسُولَ اللَّهِ وَلَا الْجِهَادُ فِي سَبِيلِ اللَّهِ قَالَ وَلَا الْجِهَادُ فِي سَبِيلِ اللَّهِ إِلَّا رَجُلٌ خَرَجَ بِنَفْسِهِ وَمَالِهِ فَلَمْ يَرْجِعْ مِنْ ذَلِكَ بِشَيْءٍ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih], dan [Mujahid], serta [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hari, amal shalih padanya yang lebih Allah cintai daripada sepuluh hari (Dzul Hijjah).\" Mereka berkata; wahai Rasulullah, tidak pula berjihad di jalan Allah? Beliau berkata: \"Tidak pula berjihad di jalan Allah, kecuali seorang laki-laki yang keluar dengan jiwa dan hartanya kemudian tidak kembali membawa sesuatupun.\""},"2018":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَائِمًا الْعَشْرَ قَطُّ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu 'Awanah], dari [Al A'masy] dari [Ibrahim], dari [Al Aswad] dari [Aisyah], ia berkata; aku pernah melihat Rasulullah shallallahu 'alaihi wasallam berpuasa sepuluh hari sama sekali. "},"2019":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَوْشَبُ بْنُ عُقَيْلٍ عَنْ مَهْدِيٍّ الْهَجَرِيِّ حَدَّثَنَا عِكْرِمَةُ قَالَكُنَّا عِنْدَ أَبِي هُرَيْرَةَ فِي بَيْتِهِ فَحَدَّثَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ صَوْمِ يَوْمِ عَرَفَةَ بِعَرَفَةَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], telah menceritakan kepada kami [Hausyab bin 'Uqail], dari [Mahdi Al Hajari], telah menceritakan kepada kami ['Ikrimah], ia berkata; dahulu kami pernah di sisi [Abu Hurairah] di rumahnya, kemudian ia bercerita kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang berpuasa pada hari 'Arafah di 'Arafah. "},"2020":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي النَّضْرِ عَنْ عُمَيْرٍ مَوْلَى عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ أُمِّ الْفَضْلِ بِنْتِ الْحَارِثِ أَنَّ نَاسًا تَمَارَوْا عِنْدَهَا يَوْمَ عَرَفَةَ فِي صَوْمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَعْضُهُمْ هُوَ صَائِمٌ وَقَالَ بَعْضُهُمْ لَيْسَ بِصَائِمٍ فَأَرْسَلَتْ إِلَيْهِ بِقَدَحِ لَبَنٍ وَهُوَ وَاقِفٌ عَلَى بَعِيرِهِ بِعَرَفَةَ فَشَرِبَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Abu An Nadhr] dari ['Umair] mantan budak Abdullah bin Abbas, dari [Ummu Al Fadhl binti Al Harits] bahwa beberapa orang berselisih di hadapannya pada Hari 'Arafah mengenai puasa Rasulullah shallallahu 'alaihi wasallam, kemudian sebagian mereka mengatakan; beliau berpuasa, dan sebagian mereka mengatakan; beliau tidak berpuasa. Kemudian Ummu Al Fadhl mengirimkan mangkuk yang berisi susu kepada beliau sementara beliau sedang berada di atas untanya di 'Arafah lalu beliau meminumnya. "},"2021":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ كَانَ يَوْمُ عَاشُورَاءَ يَوْمًا تَصُومُهُ قُرَيْشٌ فِي الْجَاهِلِيَّةِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُهُ فِي الْجَاهِلِيَّةِ فَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ صَامَهُ وَأَمَرَ بِصِيَامِهِ فَلَمَّا فُرِضَ رَمَضَانُ كَانَ هُوَ الْفَرِيضَةُ وَتُرِكَ عَاشُورَاءُ فَمَنْ شَاءَ صَامَهُ وَمَنْ شَاءَ تَرَكَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata; dahulu Hari 'Asyura adalah berpuasanya orang-orang Quraisy pada masa jahiliyah, dan Rasulullah shallallahu 'alaihi wasallam melakukan puasa pada masa jahiliyah, kemudian tatkala Rasulullah shallallahu 'alaihi wasallam datang ke Madinah beliau berpuasa pada hari tersebut dan beliau memerintahkan untuk berpuasa. Kemudian tatkala diwajibkan puasa pada Bulan Ramadhan maka puasa itulah yang diwajibkan dan puasa hari 'Asyura di tinggalkan. Barangsiapa yang berkeinginan (berpuasa) maka ia (boleh) berpuasa, dan barangsiapa berkeinginan (tidak berpuasa) maka ia (boleh) meninggalkannya. "},"2022":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَكَانَ عَاشُورَاءُ يَوْمًا نَصُومُهُ فِي الْجَاهِلِيَّةِ فَلَمَّا نَزَلَ رَمَضَانُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا يَوْمٌ مِنْ أَيَّامِ اللَّهِ فَمَنْ شَاءَ صَامَهُ وَمَنْ شَاءَ تَرَكَهُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya] dari ['Ubaidullah], ia berkata; telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar], ia berkata; Hari 'Asyura` adalah hari kami berpuasa pada masa jahiliyah. Kemudian tatkala turun kewajiban puasa Bulan Ramadhan Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ini adalah hari diantara hari-hari Allah, barangsiapa yang berkeinginan (berpuasa) ia (boleh) berpuasa, dan barangsiapa yang berkeinginan (berbuka) ia (boleh) meninggalkannya (tidak berpuasa).\""},"2023":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَجَدَ الْيَهُودَ يَصُومُونَ عَاشُورَاءَ فَسُئِلُوا عَنْ ذَلِكَ فَقَالُوا هَذَا الْيَوْمُ الَّذِي أَظْهَرَ اللَّهُ فِيهِ مُوسَى عَلَى فِرْعَوْنَ وَنَحْنُ نَصُومُهُ تَعْظِيمًا لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْنُ أَوْلَى بِمُوسَى مِنْكُمْ وَأَمَرَ بِصِيَامِهِ","id":"Telah menceritakan kepada kami [Ziyad bin Ayyub], Telah menceritakan kepada kami [Husyaim], telah menceritakan kepada kami [Abu Bisyr], dari [Sa'id bin Jubair], dari [Ibnu Abbas], ia berkata; tatkala Nabi shallallahu 'alaihi wasallam datang ke Madinah, beliau mendapati orang-orang Yahudi berpuasa pada hari 'Asyura, kemudian mereka ditanya mengenai hal tersebut. Kemudian mereka berkata; ini adalah hari dimana Allah memenangkan Musa atas Fir'aun, sementara kami sedang berpuasa sebagai pengagungan terhadapnya. Rasulullah shallallahu 'alaihi wasallam berkata; kami lebih berhak terhadap Musa daripada kalian. Dan beliau memerintahkan untuk berpuasa pada hari tersebut. "},"2024":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يَحْيَى بْنُ أَيُّوبَ أَنَّ إِسْمَعِيلَ بْنَ أُمَيَّةَ الْقُرَشِيَّ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا غَطَفَانَ يَقُولُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ يَقُولُحِينَ صَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عَاشُورَاءَ وَأَمَرَنَا بِصِيَامِهِ قَالُوا يَا رَسُولَ اللَّهِ إِنَّهُ يَوْمٌ تُعَظِّمُهُ الْيَهُودُ وَالنَّصَارَى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا كَانَ الْعَامُ الْمُقْبِلُ صُمْنَا يَوْمَ التَّاسِعِ فَلَمْ يَأْتِ الْعَامُ الْمُقْبِلُ حَتَّى تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri], telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Yahya bin Ayyub], bahwa [Isma'il bin Umayyah Al Qurasyi] telah menceritakan kepadanya bahwa ia telah mendengar [Abu Ghatafan] berkata; saya mendengar [Abdullah bin Abbas] ketika Nabi shallallahu 'alaihi wasallam berpuasa pada hari 'Asyura ia berkata; dan beliau memerintahkan kami agar berpuasa pada hari tersebut. Para sahabat kertanya; wahai Rasulullah, itu adalah hari dimana orang-orang yahudi dan nashrani mengagungkannya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila tahun depan maka kita akan berpuasa pada hari kesembilan.\" Kemudian belum datang tahun depan Rasulullah shallallahu 'alaihi wasallam telah meninggal dunia. "},"2025":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ سَعِيدٍ عَنْ مُعَاوِيَةَ بْنِ غَلَّابٍ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَعِيلُ أَخْبَرَنِي حَاجِبُ بْنُ عُمَرَ جَمِيعًا الْمَعْنَى عَنْ الْحَكَمِ بْنِ الْأَعْرَجِ قَالَأَتَيْتُ ابْنَ عَبَّاسٍ وَهُوَ مُتَوَسِّدٌ رِدَاءَهُ فِي الْمَسْجِدِ الْحَرَامِ فَسَأَلْتُهُ عَنْ صَوْمِ يَوْمِ عَاشُورَاءَ فَقَالَ إِذَا رَأَيْتَ هِلَالَ الْمُحَرَّمِ فَاعْدُدْ فَإِذَا كَانَ يَوْمُ التَّاسِعِ فَأَصْبِحْ صَائِمًا فَقُلْتُ كَذَا كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ فَقَالَ كَذَلِكَ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya bin Sa'id], dari [Mu'awiyah bin Ghallab]. Dan telah diriwayatkan dari jalur yang lain: dan telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Isma'il], telah mengabarkan kepadaku [Hajib bin Umar] secara makna, dari [Al Hakam bin Al A'raj], ia berkata; aku mendatangi [Ibnu Abbas], sementara ia sedang berbantalkan pakaiannya di Masjid Haram kemudian aku bertanya kepada mengenai puasa Hari 'Asyura`. Kemudian ia berkata; apabila engkau melihat hilal Bulan Muharram maka hitunglah, kemudian apabila pada hari yang kesembilan. Kemudian pada paginya beliau berpuasa. Aku katakan; begitulah Muhammad shallallahu 'alaihi wasallam berpuasa."},"2026":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمِنْهَالِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَسْلَمَةَ عَنْ عَمِّهِأَنَّ أَسْلَمَ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ صُمْتُمْ يَوْمَكُمْ هَذَا قَالُوا لَا قَالَ فَأَتِمُّوا بَقِيَّةَ يَوْمِكُمْ وَاقْضُوهُقَالَ أَبُو دَاوُد يَعْنِي يَوْمَ عَاشُورَاءَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Minhal], telah menceritakan kepada kami [Yazid bin Zurai'], telah menceritakan kepada kami [Sa'id], dari [Qatadah] dari [Abdurrahman bin Maslamah], dari [pamannya] bahwa orang-orang dari Kabilah Aslam datang kepada Nabi shallallahu 'alaihi wasallam kemudian beliau berkata: \"Apakah kalian berpuasa pada hari ini?\" Mereka berkata; tidak. Beliau berkata: \"Sempurnakan sisa hari kalian ini dan gantilah (pada hari yang lain).\" Abu Daud berkata; yang beliau maksudkan adalah Hari 'Asyura. "},"2027":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَمُحَمَّدُ بْنُ عِيسَى وَمُسَدَّدٌ وَالْإِخْبَارُ فِي حَدِيثِ أَحْمَدَ قَالُوا حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ عَمْرًا قَالَ أَخْبَرَنِي عَمْرُو بْنُ أَوْسٍ سَمِعَهُ مِنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَبُّ الصِّيَامِ إِلَى اللَّهِ تَعَالَى صِيَامُ دَاوُدَ وَأَحَبُّ الصَّلَاةِ إِلَى اللَّهِ تَعَالَى صَلَاةُ دَاوُدَ كَانَ يَنَامُ نِصْفَهُ وَيَقُومُ ثُلُثَهُ وَيَنَامُ سُدُسَهُ وَكَانَ يُفْطِرُ يَوْمًا وَيَصُومُ يَوْمًا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], serta [Muhammad bin Isa], dan [Musaddad], pengabaran ada dalam hadits Ahmad, mereka berkata; telah menceritakan kepada kami [Sufyan], ia berkata; saya mendengar ['Amr] berkata; telah mengabarkan kepadaku ['Amr bin Aus], ia mendengarnya dari [Abdullah bin 'Amr], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Puasa yang paling Allah ta'ala senangi adalah puasa Daud, dan shalat yang Allah ta'ala senangi adalah shalat Daud, ia tidur setengahnya dan melakukan shalat sepertiganya, dan tidur seperenamnya, dan beliau berbuka satu hari dan berpuasa satu hari.\""},"2028":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا هَمَّامٌ عَنْ أَنَسٍ أَخِي مُحَمَّدٍ عَنْ ابْنِ مِلْحَانَ الْقَيْسِيِّ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا أَنْ نَصُومَ الْبِيضَ ثَلَاثَ عَشْرَةَ وَأَرْبَعَ عَشْرَةَ وَخَمْسَ عَشْرَةَ قَالَ وَقَالَ هُنَّ كَهَيْئَةِ الدَّهْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah menceritakan kepada kami [Hammam], dari [Anas] saudara Muhammad, dari [Ibnu Milhan Al Qaisi] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami agar berpuasa pada hari Bidh yaitu tanggal tiga belas, empat belas, dan lima belas. Ia berkata; dan beliau berkata; hari-hari tersebut seperti satu tahun. "},"2029":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شَيْبَانُ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ يَعْنِي مِنْ غُرَّةِ كُلِّ شَهْرٍ ثَلَاثَةَ أَيَّامٍ","id":"Telah menceritakan kepada kami [Abu Kamil], telah menceritakan kepada kami [Abu Daud], telah menceritakan kepada kami [Syaiban], dari ['Ashim] dari [Zirr], dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam berpuasa tiga hari setiap bulan. "},"2030":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ سَوَاءٍ الْخُزَاعِيِّ عَنْ حَفْصَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ ثَلَاثَةَ أَيَّامٍ مِنْ الشَّهْرِ الِاثْنَيْنِ وَالْخَمِيسَ وَالِاثْنَيْنِ مِنْ الْجُمْعَةِ الْأُخْرَى","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], dari ['Ashim bin Bahlah], dari [Sawa` Al Khuza'i], dari [Hafshah], ia berkata; Rasulullah shallallahu 'alaihi wasallam berpuasa tiga hari setiap bulan hari Senin, dan Kamis, serta hari Senin pada Jum'at yang lain. "},"2031":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا الْحَسَنُ بْنُ عُبَيْدِ اللَّهِ عَنْ هُنَيْدَةَ الْخُزَاعِيِّ عَنْ أُمِّهِ قَالَتْدَخَلْتُ عَلَى أُمِّ سَلَمَةَ فَسَأَلْتُهَا عَنْ الصِّيَامِ فَقَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنِي أَنْ أَصُومَ ثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ أَوَّلُهَا الِاثْنَيْنِ وَالْخَمِيسِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb], telah menceritakan kepada kami [Muhammad bin Fudhail], telah menceritakan kepada kami [Al Hasan bin 'Ubaidullah] dari [Hunaidah Al Khuza'i], dari [ibunya], ia berkata; aku menemui [Ummu Salamah], kemudian bertanya kepadanya mengenai puasa. Lalu ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkanku agar berpuasa tiga hari setiap bulan, yang pertama adalah puasa Senin dan Kamis. "},"2032":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ يَزِيدَ الرِّشْكِ عَنْ مُعَاذَةَ قَالَتْقُلْتُ لِعَائِشَةَ أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ مِنْ كُلِّ شَهْرٍ ثَلَاثَةَ أَيَّامٍ قَالَتْ نَعَمْ قُلْتُ مِنْ أَيِّ شَهْرٍ كَانَ يَصُومُ قَالَتْ مَا كَانَ يُبَالِي مِنْ أَيِّ أَيَّامِ الشَّهْرِ كَانَ يَصُومُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abdul Warits] dari [Yazid Ar Risyk], dari [Mu'adzah], ia berkata; aku katakan kepada [Aisyah]; apakah Rasulullah shallallahu 'alaihi wasallam melakukan puasa tiga hari setiap bulan? Ia berkata; ya. Aku katakan; pada bulan apakah beliau berpuasa? Ia berkata; beliau tidak perduli pada bulan apakah beliau berpuasa. "},"2033":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي ابْنُ لَهِيعَةَ وَيَحْيَى بْنُ أَيُّوبَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ حَزْمٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ حَفْصَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يُجْمِعْ الصِّيَا��َ قَبْلَ الْفَجْرِ فَلَا صِيَامَ لَهُقَالَ أَبُو دَاوُد رَوَاهُ اللَّيْثُ وَإِسْحَقُ بْنُ حَازِمٍ أَيْضًا جَمِيعًا عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ مِثْلَهُ وَوَقَفَهُ عَلَى حَفْصَةَ مَعْمَرٌ وَالزُّبَيْدِيُّ وَابْنُ عُيَيْنَةَ وَيُونُسُ الْأَيْلِيُّ كُلُّهُمْ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Abdullah bin Wahb], telah menceritakan kepada kami [Ibnu Lahi'ah], serta [Yahya bin Ayyub] dari [Abdullah bin Abu Bakr bin Hazm] dari [Ibnu Syihab], dari [Salim bin Abdullah] dari [ayahnya] dari [Hafshah] isteri Nabi shallallahu 'alaihi wasallam bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Barangsiapa yang belum berniat untuk berpuasa sebelum fajar, maka tidak ada (tidak sah) puasa baginya.\" Abu Daud berkata; hadits tersebut diriwayatkan oleh [Al Laits] serta [Ishaq bin Hazim] juga, seluruhnya berasal dari [Abdullah bin Abu Bakr], seperti itu dan meriwayatkannya secara mauquf kepada [Hafshah], Dan diriwayatkan [Ma'mar], [Az Zubaidi] dan [Ibnu 'Uyainah] serta [Yunus Al Aili] seluruhnya berasal dari [Az Zuhri]. "},"2034":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ جَمِيعًا عَنْ طَلْحَةَ بْنِ يَحْيَى عَنْ عَائِشَةَ بِنْتِ طَلْحَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ عَلَيَّ قَالَ هَلْ عِنْدَكُمْ طَعَامٌ فَإِذَا قُلْنَا لَا قَالَ إِنِّي صَائِمٌ زَادَ وَكِيعٌ فَدَخَلَ عَلَيْنَا يَوْمًا آخَرَ فَقُلْنَا يَا رَسُولَ اللَّهِ أُهْدِيَ لَنَا حَيْسٌ فَحَبَسْنَاهُ لَكَ فَقَالَ أَدْنِيهِ قَالَ طَلْحَةُ فَأَصْبَحَ صَائِمًا وَأَفْطَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah menceritakan kepada kami [Sufyan], dan telah diriwayatkan [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Waki'], seluruhnya berasal dari [Thalhah bin Yahya], dari [Aisyah binti Thalhah], dari [Aisyah] radliallahu 'anha, ia berkata; Rasulullah shallallahu 'alaihi wasallam apabila menemuiku beliau mengatakan; apakah kalian memiliki makanan? Apabila kami mengatakan; tidak, maka beliau berkata; sesungguhnya aku berpuasa. Waki' berkata; kemudian pada suatu hari beliau menemui kami, lalu kami katakan; wahai Rasulullah kami telah diberi hadiah hais (makanan dari campuran kurma, keju dan mentega), kemudian kami menyimpannya untuk engkau. Lalu beliau berkata: \"Bawalah kemari!\" Thalhah berkata; maka, pada pagi hari tersebut beliau berpuasa kemudian berbuka. "},"2035":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أُمِّ هَانِئٍ قَالَتْ لَمَّا كَانَ يَوْمُ الْفَتْحِ فَتْحِ مَكَّةَ جَاءَتْ فَاطِمَةُ فَجَلَسَتْ عَنْ يَسَارِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُمُّ هَانِئٍ عَنْ يَمِينِهِ قَالَتْ فَجَاءَتْ الْوَلِيدَةُ بِإِنَاءٍ فِيهِ شَرَابٌ فَنَاوَلَتْهُ فَشَرِبَ مِنْهُ ثُمَّ نَاوَلَهُ أُمَّ هَانِئٍ فَشَرِبَتْ مِنْهُ فَقَالَتْ يَا رَسُولَ اللَّهِ لَقَدْ أَفْطَرْتُ وَكُنْتُ صَائِمَةً فَقَالَ لَهَا أَكُنْتِ تَقْضِينَ شَيْئًا قَالَتْ لَا قَالَ فَلَا يَضُرُّكِ إِنْ كَانَ تَطَوُّعًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Jarir bin Abdul Hamid], dari [Yazid bin Abu Ziyad] dari [Abdullah bin Al Harits], dari [Ummu Hani`], ia berkata; pada saat penaklukan Mekkah Fathimah datang dan duduk di sebelah kiri Rasulullah shallallahu 'alaihi wasallam sementara Ummu Hani` di sisi kanan beliau. Ummu Hani` berkata; kemudian datanglah seorang anak wanita membawa bejana berisi air minum, kemudian ia memberikannya kepada beliau. Lalu beliau minum sebagian darinya kemudian beliau memberikannya kepada Ummu Hani`, lalu ia meminum sebagian darinya dan berkata; wahai Rasulullah, sungguh saya telah berbuka, tadinya aku sedang berpuasa. Kemudian beliau berkata kepadanya: \" Apakah engkau mengqadha` puasa?\" Ia berkata; tidak. Lalu beliau berkata: \"Hal itu tidak mengapa bagimu apabila puasa sunah.\""},"2036":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي حَيْوَةُ بْنُ شُرَيْحٍ عَنْ ابْنِ الْهَادِ عَنْ زُمَيْلٍ مَوْلَى عُرْوَةَ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْأُهْدِيَ لِي وَلِحَفْصَةَ طَعَامٌ وَكُنَّا صَائِمَتَيْنِ فَأَفْطَرْنَا ثُمَّ دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْنَا لَهُ يَا رَسُولَ اللَّهِ إِنَّا أُهْدِيَتْ لَنَا هَدِيَّةٌ فَاشْتَهَيْنَاهَا فَأَفْطَرْنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا عَلَيْكُمَا صُومَا مَكَانَهُ يَوْمًا آخَرَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Abdullah bin Wahb], telah mengabarkan kepadaku [Haiwah bin Syuraih] dari [Ibnu Al Had], dari [Zumail] mantan budak 'Urwah, dari ['Urwah bin Az Zubair] dari [Aisyah], ia berkata; aku dan Hafshah telah diberi hadiah makanan sementara kami sedang berpuasa, kemudian kami berbuka. Lalu Rasulullah shallallahu 'alaihi wasallam berkata: \"Tidak mengapa, berpuasalah pada hari yang lain sebagai gantinya.\""},"2037":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَصُومُ الْمَرْأَةُ وَبَعْلُهَا شَاهِدٌ إِلَّا بِإِذْنِهِ غَيْرَ رَمَضَانَ وَلَا تَأْذَنُ فِي بَيْتِهِ وَهُوَ شَاهِدٌ إِلَّا بِإِذْنِهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdurrazzaq], telah menceritakan kepada kami [Ma'mar], dari [Hammam bin Munabbih], bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang wanita tidak boleh berpuasa sementara suaminya berada di sisinya kecuali dengan seizinnya selain puasa pada Bulan Ramadhan dan tidak boleh ia mengizinkan seseorang di dalam rumahnya sementara suaminya berada di sisinya kecuali dengan seizinnya.\""},"2038":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَجَاءَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ عِنْدَهُ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ زَوْجِي صَفْوَانَ بْنَ الْمُعَطَّلِ يَضْرِبُنِي إِذَا صَلَّيْتُ وَيُفَطِّرُنِي إِذَا صُمْتُ وَلَا يُصَلِّي صَلَاةَ الْفَجْرِ حَتَّى تَطْلُعَ الشَّمْسُ قَالَ وَصَفْوَانُ عِنْدَهُ قَالَ فَسَأَلَهُ عَمَّا قَالَتْ فَقَالَ يَا رَسُولَ اللَّهِ أَمَّا قَوْلُهَا يَضْرِبُنِي إِذَا صَلَّيْتُ فَإِنَّهَا تَقْرَأُ بِسُورَتَيْنِ وَقَدْ نَهَيْتُهَا قَالَ فَقَالَ لَوْ كَانَتْ سُورَةً وَاحِدَةً لَكَفَتْ النَّاسَ وَأَمَّا قَوْلُهَا يُفَطِّرُنِي فَإِنَّهَا تَنْطَلِقُ فَتَصُومُ وَأَنَا رَجُلٌ شَابٌّ فَلَا أَصْبِرُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ لَا تَصُومُ امْرَأَةٌ إِلَّا بِإِذْنِ زَوْجِهَا وَأَمَّا قَوْلُهَا إِنِّي لَا أُصَلِّي حَتَّى تَطْلُعَ الشَّمْسُ فَإِنَّا أَهْلُ بَيْتٍ قَدْ عُرِفَ لَنَا ذَاكَ لَا نَكَادُ نَسْتَيْقِظُ حَتَّى تَطْلُعَ الشَّمْسُ قَالَ فَإِذَا اسْتَيْقَظْتَ فَصَلِّقَالَ أَبُو دَاوُد رَوَاهُ حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ حُمَيْدٍ أَوْ ثَابِتٍ عَنْ أَبِي الْمُتَوَكِّلِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih], dari [Abu Sa'id], ia berkata; seorang wanita telah datang kepada Nabi shallallahu 'alaihi wasallam sementara kami berada di sisi beliau, kemudian wanita tersebut berkata; wahai Rasulullah, sesungguhnya suamiku yaitu Shafwan bin Al Mu'aththal memukulku apabila aku melakukan shalat dan ia memberiku makan untuk berbuka apabila aku berpuasa, dan ia tidak melakukan shalat Fajar hingga matahari terbit. Abu Said berkata; sedangkan Shafwan berada di sisinya. Kemudian dia menanyakan apa yang telah dikatakan wanita tersebut. Shafwan berkata; \"Wahai Rasulullah, pengaduannya bahwa dia memukulku jika saya shalat, itu karena dia membaca dua surat yang telah saya larang. Jika saja dia mau membaca satu surat saja yaitu An Nas, maka cukuplah hal itu. Sedangkan dia menyuruhku berbuka, itu karena dia pergi dan berpuasa, padahal saya adalah seseorang yang masih muda, maka saya tidak akan bisa bersabar.\" Rasulullah shallallahu 'alaihi wasallam bersabda pada saat itu: \"Janganlah seorang istri berpuasa kecuali dengan izin dari suaminya.\" \"Sedangkan pengaduan bahwa dia tidak shalat sehingga matahari terbit, karena kami adalah para penghuni rumah, dan hal itu sudah dimaklum bahwa kami bangun pada saat mendekati matahari terbit.\" Beliau bersabda: \"Jika kamu telah bangun maka shalatlah.\" Abu Daud berkata; dan telah meriwayatkan juga [Hammad] yaitu Ibnu Salamah, dari [Humaid] atau [Tsabit], dari [Abu Al Mutawakkil]. "},"2039":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دُعِيَ أَحَدُكُمْ فَلْيُجِبْ فَإِنْ كَانَ مُفْطِرًا فَلْيَطْعَمْ وَإِنْ كَانَ صَائِمًا فَلْيُصَلِّقَالَ هِشَامٌ وَالصَّلَاةُ الدُّعَاءُ قَالَ أَبُو دَاوُد رَوَاهُ حَفْصُ بْنُ غِيَاثٍ أَيْضًا عَنْ هِشَامٍ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id], telah menceritakan kepada kami [Abu Khalid] dari [Hisyam] dari [Ibnu Sirin] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang diantara kalian diundang, hendaknya ia memenuhi undangan tersebut, apabila ia tidak berpuasa hendaknya ia makan, dan apabila ia sedang berpuasa maka hendaknya ia mendoakan!\" Hisyam berkata; yang dimaksud dengan shalat adalah berdoa. Abu Daud berkata; hadits tersebut diriwayatkan oleh Hafsh bin Giyats juga dari Hisyam. "},"2040":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دُعِيَ أَحَدُكُمْ إِلَى طَعَامٍ وَهُوَ صَائِمٌ فَلْيَقُلْ إِنِّي صَائِمٌ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Sufyan], dari [Abu Az Zinad], dari [Al A'raj], dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang diantara kalian diundang untuk makan sementara ia sedang berpuasa, hendaknya ia mengatakan; saya sedang berpuasa.\""},"2041":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَعْتَكِفُ الْعَشْرَ الْأَوَاخِرَ مِنْ رَمَضَانَ حَتَّى قَبَضَهُ اللَّهُ ثُمَّ اعْتَكَفَ أَزْوَاجُهُ مِنْ بَعْدِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Az Zuhri] dari ['Urwah] dari [Aisyah], bahwa Nabi shallallahu 'alaihi wasallam beri'tikaf pada sepuluh hari terakhir Bulan Ramadhan hingga Allah mewafatkannya, kemudian para isterinya beri'tikaf setelah beliau. "},"2042":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ عَنْ أَبِي رَافِعٍ عَنْ أُبَيِّ بْنِ كَعْبٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَعْتَكِفُ الْعَشْرَ الْأَوَاخِرَ مِنْ رَمَضَانَ فَلَمْ يَعْتَكِفْ عَامًا فَلَمَّا كَانَ فِي الْعَامِ الْمُقْبِلِ اعْتَكَفَ عِشْرِينَ لَيْلَةً","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami [Tsabit] dari [Abu Rafi'] dari [Ubai bin Ka'bin], bahwa Nabi shallallahu 'alaihi wasallam beri'tikaf sepuluh hari Bulan Ramadhan, dan beliau tidak beri'tikaf satu tahun. Kemudian tatkala pada tahun mendatang beliau beri'tikaf selama dua puluh malam. "},"2043":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَيَعْلَى بْنُ عُبَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَس��لَّمَ إِذَا أَرَادَ أَنْ يَعْتَكِفَ صَلَّى الْفَجْرَ ثُمَّ دَخَلَ مُعْتَكَفَهُ قَالَتْ وَإِنَّهُ أَرَادَ مَرَّةً أَنْ يَعْتَكِفَ فِي الْعَشْرِ الْأَوَاخِرِ مِنْ رَمَضَانَ قَالَتْ فَأَمَرَ بِبِنَائِهِ فَضُرِبَ فَلَمَّا رَأَيْتُ ذَلِكَ أَمَرْتُ بِبِنَائِي فَضُرِبَ قَالَتْ وَأَمَرَ غَيْرِي مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبِنَائِهِ فَضُرِبَ فَلَمَّا صَلَّى الْفَجْرَ نَظَرَ إِلَى الْأَبْنِيَةِ فَقَالَ مَا هَذِهِ آلْبِرَّ تُرِدْنَ قَالَتْ فَأَمَرَ بِبِنَائِهِ فَقُوِّضَ وَأَمَرَ أَزْوَاجُهُ بِأَبْنِيَتِهِنَّ فَقُوِّضَتْ ثُمَّ أَخَّرَ الِاعْتِكَافَ إِلَى الْعَشْرِ الْأُوَلِ يَعْنِي مِنْ شَوَّالٍ قَالَ أَبُو دَاوُد رَوَاهُ ابْنُ إِسْحَقَ وَالْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ سَعِيدٍ نَحْوَهُ وَرَوَاهُ مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ اعْتَكَفَ عِشْرِينَ مِنْ شَوَّالٍ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Abu Mu'awiyah], serta [Ya'la bin 'Ubaid] dari [Yahya bin Sa'id], dari ['Amrah] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam apabila hendak beri'tikaf maka beliau melakukan shalat fajar kemudian memasuki tempat i'tikaf beliau. Aisyah berkata; suatu kali beliau hendak beri'tikaf pada sepuluh hari terakhir Bulan Ramadhan, kemudian beliau memerintahkan agar dibuatkan tempat untuk beliau. Lalu tatkala aku melihat hal tersebut maka aku memerintahkan agar dibuatkan tempat untukku. Aisyah berkata; dan beliau memerintahkan isteri Nabi yang lain agar membuat tempat. Kemudian tatkala telah melakukan shalat fajar maka beliau melihat bangunan-bangunan tersebut dan berkata: \"Kebaikan apakah yang kalian inginkan?\" Aisyah berkata; kemudian beliau memerintahkan agar dibuatkan tempat beliau, lalu tempat tersebut dihilangkan, dan para isteri beliau memerintahkan agar didirikan tempat buat mereka, lalu tempat tersebut dihilangkan. Kemudian beliau menunda i'tikaf hingga sampai pada sepuluh pertama Bulan Syawal. Abu Daud berkata; hadits tersebut diriwayatkan oleh [Ibnu Ishaq], dan [Al Auza'i], dari [Yahya bin Sa'id] seperti itu. Dan telah diriwayatkan oleh [Malik] dari [Yahya bin Sa'id], ia berkata; beliau beri'tikaf dua puluh hari Bulan Syawal. "},"2044":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ أَنَّ نَافِعًا أَخْبَرَهُ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَعْتَكِفُ الْعَشْرَ الْأَوَاخِرَ مِنْ رَمَضَانَقَالَ نَافِعٌ وَقَدْ أَرَانِي عَبْدُ اللَّهِ الْمَكَانَ الَّذِي كَانَ يَعْتَكِفُ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri], telah mengabarkan kepada kami [Ibnu Wahb], dari [Yunus], bahwa [Nafi'] telah mengabarkan kepadanya dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam beri'tikaf sepuluh hari terakhir Bulan Ramadhan. Nafi' berkata; Abdullah telah memperlihatkan kepadaku tempat yang digunakan Rasulullah shallallahu 'alaihi wasallam untuk beri'tikaf di Masjid. "},"2045":{"ar":"حَدَّثَنَا هَنَّادٌ عَنْ أَبِي بَكْرٍ عَنْ أَبِي حُصَيْنٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْتَكِفُ كُلَّ رَمَضَانَ عَشَرَةَ أَيَّامٍ فَلَمَّا كَانَ الْعَامُ الَّذِي قُبِضَ فِيهِ اعْتَكَفَ عِشْرِينَ يَوْمًا","id":"Telah menceritakan kepada kami [Hannad], dari [Abu Bakr] dari [Abu Hushain] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Nabi shallallahu 'alaihi wasallam beri'tikaf sepuluh hari setiap Bulan Ramadhan. Kemudian tatkala pada tahun meninggalnya, beliau melakukan i'tikaf sebanyak dua puluh hari."},"2046":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اعْتَكَفَ يُدْنِي إِلَيَّ رَأْسَهُ فَأُرَجِّلُهُ وَكَانَ لَا يَدْخُلُ الْبَيْتَ إِلَّا لِحَاجَةِ الْإِنْسَانِحَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَعَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَا حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ وَعَمْرَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ يُونُسُ عَنْ الزُّهْرِيِّ وَلَمْ يُتَابِعْ أَحَدٌ مَالِكًا عَلَى عُرْوَةَ عَنْ عَمْرَةَ وَرَوَاهُ مَعْمَرٌ وَزِيَادُ بْنُ سَعْدٍ وَغَيْرِهِمَا عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah], dari [Malik] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair], dari ['Amrah binti Abdurrahman] dari [Aisyah], ia berkata; apabila Rasulullah shallallahu wa'alaihi wa sallam hendak beri'tikaf, maka beliau mendekatkan kepalanya kepadaku, lalu aku menyisir rambutnya. Dan beliau tidak memasuki rumah kecuali karena suatu keperluan manusia. Telah menceritakan kepada kami [Qutaibah bin Sa'id], serta [Abdullah bin Maslamah], mereka berkata; telah menceritakan kepada kami [Al Laits], dari [Ibnu Syihab], dari ['Urwah] serta ['Amrah], dari [Aisyah], dari Nabi shallallahu 'alaihi wasallam seperti itu. Abu Daud berkata; dan begitu juga hadits tersebut diriwayatkan oleh [Yunus] dari [Az Zuhri], dan tidak ada seorangpun yang mengikutkan Malik atas 'Urwah, dari 'Amrah. Dan hadits tersebut telah diriwayatkan oleh [Ma'mar], serta [Ziyad bin Sa'd] dan yang lainnya dari [Az Zuhri] dari ['Urwah] dari [Aisyah]. "},"2047":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَمُسَدَّدٌ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكُونُ مُعْتَكِفًا فِي الْمَسْجِدِ فَيُنَاوِلُنِي رَأْسَهُ مِنْ خَلَلِ الْحُجْرَةِ فَأَغْسِلُ رَأْسَهُ وَقَالَ مُسَدَّدٌ فَأُرَجِّلُهُ وَأَنَا حَائِضٌ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], dan [Musaddad], mereka berkata; telah menceritakan kepada kami [Hammad bin Zaid], dari [Hisyam bin 'Urwah], dari [ayahnya], dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah beri'tikaf di Masjid, kemudian beliau memberikan kepalanya kepadaku melalui celah-celah kamar, lalu aku mencuci kepada beliau. Musaddad berkata; lalu aku menyisir rambutnya sementara aku dalam keadaan haid. "},"2048":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ شَبُّوَيْهِ الْمَرْوَزِيُّ حَدَّثَنِي عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ صَفِيَّةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُعْتَكِفًا فَأَتَيْتُهُ أَزُورُهُ لَيْلًا فَحَدَّثْتُهُ ثُمَّ قُمْتُ فَانْقَلَبْتُ فَقَامَ مَعِي لِيَقْلِبَنِي وَكَانَ مَسْكَنُهَا فِي دَارِ أُسَامَةَ بْنِ زَيْدٍ فَمَرَّ رَجُلَانِ مِنْ الْأَنْصَارِ فَلَمَّا رَأَيَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْرَعَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رِسْلِكُمَا إِنَّهَا صَفِيَّةُ بِنْتُ حُيَيٍّ قَالَا سُبْحَانَ اللَّهِ يَا رَسُولَ اللَّهِ قَالَ إِنَّ الشَّيْطَانَ يَجْرِي مِنْ الْإِنْسَانِ مَجْرَى الدَّمِ فَخَشِيتُ أَنْ يَقْذِفَ فِي قُلُوبِكُمَا شَيْئًا أَوْ قَالَ شَرًّاحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ بِإِسْنَادِهِ بِهَذَا قَالَتْ حَتَّى إِذَا كَانَ عِنْدَ بَابِ الْمَسْجِدِ الَّذِي عِنْدَ بَابِ أُمِّ سَلَمَةَ مَرَّ بِهِمَا رَجُلَانِ وَسَاقَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Ahmad bin Syabbuwaih Al Marwazi], telah menceritakan kepadaku [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar], dari [Az Zuhri], dari [Ali bin Husain], dari [Shafiyyah], berkata; Rasulullah shallallahu 'alaihi wasallam beri'tikaf, kemudian aku datang menjenguk beliau pada malam hari. Lalu aku mengajak beliau berbicara kemudian berdiri dan kembali. Lalu beliau berdiri bersamaku untuk mengantarku, tempat tinggal Shafiyyah adalah di rumah Usamah bin Zaid. Kemudian terdapat dua orang laki-laki anshar yang lewat. Kemudian tatkala mereka melihat Nabi shallallahu 'alaihi wasallam maka mereka mempercepat jalan. Lalu Nabi shallallahu 'alaihi wasallam berkata: \"Perlahanlah berjalan. Ia adalah Shafiyyah binti Huyai.\" Mereka berkata; subhanallah wahai Rasulullah. Beliau berkata: \"Sesungguhnya syetan berjalan pada diri manusia melalui tempat mengalirnya darah. Aku khawatir ia akan melemparkan sesuatu -atau beliau mengatakan: keburukan- pada hati kalian berdua.\" Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris], telah menceritakan kepada kami [Abu Al Yaman], telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri], dengan sanadnya; dengan hal inilah Aisyah berkata; kemudian tatkala berada di samping pintu masjid yang berada di samping pintu Ummu Salamah, terdapat dua orang laki-laki yang melewati mereka ….. dan ia menyebutkan hadits secara maknanya. "},"2049":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ وَمُحَمَّدُ بْنُ عِيسَى قَالَا حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ أَخْبَرَنَا اللَّيْثُ بْنُ أَبِي سُلَيْمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَ النُّفَيْلِيُّ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمُرُّ بِالْمَرِيضِ وَهُوَ مُعْتَكِفٌ فَيَمُرُّ كَمَا هُوَ وَلَا يُعَرِّجُ يَسْأَلُ عَنْهُ وَقَالَ ابْنُ عِيسَى قَالَتْ إِنْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُ الْمَرِيضَ وَهُوَ مُعْتَكِفٌ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], dan [Muhammad bin Isa], mereka berkata; telah menceritakan kepada kami [Abdussalam bin Harb], telah mengabarkan kepada kami [Al Laits bin Abu Sulaim], [Abdurrahman bin Al Qasim], dari [ayahnya] dari [Aisyah], An Nufaili berkata; Aisyah berkata; Rasulullah shallallahu 'alaihi wasallam melewati orang yang sedang sakit. Sementara beliau dalam keadaan sedang beri'tikaf, lalu beliau lewat dalam keadaan seperti itu tidak berbelok untuk bertanya mengenai orang tersebut. Ibnu Isa berkata; Aisyah berkata; sesungguhnya Nabi shallallahu 'alaihi wasallam pernah mengunjungi orang yang sakit sementara beliau dalam keadaan beri'tikaf. "},"2050":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ أَخْبَرَنَا خَالِدٌ عَنْ عَبْدِ الرَّحْمَنِ يَعْنِي ابْنَ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْالسُّنَّةُ عَلَى الْمُعْتَكِفِ أَنْ لَا يَعُودَ مَرِيضًا وَلَا يَشْهَدَ جَنَازَةً وَلَا يَمَسَّ امْرَأَةً وَلَا يُبَاشِرَهَا وَلَا يَخْرُجَ لِحَاجَةٍ إِلَّا لِمَا لَا بُدَّ مِنْهُ وَلَا اعْتِكَافَ إِلَّا بِصَوْمٍ وَلَا اعْتِكَافَ إِلَّا فِي مَسْجِدٍ جَامِعٍقَالَ أَبُو دَاوُد غَيْرُ عَبْدِ الرَّحْمَنِ لَا يَقُولُ فِيهِ قَالَتْ السُّنَّةُ قَالَ أَبُو دَاوُد جَعَلَهُ قَوْلَ عَائِشَةَ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah], telah mengabarkan kepada kami [Khalid], dari [Abdurrahman bin Ishaq] dari [Az Zuhri], dari ['Urwah] dari [Aisyah] bahwa ia berkata; yang disunahkan atas orang yang beri'tikaf adalah tidak menjenguk orang yang sedang sakit, serta tidak mengiringi jenazah serta tidak menyentuh wanita, tidak bercampur dengannya dan tidak keluar untuk suatu keperluan kecuali karena sesuatu yang harus ia lakukan. Dan tidak ada i'tikaf kecuali disertai puasa dan tidak ada i'tikaf kecuali di Masjid yang padanya dilakukan shalat Jum'at. Abu Daud berkata; selain Abdurrahman tidak mengatakan padanya; tidak Aisyah berkata; yang disunahkan. Abu Daud berkata; ia menjadikannya sebagai perkataan Aisyah. "},"2051":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُدَيْلٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ أَنَّ عُمَرَ رَضِيَ اللَّهُ عَنْهُ جَعَلَ عَلَيْهِ أَنْ يَعْتَكِفَ فِي الْجَاهِلِيَّةِ لَيْلَةً أَوْ يَوْمًا عِنْدَ الْكَعْبَةِ فَسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اعْتَكِفْ وَصُمْ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ بْنِ مُحَمَّدِ بْنِ أَبَانَ بْنِ صَالِحٍ الْقُرَشِيُّ حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ ي��عْنِي الْعَنْقَزِيَّ عَنْ عَبْدِ اللَّهِ بْنِ بُدَيْلٍ بِإِسْنَادِهِ نَحْوَهُ قَالَ فَبَيْنَمَا هُوَ مُعْتَكِفٌ إِذْ كَبَّرَ النَّاسُ فَقَالَ مَا هَذَا يَا عَبْدَ اللَّهِ قَالَ سَبْيُ هَوَازِنَ أَعْتَقَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَتِلْكَ الْجَارِيَةُ فَأَرْسَلَهَا مَعَهُمْ","id":"Telah menceritakan kepada kami [Ahmad bin Ibrahim], telah menceritakan kepada kami [Abu Daud], telah menceritakan kepada kami [Abdullah bin Budail], dari ['Amr bin Dinar], dari [Ibnu Umar] bahwa Umar radliallahu 'anhu telah mewajibkan dirinya pada masa jahiliyah untuk beri'tikaf satu malam atau satu hari. Kemudian ia bertanya kepada Nabi shallallahu 'alaihi wasallam. Lalu beliau berkata: \"Beri'tikaflah dan berpuasalah!\" Telah menceritakan kepada kami [Abdullah bin Umar bin Muhammad bin Aban bin Shalih Al Qurasyi], telah menceritakan kepada kami ['Amr bin Muhammad Al 'Anqazi] dari [Abdullah bin Budail] dengan sanadnya seperti itu, ia berkata; ketika Abdullah dalam keadaan beri'tikaf, tiba-tiba orang-orang bertakbir. Umar berkata; apa ini wahai Abdullah? Ia berkata; tawanan perang Hawazin, Nabi shallallahu 'alaihi wasallam telah membebaskannya. Umar berkata; dan budak wanita tersebut. Kemudian ia mengirimkannya. "},"2052":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى وَقُتَيْبَةُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا يَزِيدُ عَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاعْتَكَفَتْ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةٌ مِنْ أَزْوَاجِهِ فَكَانَتْ تَرَى الصُّفْرَةَ وَالْحُمْرَةَ فَرُبَّمَا وَضَعْنَا الطَّسْتَ تَحْتَهَا وَهِيَ تُصَلِّي","id":"Telah menceritakan kepada kami [Muhammad bin Isa], serta [Qutaibah bin Sa'id], mereka berkata; telah menceritakan kepada kami [Yazid] dari [Khalid] dari [Ikrimah] dari [Aisyah], radliallahu 'anha, ia berkata; Nabi shallallahu 'alaihi wasallam beri'tikaf bersama salah seorang isteri beliau, lalu ia melihat warna kuning atau merah, kemungkinan kami telah meletakkan baskom di bawahnya, sementara ia sedang melakukan shalat. "},"2053":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ الْفَضْلِ حَدَّثَنَا الْوَلِيدُ يَعْنِي ابْنَ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ أَعْرَابِيًّا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْهِجْرَةِ فَقَالَ وَيْحَكَ إِنَّ شَأْنَ الْهِجْرَةِ شَدِيدٌ فَهَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ فَهَلْ تُؤَدِّي صَدَقَتَهَا قَالَ نَعَمْ قَالَ فَاعْمَلْ مِنْ وَرَاءِ الْبِحَارِ فَإِنَّ اللَّهَ لَنْ يَتِرَكَ مِنْ عَمَلِكَ شَيْئًا","id":"Telah menceritakan kepada kami [Muammal bin Al Fadhl], telah menceritakan kepada kami [Al Walid bin Muslim], dari [Al Auza'i], dari [Az Zuhri], dari ['Atho` bin Yazid], dari [Abu Sa'id Al Khudri], bahwa seorang badui bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai hijrah. Kemudian beliau berkata: \"Sesungguhnya hijrah adalah perkara yang berat, apakah engkau memiliki unta?\" Ia berkata; ya. Beliau berkata: \"Apakah engkau telah menunaikan zakatnya?\" ia berkata; ya. Beliau berkata: \"Beramallah di belakang lautan, sesungguhnya Allah tidak akan meninggalkan sedikitpun dari amalanmu.\""},"2054":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ وَعُثْمَانُ ابْنَا أَبِي شَيْبَةَ قَالَا حَدَّثَنَا شَرِيكٌ عَنْ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ قَالَ سَأَلْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاعَنْ الْبَدَاوَةِ فَقَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْدُو إِلَى هَذِهِ التِّلَاعِ وَإِنَّهُ أَرَادَ الْبَدَاوَةَ مَرَّةً فَأَرْسَلَ إِلَيَّ نَاقَةً مُحَرَّمَةً مِنْ إِبِلِ الصَّدَقَةِ فَقَالَ لِي يَا عَائِشَةُ ارْفُقِي فَإِنَّ الرِّفْقَ لَمْ يَكُنْ فِي شَيْءٍ قَطُّ إِلَّا زَانَهُ وَلَا نُزِعَ مِنْ شَيْءٍ قَطُّ إِلَّا شَانَهُ","id":"Telah menceritakan kepada kami [Abu Bakr], serta [Utsman] keduanya adalah anak Abu Syaibah, mereka berkata; telah menceritakan kepada kami [Syarik] dari [Al Miqdad bin Syuraih], dari [ayahnya], ia berkata; aku bertanya kepada [Aisyah], radliallahu 'anha mengenai kehidupan nomaden, lalu Aisyah berkata; Rasulullah shallallahu 'alaihi wasallam pernah keluar menuju menuju dataran tinggi ini dan beliau menginginkan kehidupan nomaden kembali, lalu beliau mengirimkan seekor unta yang belum dinaiki dan belum digunakan dari unta zakat. Beliau berkata kepadaku: \"Wahai Aisyah, bersikaplah lembut, sesungguhnya kelembutan tidaklah ada pada sesuatu kecuali akan menghiasinya dan tidaklah tercabut dari sesuatu melainkan akan memberikan aib padanya.\""},"2055":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عِيسَى عَنْ حَرِيزِ بْنِ عُثْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَوْفٍ عَنْ أَبِي هِنْدٍ عَنْ مُعَاوِيَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَنْقَطِعُ الْهِجْرَةُ حَتَّى تَنْقَطِعَ التَّوْبَةُ وَلَا تَنْقَطِعُ التَّوْبَةُ حَتَّى تَطْلُعَ الشَّمْسُ مِنْ مَغْرِبِهَا","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi], telah mengabarkan kepada kami [Isa] dari [Hariz bin Utsman] dari [Abdurrahman bin Abu 'Auf] dari [Abu Hindun], dari [Mu'awiyah], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah hijrah terputus hingga taubat terputus, dan tidaklah taubat terputus hingga matahari terbit dari barat.\""},"2056":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ فَتْحِ مَكَّةَ لَا هِجْرَةَ وَلَكِنْ جِهَادٌ وَنِيَّةٌ وَإِذَا اسْتُنْفِرْتُمْ فَانْفِرُوا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Jarir] dari [Manshur], dari [Mujahid], dari [Thawus] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda pada saat penaklukan kota Mekkah: \"Tidak ada lagi hijrah, akan tetapi yang ada adalah jihad dan niat, apabila kalian diminta untuk pergi berperang maka pergilah berperang!\""},"2057":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ حَدَّثَنَا عَامِرٌ قَالَ أَتَى رَجُلٌ عَبْدَ اللَّهِ بْنَ عَمْرٍو وَعِنْدَهُ الْقَوْمُ حَتَّى جَلَسَ عِنْدَهُ فَقَالَ أَخْبِرْنِي بِشَيْءٍ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْمُسْلِمُ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ وَالْمُهَاجِرُ مَنْ هَجَرَ مَا نَهَى اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya], dari [Isma'il bin Abu Khalid], telah menceritakan kepada kami ['Amir], ia berkata; seorang laki-laki datang kepada [Abdullah bin 'Amr] dan bersamanya terdapat beberapa orang hingga ia duduk di sampingnya dan berkata; beritahukan kepadaku sesuatu yang telah engkau dengar dari Rasulullah shallallahu 'alaihi wasallam! Kemudian ia berkata; saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang muslim (sejati) adalah seorang muslim dimana orang-orang muslim (yang lain) selamat dari lidah dan tangannya, dan muhajir (orang yang hijrah) adalah orang yang meninggal apa yang Allah larang.\""},"2058":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَتَكُونُ هِجْرَةٌ بَعْدَ هِجْرَةٍ فَخِيَارُ أَهْلِ الْأَرْضِ أَلْزَمُهُمْ مُهَاجَرَ إِبْرَاهِيمَ وَيَبْقَى فِي الْأَرْضِ شِرَارُ أَهْلِهَا تَلْفِظُهُمْ أَرْضُوهُمْ تَقْذَرُهُمْ نَفْسُ اللَّهِ وَتَحْشُرُهُمْ النَّارُ مَعَ الْقِرَدَةِ وَالْخَنَازِيرِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar], Telah menceritakan kepada kami [Mu'adz bin Hisyam], telah menceritakan kepadaku [ayahku] dari [Qatadah], dari [Syahr bin Hausyab], dari [Abdullah bin 'Amr], ia berkata; saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan ada hijrah setelah hijrah. Sebaik-baik penduduk bumi adalah orang yang paling lama menetapi tempat hijrah Ibrahim, dan tinggal di bumi adalah seburuk-buruk penghuninya. Mereka dicampakkan bumi mereka dan dibenci oleh diri Allah, dan mereka dikumpulkan oleh api bersama kera dan babi.\""},"2059":{"ar":"حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ الْحَضْرَمِيُّ حَدَّثَنَا بَقِيَّةُ حَدَّثَنِي بَحِيرٌ عَنْ خَالِدٍ يَعْنِي ابْنَ مَعْدَانَ عَنْ ابْنِ أَبِي قُتَيْلَةَ عَنْ ابْنِ حَوَالَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَيَصِيرُ الْأَمْرُ إِلَى أَنْ تَكُونُوا جُنُودًا مُجَنَّدَةً جُنْدٌ بِالشَّامِ وَجُنْدٌ بِالْيَمَنِ وَجُنْدٌ بِالْعِرَاقِ قَالَ ابْنُ حَوَالَةَ خِرْ لِي يَا رَسُولَ اللَّهِ إِنْ أَدْرَكْتُ ذَلِكَ فَقَالَ عَلَيْكَ بِالشَّامِ فَإِنَّهَا خِيرَةُ اللَّهِ مِنْ أَرْضِهِ يَجْتَبِي إِلَيْهَا خِيرَتَهُ مِنْ عِبَادِهِ فَأَمَّا إِنْ أَبَيْتُمْ فَعَلَيْكُمْ بِيَمَنِكُمْ وَاسْقُوا مِنْ غُدُرِكُمْ فَإِنَّ اللَّهَ تَوَكَّلَ لِي بِالشَّامِ وَأَهْلِهِ","id":"Telah menceritakan kepada kami [Haiwah bin Syuraih Al Hadhrami], telah menceritakan kepada kami [Baqiyyah], telah menceritakan kepadaku [Bahir], dari [Khalid] yaitu Ibnu Ma'dan dari [Ibnu Abu Qutailah] dari [Ibnu Hawalah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keadaannya sampai kalian menjadi tentara-tentara yang terpisah-pisah, pasukan di Syam, pasukan di Yaman, dan pasukan di Irak.\" Ibnu Hawalah berkata; pilihkan (tempat terbaik) untukku wahai Rasulullah apabila aku mendapati hal tersebut! Beliau berkata: \"Hendaknya kalian menetap di Syam karena sesungguhnya Syam adalah bumi Allah yang paling terpilih, Allah memilih hamba-hamba pilihannya menuju kepadanya. Adapun jika kalian menolak maka hendaknya kalian menetap di Yaman, dan minumlah dari telaganya, karena sesungguhnya Allah telah menjamin untukku Negeri Syam dan penduduknya.\""},"2060":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ قَتَادَةَ عَنْ مُطَرِّفٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَزَالُ طَائِفَةٌ مِنْ أُمَّتِي يُقَاتِلُونَ عَلَى الْحَقِّ ظَاهِرِينَ عَلَى مَنْ نَاوَأَهُمْ حَتَّى يُقَاتِلَ آخِرُهُمْ الْمَسِيحَ الدَّجَّالَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], dari [Qatadah] dari [Mutharrif] dari [Imran bin Hushain], ia berkata; Rasulullah shallallahu wa'alaihi wa sallam bersabda: \"Akan senantiasa ada sekelompok dari umatku yang berperang di atas kebenaran dalam keadaan unggul atas orang-orang yang memusuhi mereka hingga orang terakhir diantara mereka memerangi Al Masih Dajjal.\""},"2061":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ حَدَّثَنَا الزُّهْرِيُّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سُئِلَ أَيُّ الْمُؤْمِنِينَ أَكْمَلُ إِيمَانًا قَالَ رَجُلٌ يُجَاهِدُ فِي سَبِيلِ اللَّهِ بِنَفْسِهِ وَمَالِهِ وَرَجُلٌ يَعْبُدُ اللَّهَ فِي شِعْبٍ مِنْ الشِّعَابِ قَدْ كُفِيَ النَّاسُ شَرَّهُ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi], telah menceritakan kepada kami [Sulaiman bin Katsir], telah menceritakan kepada kami [Az Zuhri], dari ['Atha` bin Yazid] dari [Abu Sa'id], dari Nabi shallallahu 'alaihi wasallam bahwa beliau ditanya; siapakah orang mukmin yang paling sempurna keimanannya? Beliau bersabda: \"Seseorang yang berperang di jalan Allah dengan jiwa dan hartanya, serta seseorang yang beribadah kepada Allah di sebuah lembah dan orang-orang telah terhindar dari keburukannya.\""},"2062":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ التَّنُوخِيُّ أَبُو الْجَمَاهِرِ حَدَّثَنَا الْهَيْثَمُ بْنُ حُمَيْدٍ أَخْبَرَنِي الْعَلَاءُ بْنُ الْحَارِثِ عَنْ الْقَاسِمِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي أُمَامَةَأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ ائْذَنْ لِي فِي السِّيَاحَةِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ سِيَاحَةَ أُمَّتِي الْجِهَادُ فِي سَبِيلِ اللَّهِ تَعَالَى","id":"Telah menceritakan kepada kami [Muhammad bin Utsman At Tanukhi Abu Al Jamahir], telah menceritakan kepada kami [Al Haitsam bin Humaid], telah mengabarkan kepadaku [Al 'Ala` bin Al Harits] dari [Al Qasim bin Abdurrahman] dari [Abu Umamah], bahwa seorang laki-laki berkata; wahai Rasulullah, izinkan aku untuk berkelana! Nabi shallallahu 'alaihi wasallam berkata: \"Sesungguhnya pengelanaan (pengembaraan) umatku adalah berjihad di jalan Allah ta'ala.\""},"2063":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ عَنْ اللَّيْثِ بْنِ سَعْدٍ حَدَّثَنَا حَيْوَةُ عَنْ ابْنِ شُفَيٍّ عَنْ شُفَيِّ بْنِ مَاتِعٍ عَنْ عَبْدِ اللَّهِ هُوَ ابْنُ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَفْلَةٌ كَغَزْوَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa], telah menceritakan kepada kami [Ali bin 'Ayyasy], dari [Al Laits bin Sa'd], telah menceritakan kepada kami [Haiwah], dari [Ibnu Syufai] dari [Syufai bin Mati'] dari [Abdullah bin 'Amr] dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Kembali dari bepergian adalah seperti berperang.\""},"2064":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَلَّامٍ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ فَرَجِ بْنِ فَضَالَةَ عَنْ عَبْدِ الْخَبِيرِ بْنِ ثَابِتِ بْنِ قَيْسِ بْنِ شَمَّاسٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ جَاءَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لَهَا أُمُّ خَلَّادٍ وَهِيَ مُنْتَقِبَةٌ تَسْأَلُ عَنْ ابْنِهَا وَهُوَ مَقْتُولٌ فَقَالَ لَهَا بَعْضُ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جِئْتِ تَسْأَلِينَ عَنْ ابْنِكِ وَأَنْتِ مُنْتَقِبَةٌ فَقَالَتْ إِنْ أُرْزَأَ ابْنِي فَلَنْ أُرْزَأَ حَيَائِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْنُكِ لَهُ أَجْرُ شَهِيدَيْنِ قَالَتْ وَلِمَ ذَاكَ يَا رَسُولَ اللَّهِ قَالَ لِأَنَّهُ قَتَلَهُ أَهْلُ الْكِتَابِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Sallam] telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Faraj bin Fadhalah] dari [Abdul Khabir bin Tsabit bin Qais bin Syammas] dari [ayahnya], dari [kakeknya], ia berkata; terdapat seorang wanita yang datang kepada Nabi shallallahu 'alaihi wasallam yang dipanggil Ummu Khallad dengan menutupi wajahnya, ia bertanya mengenai anaknya yang terbunuh. Kemudian sebagian sahabat Nabi shallallahu 'alaihi wasallam berkata kepadanya; engkau datang bertanya mengenai anakmu sementara engkau menutup wajah. Kemudian ia berkata; apabila anakku terbunuh namun rasa maluku tidaklah terbunuh. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Anakmu mendapatkan pahala dua orang yang mati syahid.\" Wanita tersebut bertanya; kenapa demikian wahai Rasulullah? Beliau berkata: \"Karena ia dibunuh oleh orang ahli kitab.\""},"2065":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ زَكَرِيَّا عَنْ مُطَرِّفٍ عَنْ بِشْرٍ أَبِي عَبْدِ اللَّهِ عَنْ بَشِيرِ بْنِ مُسْلِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرْكَبُ الْبَحْرَ إِلَّا حَاجٌّ أَوْ مُعْتَمِرٌ أَوْ غَازٍ فِي سَبِيلِ اللَّهِ فَإِنَّ تَحْتَ الْبَحْرِ نَارًا وَتَحْتَ النَّارِ بَحْرًا","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Isma'il bin Zakariya], dari [Mutharrif], dari [Bisyr Abu Abdullah] dari [Basyir bin Muslim], dari [Abdullah bin 'Amr], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada yang mengarungi laut kecuali orang yang berhaji atau yang berumrah, atau orang yang berperang di jalan Allah. Sesungguhnya di bawah laut terdapat api dan di bawah api terdapat laut.\""},"2066":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ حَدَّثَتْنِي أُمُّ حَرَامٍ بِنْتُ مِلْحَانَ أُخْتُ أُمِّ سُلَيْمٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عِنْدَهُمْ فَاسْتَيْقَظَ وَهُوَ يَضْحَكُ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا أَضْحَكَكَ قَالَ رَأَيْتُ قَوْمًا مِمَّنْ يَرْكَبُ ظَهْرَ هَذَا الْبَحْرِ كَالْمُلُوكِ عَلَى الْأَسِرَّةِ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ فَإِنَّكِ مِنْهُمْ قَالَتْ ثُمَّ نَامَ فَاسْتَيْقَظَ وَهُوَ يَضْحَكُ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا أَضْحَكَكَ فَقَالَ مِثْلَ مَقَالَتِهِ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ أَنْتِ مِنْ الْأَوَّلِينَ قَالَ فَتَزَوَّجَهَا عُبَادَةُ بْنُ الصَّامِتِ فَغَزَا فِي الْبَحْرِ فَحَمَلَهَا مَعَهُ فَلَمَّا رَجَعَ قُرِّبَتْ لَهَا بَغْلَةٌ لِتَرْكَبَهَا فَصَرَعَتْهَا فَانْدَقَّتْ عُنُقُهَا فَمَاتَتْحَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ سَمِعَهُ يَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ذَهَبَ إِلَى قُبَاءَ يَدْخُلُ عَلَى أُمِّ حَرَامٍ بِنْتِ مِلْحَانَ وَكَانَتْ تَحْتَ عُبَادَةَ بْنِ الصَّامِتِ فَدَخَلَ عَلَيْهَا يَوْمًا فَأَطْعَمَتْهُ وَجَلَسَتْ تَفْلِي رَأْسَهُ وَسَاقَ هَذَا الْحَدِيثَ قَالَ أَبُو دَاوُد وَمَاتَتْ بِنْتُ مِلْحَانَ بِقُبْرُصَ حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ عَنْ مَعْمَرٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أُخْتِ أُمِّ سُلَيْمٍ الرُّمَيْصَاءِ قَالَتْ نَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَيْقَظَ وَكَانَتْ تَغْسِلُ رَأْسَهَا فَاسْتَيْقَظَ وَهُوَ يَضْحَكُ فَقَالَتْ يَا رَسُولَ اللَّهِ أَتَضْحَكُ مِنْ رَأْسِي قَالَ لَا وَسَاقَ هَذَا الْخَبَرَ يَزِيدُ وَيَنْقُصُ قَالَ أَبُو دَاوُد الرُّمَيْصَاءُ أُخْتُ أُمِّ سُلَيْمٍ مِنْ الرَّضَاعَةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al 'Ataki], telah menceritakan kepada kami [Hammad bin Zaid], dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Anas bin Malik], ia berkata; telah menceritakan kepadaku [Ummu Haram binti Milhan], saudara Ummu Sulaim bahwa Rasulullah shallallahu 'alaihi wasallam tidur siang di rumah mereka, kemudian beliau terbangun dan tertawa, Ummu Haram berkata; lalu aku katakan; wahai Rasulullah, apakah yang membuat engkau tertawa? Beliau berkata: \"Aku melihat sebuah kaum yang mengarungi laut ini seperti para raja di atas dipan-dipan.\" Ia berkata; aku katakan; wahai Rasulullah, doakan kepada Allah agar menjadikanku bagian dari mereka! Beliau berkata: \"Sesungguhnya engkau bagian dari mereka.\" Ummu Haram berkata; kemudian beliau tidur lalu terbangun dan tertawa. Ummu Haram berkata; lalu aku katakan; wahai Rasulullah, apakah yang membuat engkau tertawa? Kemudian beliau mengatakan seperti apa yang telah beliau katakan. Ia berkata; aku katakan; wahai Rasulullah, doakan kepada Allah agar menjadikanku bagian dari mereka! Beliau berkata: \"Sesungguhnya engkau bagian dari orang-orang yang pertama.\" Anas berkata; kemudian 'Ubadah bin Ash Shamit menikahi Ummu Haram, lalu ia berperang di laut dan membawa Ummu Haram bersamanya. Kemudian tatkala kembali di dekatkan kepada Ummu Haram seekor bighal untuk ia naiki. Lalu bighal tersebut menjatuhkan Ummu Haram sehingga lehernya patah dan ia pun meninggal. Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah], dari [Anas bin Malik], bahwa ia mendengarnya berkata; Rasulullah shallallahu 'alaihi wasallam apabila pergi ke Quba` beliau menemui Ummu Haram binti Milhan, ia adalah isteri 'Ubadah bin Ash Shamit. Kemudian ia menemuinya pada suatu hari lalu ia memberi makan beliau dan duduk serta mencari kutu pada rambut kepala beliau, …… Al Qa'nabi menyebutkan hadits ini. Abu Daud berkata; dan Bintu Milhan meninggal di Qubrush. Telah menceritakan kepada kami [Yahya bin Ma'in], telah menceritakan kepada kami [Hisyam bin Yusuf], dari [Ma'mar] dari [Zaid bin Aslam], dari ['Atha` bin Yasar], dari [Saudari Ummu Sulaim Ar Rumaisha`], ia berkata; Nabi shallallahu 'alaihi wasallam tidur kemudian terbangun -dan Saudari Ummu Sulaim Ar Rumaisha`sedang mencuci kepalanya- kemudian beliau terbangun dan tertawa. Lalu ia berkata; wahai Rasulullah, apakah anda mentertawakan rambut kepalaku? Ia berkata; tidak….. dan Yahya menyebutkan hadits ini, dengan menambah dan mengurangi. Abu Daud berkata; Ar Rumaisha` adalah saudari Ummu Sulaim sepersusuan. "},"2067":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكَّارٍ الْعَيْشِيُّ حَدَّثَنَا مَرْوَانُ ح و حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الرَّحِيمِ الْجَوْبَرِيُّ الدِّمَشْقِيُّ الْمَعْنَى قَالَ حَدَّثَنَا مَرْوَانُ أَخْبَرَنَا هِلَالُ بْنُ مَيْمُونٍ الرَّمْلِيِّ عَنْ يَعْلَى بْنِ شَدَّادٍ عَنْ أُمِّ حَرَامٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْمَائِدُ فِي الْبَحْرِ الَّذِي يُصِيبُهُ الْقَيْءُ لَهُ أَجْرُ شَهِيدٍ وَالْغَرِقُ لَهُ أَجْرُ شَهِيدَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Bakkar Al 'Aisyi], telah menceritakan kepada kami [Marwan], telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Abdul Wahhab bin Abdurrahim Al Jaubari Ad Dimasyqi], secara makna, ia berkata; telah menceritakan kepada kami [Marwan], telah mengabarkan kepada kami [Hilal bin Maimun Ar Ramli], dari [Ya'la bin Syaddad], dari [Ummu Haram], dari Nabi shallallahu 'alaihi wasallam bahwa beliau berkata: \"Orang yang mabuk di laut yang mengalami muntah, baginya pahala orang yang syahid, dan orang yang tenggelam baginya pahala dua orang syahid.\""},"2068":{"ar":"حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ عَتِيقٍ حَدَّثَنَا أَبُو مُسْهِرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ يَعْنِي ابْنَ سَمَاعَةَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي سُلَيْمَانُ بْنُ حَبِيبٍ عَنْ أَبِي أُمَامَةَ الْبَاهِلِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثَةٌ كُلُّهُمْ ضَامِنٌ عَلَى اللَّهِ عَزَّ وَجَلَّ رَجُلٌ خَرَجَ غَازِيًا فِي سَبِيلِ اللَّهِ فَهُوَ ضَامِنٌ عَلَى اللَّهِ حَتَّى يَتَوَفَّاهُ فَيُدْخِلَهُ الْجَنَّةَ أَوْ يَرُدَّهُ بِمَا نَالَ مِنْ أَجْرٍ وَغَنِيمَةٍ وَرَجُلٌ رَاحَ إِلَى الْمَسْجِدِ فَهُوَ ضَامِنٌ عَلَى اللَّهِ حَتَّى يَتَوَفَّاهُ فَيُدْخِلَهُ الْجَنَّةَ أَوْ يَرُدَّهُ بِمَا نَالَ مِنْ أَجْرٍ وَغَنِيمَةٍ وَرَجُلٌ دَخَلَ بَيْتَهُ بِسَلَامٍ فَهُوَ ضَامِنٌ عَلَى اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Abdussalam bin 'Atiq], telah menceritakan kepada kami [Abu Mushir], telah menceritakan kepada kami [Isma'il bin Abdullah bin Sama'ah], telah menceritakan kepada kami [Al Auza'i], telah menceritakan kepadaku [Sulaiman bin Habib], dari [Abu Umamah Al Bahili], dari Rasulullah shallallahu 'alaihi wasallam, beliau berkata: \"Tiga golongan, seluruhnya mendapat jaminan dari Allah 'azza wajalla, yaitu: orang yang keluar untuk berperang di jalan Allah, maka ia mendapat jaminan dari Allah hingga Allah mematikannya dan memasukkannya ke dalam Surga, atau memberikan kepadanya apa yang ia peroleh berupa pahala atau rampasan perang. Dan seorang laki-laki yang pergi ke masjid, maka ia mendapat jaminan dari Allah hingga Dia mematikannya dan memasukkannya ke dalam surga atau memberikan kepadanya apa yang ia peroleh berupa pahala dan ghanimah, serta seorang laki-laki yang memasuki rumahnya dengan mengucapkan salam maka ia mendapat jaminan dari Allah 'azza wajalla.\""},"2069":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ جَعْفَرٍ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَجْتَمِعُ فِي النَّارِ كَافِرٌ وَقَاتِلُهُ أَبَدًا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah Al Bazzaz], telah menceritakan kepada kami [Isma'il bin Ja'far], dari [Al 'Ala`], dari [ayahnya], dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah berkumpul dalam neraka orang yang kafir dan orang yang membunuhnya untuk selamanya.\""},"2070":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا سُفْيَانُ عَنْ قَعْنَبٍ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُرْمَةُ نِسَاءِ الْمُجَاهِدِينَ عَلَى الْقَاعِدِينَ كَحُرْمَةِ أُمَّهَاتِهِمْ وَمَا مِنْ رَجُلٍ مِنْ الْقَاعِدِينَ يَخْلُفُ رَجُلًا مِنْ الْمُجَاهِدِينَ فِي أَهْلِهِ إِلَّا نُصِبَ لَهُ يَوْمَ الْقِيَامَةِ فَقِيلَ لَهُ هَذَا قَدْ خَلَفَكَ فِي أَهْلِكَ فَخُذْ مِنْ حَسَنَاتِهِ مَا شِئْتَ فَالْتَفَتَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا ظَنُّكُمْقَالَ أَبُو دَاوُد كَانَ قَعْنَبٌ رَجُلًا صَالِحًا وَكَانَ ابْنُ أَبِي لَيْلَى أَرَادَ قَعْنَبًا عَلَى الْقَضَاءِ فَأَبَى عَلَيْهِ وَقَالَ أَنَا أُرِيدُ الْحَاجَةَ بِدِرْهَمٍ فَأَسْتَعِينُ عَلَيْهَا بِرَجُلٍ قَالَ وَأَيُّنَا لَا يَسْتَعِينُ فِي حَاجَتِهِ قَالَ أَخْرِجُونِي حَتَّى أَنْظُرَ فَأُخْرِجَ فَتَوَارَى قَالَ سُفْيَانُ بَيْنَمَا هُوَ مُتَوَارٍ إِذْ وَقَعَ عَلَيْهِ الْبَيْتُ فَمَاتَ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Sufyan], dari [Qa'nab], dari ['Alqamah bin Martsad], dari [Ibnu Buraidah], dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Kehormatan para isteri orang-orang mujahidin atas orang-orang yang tidak ikut berperang seperti kehormatan para ibu mereka. Tidaklah seorang laki-laki yang tidak berjihad menggantikan seseorang yang berjihad dalam diri isterinya kecuali akan ditegakkan peradilan baginya pada Hari Kiamat, kemudian dikatakan; wahai Fulan, inilah si Fulan. Ambillah kebaikan-kebaikannya semaumu.\" Kemudian Nabi shallallahu 'alaihi wasallam menoleh kepada kami, kemudian bersabda: \"Bagaimana perkiraan kalian?\" Abu Daud berkata; Qa'nab adalah orang shalih, dan Ibnu Abu Laila menginginkan Qa'nab agar menjadi hakim yang mengurusi peradilan, kemudian ia menolak dan berkata; aku menginginkan suatu keperluan dengan uang satu dirham, aku minta bantuan seseorang untuk melakukan keperluan tersebut. Abu Laila berkata; siapakah diantara kita yang tidak meminta bantuan dalam melakukan keperluannya? Qa'nab berkata; keluarkan aku hingga aku bisa mempertimbangkan. Kemudian ia dikeluarkan lalu ia pun bersembunyi. Sufyan berkata; tatkala ia sedang bersembunyi tiba-tiba ia tertimpa rumah hingga meninggal. "},"2071":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ وَابْنُ لَهِيعَةَ قَالَا حَدَّثَنَا أَبُو هَانِئٍ الْخَوْلَانِيُّ أَنَّهُ سَمِعَ أَبَا عَبْدِ الرَّحْمَنِ الحُبُلِيَّ يَقُولُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ غَازِيَةٍ تَغْزُو فِي سَبِيلِ اللَّهِ فَيُصِيبُونَ غَنِيمَةً إِلَّا تَعَجَّلُوا ثُلُثَيْ أَجْرِهِمْ مِنْ الْآخِرَةِ وَيَبْقَى لَهُمْ الثُّلُثُ فَإِنْ لَمْ يُصِيبُوا غَنِيمَةً تَمَّ لَهُمْ أَجْرُهُمْ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar bin Maisarah], telah menceritakan kepada kami [Abdullah bin Yazid], telah menceritakan kepada kami [Haiwah], serta [Ibnu Lahi'ah], mereka berkata; telah menceritakan kepada kami [Abu Hani` Al Khaulani] bahwa ia mendengar [Abu Abdurrahman Al Hubuli] berkata; saya mendengar [Abdullah bin 'Amr], berkata; Rasulullah shallallahu wa'alaihi wa sallam bersabda: \"Tidaklah orang-orang yang berperang di jalan Allah kemudian mereka mendapatkan rampasan perang melainkan mereka telah menyegerakan dua pertiga pahala mereka di akhirat dan tersisa bagi mereka sepertiga, jika mereka tidak mendapatkan rampasan perang maka pahala mereka sempurna.\""},"2072":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يَحْيَى بْنِ أَيُّوبَ وَسَعِيدِ بْنِ أَبِي أَيُّوبَ عَنْ زَبَّانَ بْنِ فَائِدٍ عَنْ سَهْلِ بْنِ مُعَاذٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الصَّلَاةَ وَالصِّيَامَ وَالذِّكْرَ تُضَاعَفُ عَلَى النَّفَقَةِ فِي سَبِيلِ اللَّهِ بِسَبْعِ مِائَةِ ضِعْفٍ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amr bin As Sarh], telah menceritakan kepada kami [Ibnu Wahb], dari [Yahya bin Ayyub], serta [Sa'id bin Abu Ayyub], dari [Zabban bin Faid], dari [Sahl bin Mu'adz] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya shalat, puasa dan dzikir akan dilipat gandakan di atas berinfaq di jalan Allah sebanyak tujuh ratus kali lipat.\""},"2073":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ ابْنِ ثَوْبَانَ عَنْ أَبِيهِ يَرُدُّ إِلَى مَكْحُولٍ إِلَى عَبْدِ الرَّحْمَنِ بْنِ غُنْمٍ الْأَشْعَرِيِّ أَنَّ أَبَا مَالِكٍ الْأَشْعَرِيَّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ فَصَلَ فِي سَبِيلِ اللَّهِ فَمَاتَ أَوْ قُتِلَ فَهُوَ شَهِيدٌ أَوْ وَقَصَهُ فَرَسُهُ أَوْ بَعِيرُهُ أَوْ لَدَغَتْهُ هَامَّةٌ أَوْ مَاتَ عَلَى فِرَاشِهِ أَوْ بِأَيِّ حَتْفٍ شَاءَ اللَّهُ فَإِنَّهُ شَهِيدٌ وَإِنَّ لَهُ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Najdah], telah menceritakan kepada kami [Baqiyyah bin Al Walid], dari [Ibnu Tsauban] dari [ayahnya], ia menisbatkannya kepada [Makhul], kepada [Abdurrahman bin Ghunm Al Asy'ari] bahwa [Abu Malik], Al Asy'ari berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda; \"Barangsiapa yang memutuskan di jalan Allah kemudian ia meninggal, atau terbunuh maka ia adalah syahid, atau kuda atau untanya telah mematahkan lehernya atau ia tersengat kalajengking atau ia meninggal di atas ranjangnya, atau dengan kematian bagaimanapun yang ia kehendaki maka ia adalah syahid, dan baginya surga.\""},"2074":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي أَبُو هَانِئٍ عَنْ عَمْرِو بْنِ مَالِكٍ عَنْ فَضَالَةَ بْنِ عُبَيْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ الْمَيِّتِ يُخْتَمُ عَلَى عَمَلِهِ إِلَّا الْمُرَابِطَ فَإِنَّهُ يَنْمُو لَهُ عَمَلُهُ إِلَى يَوْمِ الْقِيَامَةِ وَيُؤَمَّنُ مِنْ فَتَّانِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], Telah menceritakan kepada kami [Abdullah bin Wahb], telah menceritakan kepadaku [Abu Hani`] dari ['Amr bin Malik], dari [Fadhalah bin 'Ubaid], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap orang yang meninggal ditutup amalannya kecuali mujahid atau orang yang berjaga-jaga dalam peperangan, sesungguhnya amalannya akan berkembang hingga Hari Kiamat, dan diberi keamanan dari para Malaikat yang memberikan ujian di Kubur.\""},"2075":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ سَلَّامٍ عَنْ زَيْدٍ يَعْنِي ابْنَ سَلَّامٍ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ قَالَ حَدَّثَنِي السَّلُولِيُّ أَبُو كَبْشَةَ أَنَّهُ حَدَّثَهُ سَهْلُ ابْنُ الْحَنْظَلِيَّةِأَنَّهُمْ سَارُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ فَأَطْنَبُوا السَّيْرَ حَتَّى كَانَتْ عَشِيَّةً فَحَضَرْتُ الصَّلَاةَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ رَجُلٌ فَارِسٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي انْطَلَقْتُ بَيْنَ أَيْدِيكُمْ حَتَّى طَلَعْتُ جَبَلَ كَذَا وَكَذَا فَإِذَا أَنَا بِهَوَازِنَ عَلَى بَكْرَةِ آبَائِهِمْ بِظُعُنِهِمْ وَنَعَمِهِمْ وَشَائِهِمْ اجْتَمَعُوا إِلَى حُنَيْنٍ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ تِلْكَ غَنِيمَةُ الْمُسْلِمِينَ غَدًا إِنْ شَاءَ اللَّهُ ثُمَّ قَالَ مَنْ يَحْرُسُنَا اللَّيْلَةَ قَالَ أَنَسُ بْنُ أَبِي مَرْثَدٍ الْغَنَوِيُّ أَنَا يَا رَسُولَ اللَّهِ قَالَ فَارْكَبْ فَرَكِبَ فَرَسًا لَهُ فَجَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَقْبِلْ هَذَا الشِّعْبَ حَتَّى تَكُونَ فِي أَعْلَاهُ وَلَا نُغَرَّنَّ مِنْ قِبَلِكَ اللَّيْلَةَ فَلَمَّا أَصْبَحْنَا خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى مُصَلَّاهُ فَرَكَعَ رَكْعَتَيْنِ ثُمَّ قَالَ هَلْ أَحْسَسْتُمْ فَارِسَكُمْ قَالُوا يَا رَسُولَ اللَّهِ مَا أَحْسَسْنَاهُ فَثُوِّبَ بِالصَّلَاةِ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَهُوَ يَلْتَفِتُ إِلَى الشِّعْبِ حَتَّى إِذَا قَضَى صَلَاتَهُ وَسَلَّمَ قَالَ أَبْشِرُوا فَقَدْ جَاءَكُمْ فَارِسُكُمْ فَجَعَلْنَا نَنْظُرُ إِلَى خِلَالِ الشَّجَرِ فِي الشِّعْبِ فَإِذَا هُوَ قَدْ جَاءَ حَتَّى وَقَفَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ فَقَالَ إِنِّي انْطَلَقْتُ حَتَّى كُنْتُ فِي أَعْلَى هَذَا الشِّعْبِ حَيْثُ أَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا أَصْبَحْتُ اطَّلَعْتُ الشِّعْبَيْنِ كِلَيْهِمَا فَنَظَرْتُ فَلَمْ أَرَ أَحَدًا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ نَزَلْتَ اللَّيْلَةَ قَالَ لَا إِلَّا مُصَلِّيًا أَوْ قَاضِيًا حَاجَةً فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَوْجَبْتَ فَلَا عَلَيْكَ أَنْ لَا تَعْمَلَ بَعْدَهَا","id":"Telah menceritakan kepada kami [Abu Taubah], telah menceritakan kepada kami [Mu'awiyah bin Sallam], dari [Zaid bin Sallam], bahwa ia telah mendengar [Abu Sallam] berkata; telah menceritakan kepadaku [As Saluli Abu Kabsyah], bahwa [Sahl bin Al Hanzhalah] telah menceritakan kepadanya bahwa mereka pada saat perang Hunain berjalan bersama Rasulullah shallallahu wa'alaihi wa sallam dan mereka mempercepat jalan hingga sore hari, kemudian saya melakukan shalat bersama Rasulullah shallallahu 'alaihi wasallam. Lalu terdapat seorang laki-laki Persia datang dan berkata; wahai Rasulullah, sesungguhnya aku pergi mendahului anda hingga mendaki gunung ini dan ini, dan tiba-tiba saya melihat orang-orang Hawazin, mereka semua telah datang dan tidak satupun diantara mereka yang tertinggal dengan membawa para wanita mereka, hewan-hewan ternak serta kambing-kambing mereka. Mereka telah berkumpul di Hunain. Maka Rasulullah shallallahu 'alaihi wasallam tertawa dan berkata: \"Itu adalah rampasan perang orang-orang muslim besok insya Allah.\" Kemudian beliau berkata: \"Siapakah yang akan menjaga kami pada malam ini?\" Anas bin Abu Martsad Al Ghanawi berkata; saya wahai Rasulullah. Beliau berkata; \"Naiklah kuda!\" kemudian ia menaiki kudanya dan datang kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Datangilah jalan bukit ini hingga engkau berada di puncaknya, dan jangan sampai kami terkecohkan karenamu pada malam ini!\" Kemudian tatkala pagi hari Rasulullah shallallahu 'alaihi wasallam keluar ke tempat shalat beliau lalu melakukan shalat dua raka'at. Kemudian beliau berkata: \"Apakah kalian telah merasakan kedatangan penunggang kuda kalian?\" Mereka berkata; wahai Rasulullah, kami tidak merasakan kedatangannya. Kemudian beliau menyeru untuk melakukan shalat. Lalu Rasulullah shallallahu 'alaihi wasallam melakukan shalat dan menoleh ke bukit hingga setelah selesai shalat beliau berkata: \"Bergembiralah, telah datang penunggang kuda kalian!\" Kemudian kami melihat ke sela-sela pepohonan di jalan bukit tersebut, dan ternyata penunggang kuda tersebut telah datang hingga ia berdiri di hadapan Rasulullah shallallahu 'alaihi wasallam lalu mengucapkan salam dan berkata; sesungguhnya saya telah telah pergi hingga berada di puncak jalan bukit ini dimana Rasulullah shallallahu 'alaihi wasallam memerintahkanku. Kemudian tatkala pagi hari aku melihat kedua jalan bukit tersebut dan aku tidak melihat seorangpun. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Apakah engkau singgah pada malam ini?\" Ia berkata; tidak, kecuali hanya melakukan shalat atau menunaikan hajat. Lalu Rasulullah shallallahu 'alaihi wasallam berkata: \"Sungguh engkau telah melakukan tugas ini, maka tidak mengapa engkau tidak melakukannya setelah itu.\""},"2076":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ الْمَرْوَزِيُّ أَخْبَرَنَا ابْنُ الْمُبَارَكِ أَخْبَرَنَا وُهَيْبٌ قَالَ عَبْدَةُ يَعْنِي ابْنَ الْوَرْدِ أَخْبَرَنِي عُمَرُ بْنُ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَاتَ وَلَمْ يَغْزُ وَلَمْ يُحَدِّثْ نَفْسَهُ بِالْغَزْوِ مَاتَ عَلَى شُعْبَةٍ مِنْ نِفَاقٍ","id":"Telah menceritakan kepada kami ['Abdah bin Sulaiman Al Marwazi], telah mengabarkan kepada kami [Ibnu Al Mubarak], telah mengabarkan kepada kami [Wuhaib], telah berkata 'Abdah bin Al Ward; telah mengabarkan kepadaku [Umar bin Muhammad bin Al Munkadir], dari [Sumai], dari [Abu Shalih], dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Barangsiapa yang meninggal dan belum berperang serta belum berniat untuk berperang, maka ia meninggal berada di atas cabang kemunafikan.\""},"2077":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ وَقَرَأْتُهُ عَلَى يَزِيدَ بْنِ عَبْدِ رَبِّهِ الْجُرْجُسِيِّ قَالَا حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ يَحْيَى بْنِ الْحَارِثِ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ أَبِي أُمَامَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يَغْزُ أَوْ يُجَهِّزْ غَازِيًا أَوْ يَخْلُفْ غَازِيًا فِي أَهْلِهِ بِخَيْرٍ أَصَابَهُ اللَّهُ بِقَارِعَةٍ قَالَ يَزِيدُ بْنُ عَبْدِ رَبِّهِ فِي حَدِيثِهِ قَبْلَ يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami ['Amr bin Utsman], dan aku bacakan kepada [Yazid bin 'Abdu Rabbih Al Jurjusi], mereka berdua mengatakan; telah menceritakan kepada kami [Al Walid bin Muslim] dari [Yahya bin Al Harits], dari [Al Qasim Abu Abdurrahman] dari [Abu Umamah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa yang tidak berperang atau mempersiapkan orang yang berperang atau menggantikan orang yang berperang dalam memberikan kebaikan kepada keluarganya maka Allah akan menimpakan bencana kepadanya.\" Yazid bin 'Abdul Rabbih dalam haditsnya berkata; sebelum Hari Kiamat. "},"2078":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ حُمَيْدٍ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جَاهِدُوا الْمُشْرِكِينَ بِأَمْوَالِكُمْ وَأَنْفُسِكُمْ وَأَلْسِنَتِكُمْ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Humaid], dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Perangilah orang-orang musyrik dengan harta, jiwa dan lidah kalian.\""},"2079":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ الْحُسَيْنِ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ إِلَّا تَنْفِرُوا يُعَذِّبْكُمْ عَذَابًا أَلِيمًا }وَ{ مَا كَانَ لِأَهْلِ الْمَدِينَةِ إِلَى قَوْلِهِ يَعْمَلُونَ }نَسَخَتْهَا الْآيَةُ الَّتِي تَلِيهَا{ وَمَا كَانَ الْمُؤْمِنُونَ لِيَنْفِرُوا كَافَّةً }","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi], telah menceritakan kepadaku [Ali bin Al Husain], dari [ayahnya], dari [Yazid An Nahwi], dari [Ikrimah] dari [Ibnu Abbas], ia berkata; \"Jika kamu tidak berangkat untuk berperang, niscaya Allah menyiksa kamu dengan siksa yang pedih.\" \"Tidaklah sepatutnya bagi penduduk Madinah…….\" hingga firman Allah \"……yang telah mereka kerjakan.\" Ayat tersebut telah digantikan dengan ayat yang berikutnya: \"Tidak sepatutnya bagi mukminin itu pergi semuanya (ke medan perang).\""},"2080":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ عَبْدِ الْمُؤْمِنِ بْنِ خَالِدٍ الْحَنَفِيِّ حَدَّثَنِي نَجْدَةُ بْنُ نُفَيْعٍ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍعَنْ هَذِهِ الْآيَةِ{ إِلَّا تَنْفِرُوا يُعَذِّبْكُمْ عَذَابًا أَلِيمًا }قَالَ فَأُمْسِكَ عَنْهُمْ الْمَطَرُ وَكَانَ عَذَابَهُمْ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Zaid bin Al Hubab], dari [Abdul Mukmin bin Khalid Al Hanafi], telah menceritakan kepadaku [Najdah bin Nufai'], ia berkata; saya bertanya kepada [Ibnu Abbas] mengenai ayat ini: \"Jika kamu tidak berangkat untuk berperang, niscaya Allah menyiksa kamu dengan siksa yang pedih.\" Ia berkata; kemudian ditahanlah hujan dari mereka, dan hal tersebut merupakan adzab bagi mereka. "},"2081":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ خَارِجَةَ بْنِ زَيْدٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَكُنْتُ إِلَى جَنْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَغ��شِيَتْهُ السَّكِينَةُ فَوَقَعَتْ فَخِذُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى فَخِذِي فَمَا وَجَدْتُ ثِقْلَ شَيْءٍ أَثْقَلَ مِنْ فَخِذِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ سُرِّيَ عَنْهُ فَقَالَ اكْتُبْ فَكَتَبْتُ فِي كَتِفٍ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }{ وَالْمُجَاهِدُونَ فِي سَبِيلِ اللَّهِ }إِلَى آخِرِ الْآيَةِ فَقَامَ ابْنُ أُمِّ مَكْتُومٍ وَكَانَ رَجُلًا أَعْمَى لَمَّا سَمِعَ فَضِيلَةَ الْمُجَاهِدِينَ فَقَالَ يَا رَسُولَ اللَّهِ فَكَيْفَ بِمَنْ لَا يَسْتَطِيعُ الْجِهَادَ مِنْ الْمُؤْمِنِينَ فَلَمَّا قَضَى كَلَامَهُ غَشِيَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّكِينَةُ فَوَقَعَتْ فَخِذُهُ عَلَى فَخِذِي وَوَجَدْتُ مِنْ ثِقَلِهَا فِي الْمَرَّةِ الثَّانِيَةِ كَمَا وَجَدْتُ فِي الْمَرَّةِ الْأُولَى ثُمَّ سُرِّيَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اقْرَأْ يَا زَيْدُ فَقَرَأْتُ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ غَيْرُ أُولِي الضَّرَرِ }الْآيَةَ كُلَّهَا قَالَ زَيْدٌ فَأَنْزَلَهَا اللَّهُ وَحْدَهَا فَأَلْحَقْتُهَا وَالَّذِي نَفْسِي بِيَدِهِ لَكَأَنِّي أَنْظُرُ إِلَى مُلْحَقِهَا عِنْدَ صَدْعٍ فِي كَتِفٍ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Abdurrahman bin Abu Az Zinad], dari [ayahnya], dari [Kharijah bin Zaid] dari [Zaid bin Tsabit], ia berkata; aku pernah berada di sisi Rasulullah shallallahu 'alaihi wasallam, kemudian beliau diliputi oleh ketenangan, kemudian paha Rasulullah shallallahu 'alaihi wasallam terjatuh di atas pahaku, dan tidaklah aku mendapatkan sesuatu yang lebih berat daripada paha Rasulullah shallallahu 'alaihi wasallam. Kemudian rasa berat tersebut hilang dari beliau. Kemudian beliau berkata: \"Tulislah!\" Kemudian aku tuliskan di tulang pundak hewan firman Allah: \"Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) dengan orang-orang yang berjihad di jalan Allah……\" hingga akhir ayat. Kemudian Ibnu Ummi Maktum orang yang buta berdiri tatkala ia mendengar keutamaan orang-orang yang berjihad dijalan Allah, lalu berkata; wahai Rasulullah, bagaimana dengan orang mukmin yang tidak mampu untuk berjihad? Kemudian tatkala ia telah selesai berbicara maka Rasulullah shallallahu 'alaihi wasallam diliputi rasa tenang kemudian pahanya terjatuh di atas pahaku dan aku merasakan beratnya lagi sebagaimana aku merasakannya pada kali pertama. Kemudian rasa berat tersebut hilang dari Rasulullah shallallahu 'alaihi wasallam. Beliau berkata: \"Bacalah wahai Zaid!\" kemudian aku membaca: \"Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) …\" kemudian beliau berkata: \"Selain orang-orang yang berudzur.\" Zaid berkata; Allah menurunkan ayat tersebut tersendiri, kemudian aku menggabungkannya. Demi Dzat yang jiwaku ada di tanganNya, sungguh sepertinya aku melihat gabungannya pada belahan tulang pundak. "},"2082":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ حُمَيْدٍ عَنْ مُوسَى بْنِ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَقَدْ تَرَكْتُمْ بِالْمَدِينَةِ أَقْوَامًا مَا سِرْتُمْ مَسِيرًا وَلَا أَنْفَقْتُمْ مِنْ نَفَقَةٍ وَلَا قَطَعْتُمْ مِنْ وَادٍ إِلَّا وَهُمْ مَعَكُمْ فِيهِ قَالُوا يَا رَسُولَ اللَّهِ وَكَيْفَ يَكُونُونَ مَعَنَا وَهُمْ بِالْمَدِينَةِ فَقَالَ حَبَسَهُمْ الْعُذْرُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Humaid], dari [Musa bin Anas bin Malik], dari [ayahnya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh aku telah meninggalkan di Madinah beberapa orang, tidaklah kalian melakukan suatu perjalanan dan memberikan suatu infaq serta melewati sebuah bukit melainkan mereka bersama dengan kalian.\" Mereka berkata; wahai Rasulullah, bagaimana mereka bersama dengan kami sementara mereka berada di Madinah? beliau berkata: \"Mereka tertahan oleh udzur.\""},"2083":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ أَبِي الْحَجَّاجِ أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا الْحُسَيْنُ حَدَّثَنِي يَحْيَى حَدَّثَنِي أَبُو سَلَمَةَ حَدَّثَنِي بُسْرُ بْنُ سَعِيدٍ حَدَّثَنِي زَيْدُ بْنُ خَالِدٍ الْجُهَنِيُّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ جَهَّزَ غَازِيًا فِي سَبِيلِ اللَّهِ فَقَدْ غَزَا وَمَنْ خَلَفَهُ فِي أَهْلِهِ بِخَيْرٍ فَقَدْ غَزَا","id":"Telah menceritakan kepada kami [Abdullah bin 'Amr bin Abu Al Hajjaj Abu Ma'mar], telah menceritakan kepada kami [Abdul Warits], telah menceritakan kepada kami [Al Husain], telah menceritakan kepadaku [Yahya] telah menceritakan kepadaku [Abu Salamah], telah menceritakan kepadaku [Busr bin Sa'id], telah menceritakan kepadaku [Zaid bin Khalid Al Juhani], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang mempersiapkan orang yang berperang di jalan Allah maka sungguh ia telah berperang, dan barangsiapa yang menggantikannya menjaga keluarganya dengan baik maka sungguh ia telah berperang.\""},"2084":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ يَزِيدَ بْنِ أَبِي سَعِيدٍ مَوْلَى الْمَهْرِيِّ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ إِلَى بَنِي لَحْيَانَ وَقَالَ لِيَخْرُجْ مِنْ كُلِّ رَجُلَيْنِ رَجُلٌ ثُمَّ قَالَ لِلْقَاعِدِ أَيُّكُمْ خَلَفَ الْخَارِجَ فِي أَهْلِهِ وَمَالِهِ بِخَيْرٍ كَانَ لَهُ مِثْلُ نِصْفِ أَجْرِ الْخَارِجِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah mengabarkan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku ['Amr bin Al Harits], dari [Yazid bin Abu Habib], dari [Yazid bin Abu Sa'id] mantan budak Al Mahri, dari [ayahnya], dari [Abu Sa'id Al Khudri], bahwa Rasulullah shallallahu 'alaihi wasallam telah mengirim utusan kepada Bani Lahyan, dan berkata: \"Hendaknya diantara dua orang ada satu orang yang keluar!\" Kemudian beliau berkata kepada orang yang tidak berperang: \"Barangsiapa yang menggantikan orang yang keluar menjaga keluarga dan hartanya dengan baik maka baginya seperti setengah pahala orang yang keluar berperang.\""},"2085":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ مُوسَى بْنِ عَلِيِّ بْنِ رَبَاحٍ عَنْ أَبِيهِ عَنْ عَبْدِ الْعَزِيزِ بْنِ مَرْوَانَ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ شَرُّ مَا فِي رَجُلٍ شُحٌّ هَالِعٌ وَجُبْنٌ خَالِعٌ","id":"Telah menceritakan kepada kami [Abdullah bin Al Jarrah], dari [Abdullah bin Yazid] dari [Musa bin Ali bin Rabah], dari [ayahnya], dari [Abdul 'Aziz bin Marwan], ia berkata; saya mendengar [Abu Hurairah] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seburuk-buruk perkara yang ada pada seseorang adalah kekikiran serta ketamakan, dan sifat penakut serta lemah.\""},"2086":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ وَابْنِ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَسْلَمَ أَبِي عِمْرَانَ قَالَغَزَوْنَا مِنْ الْمَدِينَةِ نُرِيدُ الْقُسْطَنْطِينِيَّةَ وَعَلَى الْجَمَاعَةِ عَبْدُ الرَّحْمَنِ بْنُ خَالِدِ بْنِ الْوَلِيدِ وَالرُّومُ مُلْصِقُو ظُهُورِهِمْ بِحَائِطِ الْمَدِينَةِ فَحَمَلَ رَجُلٌ عَلَى الْعَدُوِّ فَقَالَ النَّاسُ مَهْ مَهْ لَا إِلَهَ إِلَّا اللَّهُ يُلْقِي بِيَدَيْهِ إِلَى التَّهْلُكَةِ فَقَالَ أَبُو أَيُّوبَ إِنَّمَا نَزَلَتْ هَذِهِ الْآيَةُ فِينَا مَعْشَرَ الْأَنْصَارِ لَمَّا نَصَرَ اللَّهُ نَبِيَّهُ وَأَظْهَرَ الْإِسْلَامَ قُلْنَا هَلُمَّ نُقِيمُ فِي أَمْوَالِنَا وَنُصْلِحُهَا فَأَنْزَلَ اللَّهُ تَعَالَى{ وَأَنْفِقُوا فِي سَبِيلِ اللَّهِ وَلَا تُلْقُوا بِأَيْدِيكُمْ إِلَى التَّهْلُكَةِ }فَالْإِلْقَاءُ بِالْأَيْدِي إِلَى التَّهْلُكَةِ أَنْ نُقِيمَ فِي أَمْوَالِنَا وَنُصْلِحَهَا وَنَدَعَ الْجِهَادَقَالَ أَبُو عِمْرَانَ فَلَمْ يَزَلْ أَبُو أَيُّوبَ يُجَاهِدُ فِي سَبِيلِ اللَّهِ حَتَّى دُفِنَ بِالْقُسْطَنْطِينِيَّةِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amr bin As Sarh], telah menceritakan kepada kami [Ibnu Wahb], dari [Haiwah bin Syuraih], dan [Ibnu Luhai'ah], dari [Yazid bin Abu Habib], dari [Aslam Abu Imran], ia berkata; kami pergi berperang dari Madinah menuju Al Qusthanthiniyyah, dan kami dipimpin oleh Abdurrahman bin Khalid bin Al Walid, sementara orang-orang Romawi menempelkan punggung mereka pada dinding kota. Kemudian terdapat seseorang yang menyerbu musuh, lalu orang-orang berkata; tahan, tahan! Laa ilaaha illah, ia telah melemparkan dirinya kepada kebinasaan. Kemudian [Abu Ayyub] berkata; sesungguhnya ayat ini turun mengenai kami, orang-orang anshar. Tatkala Allah membela Nabinya dan memenangkan Islam kami berkata; mari kita mengurusi harta kita dan memperbaikinya. Kemudian Allah ta'ala menurunkan ayat: \"Dan belanjakanlah (harta bendamu) di jalan Allah, dan janganlah kamu menjatuhkan dirimu sendiri ke dalam kebinasaan.\" Menjatuhkan diri sendri ke dalam kebinasaan adalah mengurusi harta kami dan memperbaikinya serta meninggalkan jihad. Abu Imran berkata; Abu Ayyub terus berjihad di jalan Allah hingga ia dikuburkan di Qusthanthiniyyah. "},"2087":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ حَدَّثَنِي أَبُو سَلَّامٍ عَنْ خَالِدِ بْنِ زَيْدٍ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ يُدْخِلُ بِالسَّهْمِ الْوَاحِدِ ثَلَاثَةَ نَفَرٍ الْجَنَّةَ صَانِعَهُ يَحْتَسِبُ فِي صَنْعَتِهِ الْخَيْرَ وَالرَّامِيَ بِهِ وَمُنْبِلَهُ وَارْمُوا وَارْكَبُوا وَأَنْ تَرْمُوا أَحَبُّ إِلَيَّ مِنْ أَنْ تَرْكَبُوا لَيْسَ مِنْ اللَّهْوِ إِلَّا ثَلَاثٌ تَأْدِيبُ الرَّجُلِ فَرَسَهُ وَمُلَاعَبَتُهُ أَهْلَهُ وَرَمْيُهُ بِقَوْسِهِ وَنَبْلِهِ وَمَنْ تَرَكَ الرَّمْيَ بَعْدَ مَا عَلِمَهُ رَغْبَةً عَنْهُ فَإِنَّهَا نِعْمَةٌ تَرَكَهَا أَوْ قَالَ كَفَرَهَا","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Abdullah bin Al Mubarak], telah menceritakan kepadaku [Abdurrahman bin Yazid bin Jabir], telah menceritakan kepadaku [Abu Sallam], dari [Khalid bin Zaid] dari ['Uqbah], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Sesungguhnya Allah memasukkan tiga orang ke dalam surga karena satu anak panah, yaitu: Pembuatnya yang menginginkan kebaikan dalam membuatnya, orang yang memanah dengannya, serta orang yang mengambilkan anak panah untuknya. Panah dan naiklah kuda, kalian memanah adalah lebih aku sukai daripada kalian menaiki kuda. Bukan termasuk hiburan (yang disunahkan) kecuali tiga perkara: seseorang melatih kudanya, bercanda dengan isterinya, dan memanah menggunakan busurnya serta anak panahnya. Dan barangsiapa yang meninggalkan memanah setelah ia mengetahuinya karena tidak senang kepadanya maka sesungguhnya hal tersebut adalah kenikmatan yang ia tinggalkan atau ia berkata: yang ia ingkari.\""},"2088":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ أَبِي عَلِيٍّ ثُمَامَةَ بْنِ شُفَيٍّ الْهَمْدَانِيِّ أَنَّهُ سَمِعَ عُقْبَةَ بْنَ عَامِرٍ الْجُهَنِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ يَقُولُ{ وَأَعِدُّوا لَهُمْ مَا اسْتَطَعْتُمْ مِنْ قُوَّةٍ }أَلَا إِنَّ الْقُوَّةَ الرَّمْيُ أَلَا إِنَّ الْقُوَّةَ الرَّمْيُ أَلَا إِنَّ الْقُوَّةَ الرَّمْيُ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Abdullah bin Wahb], telah mengabarkan kepadaku ['Amr bin Al Harits] dari [Abu Ali Tsumamah bin Syufi Al Hamdani], bahwa ia mendengar ['Uqbah bin 'Amir Al Juhani], berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam berada di atas mimbar berkata: \"Dan persiapkan untuk mereka apa yang kalian mampu berupa kekuatan. Ketahuilah bahwa kekuatan itu adalah memanah, ketahuilah bahwa kekuatan itu adalah memanah, ketahuilah bahwa kekuatan itu adalah memanah! "},"2089":{"ar":"حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ الْحَضْرَمِيُّ حَدَّثَنَا بَقِيَّةُ حَدَّثَنِي بَحِيرٌ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ أَبِي بَحْرِيَّةَ عَنْ مُعَاذِ بْنِ جَبَلٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْغَزْوُ غَزْوَانِ فَأَمَّا مَنْ ابْتَغَى وَجْهَ اللَّهِ وَأَطَاعَ الْإِمَامَ وَأَنْفَقَ الْكَرِيمَةَ وَيَاسَرَ الشَّرِيكَ وَاجْتَنَبَ الْفَسَادَ فَإِنَّ نَوْمَهُ وَنُبْهَهُ أَجْرٌ كُلُّهُ وَأَمَّا مَنْ غَزَا فَخْرًا وَرِيَاءً وَسُمْعَةً وَعَصَى الْإِمَامَ وَأَفْسَدَ فِي الْأَرْضِ فَإِنَّهُ لَمْ يَرْجِعْ بِالْكَفَافِ","id":"Telah menceritakan kepada kami [Haiwah bin Syuraih Al Hadhrami], telah menceritakan kepada kami [Baqiyyah], telah menceritakan kepadaku [Bahir] dari [Khalid bin Ma'dan] dari [Abu Bahriyyah] dari [Mu'adz bin Jabal] dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Berperang ada dua, adapun orang yang mengharapkan wajah Allah, mentaati pemimpin, menginfakkan barang berharga, dan bergaul dengan sekutunya dengan mudah, serta menjauhi kerusakan maka tidurnya dan terjaganya adalah pahala semua. Adapun orang yang berperang karena berbangga diri, ingin dilihat dan didengar orang, durhaka kepada pemimpin serta membuat kerusakan, maka ia tidak kembali dengan membawa manfaat.\""},"2090":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ عَنْ ابْنِ الْمُبَارَكِ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الْقَاسِمِ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ ابْنِ مِكْرَزٍ رَجُلٍ مِنْ أَهْلِ الشَّامِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ رَجُلٌ يُرِيدُ الْجِهَادَ فِي سَبِيلِ اللَّهِ وَهُوَ يَبْتَغِي عَرَضًا مِنْ عَرَضِ الدُّنْيَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَجْرَ لَهُ فَأَعْظَمَ ذَلِكَ النَّاسُ وَقَالُوا لِلرَّجُلِ عُدْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَعَلَّكَ لَمْ تُفَهِّمْهُ فَقَالَ يَا رَسُولَ اللَّهِ رَجُلٌ يُرِيدُ الْجِهَادَ فِي سَبِيلِ اللَّهِ وَهُوَ يَبْتَغِي عَرَضًا مِنْ عَرَضِ الدُّنْيَا فَقَالَ لَا أَجْرَ لَهُ فَقَالُوا لِلرَّجُلِ عُدْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ الثَّالِثَةَ فَقَالَ لَهُ لَا أَجْرَ لَهُ","id":"Telah menceritakan kepada kami [Abu Taubah Ar Rabi' bin Nafi'] dari [Ibnu Al Mubarak], dari [Ibnu Dzi`b] dari [Al Qasim] dari [Bukair bin Abdullah bin Al Asyajj] dari [Ibnu Mikraz] seorang penduduk Syam, dari [Abu Hurairah] bahwa seorang laki-laki berkata; wahai Rasulullah, seseorang ingin berjihad di jalan Allah, dan ia mengharapkan harta-harta dunia. Lalu Rasulullah shallallahu 'alaihi wasallam berkata: \"Ia tidak mendapatkan pahala.\" Maka hal tersebut terasa berat bagi orang-orang, dan mereka berkata kepada orang tersebut; kembalilah kepada Rasulullah shallallahu 'alaihi wasallam! Kemungkinan engkau belum memahamkan beliau. Lalu orang tersebut berkata; wahai Rasulullah, seseorang ingin berjihad di jalan Allah, dan ia mengharapkan harta-harta dunia. Lalu Rasulullah shallallahu 'alaihi wasallam berkata: \"Ia tidak mendapatkan pahala.\" Dan mereka berkata kepada orang tersebut; kembalilah kepada Rasulullah shallallahu 'alaihi wasallam! Kemudian orang tersebut berkata kepada beliau untuk ketiga kalinya, lalu beliau berkata kepadanya: \"Ia tidak mendapatkan pahala.\""},"2091":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مُوسَىأَنَّ أَعْرَابِيًّا جَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ الرَّجُلَ يُقَاتِلُ لِلذِّكْرِ وَيُقَاتِلُ لِيُحْمَدَ وَيُقَاتِلُ لِيَغْنَمَ وَيُقَاتِلُ لِيُرِيَ مَكَانَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَاتَلَ حَتَّى تَكُونَ كَلِمَةُ اللَّهِ هِيَ أَعْلَى فَهُوَ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّحَدَّثَنَا عَلِيُّ بْنُ مُسْلِمٍ حَدَّثَنَا أَبُو دَاوُدَ عَنْ شُعْبَةَ عَنْ عَمْرٍو قَالَ سَمِعْتُ مِنْ أَبِي وَائِلٍ حَدِيثًا أَعْجَبَنِي فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar], telah menceritakan kepada kami [Syu'bah bin Murrah], dari [Amr bin Murrah] dari [Abu Wail] dari [Abu Musa] bahwa seorang badui datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; sesungguhnya terdapat seorang laki-laki yang berperang agar disebut-sebut, dan berperang agar dipuji dan berperang agar mendapatkan rampasan perang dan berperang agar dilihat kedudukannya. Maka Rasulullah shallallahu 'alaihi wasallam berkata: \"Barangsiapa yang berperang agar kalimat Allah menjadi yang paling tinggi maka ia berada di jalan Allah 'azza wajalla.\" Telah menceritakan kepada kami [Ali bin Muslim], telah menceritakan kepada kami [Abu Daud], dari [Syu'bah] dari ['Amr], ia berkata; saya telah mendengar dari [Abu Wa`il] sebuah hadits yang mengagumkanku. Kemudian ia menyebutkan hadits tersebut secara makna. "},"2092":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ حَاتِمٍ الْأَنْصَارِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي الْوَضَّاحِ عَنْ الْعَلَاءِ بْنِ عَبْدِ اللَّهِ بْنِ رَافِعٍ عَنْ حَنَانِ بْنِ خَارِجَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ عَبْدُ اللَّهِ بْنُ عَمْرٍو يَا رَسُولَ اللَّهِ أَخْبِرْنِي عَنْ الْجِهَادِ وَالْغَزْوِ فَقَالَ يَا عَبْدَ اللَّهِ بْنَ عَمْرٍو إِنْ قَاتَلْتَ صَابِرًا مُحْتَسِبًا بَعَثَكَ اللَّهُ صَابِرًا مُحْتَسِبًا وَإِنْ قَاتَلْتَ مُرَائِيًا مُكَاثِرًا بَعَثَكَ اللَّهُ مُرَائِيًا مُكَاثِرًا يَا عَبْدَ اللَّهِ بْنَ عَمْرٍو عَلَى أَيِّ حَالٍ قَاتَلْتَ أَوْ قُتِلْتَ بَعَثَكَ اللَّهُ عَلَى تِلْكَ الْحَالِ","id":"Telah menceritakan kepada kami [Muslim bin Hatim Al Anshari], telah menceritakan kepada kami [Abdurrahman bin Mahdi], telah menceritakan kepada kami [Muhammad bin Abu Al Wadhdhah] dari [Al 'Ala` bin Abdullah bin Rafi'] dari [Hanan bin Kharijah], dari [Abdullah bin 'Amr], ia berkata; wahai Rasulullah, beritahukan kepadaku mengenai jihad dan perang! Kemudian beliau berkata: \"Wahai Abdullah bin 'Amr, seandainya engkau berperang dalam keadaan bersabar dan mengharapkan pahala, maka Allah akan membangkitkanmu dalam keadaan bersabar dan mengharapkan pahala. Dan apabila engkau berperang untuk dilihat dan berbangga diri, maka Allah akan membangkitkanmu dalam keadaan ingin dilihat serta berbangga diri. Wahai Abdullah bin 'Amr, dalam keadaan yang mana engkau berperang atau terbunuh maka Allah akan membangkitkanmu dalam keadaan seperti itu.\""},"2093":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ أَبِي الزُّبَيْرِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا أُصِيبَ إِخْوَانُكُمْ بِأُحُدٍ جَعَلَ اللَّهُ أَرْوَاحَهُمْ فِي جَوْفِ طَيْرٍ خُضْرٍ تَرِدُ أَنْهَارَ الْجَنَّةِ تَأْكُلُ مِنْ ثِمَارِهَا وَتَأْوِي إِلَى قَنَادِيلَ مِنْ ذَهَبٍ مُعَلَّقَةٍ فِي ظِلِّ الْعَرْشِ فَلَمَّا وَجَدُوا طِيبَ مَأْكَلِهِمْ وَمَشْرَبِهِمْ وَمَقِيلِهِمْ قَالُوا مَنْ يُبَلِّغُ إِخْوَانَنَا عَنَّا أَنَّا أَحْيَاءٌ فِي الْجَنَّةِ نُرْزَقُ لِئَلَّا يَزْهَدُوا فِي الْجِهَادِ وَلَا يَنْكُلُوا عِنْدَ الْحَرْبِ فَقَالَ اللَّهُ سُبْحَانَهُ أَنَا أُبَلِّغُهُمْ عَنْكُمْ قَالَ فَأَنْزَلَ اللَّهُ{ وَلَا تَحْسَبَنَّ الَّذِينَ قُتِلُوا فِي سَبِيلِ اللَّهِ }إِلَى آخِرِ الْآيَةِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Abdullah bin Idris], dari [Muhammad bin Ishaq], dari [Isma'il bin Umayyah], dari [Abu Az Zubair] dari [Sa'id bin Jubair], dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu wa'alaihi wa sallam bersabda: \"Tatkala saudara-saudara kalian tertimpa musibah di Uhud, Allah menjadikan nyawa mereka berada di dalam perut burung hijau, yang akan mendatangi sungai-sungai di Surga, dan makan sebagian dari buah-buahannya, serta kembali ke pelita-pelita emas yang tergantung dalam naungan 'arsy. Kemudian tatkala mereka mendapati makanan mereka, minuman, serta perkataan mereka yang baik maka mereka mengatakan; siapakah yang akan menyampaikan dari kami kepada saudara-saudara kami bahwa kami hidup di Surga, dan kami diberi rizqi. Agar mereka tidak bersikap zuhud dalam berjihad, serta tidak takut ketika berperang.\" Kemudian Allah berfirman: \"Aku yang akan menyampaikan kepada mereka untuk kalian.\" Ibnu Abbas berkata; kemudian Allah menurunkan ayat: \"Janganlah kamu mengira bahwa orang-orang yang gugur di jalan Allah itu mati………..\" hingga akhir ayat. "},"2094":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا عَوْفٌ حَدَّثَتْنَا حَسْنَاءُ بِنْتُ مُعَاوِيَةَ الصَّرِيمِيَّةُ قَالَتْ حَدَّثَنَا عَمِّي قَالَقُلْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ فِي الْجَنَّةِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْجَنَّةِ وَالشَّهِيدُ فِي الْجَنَّةِ وَالْمَوْلُودُ فِي الْجَنَّةِ وَالْوَئِيدُ فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yazid bin Zurai'], telah menceritakan kepada kami ['Auf], telah menceritakan kepada kami [Hasna` binti Mu'awiyah Ash Sharimiyyah], ia berkata; telah menceritakan kepada kami [pamanku], ia berkata; aku berkata kepada Nabi shallallahu 'alaihi wasallam; siapakah yang ada di dalam Surga? Beliau berkata: \"Nabi shallallahu 'alaihi wasallam berada di Surga, orang yang syahid berada di Surga, orang yang terlahir berada di Surga, dan orang yang dikubur hidup-hidup berada di Surga.\""},"2095":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا الْوَلِيدُ بْنُ رَبَاحٍ الذِّمَارِيُّ حَدَّثَنِي عَمِّي نِمْرَانُ بْنُ عُتْبَةَ الذِّمَارِيُّ قَالَ دَخَلْنَا عَلَى أُمِّ الدَّرْدَاءِ وَنَحْنُ أَيْتَامٌ فَقَالَتْ أَبْشِرُوا فَإِنِّي سَمِعْتُ أَبَا الدَّرْدَاءَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُشَفَّعُ الشَّهِيدُ فِي سَبْعِينَ مِنْ أَهْلِ بَيْتِهِقَالَ أَبُو دَاوُد صَوَابُهُ رَبَاحُ بْنُ الْوَلِيدِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Yahya bin Hassan], telah menceritakan kepada kami [Al Walid bin Rabah Adz Dzimari], telah menceritakan kepadaku [pamanku] yaitu; Namran bin 'Utbah, ia berkata; kami menemui [Ummu Ad Darda`] sementara kami adalah anak-anak yatim. [Ummu Ad Darda`] berkata; bergembiralah, karena aku pernah mendengar Abu Ad Darda` berkata; Rasulullah shallallahu 'alaihi wasallam berkata: \"Orang yang syahid diberi hak untuk memberikan syafa'at kepada tujuh puluh penghuni rumahnya.\" Abu Daud berkata; yang benar adalah Rabah bin Al Walid. "},"2096":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو الرَّازِيُّ حَدَّثَنَا سَلَمَةُ يَعْنِي ابْنَ الْفَضْلِ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي يَزِيدُ بْنُ رُومَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْلَمَّا مَاتَ النَّجَاشِيُّ كُنَّا نَتَحَدَّثُ أَنَّهُ لَا يَزَالُ يُرَى عَلَى قَبْرِهِ نُورٌ","id":"Telah menceritakan kepada kami [Muhammad bin 'Amr Ar Razi], telah menceritakan kepada kami [Salamah bin Al Fadhl], dari [Muhammad bin Ishaq], telah menceritakan kepadaku [Yazid bin Ruman], dari ['Urwah] dari [Aisyah], ia berkata; tatkala An Najasyi meninggal kami bercerita bahwa terus terlihat cahaya di atas kuburannya. "},"2097":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ عَمْرَو بْنَ مَيْمُونٍ عَنْ عَبْدِ اللَّهِ بْنِ رُبَيِّعَةَ عَنْ عُبَيْدِ بْنِ خَالِدٍ السُّلَمِيِّ قَالَآخَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ رَجُلَيْنِ فَقُتِلَ أَحَدُهُمَا وَمَاتَ الْآخَرُ بَعْدَهُ بِجُمُعَةٍ أَوْ نَحْوِهَا فَصَلَّيْنَا عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قُلْتُمْ فَقُلْنَا دَعَوْنَا لَهُ وَقُلْنَا اللَّهُمَّ اغْفِرْ لَهُ وَأَلْحِقْهُ بِصَاحِبِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَيْنَ صَلَاتُهُ بَعْدَ صَلَاتِهِ وَصَوْمُهُ بَعْدَ صَوْمِهِ شَكَّ شُعْبَةُ فِي صَوْمِهِ وَعَمَلُهُ بَعْدَ عَمَلِهِ إِنَّ بَيْنَهُمَا كَمَا بَيْنَ السَّمَاءِ وَالْأَرْضِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Syu'bah] dari ['Amr bin Murrah], ia berkata; saya mendengar ['Amr bin Maimun] dari [Abdullah bin Rubayyi'ah] dari ['Ubaid bin Khalid As Sulami], ia berkata; Rasulullah shallallahu 'alaihi wasallam mempersaudarakan antara dua orang, kemudian salah seorang diantara mereka berdua dan yang lainnya meninggal setelah itu pada hari Jumu'ah atau yang lainnya. Kemudian kami menshalatinya, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang kalian ucapkan?\" Maka kami katakan; kami mendoakannya, dan kami mengucapkan; ALLAAHUMMAGHFIR LAHU WA ALHIQHU BISHAAHIBIHI (Ya Allah, ampunilah dia dan kumpulkanlah ia dengan sahabatnya!) kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dimanakah shalatnya setelah shalatnya, dan puasanya setelah puasanya?\" Syu'bah merasa ragu mengenai kata; \"puasanya dan amalannya setelah amalannya. sesungguhnya antara keduanya seperti langit dan bumi.\""},"2098":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا ح و حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ الْمَعْنَى وَأَنَا لِحَدِيثِهِ أَتْقَنُ عَنْ أَبِي سَلَمَةَ سُلَيْمَانُ بْنُ سُلَيْمٍ عَنْ يَحْيَى بْنِ جَابِرٍ الطَّائِيِّ عَنْ ابْنِ أَخِي أَبِي أَيُّوبَ الْأَنْصَارِيِّ عَنْ أَبِي أَيُّوبَأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَتُفْتَحُ عَلَيْكُمْ الْأَمْصَارُ وَسَتَكُونُ جُنُودٌ مُجَنَّدَةٌ تُقْطَعُ عَلَيْكُمْ فِيهَا بُعُوثٌ فَيَكْرَهُ الرَّجُلُ مِنْكُمْ الْبَعْثَ فِيهَا فَيَتَخَلَّصُ مِنْ قَوْمِهِ ثُمَّ يَتَصَفَّحُ الْقَبَائِلَ يَعْرِضُ نَفْسَهُ عَلَيْهِمْ يَقُولُ مَنْ أَكْفِيهِ بَعْثَ كَذَا مَنْ أَكْفِيهِ بَعْثَ كَذَا أَلَا وَذَلِكَ الْأَجِيرُ إِلَى آخِرِ قَطْرَةٍ مِنْ دَمِهِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi], telah mengabarkan kepada kami, dan telah diriwayatkan melalui jalur yang lain: Telah menceritakan kepada kami ['Amr bin Utsman], telah menceritakan kepada kami [Muhammad bin Harb] secara makna, dan aku lebih yakin kepada haditsnya, dari [Abu Salamah Sulaiman bin Sulaim], dari [Yahya bin Jabir Ath Tha`i], dari [anak saudara Abu Ayyub Al Anshari], dari [Abu Ayyub] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Akan ditaklukkan untuk kalian berbagai negari dan akan ada tentara-tentara yang bersatu, akan ditunjuk diantara tentara tersebut beberapa pasukan, kemudian diantara kalian terdapat orang yang tidak mau keluar berperang, kemudian ia lari dari kaumnya kemudian ia menyelidiki kabilah-kabilah dan menawarkan dirinya kepada mereka. Orang tersebut berkata; siapakah yang menyewaku untuk keluar berperang demikian? Siapakah yang menyewaku untuk keluar berperang demikian? Ketahuilah ia adalah orang sewaan, ketahuilah ia adalah orang sewaan hingga tetesan darah terakhir.\""},"2099":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ الْمِصِّيصِيُّ حَدَّثَنَا حَجَّاجٌ يَعْنِي ابْنَ مُحَمَّدٍ ح و حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبٍ وَحَدَّثَنَا ابْنُ وَهْبٍ عَنْ اللَّيْثِ بْنِ سَعْدٍ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ عَنْ ابْنِ شُفَيٍّ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْغَازِي أَجْرُهُ وَلِلْجَاعِلِ أَجْرُهُ وَأَجْرُ الْغَازِي","id":"Telah menceritakan kepada kami [Ibrahim bin Al Hasan Al Mashishi], telah menceritakan kepada kami [Hajjaj bin Muhammad], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Abdul Malik bin Syu'aib], telah menceritakan kepada kami [Wahb] dari [Al Laits bin Sa'd] dari [Haiwah bin Syuraih] dari [Ibnu Syufai], dari [ayahnya] dari [Abdullah bin 'Amr] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang berperang baginya pahalanya, dan orang yang memberikan sayembara baginya pahalanya serta pahala orang yang berperang.\""},"2100":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَاصِمُ بْنُ حَكِيمٍ عَنْ يَحْيَى بْنِ أَبِي عَمْرٍو السَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الدَّيْلَمِيِّ أَنَّ يَعْلَى ابْنَ مُنْيَةَ قَالَآذَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْغَزْوِ وَأَنَا شَيْخٌ كَبِيرٌ لَيْسَ لِي خَادِمٌ فَالْتَمَسْتُ أَجِيرًا يَكْفِينِي وَأُجْرِي لَهُ سَهْمَهُ فَوَجَدْتُ رَجُلًا فَلَمَّا دَنَا الرَّحِيلُ أَتَانِي فَقَالَ مَا أَدْرِي مَا السُّهْمَانِ وَمَا يَبْلُغُ سَهْمِي فَسَمِّ لِي شَيْئًا كَانَ السَّهْمُ أَوْ لَمْ يَكُنْ فَسَمَّيْتُ لَهُ ثَلَاثَةَ دَنَانِيرَ فَلَمَّا حَضَرَتْ غَنِيمَتُهُ أَرَدْتُ أَنْ أُجْرِيَ لَهُ سَهْمَهُ فَذَكَرْتُ الدَّنَانِيرَ فَجِئْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ لَهُ أَمْرَهُ فَقَالَ مَا أَجِدُ لَهُ فِي غَزْوَتِهِ هَذِهِ فِي الدُّنْيَا وَالْآخِرَةِ إِلَّا دَنَانِيرَهُ الَّتِي سَمَّى","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Abdullah bin Wahb], telah mengabarkan kepadaku ['Ashim bin Hakim], dari [Yahya bin As Saibani], dari [Abdullah bin Ad Dailami], bahwa [Ya'la bin Munyah] berkata; Rasulullah shallallahu 'alaihi wasallam mengumumkan peperangan sementara aku adalah orang yang sudah tua dan tidak memiliki pembantu. Kemudian aku mencari orang upahan yang akan mewakiliku dan aku memberikan kepadanya sahamnya. Kemudian aku mendapatkan seseorang, lalu tatkala telah dekat waktu pemberangkatan orang tersebut datang kepadaku dan berkata; aku tidak tahu apa dua saham tersebut, dan saham apakah yang akan aku dapatkan, maka sebutkanlah sesuatu untukku baik terdapat saham atau tidak. Kemudian aku sebutkan tiga dinar untuknya. Kemudian tatkala telah datang rampasan perangnya maka aku hendak memberikan sahamnya kepadanya. Lalu aku ingat uang dinar tersebut, maka aku datang kepada Nabi shallallahu 'alaihi wasallam dan aku ceritakan kepadanya permasalahan mengenainya. Beliau berkata: \"Aku tidak mendapati baginya dalam peperangannya ini baik di dunia maupun di akhirat kecuali beberapa uang dinar yang telah ia sebutkan.\""},"2101":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ جِئْتُ أُبَايِعُكَ عَلَى الْهِجْرَةِ وَتَرَكْتُ أَبَوَيَّ يَبْكِيَانِ فَقَالَ ارْجِعْ عَلَيْهِمَا فَأَضْحِكْهُمَا كَمَا أَبْكَيْتَهُمَا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan], telah menceritakan kepada kami ['Atha` bin As Saib], dari [ayahnya], dari [Abdullah bin 'Amr], ia berkata; terdapat seorang laki-laki yang datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; aku datang membai'at engkau untuk berhijrah, dan aku telah meninggalkan kedua orang tuaku dalam keadaan menangis. Kemudian beliau berkata: \"Kembalilah kepada mereka berdua dan buatlah mereka tertawa sebagaimana engkau membuat mereka menangis!\""},"2102":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أَبِي الْعَبَّاسِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أُجَاهِدُ قَالَ أَلَكَ أَبَوَانِ قَالَ نَعَمْ قَالَ فَفِيهِمَا فَجَاهِدْقَالَ أَبُو دَاوُد أَبُو الْعَبَّاسِ هَذَا الشَّاعِرُ اسْمُهُ السَّائِبُ بْنُ فَرُّوخَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Habib bin Abu Tsabit], dari [Abu Al 'Abbas] dari [Abdullah bin 'Amr], ia berkata; terdapat seorang laki-laki yang datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, aku ingin berjihad. Beliau berkata: \"Apakah engkau memiliki kedua orang tua?\" Orang tersebut berkata; ya. Beliau berkata: \"Berjihadlah di sisi mereka!\" Abu Daud berkata; Abu Al Abbas ini adalah ahli syair, namanya adalah As Saib bin Farruh. "},"2103":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ دَرَّاجًا أَبَا السَّمْحِ حَدَّثَهُ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَجُلًا هَاجَرَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْيَمَنِ فَقَالَ هَلْ لَكَ أَحَدٌ بِالْيَمَنِ قَالَ أَبَوَايَ قَالَ أَذِنَا لَكَ قَالَ لَا قَالَ ارْجِعْ إِلَيْهِمَا فَاسْتَأْذِنْهُمَا فَإِنْ أَذِنَا لَكَ فَجَاهِدْ وَإِلَّا فَبِرَّهُمَا","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Abdullah bin Wahb], telah mengabarkan kepadaku ['Amr bin Al Harits], bahwa [Darraj Abu As Samh] telah menceritakan kepadanya dari [Abu Al Haitsam], dari [Abu Sa'id Al Khudri], bahwa seorang laki-laki berhijrah kepada Rasulullah shallallahu 'alaihi wasallam dari Yaman dan berkata; apakah engkau memiliki seseorang di Yaman? Ia berkata; kedua orang tuaku. Beliau berkata: \"Apakah mereka berdua mengizinkanmu?\" Ia berkata; tidak. Beliau berkata: \"Kembalilah kepada mereka berdua dan mintalah izin kepada mereka, apabila mereka mengizinkan maka berjihadlah dan jika tidak maka berbaktilah kepada mereka berdua!\""},"2104":{"ar":"حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ مُطَهِّرٍ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْزُو بِأُمِّ سُلَيْمٍ وَنِسْوَةٍ مِنْ الْأَنْصَارِ لِيَسْقِينَ الْمَاءَ وَيُدَاوِينَ الْجَرْحَى","id":"Telah menceritakan kepada kami [Abdussalam bin Muthahhir], telah menceritakan kepada kami [Ja'far bin Sulaiman], dari [Tsabit], dari [Anas], ia berkata; Rasulullah shallallahu wa'alaihi wa sallam berperang bersama Ummu Sulaim dan beberapa wanita anshar agar mereka memberi minum air dan mengobati orang yang sakit. "},"2105":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا جَعْفَرُ بْنُ بُرْقَانَ عَنْ يَزِيدَ بْنِ أَبِي نُشْبَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثٌ مِنْ أَصْلِ الْإِيمَانِ الْكَفُّ عَمَّنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَلَا نُكَفِّرُهُ بِذَنْبٍ وَلَا نُخْرِجُهُ مِنْ الْإِسْلَامِ بِعَمَلٍ وَالْجِهَادُ مَاضٍ مُنْذُ بَعَثَنِي اللَّهُ إِلَى أَنْ يُقَاتِلَ آخِرُ أُمَّتِي الدَّجَّالَ لَا يُبْطِلُهُ جَوْرُ جَائِرٍ وَلَا عَدْلُ عَادِلٍ وَالْإِيمَانُ بِالْأَقْدَارِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Abu Mu'awiyah], telah menceritakan kepada kami [Ja'far bin Burqan], dari [Yazid bin Abu Nusybah], dari [Anas bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata: \"Tiga perkara yang merupakan dasar keimanan, yaitu: menahan diri dari orang yang mengucapkan LAA ILAAHA ILLALLAAH, dan kita tidak mengkafirkannya karena suatu dosa, serta tidak mengeluarkannya dari keislaman karena sebuah amalan. Jihad tetap berjalan sejak Allah mengutusku hingga umatku yang terakhir memerangi Dajjal, hal itu tidaklah digugurkan oleh kelaliman orang yang lalim, serta keadilan orang yang adil, dan beriman kepada taqdir.\""},"2106":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ الْعَلَاءِ بْنِ الْحَارِثِ عَنْ مَكْحُولٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجِهَادُ وَاجِبٌ عَلَيْكُمْ مَعَ كُلِّ أَمِيرٍ بَرًّا كَانَ أَوْ فَاجِرًا وَالصَّلَاةُ وَاجِبَةٌ عَلَيْكُمْ خَلْفَ كُلِّ مُسْلِمٍ بَرًّا كَانَ أَوْ فَاجِرًا وَإِنْ عَمِلَ الْكَبَائِرَ وَالصَّلَاةُ وَاجِبَةٌ عَلَى كُلِّ مُسْلِمٍ بَرًّا كَانَ أَوْ فَاجِرًا وَإِنْ عَمِلَ الْكَبَائِرَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Wahb], telah menceritakan kepadaku [Mu'awiyah bin Shalih], dari [Al 'Ala` bin Al Harits], dari [Makhul] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berjihad adalah wajib atas kalian bersama seluruh pemimpin yang baik maupun jahat. Shalat adalah wajib atas kalian di belakang setiap muslim, yang baik maupun yang jahat dan walaupun ia telah melakukan dosa-dosa besar. Dan shalat adalah wajib atas setiap muslim yang baik maupun yang jahat, walaupun ia telah melakukan dosa-dosa besar.\""},"2107":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا عُبَيْدَةُ بْنُ حُمَيْدٍ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ نُبَيْحٍ الْعَنَزِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ حَدَّثَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ أَرَادَ أَنْ يَغْزُوَ فَقَالَ يَا مَعْشَرَ الْمُهَاجِرِينَ وَالْأَنْصَارِ إِنَّ مِنْ إِخْوَانِكُمْ قَوْمًا لَيْسَ لَهُمْ مَالٌ وَلَا عَشِيرَةٌ فَلْيَضُمَّ أَحَدُكُمْ إِلَيْهِ الرَّجُلَيْنِ أَوْ الثَّلَاثَةِ فَمَا لِأَحَدِنَا مِنْ ظَهْرٍ يَحْمِلُهُ إِلَّا عُقْبَةٌ كَعُقْبَةِ يَعْنِي أَحَدِهِمْ قَالَ فَضَمَمْتُ إِلَيَّ اثْنَيْنِ أَوْ ثَلَاثَةً قَالَ مَا لِي إِلَّا عُقْبَةٌ كَعُقْبَةِ أَحَدِهِمْ مِنْ جَمَلِي","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari], telah menceritakan kepada kami ['Ubaidah bin Humaid], dari [Al Aswad bin Qais], dari [Nubaih Al 'Anazi], dari [Jabir bin Abdullah], ia telah menceritakan dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau hendak berperang. Lalu beliau berkata: \"Wahai orang-orang muhajirin, dan anshar. Sesungguhnya diantara saudara-saudara kalian terdapat orang-orang yang tidak memiliki harta dan keluarga, maka hendaknya salah seorang diantara kalian menggabungkan dua atau tiga orang kepadanya.\" Tidaklah salah seorang diantara kami memiliki tunggangan yang membawanya melainkan bergantian seperti salah seorang diantara mereka bergiliran. Jabir bin Abdullah berkata; dan aku menggabungkan dua atau tiga orang kepadaku. Ia berkata; aku tidak memiliki melainkan unta melainkan untuk bergiliran seperti salah seorang dari mereka bergiliran. "},"2108":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا أَسَدُ بْنُ مُوسَى حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ حَدَّثَنِي ضَمْرَةُ أَنَّ ابْنَ زُغْبٍ الْإِيَادِيَّ حَدَّثَهُ قَالَنَزَلَ عَلَيَّ عَبْدُ اللَّهِ بْنُ حَوَالَةَ الْأَزْدِيُّ فَقَالَ لِي بَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِنَغْنَمَ عَلَى أَقْدَامِنَا فَرَجَعْنَا فَلَمْ نَغْنَمْ شَيْئًا وَعَرَفَ الْجَهْدَ فِي وُجُوهِنَا فَقَامَ فِينَا فَقَالَ اللَّهُمَّ لَا تَكِلْهُمْ إِلَيَّ فَأَضْعُفَ عَنْهُمْ وَلَا تَكِلْهُمْ إِلَى أَنْفُسِهِمْ فَيَعْجِزُوا عَنْهَا وَلَا تَكِلْهُمْ إِلَى النَّاسِ فَيَسْتَأْثِرُوا عَلَيْهِمْ ثُمَّ وَضَعَ يَدَهُ عَلَى رَأْسِي أَوْ قَالَ عَلَى هَامَتِي ثُمَّ قَالَ يَا ابْنَ حَوَالَةَ إِذَا رَأَيْتَ الْخِلَافَةَ قَدْ نَزَلَتْ أَرْضَ الْمُقَدَّسَةِ فَقَدْ دَنَتْ الزَّلَازِلُ وَالْبَلَابِلُ وَالْأُمُورُ الْعِظَامُ وَالسَّاعَةُ يَوْمَئِذٍ أَقْرَبُ مِنْ النَّاسِ مِنْ يَدِي هَذِهِ مِنْ رَأْسِكَقَالَ أَبُو دَاوُد عَبْدُ اللَّهِ بْنُ حَوَالَةَ حِمْصِيٌّ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Asad bin Musa], telah menceritakan kepada kami [Mu'awiyah bin Shalih], telah menceritakan kepadaku [Dhamrah] bahwa [Ibnu Zughb Al Iyadi] telah menceritakan kepadanya, ia berkata; [Abdullah bin Hawalah Al Azdi] singgah di tempatku, lalu ia berkata kepadaku; Rasulullah shallallahu 'alaihi wasallam mengutus kami untuk mendapat rampasan perang dengan berjalan kaki. Kemudian kami tidak mendapatkan sesuatu, dan beliau mengetahui kondisi berat pada wajah kami. Kemudian beliau berdiri dan berdoa: ALLAAHUMMA LAA TAKILHUM ILAYYA FA-ADH'UFA 'ANHUM, WA LAA TAKILHUM ILAA ANFUSIHIM FAYA'JIZUU ANHAA, WA LAA TAKILHUM ILAN NAASI FAYASTA`RUU 'ALAIHIM (Ya Allah, janganlah engkau serahkan mereka kepadaku sehingga aku lemah (tidak kuat) menanggung mereka, dan janganlah Engkau serahkan diri mereka kepada mereka sehingga mereka tidak mampu menanggung diri mereka. Dan janganlah Engkau serahkan mereka kepada orang-orang sehingga mereka mementingkan diri mereka atas diri mereka.\"kemudian beliau meletakkan tanganku di atas kepalaku. Kemudian beliau berkata: \"Wahai anak Hawalah, apabila engkau melihat kekhilafahan telah turun di bumi yang disucikan maka sungguh telah dekat bencana gempa dan berbagai kesedihan serta perkara-perkara besar. Pada saat itu Hari Kiamat lebih dekat kepada orang-orang daripada tanganku ini dari kepalaku.\" Abu Daud berkata; Abdullah bin Hawalah adalah orang Himsh. "},"2109":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ مُرَّةَ الْهَمْدَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَجِبَ رَبُّنَا عَزَّ وَجَلَّ مِنْ رَجُلٍ غَزَا فِي سَبِيلِ اللَّهِ فَانْهَزَمَ يَعْنِي أَصْحَابَهُ فَعَلِمَ مَا عَلَيْهِ فَرَجَعَ حَتَّى أُهَرِيقَ دَمُهُ فَيَقُولُ اللَّهُ تَعَالَى لِمَلَائِكَتِهِ انْظُرُوا إِلَى عَبْدِي رَجَعَ رَغْبَةً فِيمَا عِنْدِي وَشَفَقَةً مِمَّا عِنْدِي حَتَّى أُهَرِيقَ دَمُهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami ['Atha` bin As Sa'ib], dari [Murrah Al Hamdani], dari [Abdullah bin Mas'ud], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata: \"Tuhan kalian 'azza wajalla merasa kagum kepada seorang laki-laki yang berperang di jalan Allah. Kemudian para sahabatkan kalah dan ia mengetahui kewajibannya, kemudian ia kembali hingga telah bercucuran darahnya. Kemudian Allah ta'la berfirman kepada para malaikatNya: \"Lihatlah kepada hambaKu, ia kembali karena menginginkan apa yang ada di sisiKu, dan rindu kepada apa yang ada di sisiKu hingga bercucuran darahnya.\""},"2110":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنْ عَمْرَو بْنَ أُقَيْشٍ كَانَ لَهُ رِبًا فِي الْجَاهِلِيَّةِ فَكَرِهَ أَنْ يُسْلِمَ حَتَّى يَأْخُذَهُ فَجَاءَ يَوْمُ أُحُدٍ فَقَالَ أَيْنَ بَنُو عَمِّي قَالُوا بِأُحُدٍ قَ��لَ أَيْنَ فُلَانٌ قَالُوا بِأُحُدٍ قَالَ فَأَيْنَ فُلَانٌ قَالُوا بِأُحُدٍ فَلَبِسَ لَأْمَتَهُ وَرَكِبَ فَرَسَهُ ثُمَّ تَوَجَّهَ قِبَلَهُمْ فَلَمَّا رَآهُ الْمُسْلِمُونَ قَالُوا إِلَيْكَ عَنَّا يَا عَمْرُو قَالَ إِنِّي قَدْ آمَنْتُ فَقَاتَلَ حَتَّى جُرِحَ فَحُمِلَ إِلَى أَهْلِهِ جَرِيحًا فَجَاءَهُ سَعْدُ بْنُ مُعَاذٍ فَقَالَ لِأُخْتِهِ سَلِيهِ حَمِيَّةً لِقَوْمِكَ أَوْ غَضَبًا لَهُمْ أَمْ غَضَبًا لِلَّهِ فَقَالَ بَلْ غَضَبًا لِلَّهِ وَلِرَسُولِهِ فَمَاتَ فَدَخَلَ الْجَنَّةَ وَمَا صَلَّى لِلَّهِ صَلَاةً","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami [Muhammad bin 'Amr], dari [Abu Salamah], dari [Abu Hurairah], bahwa 'Amr bin Uqaisy dahulu memiliki harta riba pada masa jahiliyah dan ia tidak ingin masuk Islam hingga ia mengambil harta tersebut. Kemudian datang waktu perang Uhud, kemudian ia berkata; dimanakah anak-anak pamanku? Mereka berkata; di Uhud. Ia berkata; dimanakah Fulan? Mereka berkata; di Uhud. Ia berkata; dimanakah Fulan? Mereka berkata; di Uhud. Kemudian ia memakai baju zirahnya dan menaiki kudanya kemudian ia menuju ke arah mereka. Kemudian tatkala orang-orang muslim melihatnya mereka berkata; menjauhlah engkau dari kami wahai 'Amr! Ia berkata; aku telah beriman. Kemudian ia bertempur hingga terluka, kemudian ia dibawa kepada keluarganya dalam keadaan terluka. Lalu Sa'd bin Mu'adz datang kepadanya dan berkata kepada saudarinya; tanyakan kepadanya, apakah karena kesombongan untuk kaumnya atau karena kemarahan untuk karena mereka atau karena kemarahan karena Allah? Ia berkata; bahkan karena kemarahan karena Allah dan rasulNya. Kemudian ia meninggal dan masuk Surga sementera ia belum pernah melakukan satu shalatpun untuk Allah. "},"2111":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ وَعَبْدُ اللَّهِ بْنُ كَعْبِ بْنِ مَالِكٍ قَالَ أَبُو دَاوُد قَالَ أَحْمَدُ كَذَا قَالَ هُوَ يَعْنِي ابْنَ وَهْبٍ وَعَنْبَسَةُ يَعْنِي ابْنَ خَالِدٍ جَمِيعًا عَنْ يُونُسَ قَالَ أَحْمَدُ وَالصَّوَابُ عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ أَنَّ سَلَمَةَ بْنَ الْأَكْوَعِ قَالَلَمَّا كَانَ يَوْمُ خَيْبَرَ قَاتَلَ أَخِي قِتَالًا شَدِيدًا فَارْتَدَّ عَلَيْهِ سَيْفُهُ فَقَتَلَهُ فَقَالَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ وَشَكُّوا فِيهِ رَجُلٌ مَاتَ بِسِلَاحِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاتَ جَاهِدًا مُجَاهِدًاقَالَ ابْنُ شِهَابٍ ثُمَّ سَأَلْتُ ابْنًا لِسَلَمَةَ بْنِ الْأَكْوَعِ فَحَدَّثَنِي عَنْ أَبِيهِ بِمِثْلِ ذَلِكَ غَيْرَ أَنَّهُ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَبُوا مَاتَ جَاهِدًا مُجَاهِدًا فَلَهُ أَجْرُهُ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Abdullah bin Wahb], telah mengabarkan kepadaku [Yunus], dari [Ibnu Syihab], ia berkata; telah mengabarkan kepadaku [Abdurrahman] dan Abdullah bin Ka'bin bin Malik, Abu Daud berkata; [Ahmad] berkata; demikianlah yang dikatakan [Ibnu Wahb], serta ['Anbasah bin Khalid], semuanya berasal dari [Yunus], Ahmad berkata; dan yang benar adalah Abdurrahman bin Abdullah. Bahwa [Salamah bin Al Akwa'] berkata; tatkala ada hari terjadinya perang Khaibar saudaraku berperang dengan perang yang sengit, kemudian pedangnya berbalik kemudian membunuhnya. Kemudian para sahabat Rasulullah shallallahu 'alaihi wasallam berkata mengenai hal tersebut dan mereka merasa ragu; ia adalah orang yang mati dengan senjatanya. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Ia meninggal dalam keadaan bersungguh-sungguh dan berjihad.\" [Ibnu Syihab] berkata; kemudian aku bertanya kepada [anak Salamah bin Al Akwa'], kemudian ia menceritakan dari [ayahnya], seperti itu hanya saja ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mereka telah berdusta, ia meninggal dalam keadaan bersungguh-sungguh dan berjihad, dan baginya pahala dua kali.\""},"2112":{"ar":"حَدَّثَنَا هِشَامُ بْنُ خَالِدٍ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ عَنْ مُعَاوِيَةَ بْنِ أَبِي سَلَّامٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَبِي سَلَّامٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَأَغَرْنَا عَلَى حَيٍّ مِنْ جُهَيْنَةَ فَطَلَبَ رَجُلٌ مِنْ الْمُسْلِمِينَ رَجُلًا مِنْهُمْ فَضَرَبَهُ فَأَخْطَأَهُ وَأَصَابَ نَفْسَهُ بِالسَّيْفِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخُوكُمْ يَا مَعْشَرَ الْمُسْلِمِينَ فَابْتَدَرَهُ النَّاسُ فَوَجَدُوهُ قَدْ مَاتَ فَلَفَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثِيَابِهِ وَدِمَائِهِ وَصَلَّى عَلَيْهِ وَدَفَنَهُ فَقَالُوا يَا رَسُولَ اللَّهِ أَشَهِيدٌ هُوَ قَالَ نَعَمْ وَأَنَا لَهُ شَهِيدٌ","id":"Telah menceritakan kepada kami [Hisyam bin Khalid Ad Dimasyqi], Telah menceritakan kepada kami [Al Walid] dari [Mu'awiyah bin Abu Sallam], dari [ayahnya], dari [kakeknya yaitu Abu Sallam], dari [seorang sahabat Nabi shallallahu 'alaihi wasallam], ia berkata; kami penah menyerang sebuah kampong dari Suku Juhainah, kemudian salah seorang muslim mencari seseorang dari kalangan mereka kemudian menebasnya dengan pedang namun tidak mengenainya dan mengenai dirinya. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Ia adalah saudara kalian wahai kaum muslimin!\" kemudian orang-orang bersegera menuju kepadanya, lalu mereka mendapatinya telah meninggal. Kemudian Rasulullah shallallahu 'alaihi wasallam membungkusnya menggunakan baju serta darahnya dan beliau menshalatkan serta menguburnya. Orang-orang berkata; wahai Rasulullah, apakah ia syahid? Beliau berkata: \"Ya, dan aku bersaksi untuknya.\""},"2113":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا مُوسَى بْنُ يَعْقُ��بَ الزَّمْعِيُّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثِنْتَانِ لَا تُرَدَّانِ أَوْ قَلَّمَا تُرَدَّانِ الدُّعَاءُ عِنْدَ النِّدَاءِ وَعِنْدَ الْبَأْسِ حِينَ يُلْحِمُ بَعْضُهُمْ بَعْضًاقَالَ مُوسَى وَحَدَّثَنِي رِزْقُ بْنُ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَوَقْتُ الْمَطَرِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Ibnu Abu Maryam], telah menceritakan kepada kami [Musa bin Ya'qub Az Zam'i], dari [Abu Hazim], dari [Sahl bin Sa'd], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua perkara yang tidak ditolak atau jarang ditolak, yaitu: berdoa ketika adzan, dan (berdoa) ketika susah di saat sebagian mereka membunuh sebagian yang lain (ketika perang).\" Musa berkata; dan telah menceritakan kepadaku [Rizq bin Sa'id bin Abdurrahman] dari [Abu Hazim], dari [Sahl bin Sa'd], dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \" Dan waktu hujan.\""},"2114":{"ar":"حَدَّثَنَا هِشَامُ بْنُ خَالِدٍ أَبُو مَرْوَانَ وَابْنُ الْمُصَفَّى قَالَا حَدَّثَنَا بَقِيَّةُ عَنْ ابْنِ ثَوْبَانَ عَنْ أَبِيهِ يُرَدُّ إِلَى مَكْحُولٍ إِلَى مَالِكِ بْنِ يُخَامِرَ أَنَّ مُعَاذَ بْنَ جَبَلٍ حَدَّثَهُمْأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ قَاتَلَ فِي سَبِيلِ اللَّهِ فُوَاقَ نَاقَةٍ فَقَدْ وَجَبَتْ لَهُ الْجَنَّةُ وَمَنْ سَأَلَ اللَّهَ الْقَتْلَ مِنْ نَفْسِهِ صَادِقًا ثُمَّ مَاتَ أَوْ قُتِلَ فَإِنَّ لَهُ أَجْرَ شَهِيدٍ زَادَ ابْنُ الْمُصَفَّى مِنْ هُنَا وَمَنْ جُرِحَ جُرْحًا فِي سَبِيلِ اللَّهِ أَوْ نُكِبَ نَكْبَةً فَإِنَّهَا تَجِيءُ يَوْمَ الْقِيَامَةِ كَأَغْزَرِ مَا كَانَتْ لَوْنُهَا لَوْنُ الزَّعْفَرَانِ وَرِيحُهَا رِيحُ الْمِسْكِ وَمَنْ خَرَجَ بِهِ خُرَاجٌ فِي سَبِيلِ اللَّهَ فَإِنَّ عَلَيْهِ طَابَعَ الشُّهَدَاءِ","id":"Telah menceritakan kepada kami [Hisyam bin Khalid Abu Marwan], dan [Ibnu Al Mushaffa], mereka berkata; telah menceritakan kepada kami [Baqiyyah] dari [Ibnu Tsauban], dari [ayahnya], dan dikembalikan kepada [Makhul], kepada [Malik bin Yukhamir], bahwa [Mu'adz bin Jabal], telah menceritakan kepada mereka bahwa ia telah mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Barangsiapa yang berperang di jalan Allah di atas unta maka telah wajib Surga baginya, dan barang siapa yang memohon kepada Allah agar terbunuh dengan niat yang benar, kemudian ia meninggal atau terbunuh maka baginya pahala orang yang mati syahid.\" Ibnu Al Mushaffa menambahkan dari sini; dan barangsiapa yang terluka di jalan Allah, atau tertimpa musibah maka sesungguhnya musibah tersebut akan datang pada Hari Kiamat seperti darah yang paling deras, warnanya adalah warna za'faran dan baunya adalah bau minyak kasturi. Barangsiapa yang padanya keluar bisul di jalan Allah maka sesungguhnya padanya terdapat stempel sebagai orang syahid. "},"2115":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ عَنْ الْهَيْثَمِ بْنِ حُمَيْدٍ ح و حَدَّثَنَا خُشَيْشُ بْنُ أَصْرَمَ حَدَّثَنَا أَبُو عَاصِمٍ جَمِيعًا عَنْ ثَوْرِ بْنِ يَزِيدَ عَنْ نَصْرٍ الْكِنَانِيِّ عَنْ رَجُلٍ وَقَالَ أَبُو تَوْبَةَ عَنْ ثَوْرِ بْنِ يَزِيدَ عَنْ شَيْخٍ مِنْ بَنِي سُلَيْمٍ عَنْ عُتْبَةَ بْنِ عَبْدٍ السُّلَمِيِّ وَهَذَا لَفْظُهُأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَقُصُّوا نَوَاصِي الْخَيْلِ وَلَا مَعَارِفَهَا وَلَا أَذْنَابَهَا فَإِنَّ أَذْنَابَهَا مَذَابُّهَا وَمَعَارِفَهَا دِفَاؤُهَا وَنَوَاصِيَهَا مَعْقُودٌ فِيهَا الْخَيْرُ","id":"Telah menceritakan kepada kami [Abu Taubah] dari [Al Haitsam bin Humaid], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Husyaisy bin Ashram], telah menceritakan kepada kami [Abu 'Ashim], seluruhnya berasal dari [Tsaur bin Yazid] dari [Nashir Al Kinani], dari [seorang laki-laki], [Abu Taubah] berkata; dari [Tsaur bin Yazid], dari [seorang syekh] dari Bani Sulaim, dari ['Utbah bin Abdussalami], dan ini adalah lafazhnya, bahwa ia telah mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Janganlah kalian cukur jambul kuda, dan rambut leher, serta ekornya, karena sesungguhnya ekornya adalah yang akan membelanya, rambut lehernya adalah pakaian yang akan menghangatkannya, dan pada jambulnya terikat seluruh kebaikan.\""},"2116":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا هِشَامُ بْنُ سَعِيدٍ الطَّالْقَانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُهَاجِرِ الْأَنْصَارِيُّ حَدَّثَنِي عَقِيلُ بْنُ شَبِيبٍ عَنْ أَبِي وَهْبٍ الْجُشَمِيِّ وَكَانَتْ لَهُ صُحْبَةٌ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ بِكُلِّ كُمَيْتٍ أَغَرَّ مُحَجَّلٍ أَوْ أَشْقَرَ أَغَرَّ مُحَجَّلٍ أَوْ أَدْهَمَ أَغَرَّ مُحَجَّلٍحَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ الطَّائِيُّ حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا مُحَمَّدُ بْنُ مُهَاجِرٍ حَدَّثَنَا عَقِيلُ بْنُ شَبِيبٍ عَنْ أَبِي وَهْبٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ بِكُلِّ أَشْقَرَ أَغَرَّ مُحَجَّلٍ أَوْ كُمَيْتٍ أَغَرَّ فَذَكَرَ نَحْوَهُ قَالَ مُحَمَّدٌ يَعْنِي ابْنَ مُهَاجِرٍ وَسَأَلْتُهُ لِمَ فُضِّلَ الْأَشْقَرُ قَالَ لِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ سَرِيَّةً فَكَانَ أَوَّلَ مَنْ جَاءَ بِالْفَتْحِ صَاحِبُ أَشْقَرَ","id":"Telah menceritakan kepada kami [Harun bin Abdullah], telah menceritakan kepada kami [Hisyam bin Sa'id Ath Thalqani], telah menceritakan kepada kami [Muhammad bin Al Muhajir Al Anshari], telah menceritakan kepadaku ['Aqil bin Syabib], dari [Abu Wahb Al Jusyami], dan ia pernah menyertai Rasulullah shallallahu 'alaihi wasallam, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya kalian memiliki kuda hitam kemerah-merahan yang dahinya dan kakinya berwarna putih, atau yang berwarna blonde yang dahi dan kakinya berwarna putih, atau kuda hitam yang dahi dan kakinya berwarna putih.\" Telah menceritakan kepada kami [Muhammad bin 'Auf Ath Thai], telah menceritakan kepada kami [Abu Al Mughirah], telah menceritakan kepada kami [Muhammad bin Muhajir], telah menceritakan kepada kami ['Aqil bin Syabib], dari [Abu Wahb], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap kuda yang berwarna blonde yang dahi dan kakinya berwarna putih, atau kuda yang kemerah-merahan yang dahi dan kakinya berwarna putih.\" Ia menyebutkan seperti hadits tersebut. Muhammad bin Muhajir berkata; dan aku bertanya kepada 'Aqil; kenapa lebih diutamakan yang berwarna kemerahan? Ia berkata; karena Nabi shallallahu 'alaihi wasallam telah mengutus sebuah pasukan dan orang yang paling pertama membawa berita kemenangan adalah orang yang memiliki kuda kemerah-merahan. "},"2117":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ عَنْ شَيْبَانَ عَنْ عِيسَى بْنِ عَلِيٍّ عَنْ أَبِيهِ عَنْ جَدِّهِ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُمْنُ الْخَيْلِ فِي شُقْرِهَا","id":"Telah menceritakan kepada kami [Yahya bin Ma'in], telah menceritakan kepada kami [Husain bin Muhammad], dari [Syaiban], dari [Isa bin Ali], dari [ayahnya], dari [kakeknya yaitu Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kebaikan dan berkah kuda ada pada warna blondenya.\""},"2118":{"ar":"حَدَّثَنَا مُوسَى بْنُ مَرْوَانَ الرَّقِيُّ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ عَنْ أَبِي حَيَّانَ حَدَّثَنَا أَبُو زَرْعَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُسَمِّي الْأُنْثَى مِنْ الْخَيْلِ فَرَسًا","id":"Telah menceritakan kepada kami [Musa bin Marwan Ar Raqi], telah menceritakan kepada kami [Marwan bin Mu'awiyah], dari [Abu Hayyan], telah menceritakan kepada kami [Abu Zur'ah], dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam menamakan kuda betina Faras. "},"2119":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ سَلْمٍ هُوَ ابْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْرَهُ الشِّكَالَ مِنْ الْخَيْلِ وَالشِّكَالُ يَكُونُ الْفَرَسُ فِي رِجْلِهِ الْيُمْنَى بَيَاضٌ وَفِي يَدِهِ الْيُسْرَى بَيَاضٌ أَوْ فِي يَدِهِ الْيُمْنَى وَفِي رِجْلِهِ الْيُسْرَىقَالَ أَبُو دَاوُد أَيْ مُخَالِفٌ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Salm bin Ibnu Abdurrahman] dari [Abu Zur'ah] dari [Abu Hurairah], ia berkata; Nabi shallallahu 'alaihi wasallam tidak menyukai kuda syikal, syikal adalah kuda betina yang pada kaki kanannya terdapat warna putih, dan pada tangan kirinya terdapat warna putih atau pada tangan kanannya dan kaki kirinya. Abu Daud berkata; yaitu secara silang. "},"2120":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مِسْكِينٌ يَعْنِي بْنَ بُكَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُهَاجِرٍ عَنْ رَبِيعَةَ بْنِ يَزِيدَ عَنْ أَبِي كَبْشَةَ السَّلُولِيِّ عَنْ سَهْلِ ابْنِ الْحَنْظَلِيَّةِ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبَعِيرٍ قَدْ لَحِقَ ظَهْرُهُ بِبَطْنِهِ فَقَالَ اتَّقُوا اللَّهَ فِي هَذِهِ الْبَهَائِمِ الْمُعْجَمَةِ فَارْكَبُوهَا صَالِحَةً وَكُلُوهَا صَالِحَةً","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Miskin bin Bukair], telah menceritakan kepada kami [Muhammad bin Muhajir], dari [Rabi'ah bin Yazid], dari [Abu Kabsyah As Saluli], dari [Sahl bin Al Hanzhaliyyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah melewati seekor unta punggungnya telah menempel dengan perutnya. Kemudian beliau berkata: \"Bertakwalah kepada Allah dalam merawat binatang-binatang ternak yang tidak bisa berbicara ini, dan tunggangilah dengan dalam keadaan layak, dan makanlah dalam keadaan layak!\""},"2121":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا مَهْدِيٌّ حَدَّثَنَا ابْنُ أَبِي يَعْقُوبَ عَنْ الْحَسَنِ بْنِ سَعْدٍ مَوْلَى الْحَسَنِ بْنِ عَلِيٍّ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَأَرْدَفَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلْفَهُ ذَاتَ يَوْمٍ فَأَسَرَّ إِلَيَّ حَدِيثًا لَا أُحَدِّثُ بِهِ أَحَدًا مِنْ النَّاسِ وَكَانَ أَحَبُّ مَا اسْتَتَرَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَاجَتِهِ هَدَفًا أَوْ حَائِشَ نَخْلٍ قَالَ فَدَخَلَ حَائِطًا لِرَجُلٍ مِنْ الْأَنْصَارِ فَإِذَا جَمَلٌ فَلَمَّا رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَنَّ وَذَرَفَتْ عَيْنَاهُ فَأَتَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَسَحَ ذِفْرَاهُ فَسَكَتَ فَقَالَ مَنْ رَبُّ هَذَا الْجَمَلِ لِمَنْ هَذَا الْجَمَلُ فَجَاءَ فَتًى مِنْ الْأَنْصَارِ فَقَالَ لِي يَا رَسُولَ اللَّهِ فَقَالَ أَفَلَا تَتَّقِي اللَّهَ فِي هَذِهِ الْبَهِيمَةِ الَّتِي مَلَّكَكَ اللَّهُ إِيَّاهَا فَإِنَّهُ شَكَا إِلَيَّ أَنَّكَ تُجِيعُهُ وَتُدْئِبُهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Mahdi], telah menceritakan kepada kami [Ibnu Abu Ya'qub] dari [Al Hasan bin Sa'd] mantan budak Al Hasan bin Ali, dari [Abdullah bin Ja'far], ia berkata; Rasulullah shallallahu wa'alaihi wa sallam pada suatu hari pernah memboncengkanku dibelakangnya kemudian beliau membisikkan suatu perkataan kepadaku yang tidak aku ceritakan kepada siapapun dari manusia. Dan sesuatu yang paling Rasulullah shallallahu 'alaihi wasallam senangi untuk menutupi hajatnya adalah tanah tinggi atau pohon kurma yang rimbun. Ia berkata; kemudian beliau memasuki kebun seorang laki-laki anshar, dan kemudian tiba-tiba terdapat unta. Tatkala unta tersebut melihat Nabi shallallahu 'alaihi wasallam maka ia merintih dan kedua matanya mengeluarkan air mata. Kemudian Nabi shallallahu 'alaihi wasallam mendatanginya dan mengusap tulang di belakang telinganya, lalu unta tersebut terdiam. Lalu beliau berkata: \"Siapakah pemilik unta ini?\" kemudian terdapat seorang pemuda anshar yang datang dan berkata; saya wahai Rasulullah. Kemudian beliau berkata: \"Tidakkah engkau bertakwa kepada Allah dalam bertindak terhadap binatang ternak yang telah Allah berikan ini? Sesungguhnya unta tersebut telah mengeluhkan kepadaku bahwa engkau menyakitinya dan membuatnya menjadi letih.\""},"2122":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرٍ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا رَجُلٌ يَمْشِي بِطَرِيقٍ فَاشْتَدَّ عَلَيْهِ الْعَطَشُ فَوَجَدَ بِئْرًا فَنَزَلَ فِيهَا فَشَرِبَ ثُمَّ خَرَجَ فَإِذَا كَلْبٌ يَلْهَثُ يَأْكُلُ الثَّرَى مِنْ الْعَطَشِ فَقَالَ الرَّجُلُ لَقَدْ بَلَغَ هَذَا الْكَلْبَ مِنْ الْعَطَشِ مِثْلُ الَّذِي كَانَ بَلَغَنِي فَنَزَلَ الْبِئْرَ فَمَلَأَ خُفَّهُ فَأَمْسَكَهُ بِفِيهِ حَتَّى رَقِيَ فَسَقَى الْكَلْبَ فَشَكَرَ اللَّهُ لَهُ فَغَفَرَ لَهُ فَقَالُوا يَا رَسُولَ اللَّهِ وَإِنَّ لَنَا فِي الْبَهَائِمِ لَأَجْرًا فَقَالَ فِي كُلِّ ذَاتِ كَبِدٍ رَطْبَةٍ أَجْرٌ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi] dari [Malik] dari [Sumai], mantan budak Abu Bakr dari [Abu Shalih As Samman] dari [Abu Hurairah] bahwa Rasulullah shallallahu wa'alaihi wa sallam bersabda: \"Ketika seorang laki-laki berjalan di sebuah jalan, dan ia merasakan sangat kehausan, ternyata ia mendapatkan sebuah sumur. Lalu ia menuruninya lalu minum, kemudian ia keluar dan tiba-tiba terdapat anjing yang menjulurkan lidahnya, ia makan tanah yang lembab karena kehausan. Lalu orang tersebut berkata; sungguh anjing ini telah kehausan seperti yang pernah aku rasakan. Kemudian ia turun ke sumur dan ia memenuhi sepatunya lalu ia memegangnya menggunakan mulutnya dan naik ke atas kemudian memberi minum anjing tersebut. Maka Allah berterima kasih kepadanya dan mengampuni dosanya.\" Kemudian mereka berkata; wahai Rasulullah, apakah kami mendapatkan pahala karena berbuat baik kepada hewan? Beliau berkata: \"Dalam setiap hewan yang memiliki hati yang basah terdapat pahala.\""},"2123":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنِي مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ حَمْزَةَ الضَّبِيِّ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَكُنَّا إِذَا نَزَلْنَا مَنْزِلًا لَا نُسَبِّحُ حَتَّى تُحَلَّ الرِّحَالُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepadaku [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari [Hamzah Adh Dhabbi], ia berkata; saya mendengar [Anas bin Malik], berkata; dahulu kami apabila singgah di suatu tempat maka kami tidak melakukan shalat hingga menurunkan beban dari hewan tunggangan kami. "},"2124":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ أَنَّ أَبَا بَشِيرٍ الْأَنْصَارِيَّ أَخْبَرَهُأَنَّهُ كَانَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَسُولًا قَالَ عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ حَسِبْتُ أَنَّهُ قَالَ وَالنَّاسُ فِي مَبِيتِهِمْ لَا يَبْقَيَنَّ فِي رَقَبَةِ بَعِيرٍ قِلَادَةٌ مِنْ وَتَرٍ وَلَا قِلَادَةٌ إِلَّا قُطِعَتْقَالَ مَالِكٌ أَرَى أَنَّ ذَلِكَ مِنْ أَجْلِ الْعَيْنِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik], dari [Abdullah bin Abu Bakr bin Muhammad bin 'Amr bin Hazm], dari ['Abbad bin Tamim], bahwa [Abu Basyir Al Anshari] telah mengabarkan kepadanya bahwa ia pernah bersama Rasulullah shallallahu wa'alaihi wa sallam dalam sebagian perjalanannya. Kemudian Rasulullah shallallahu wa'alaihi wa sallam mengirim sebuah utusan. Abdullah bin Abu Bakr berkata; aku mengira ia berkata; dan orang-orang sedang berada di tempat mereka bermalam. Utusan tersebut mengumumkan; tidak boleh ada tali busur dan kalung tertinggal di leher unta kecuali diputus. Malik berkata; aku melihat bahwa hal tersebut dengan tujuan untuk menangkal 'ain. "},"2125":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا هِشَامُ بْنُ سَعِيدٍ الطَّالْقَانِيُّ أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُهَاجِرِ حَدَّثَنِي عُقَيْلُ بْنُ شَبِيبٍ عَنْ أَبِي وَهْبٍ الْجُشَمِيِّ وَكَانَتْ لَهُ صُحْبَةٌ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْتَبِطُوا الْخَيْلَ وَامْسَحُوا بِنَوَاصِيهَا وَأَعْجَازِهَا أَوْ قَالَ أَكْفَالِهَا وَقَلِّدُوهَا وَلَا تُقَلِّدُوهَا الْأَوْتَارَ","id":"Telah menceritakan kepada kami [Harun bin Abdullah], telah menceritakan kepada kami [Hisyam bin Sa'id Ath Thalqani], telah mengabarkan kepada kami [Muhammad bin Al Muhajir], telah menceritakan kepadaku ['Uqail bin Syabib], dari [Abu Wahb Al Jusyami], ia adalah orang yang pernah menyertai Rasulullah shallallahu 'alaihi wasallam, ia berkata; Rasulullah shallallahu wa'alaihi wa sallam bersabda: \"Ikatlah kuda dan usaplah jambul serta pantatnya -atau beliau mengatakan: \"bagian diantara pangkal paha.\" Dan kalungilah kuda tersebut dan jangan kalian kalungi menggunakan tali busur!\""},"2126":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ سَالِمٍ عَنْ أَبِي الْجَرَّاحِ مَوْلَى أُمِّ حَبِيبَةَ عَنْ أُمِّ حَبِيبَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصْحَبُ الْمَلَائِكَةُ رِفْقَةً فِيهَا جَرَسٌ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] dari [Nafi'], dari [Salim], dari [Abu Al Jarrah] mantan budak Ummu Habibah, dari [Ummu Habibah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Malaikat tidak menyertai rombongan yang membawa lonceng.\""},"2127":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَصْحَبُ الْمَلَائِكَةُ رِفْقَةً فِيهَا كَلْبٌ أَوْ جَرَسٌ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Suhail bin Abu Shalih], dari [ayahnya] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu wa'alaihi wa sallam bersabda: \"Malaikat tidak menyertai rombongan yang membawa anjing atau lonceng.\""},"2128":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ أُوَيْسٍ حَدَّثَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْجَرَسِ مِزْمَارُ الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'], telah menceritakan kepada kami [Abu Bakr bin Uwais], telah menceritakan kepadaku [Sulaiman bin Bilal], dari [Al 'Ala` bin Abdurrahman] dari [ayahnya], dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda mengenai lonceng: \"Itu adalah seruling syetan.\""},"2129":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنُهِيَ عَنْ رُكُوبِ الْجَلَّالَةِ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abdul Warits], dari [Ayyub], dari [Nafi'] dari [Ibnu Umar], ia berkata; telah dilarang menaiki jallalah (hewan yang makan sesuatu yang najis). "},"2130":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي سُرَيْجٍ الرَّازِيُّ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ الْجَهْمِ حَدَّثَنَا عَمْرٌو يَعْنِي ابْنَ أَبِي قَيْسٍ عَنْ أَيُّوبَ السَّخْتَيَانِيِّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجَلَّالَةِ فِي الْإِبِلِ أَنْ يُرْكَبَ عَلَيْهَا","id":"Telah menceritakan kepada kami [Ahmad bin Abu Suraij Ar Razi], telah mengabarkan kepadaku [Abdullah bin Al Jahm], telah menceritakan kepada kami ['Amr bin Abu Qais] dari [Ayyub As Sakhtiyani], dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah melarang menaiki unta jallalah (yang makan sesuatu yang najis). "},"2131":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ مُعَاذٍ قَالَكُنْتُ رِدْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى حِمَارٍ يُقَالُ لَهُ عُفَيْرٌ","id":"Telah menceritakan kepada kami [Hannad bin As Sari], dari [Abu Al Ajwash] dari [Abu Ishaq], dari ['Amr bin Maimun], dari [Mu'adz], ia berkaa; aku pernah membonceng Rasulullah shallallahu 'alaihi wasallam di atas keledai yang bernama 'Ufair. "},"2132":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ دَاوُدَ بْنِ سُفْيَانَ حَدَّثَنِي يَحْيَى بْنُ حَسَّانَ أَخْبَرَنَا سُلَيْمَانُ بْنُ مُوسَى أَبُو دَاوُدَ حَدَّثَنَا جَعْفَرُ بْنُ سَعْدِ بْنِ سَمُرَةَ بْنِ جُنْدُبٍ حَدَّثَنِي خُبَيْبُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ سُلَيْمَانَ بْنِ سَمُرَةَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍأَمَّا بَعْدُ فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمَّى خَيْلَنَا خَيْلَ اللَّهِ إِذَا فَزِعْنَا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا إِذَا فَزِعْنَا بِالْجَمَاعَةِ وَالصَّبْرِ وَالسَّكِينَةِ وَإِذَا قَاتَلْنَا","id":"Telah menceritakan kepada kami [Muhammad bin Daud bin Sufyan], telah menceritakan kepadaku [Yahya bin Hassan], telah mengabarkan kepada kami [Sulaiman bin Musa Abu Daud], telah menceritakan kepada kami [Ja'far bin Sa'd bin Samurah bin Jundab], telah menceritakan kepadaku [Khubaib bin Sulaiman], dari [ayahnya yaitu Sulaiman bin Samurah] dari [Samurah bin Jundub], adapun selanjutnya, sesungguhnya Nabi shallallahu 'alaihi wasallam telah menamakan kuda kami sebagai kuda Allah apabila kami merasa takut, dan Rasulullah shallallahu wa'alaihi wa sallam memerintahkan kami apabila merasa takut agar berjama'ah, bersabar, dan tenang dan apabila kami berperang. "},"2133":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي سَفَرٍ فَسَمِعَ لَعْنَةً فَقَالَ مَا هَذِهِ قَالُوا هَذِهِ فُلَانَةُ لَعَنَتْ رَاحِلَتَهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَعُوا عَنْهَا فَإِنَّهَا مَلْعُونَةٌ فَوَضَعُوا عَنْهَاقَالَ عِمْرَانُ فَكَأَنِّي أَنْظُرُ إِلَيْهَا نَاقَةٌ وَرْقَاءُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Abu Qilabah], dari [Abu Al Muhallab], dari [Imran bin Hushain] bahwa Nabi shallallahu 'alaihi wasallam pernah berada dalam suatu perjalanan dan mendengar sebuah laknat. Kemudian beliau berkata: \"Apakah ini?\" Mereka berkata; Fulanah telah melaknat kendaraanya. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Turunkan barang-barang darinya, karena sesungguhnya unta tersebut telah ditinggalkan.\" Kemudian mereka menurunkan barang-barang darinya. Imran berkata; sepertinya aku melihatnya, yaitu unta yang berwarna pirang. "},"2134":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَخْبَرَنَا يَحْيَى بْنُ آدَمَ عَنْ قُطْبَةَ بْنِ عَبْدِ الْعَزِيزِ بْنِ سِيَاهٍ عَنْ الْأَعْمَشِ عَنْ أَبِي يَحْيَى الْقَتَّاتِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّحْرِيشِ بَيْنَ الْبَهَائِمِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], telah mengabarkan kepada kami [Yahya bin Adam], dari [Quthbah bin Abdul Aziz bin Siyah] dari [Al A'masy] dari [Abu Yahya Al Qattat], dari [Mujahid] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menyabung hewan. "},"2135":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ زَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَخٍ لِي حِينَ وُلِدَ لِيُحَنِّكَهُ فَإِذَا هُوَ فِي مِرْبَدٍ يَسِمُ غَنَمًا أَحْسَبُهُ قَالَ فِي آذَانِهَا","id":"Telah menceritakan kepada kami [Hafsh bin Umar], telah menceritakan kepada kami [Syu'bah] dari [Hisyam bin Zaid], dari [Anas bin Malik], ia berkata; aku datang kepada Nabi shallallahu 'alaihi wasallam membawa saudaraku ketika telah lahir agar beliau mengunyahkan makanannya (tahannuk), dan ternyata beliau berada di tempat penambatan kambing sedang memberi memberi cap kambing (menggunakan besi panas). Aku kira ia berkata; pada telingnya. "},"2136":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرَّ عَلَيْهِ بِحِمَارٍ قَدْ وُسِمَ فِي وَجْهِهِ فَقَالَ أَمَا بَلَغَكُمْ أَنِّي قَدْ لَعَنْتُ مَنْ وَسَمَ الْبَهِيمَةَ فِي وَجْهِهَا أَوْ ضَرَبَهَا فِي وَجْهِهَا فَنَهَى عَنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam telah lewat dihadapannya seekor keledai yang telah dicap pada wajahnya. Kemudian beliau berkata: \"Bukankah telah sampai kepada kalian bahwa aku telah melaknat orang yang mencap hewan pada wajahnya atau memukul pada wajahnya?\" kemudian beliau melarang hal tersebut. "},"2137":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ ابْنِ زُرَيْرٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَ أُهْدِيَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَغْلَةٌ فَرَكِبَهَا فَقَالَ عَلِيٌّ لَوْ حَمَلْنَا الْحَمِيرَ عَلَى الْخَيْلِ فَكَانَتْ لَنَا مِثْلُ هَذِهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا يَفْعَلُ ذَلِكَ الَّذِينَ لَا يَعْلَمُونَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib], dari [Abu Al Khair], dari [Ibnu Zurair] dari [Ali bin Abu Thalib] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam telah diberi hadiah seekor baghal. Kemudian beliau menaikinya. Lalu Ali berkata; seandainya kita naikkan keledai di atas kuda yang dahulu kita memiliki kebiasaan seperti ini. Rasulullah shallallahu 'alaihi wasallam berkata: \"Sesungguhnya yang melakukan hal tersebut hanyalah orang-orang yang tidak mengetahui.\""},"2138":{"ar":"حَدَّثَنَا أَبُو صَالِحٍ مَحْبُوبُ بْنُ مُوسَى أَخْبَرَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ عَاصِمِ بْنِ سُلَيْمَانَ عَنْ مُوَرِّقٍ يَعْنِي الْعِجْلِيَّ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ جَعْفَرٍ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَدِمَ مِنْ سَفَرٍ اسْتُقْبِلَ بِنَا فَأَيُّنَا اسْتُقْبِلَ أَوَّلًا جَعَلَهُ أَمَامَهُ فَاسْتُقْبِلَ بِي فَحَمَلَنِي أَمَامَهُ ثُمَّ اسْتُقْبِلَ بِحَسَنٍ أَوْ حُسَيْنٍ فَجَعَلَهُ خَلْفَهُ فَدَخَلْنَا الْمَدِينَةَ وَإِنَّا لَكَذَلِكَ","id":"Telah menceritakan kepada kami [Abu Shalih Mahbub bin Musa], telah mengabarkan kepada kami [Abu Ishaq Al Fazari], dari ['Ashim bin Sulaiman], dari [Muwarriq Al 'Ijli], telah menceritakan kepadaku [Abdullah bin Ja'far], ia berkata; Nabi shallallahu 'alaihi wasallam apabila datang dari sebuah perjalanan beliau disambut bersama kami, siapa diantara kami yang disambut terlebih dahulu maka beliau meletakkannya di depan beliau. Kemudian beliau disambut bersamaku, lalu beliau membawaku di hadapannya, kemudian beliau disambut bersama Hasan, atau Husain lalu beliau menempatkannya di belakang beliau. Lalu kami memasuki Madinah dalam keadaan seperti itu. "},"2139":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا ابْنُ عَيَّاشٍ عَنْ يَحْيَى بْنِ أَبِي عَمْرٍو السَّيْبَانِيِّ عَنْ ابْنِ أَبِي مَرْيَمَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِيَّاكُمْ أَنْ تَتَّخِذُوا ظُهُورَ دَوَابِّكُمْ مَنَابِرَ فَإِنَّ اللَّهَ إِنَّمَا سَخَّرَهَا لَكُمْ لِتُبَلِّغَكُمْ إِلَى بَلَدٍ لَمْ تَكُونُوا بَالِغِيهِ إِلَّا بِشِقِّ الْأَنْفُسِ وَجَعَلَ لَكُمْ الْأَرْضَ فَعَلَيْهَا فَاقْضُوا حَاجَتَكُمْ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Najdah], telah menceritakan kepada kami [Ibnu 'Ayyasy], dari [Yahya bin Abu 'Amr As Saibani], dari [Ibnu Abu Maryam], dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Janganlah kalian menjadikan punggung-punggung hewan kalian sebagai mimbar, karena sesungguhnya Allah telah menundukkannya untuk kalian agar dapat menyampaikan kalian ke negeri yang tidak dapat kalian capai kecuali dengan bersusah payah, dan Allah jadikan bumi untuk kalian, maka tunaikanlah hajat kalian di atasnya.\""},"2140":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي يَحْيَى عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ قَالَ قَالَ أَبُو هُرَيْرَةَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَكُونُ إِبِلٌ لِلشَّيَاطِينِ وَبُيُوتٌ لِلشَّيَاطِينِ فَأَمَّا إِبِلُ الشَّيَاطِينِ فَقَدْ رَأَيْتُهَا يَخْرُجُ أَحَدُكُمْ بِجُنَيْبَاتٍ مَعَهُ قَدْ أَسْمَنَهَا فَلَا يَعْلُو بَعِيرًا مِنْهَا وَيَمُرُّ بِأَخِيهِ قَدْ انْقَطَعَ بِهِ فَلَا يَحْمِلُهُ وَأَمَّا بُيُوتُ الشَّيَاطِينِ فَلَمْ أَرَهَاكَانَ سَعِيدٌ يَقُولُ لَا أُرَاهَا إِلَّا هَذِهِ الْأَقْفَاصُ الَّتِي يَسْتُرُ النَّاسُ بِالدِّيبَاجِ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'], telah menceritakan kepada kami [Ibnu Abu Fudaik], telah menceritakan kepadaku [Abdullah bin Abu Yahya], dari [Sa'id bin Abu Hindun], ia berkata; [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Terdapat unta untuk syetan dan rumah untuk syetan, adapun unta syetan sungguh aku telah melihatnya, yaitu: salah seorang diantara kalian keluar dengan membawa unta yang tidak dikendarai yang telah ia gemukkan, lalu ia tidak menaiki satu untapun darinya, ia melewati saudaranya yang telah kehabisan bekal namun ia tidak menaikkannya. Adapun rumah syetan aku belum melihatnya.\" Sa'id berkata; aku belum diperlihatkan kepadanya, kecuali tandu-tandu yang ditutupi orang dengan kain sutera. "},"2141":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَافَرْتُمْ فِي الْخِصْبِ فَأَعْطُوا الْإِبِلَ حَقَّهَا وَإِذَا سَافَرْتُمْ فِي الْجَدْبِ فَأَسْرِعُوا السَّيْرَ فَإِذَا أَرَدْتُمْ التَّعْرِيسَ فَتَنَكَّبُوا عَنْ الطَّرِيقِحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامٌ عَنْ الْحَسَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا قَالَ بَعْدَ قَوْلِهِ حَقَّهَا وَلَا تَعْدُوا الْمَنَازِلَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami [Suhail bin Abu Shalih], dari [ayahnya], dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian bersafar di tempat yang subur maka berilah unta haknya, dan apabila kalian bersafar di tempat yang tandus maka percepatlah jalan. Apabila kalian hendak singgah untuk bermalam maka menjauhlah dari jalan!\" telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Yazid bin Harun], telah mengabarkan kepada kami [Hisyam], dari [Al Hasan] dari [Jabir bin Abdullah] dari Nabi shallallahu 'alaihi wasallam seperti ini. Setelah ucapan \"haknya\" ia mengatakan; dan janganlah kalian melampaui tempat-tempat persinggahan (yang sudah biasa). "},"2142":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا خَالِدُ بْنُ يَزِيدَ حَدَّثَنَا أَبُو جَعْفَرٍ الرَّازِيُّ عَنْ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ بِالدُّلْجَةِ فَإِنَّ الْأَرْضَ تُطْوَى بِاللَّيْلِ","id":"Telah menceritakan kepada kami ['Amr bin Ali], telah menceritakan kepada kami [Khalid bin Yazid], telah menceritakan kepada kami [Abu Ja'far Ar Razi], dari [Ar Rabi' bin Anas], dari [Anas], ia berkata; Rasulullah shallallahu wa'alaihi wa sallam bersabda: \"Hendaknya kalian pergi pada malam hari, karena sesungguhnya bumi diperpendek jaraknya pada malam hari.\""},"2143":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنٍ حَدَّثَنِي أَبِي حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ قَالَ سَمِعْتُ بُرَيْدَةَ يَقُولُبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي جَاءَ رَجُلٌ وَمَعَهُ حِمَارٌ فَقَالَ يَا رَسُولَ اللَّهِ ارْكَبْ وَتَأَخَّرَ الرَّجُلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَنْتَ أَحَقُّ بِصَدْرِ دَابَّتِكَ مِنِّي إِلَّا أَنْ تَجْعَلَهُ لِي قَالَ فَإِنِّي قَدْ جَعَلْتُهُ لَكَ فَرَكِبَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Tsabit Al Marwazi], telah menceritakan kepadaku [Ali bin Husain], telah menceritakan kepadaku [ayahku], telah menceritakan kepadaku [Abdullah bin Buraidah], ia berkata; saya mendengar [Buraidah], berkata; ketika Rasulullah shallallahu 'alaihi wasallam berjalan, terdapat seorang laki-laki yang datang membawa seekor keledai dan berkata; wahai Rasulullah, naiklah! Dan orang tersebut berhenti. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak, engkau lebih berhak terhadap hewan tungganganmu, kecuali engkau memberikannya kepadaku.\" Ia berkata; aku telah memberikannya kepada engkau. Kemudian beliau menaiki keledai tersebut. "},"2144":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي ابْنُ عَبَّادٍ عَنْ أَبِيهِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ قَالَ أَبُو دَاوُد هُوَ يَحْيَى بْن عَبَّادٍ حَدَّثَنِي أَبِي الَّذِي أَرْضَعَنِي وَهُوَ أَحَدُ بَنِي مُرَّةَ بْنِ عَوْفٍ وَكَانَ فِي تِلْكَ الْغَزَاةِ غَزَاةِ مُؤْتَةَ قَالَ وَاللَّهِ لَكَأَنِّي أَنْظُرُ إِلَى جَعْفَرٍ حِينَ اقْتَحَمَ عَنْ فَرَسٍ لَهُ شَقْرَاءَ فَعَقَرَهَا ثُمَّ قَاتَلَ الْقَوْمَ حَتَّى قُتِلَ قَالَ أَبُو دَاوُد هَذَا الْحَدِيثُ لَيْسَ بِالْقَوِيِّ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Muhammad bin Salamah], dari [Muhammad bin Ishaq], telah menceritakan kepadaku [Ibnu 'Abbad], dari [ayahnya yaitu 'Abbad bin Abdullah bin Az Zubair]. Abu Daud berkata; ia adalah Yahya bin 'Abbad, telah menceritakan kepadaku [ayahku] yang isterinya telah menyusuiku, ia adalah salah seorang dari Bani Murrah bin 'Auf, dan hal tersebut pada saat perang Muktah. Ia berkata; demi Allah, sungguh aku telah melihat Ja'far ketika turun dari kudanya yang berwarna blonde lalu ia menyembelihnya kemudian ia berperang melawan musuh hingga terbunuh. Abu Daud berkata; hadits ini tidaklah kuat. "},"2145":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ نَافِعِ بْنِ أَبِي نَافِعٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا سَبَقَ إِلَّا فِي خُفٍّ أَوْ فِي حَافِرٍ أَوْ نَصْلٍ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Nafi'] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada perlombaan kecuali dalam hewan yang bertapak kaki, yang berkuku serta memanah.\""},"2146":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَابَقَ بَيْنَ الْخَيْلِ الَّتِي قَدْ ضُمِّرَتْ مِنْ الْحَفْيَاءِ وَكَانَ أَمَدُهَا ثَنِيَّةَ الْوَدَاعِ وَسَابَقَ بَيْنَ الْخَيْلِ الَّتِي لَمْ تُضَمَّرْ مِنْ الثَّنِيَّةِ إِلَى مَسْجِدِ بَنِي زُرَيْقٍ وَإِنَّ عَبْدَ اللَّهِ كَانَ مِمَّنْ سَابَقَ بِهَا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah], dari [Malik], dari [Nafi'], dari [Abdullah bin Umar], bahwa Rasulullah shallallahu 'alaihi wasallam memperlombakan antara kuda yang telah dipersiapkan untuk berlomba dari Al Hafya`, dan berakhir di Tsaniyah Al Qada`. Dan beliau melombakan kuda yang tidak dipersiapkan untuk berlomba dari Tsaniyah hingga masjid Bani Zuraiq, dan Abdullah adalah temasuk orang yang melombakannya. "},"2147":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا مُعْتَمِرٌ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُضَمِّرُ الْخَيْلَ يُسَابِقُ بِهَا","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Mu'tamir] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam mempersiapkan kuda untuk berlomba. "},"2148":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبَّقَ بَيْنَ الْخَيْلِ وَفَضَّلَ الْقُرَّحَ فِي الْغَايَةِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami ['Uqbah bin Khalid], dari ['Ubaidullah] dari [Nafi'], dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam melombakan antar kuda. Dan beliau lebih memilih kuda yang masuk pada umur lima tahun. "},"2149":{"ar":"حَدَّثَنَا أَبُو صَالِحٍ الْأَنْطَاكِيُّ مَحْبُوبُ بْنُ مُوسَى أَخْبَرَنَا أَبُو إِسْحَقَ يَعْنِي الْفَزَارِيَّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ وَعَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّهَا كَانَتْ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ قَالَتْ فَسَابَقْتُهُ فَسَبَقْتُهُ عَلَى رِجْلَيَّ فَلَمَّا حَمَلْتُ اللَّحْمَ سَابَقْتُهُ فَسَبَقَنِي فَقَالَ هَذِهِ بِتِلْكَ السَّبْقَةِ","id":"Telah menceritakan kepada kami [Abu Shalih Al Anthoki Mahbub bin Musa], telah mengabarkan kepada kami [Al Fazari], dari [Hisyam bin 'Urwah], dari [ayahnya], dan dari [Abu Salamah], dari [Aisyah], radliallahu 'anha, bahwa ia pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, ia berkata; kemudian aku berlomba dengan beliau, lalu aku mendahului beliau dengan berjalan kaki. Kemudian setelah gemuk aku berlomba dengan beliau kemudian beliau mendahuluiku. Beliau berkata: \"Ini menggantikan kekalahan pada perlombaan terdahulu.\""},"2150":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حُصَيْنُ بْنُ نُمَيْرٍ حَدَّثَنَا سُفْيَانُ بْنُ حُسَيْنٍ ح و حَدَّثَنَا عَلِيُّ بْنُ مُسْلِمٍ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ أَخْبَرَنَا سُفْيَانُ بْنُ حُسَيْنٍ الْمَعْنَى عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْخَلَ فَرَسًا بَيْنَ فَرَسَيْنِ يَعْنِي وَهُوَ لَا يُؤْمَنُ أَنْ يَسْبِقَ فَلَيْسَ بِقِمَارٍ وَمَنْ أَدْخَلَ فَرَسًا بَيْنَ فَرَسَيْنِ وَقَدْ أُمِنَ أَنْ يَسْبِقَ فَهُوَ قِمَارٌحَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ سَعِيدِ بْنِ بَشِيرٍ عَنْ الزُّهْرِيِّ بِإِسْنَادِ عَبَّادٍ وَمَعْنَاهُ قَالَ أَبُو دَاوُد رَوَاهُ مَعْمَرٌ وَشُعَيْبٌ وَعَقِيلٌ عَنْ الزُّهْرِيِّ عَنْ رِجَالٍ مِنْ أَهْلِ الْعَلْمِ وَهَذَا أَصَحُّ عِنْدَنَا","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Hushain bin Numair], telah menceritakan kepada kami [Sufyan bin Husain], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ali bin Muslim], telah menceritakan kepada kami ['Abbad bin Al 'Awwam], telah mengabarkan kepada kami [Sufyan bin Husain] secara makna, dari [Az Zuhri], dari [Sa'id bin Al Musayyab], dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang memasukkan kuda diantara dua kuda sementara tidak diyakini kuda tersebut akan menang, maka hal tersebut bukanlah judi, dan barangsiapa yang memasukkan kuda diantara dua kuda dan telah diyakini kuda tersebut akan menang maka hal tersebut adalah judi.\" Telah menceritakan kepada kami [Mahmud bin Khalid], telah menceritakan kepada kami [Al Walid bin Muslim], dari [Sa'id bin Basyir], dari [Az Zuhri], dengan sanad 'Abbad dan maknanya. Abu Daud berkata; hadits tersebut telah diriwayatkan oleh [Ma'mar] serta [Syu'aib], dan ['Uqail] dari [Az Zuhri], dari [beberapa ahli ilmu]. Dan ini lebih shahih menurut kami."},"2151":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا عَنْبَسَةُ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ حُمَيْدٍ الطَّوِيلِ جَمِيعًا عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا جَلَبَ وَلَا جَنَبَ زَادَ يَحْيَى فِي حَدِيثِهِ فِي الرِّهَانِ حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ سَعِيدٍ عَنْ قَتَادَةَ قَالَ الْجَلَبُ وَالْجَنَبُ فِي الرِّهَانِ","id":"Telah menceritakan kepada kami [Yahya bin Khalaf], telah menceritakan kepada kami [Abdul Wahhab bin Abdul Majid], telah menceritakan kepada kami ['Anbasah], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal], dari [Humaid Ath Thawil], seluruhnya dari [Al Hasan] dari [Imran bin Hushain] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada jalab (seseorang meminta orang lain mengikuti kudanya untuk menghardiknya supaya berlari cepat), janab (mengiringkan kuda lain di samping kuda yang digunakan untuk lomba kemudian apabila telah lelah maka ia berpindah kepada kuda yang lain).\" Yahya menambahkan dalam haditsnya; dalam pacuan."},"2152":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ قَالَ كَانَتْ قَبِيعَةُ سَيْفِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِضَّةً","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Jarir bin Hazim], telah menceritakan kepada kami [Qatadah], dari [Anas], ia berkata; gagang pedang Rasulullah shallallahu 'alaihi wasallam adalah perak. "},"2153":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ أَبِي الْحَسَنِ قَالَ كَانَتْ قَبِيعَةُ سَيْفِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِضَّةً قَالَ قَتَادَةُ وَمَا عَلِمْتُ أَحَدًا تَابَعَهُ عَلَى ذَلِكَ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنِي يَحْيَى بْنُ كَثِيرٍ أَبُو غَسَّانَ الْعَنْبَرِيُّ عَنْ عُثْمَانَ بْنِ سَعْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ كَانَتْ فَذَكَرَ مِثْلَهُ قَالَ أَبُو دَاوُد أَقْوَى هَذِهِ الْأَحَادِيثِ حَدِيثُ سَعِيدِ بْنِ أَبِي الْحَسَنِ وَالْبَاقِيَةُ ضِعَافٌ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Mu'adz bin Hisyam], telah menceritakan kepadaku [ayahku], dari [Qatadah], dari [Sa'id bin Abu Al Hasan], ia berkata; gagang pedang Rasulullah shallallahu 'alaihi wasallam adalah perak. Qatadah berkata; aku tidak mengetahui seorangpun yang mengoreksinya dalam hal tersebut. Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepadaku [Yahya bin Katsir Abu Ghassan Al 'Anbari], dari [Utsman bin Sa'd] dari [Anas bin Malik], ia berkata; …… kemudian ia menyebutkan seperti itu. Abu Daud berkata; hadits yang terkuat diantara hadits tersebut adalah hadits Sa'id bin Abu Al Hasan. Dan hadits yang lain adalah lemah."},"2154":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ أَمَرَ رَجُلًا كَانَ يَتَصَدَّقُ بِالنَّبْلِ فِي الْمَسْجِدِ أَنْ لَا يَمُرَّ بِهَا إِلَّا وَهُوَ آخِذٌ بِنُصُولِهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Al Laits], dari [Abu Az Zubair], dari [Jabir], dari Rasulullah shallallahu wa'alaihi wa sallam bahwa beliau telah memerintahkan seorang laki-laki yang telah bersedekah dengan anak panah di Masjid, agar tidak melewatinya kecuali ia memegang mata panahnya. "},"2155":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا مَرَّ أَحَدُكُمْ فِي مَسْجِدِنَا أَوْ فِي سُوقِنَا وَمَعَهُ نَبْلٌ فَلْيُمْسِكْ عَلَى نِصَالِهَا أَوْ قَالَ فَلْيَقْبِضْ كَفَّهُ أَوْ قَالَ فَلْيَقْبِضْ بِكَفِّهِ أَنْ تُصِيبَ أَحَدًا مِنْ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], telah menceritakan kepada kami [Abu Usamah], dari [Buraid], dari [Abu Burdah], dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila salah seorang diantara kalian lewat di masjid kami atau pasar kami dengan membawa anak panah, maka hendaknya ia memegang mata panahnya -atau beliau berkata: \"maka hendaknya ia menggenggam telapak tangannya.\" Atau \"hendaknya ia menggenggam dengan telapak tangannya- agar tidak mengenai seorang muslim.\""},"2156":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُتَعَاطَى السَّيْفُ مَسْلُولًا","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], dari [Abu Az Zubair], dari [Jabir], bahwa Nabi shallallahu 'alaihi wasallam telah melarang menerima pedang dalam keadaan terhunus. "},"2157":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا قُرَيْشُ بْنُ أَنَسٍ حَدَّثَنَا أَشْعَثُ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُقَدَّ السَّيْرُ بَيْنَ إِصْبَعَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Quraisy bin Anas], telah menceritakan kepada kami [Asy'ats] dari [Al Hasan] dari [Samrah bin Jundub], bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang mengerat tali kulit diantara kedua jari. "},"2158":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ قَالَ حَسِبْتُ أَنِّي سَمِعْتُ يَزِيدَ بْنَ خُصَيْفَةَ يَذْكُرُ عَنْ السَّائِبِ بْنِ يَزِيدَ عَنْ رَجُلٍ قَدْ سَمَّاهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ظَاهَرَ يَوْمَ أُحُدٍ بَيْنَ دِرْعَيْنِ أَوْ لَبِسَ دِرْعَيْنِ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Sufyan], ia berkata; aku mendengar [Yazid bin Khushaifah], menyebutkan dari [As Saib bin Yazid], dari [seorang laki-laki] yang telah ia sebutkan namanya, bahwa Rasulullah shallallahu 'alaihi wasallam pada saat perang Uhud nampak memakai dua baju dira` (baju besi), atau memakai dua baju besi. "},"2159":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا ابْنُ أَبِي زَائِدَةَ أَخْبَرَنَا أَبُو يَعْقُوبَ الثَّقَفِيُّ حَدَّثَنِي يُونُسُ بْنُ عُبَيْدٍ مَوْلَى مُحَمَّدِ بْنِ الْقَاسِمِ قَالَ بَعَثَنِي مُحَمَّدُ بْنُ الْقَاسِمِ إِلَى الْبَرَاءِ بْنِ عَازِبٍ يَسْأَلُهُ عَنْ رَايَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا كَانَتْ فَقَالَ كَانَتْ سَوْدَاءَ مُرَبَّعَةً مِنْ نَمِرَةٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi], telah mengabarkan kepada kami [Ibnu Abu Zaidah], telah mengabarkan kepada kami [Abu Ya'qub Ats Tsaqafi], telah menceritakan kepadaku [Yunus bin 'Ubaid] mantan budak Muhammad bin Al Qasim, ia berkata; Muhammad bin Al Qasim telah mengirimku untuk datang kepada [Al Barra` bin 'Azib] agar bertanya kepadanya mengenai bendera Rasulullah shallallahu 'alaihi wasallam. Kemudian ia berkata; bendera beliau berwarna hitam persegi panjang terbuat dari namirah (kain yang bergaris hitam putih yang terbuat dari wol dan sejenisnya). "},"2160":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْمَرْوَزِيُّ وَهُوَ ابْنُ رَاهَوَيْهِ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا شَرِيكٌ عَنْ عَمَّارٍ الدُّهْنِيِّ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ يَرْفَعُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ لِوَاؤُهُ يَوْمَ دَخَلَ مَكَّةَ أَبْيَضَ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Marwazi bin Rahawai], telah menceritakan kepada kami [Yahya bin Adam], telah menceritakan kepada kami [Syarik] dari ['Ammar Ad Duhni], dari [Abu Az Zubair], dari [Jabir], dan ia memarfu'kannya kepada Nabi shallallahu 'alaihi wasallam, bahwa bendera beliau pada saat memasuki Mekkah berwarna putih. "},"2161":{"ar":"حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ حَدَّثَنَا سَلْمُ بْنُ قُتَيْبَةَ الشَّعِيرِيُّ عَنْ شُعْبَةَ عَنْ سِمَاكٍ عَنْ رَجُلٍ مِنْ قَوْمِهِ عَنْ آخَرَ مِنْهُمْ قَالَ رَأَيْتُ رَايَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَفْرَاءَ","id":"Telah menceritakan kepada kami ['Uqbah bin Mukram], telah menceritakan kepada kami [Salm bin Qutaibah Asy Sya'iri], dari [Syu'bah], dari [Simak], dari [seorang laki-laki] dari kaumnya dari (orang lain diantara mereka), ia berkata; aku melihat bendera Rasulullah shallallahu 'alaihi wasallam berwarna kuning. "},"2162":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ الْفَضْلِ الْحَرَّانِيُّ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا ابْنُ جَابِرٍ عَنْ زَيْدِ بْنِ أَرْطَاةَ الْفَزَارِيِّ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ الْحَضْرَمِيِّ أَنَّهُ سَمِعَ أَبَا الدَّرْدَاءِ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ابْغُونِي الضُّعَفَاءَ فَإِنَّمَا تُرْزَقُونَ وَتُنْصَرُونَ بِضُعَفَائِكُمْقَالَ أَبُو دَاوُد زَيْدُ بْنُ أَرْطَاةَ أَخُو عَدِيِّ بْنِ أَرْطَاةَ","id":"Telah menceritakan kepada kami [Muammal bin Al Fadhl Al Harrani], telah menceritakan kepada kami [Al Walid], telah menceritakan kepada kami [Ibnu Jabir], dari [Zaid bin Artha`ah Al Fazari], dari [Jubair bin Nufair Al Hadhrami], bahwa ia mendengar [Abu Ad Darda`] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Carikan orang-orang lemah untukku, sesungguhnya kalian diberi rizki dan diberi kemenangan karena orang-orang lemah kalian.\" Abu Daud berkata; Zaid bin Artha`ah adalah saudara 'Adi bin Artha`ah. "},"2163":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا يَزِيْدُ بْنُ هَارُونَ عَنْ الْحَجَّاجِ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ قَالَكَانَ شِعَارُ الْمُهَاجِرِينَ عَبْدَ اللَّهِ وَشِعَارُ الْأَنْصَارِ عَبْدَ الرَّحْمَنِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Yazid bin Harun], dari [Al Hajjaj] dari [Qatadah], dari [Al Hasan] dari [Samurah bin Jundub], ia berkata; perlambang (tanda yang dikenal oleh para tentara dalam medan perang) orang-orang muhajirin adalah Abdullah, dan perlambang orang-orang anshar adalah Abdurrahman. "},"2164":{"ar":"حَدَّثَنَا هَنَّادٌ عَنْ ابْنِ الْمُبَارَكِ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ عَنْ أَبِيهِ قَالَغَزَوْنَا مَعَ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ زَمَنَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ شِعَارُنَا أَمِتْ أَمِتْ","id":"Telah menceritakan kepada kami [Hannad] dari [Ibnu Al Mubarak] dari [Ikrimah bin 'Ammar], dari [Iyas bin Salamah], dari [ayahnya], ia berkata; kami telah berperang bersama Abu Bakr radliallahu 'anhu pada zaman Nabi shallallahu 'alaihi wasallam, dan slogan kami adalah kata: bunuh, bunuh."},"2165":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ الْمُهَلَّبِ بْنِ أَبِي صُفْرَةَ قَالَ أَخْبَرَنِي مَنْسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنْ بُيِّتُّمْ فَلْيَكُنْ شِعَارُكُمْ حم لَا يُنْصَرُونَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Abu Ishaq], dari [Al Muhallab bin Abu Shufrah], ia berkata; telah mengabarkan kepadaku [orang yang] telah mendengar Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila musuh hendak membunuh kalian pada malam hari, maka hendaknya slogan kalian adalah demi Allah mereka tidak akan diberi kemenangan.\""},"2166":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ عَجْلَانَ حَدَّثَنِي سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَافَرَ قَالَ اللَّهُمَّ أَنْتَ الصَّاحِبُ فِي السَّفَرِ وَالْخَلِيفَةُ فِي الْأَهْلِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ وَعْثَاءِ السَّفَرِ وَكَآبَةِ الْمُنْقَلَبِ وَسُوءِ الْمَنْظَرِ فِي الْأَهْلِ وَالْمَالِ اللَّهُمَّ اطْوِ لَنَا الْأَرْضَ وَهَوِّنْ عَلَيْنَا السَّفَرَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya], telah menceritakan kepada kami [Muhammad bin 'Ajlan], telah menceritakan kepadaku [Sa'id Al Maqburi], dari [Abu Hurairah], ia berkata; Rasulullah shallallahu wa'alaihi wa sallam apabila bersafar beliau mengucapkan: \"ALLAAHUMMA ANTASH SHAAHIBU FISSAFARI WAL KHALIIFATU FIL AHLI, ALLAAHUMMA INNII A'UUDZU BIKA MIN WA'TSAA-ISSAFARI WA KA-AABATIL MUNQALABI WA SUUIL MANZHARI FIL AHLI WAL MAALI. ALLAAHUMMATHWI ANNAL ARDHA WA HAWWIN 'ALAINAS SAFARA\" (Ya Allah, Engkau adalah Teman dalam perjalanan, dan Pengganti di dalam keluarga. Ya Allah, sesungguhnya aku berlindung kepadaMu dari beratnya perjalanan, kesedihan saat kembali, dan keburukan pemandangan dalam keluarga, serta harta. Ya Allah, pendekkanlah jarak bumi, dan mudahkanlah perjalanan bagi kami).\""},"2167":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّ عَلِيًّا الْأَزَدِيَّ أَخْبَرَهُأَنَّ ابْنَ عُمَرَ عَلَّمَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا اسْتَوَى عَلَى بِعِيرِهِ خَارِجًا إِلَى سَفَرٍ كَبَّرَ ثَلَاثًا ثُمَّ قَالَ{ سُبْحَانَ الَّذِي سَخَّرَ لَنَا هَذَا وَمَا كُنَّا لَهُ مُقْرِنِينَ وَإِنَّا إِلَى رَبِّنَا لَمُنْقَلِبُونَ }اللَّهُمَّ إِنِّي أَسْأَلُكَ فِي سَفَرِنَا هَذَا الْبِرَّ وَالتَّقْوَى وَمِنْ الْعَمَلِ مَا تَرْضَى اللَّهُمَّ هَوِّنْ عَلَيْنَا سَفَرَنَا هَذَا اللَّهُمَّ اطْوِ لَنَا الْبُعْدَ اللَّهُمَّ أَنْتَ الصَّاحِبُ فِي السَّفَرِ وَالْخَلِيفَةُ فِي الْأَهْلِ وَالْمَالِ وَإِذَا رَجَعَ قَالَهُنَّ وَزَادَ فِيهِنَّ آيِبُونَ تَائِبُونَ عَابِدُونَ لِرَبِّنَا حَامِدُونَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجُيُوشُهُ إِذَا عَلَوْا الثَّنَايَا كَبَّرُوا وَإِذَا هَبَطُوا سَبَّحُوا فَوُضِعَتْ الصَّلَاةُ عَلَى ذَلِكَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], Telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ibnu Juraij], telah mengabarkan kepadaku [Abu Az Zubair], bahwa [Ali Al Azdi] telah mengabarkan kepadanya bahwa [Ibnu Umar] telah memberitahukan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam apabila telah berada di atas untanya keluar untuk melakukan safar, beliau bertakbir tiga kali, kemudian mengucapkan: SUBHAANALLADZII SAKHKHARA LANAA HAADZAA WA MAA KUNNAA LAHUU MUQRINIIN, WA INNAA ILAA RABBINAA LAMUNQALIBUUN. ALLAAHUMMA HAWWIN 'ALAINAA SAFARANAA HAADZAA, ALLAAHUMMATHWI LANAL BU'DA. ALLAAHUMMA ANTASH SHAAHIBU FIS SAFARI WAL KHALIIATU FIL AHLI WAL MAALI (Maha Suci Dzat yang telah menundukkan untuk kami hewan ini, dan tidaklah kami dapat memaksakannya, dan kepada Tuhan kami niscaya kami akan kembali. Ya Allah, permudahlah bagi kami perjananan ini, dan dekatkanlah jarak yang jauh. Ya Allah, Engkau adalah Teman diperjalanan dan pengganti berada diantara keluarga serta harta kami). Dan apabila kembali beliau mengucapkan hal tersebut ditambah: \"AAYIBUUNA, TAAIBUUNA 'AABIDUUNA LIRABBINAA HAAMIDUUN\" (Kami kembali, kami bertaubat, kami menyembah, dan kepada Tuhan kami, kami memuji). Dan Rasulullah shallallahu 'alaihi wasallam serta para pasukannya apabila menaiki tempat yang tinggi mereka bertakbir dan apabila turun mereka bertasbih, kemudian shalat ditetapkan seperti itu. "},"2168":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ عَبْدِ الْعَزِيزِ بْنِ عُمَرَ عَنْ إِسْمَعِيلَ بْنِ جَرِيرٍ عَنْ قَزَعَةَ قَالَ قَالَ لِي ابْنُ عُمَرَ هَلُمَّ أُوَدِّعْكَ كَمَا وَدَّعَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْتَوْدِعُ اللَّهَ دِينَكَ وَأَمَانَتَكَ وَخَوَاتِيمَ عَمَلِكَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abdullah bin Daud], dari [Abdul Aziz bin Umar], dari [Isma'il bin Jarir], dari [Qaza'ah], ia berkata; [Ibnu Umar] berkata kepadaku; kemarilah aku akan mengantarmu sebagaimana Rasulullah shallallahu wa'alaihi wa sallam mengantarku, kemudian ia mengucapkan; \"ASTAUDI'ULLAAHA DIINAKA WA AMAANATAKA WA KHAWAATIIMA 'AMALIKA\" (Aku titipkan kepada Allah agamamu, amanahmu dan akhir dari amalanmu). "},"2169":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ إِسْحَقَ السَّيْلَحِينِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي جَعْفَرٍ الْخَطْمِيِّ عَنْ مُحَمَّدِ بْنِ كَعْبٍ عَنْ عَبْدِ اللَّهِ الْخَطْمِيِّ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَسْتَوْدِعَ الْجَيْشَ قَالَ أَسْتَوْدِعُ اللَّهَ دِينَكُمْ وَأَمَانَتَكُمْ وَخَوَاتِيمَ أَعْمَالِكُمْ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Yahya bin Ishaq As Sailahini], telah menceritakan kepada kami [Hammad bin Salamah], dari [Abu Ja'far Al Khathmi], dari [Muhammad bin Ka'bin], dari [Abdullah Al Khathmi], ia berkata; Nabi shallallahu 'alaihi wasallam apabila hendak mengantarkan pasukan beliau berkata: \"ASTAUDI'ULLAAHA DIINAKUM WA AMAANATAKUM WA KHAWAATIIMA 'AMALIKUM\" (Aku titipkan kepada Allah agama kalian, amanah dan akhir dari amalan kalian)."},"2170":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا أَبُو إِسْحَقَ الْهَمْدَانِيُّ عَنْ عَلِيِّ بْنِ رَبِيعَةَ قَالَشَهِدْتُ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ وَأُتِيَ بِدَابَّةٍ لِيَرْكَبَهَا فَلَمَّا وَضَعَ رِجْلَهُ فِي الرِّكَابِ قَالَ بِسْمِ اللَّهِ فَلَمَّا اسْتَوَى عَلَى ظَهْرِهَا قَالَ الْحَمْدُ لِلَّهِ ثُمَّ قَالَ{ سُبْحَانَ الَّذِي سَخَّرَ لَنَا هَذَا وَمَا كُنَّا لَهُ مُقْرِنِينَ وَإِنَّا إِلَى رَبِّنَا لَمُنْقَلِبُونَ }ثُمَّ قَالَ الْحَمْدُ لِلَّهِ ثَلَاثَ مَرَّاتٍ ثُمَّ قَالَ اللَّهُ أَكْبَرُ ثَلَاثَ مَرَّاتٍ ثُمَّ قَالَ سُبْحَانَكَ إِنِّي ظَلَمْتُ نَفْسِي فَاغْفِرْ لِي فَإِنَّهُ لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ ثُمَّ ضَحِكَ فَقِيلَ يَا أَمِيرَ الْمُؤْمِنِينَ مِنْ أَيِّ شَيْءٍ ضَحِكْتَ قَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَ كَمَا فَعَلْتُ ثُمَّ ضَحِكَ فَقُلْتُ يَا رَسُولَ اللَّهِ مِنْ أَيِّ شَيْءٍ ضَحِكْتَ قَالَ إِنَّ رَبَّكَ يَعْجَبُ مِنْ عَبْدِهِ إِذَا قَالَ اغْفِرْ لِي ذُنُوبِي يَعْلَمُ أَنَّهُ لَا يَغْفِرُ الذُّنُوبَ غَيْرِي","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu Al Ahwash], telah menceritakan kepada kami [Abu Ishaq Al Hamdani], dari [Ali bin Rabi'ah], ia berkata; aku menyaksikan [Ali] radliallahu 'anhu dan ia telah diberi unta untuk ia naiki, kemudian tatkala ia telah meletakkan kakinya di dalam sanggurdi, ia mengucapkan; BISMILLAAH, dan ketika telah berada di atas punggungnya ia mengucapkan; AlHAMDULILLAAH, kemudian ia mengucapkan; SUBHAANALLADZII SAKHKHARA LANAA HAADZAA WA MAA KUNNAA LAHUU MUQRINIIN, WA INNAA ILAA RABBINAA LAMUNQALIBUUN (Maha Suci Dzat yang telah menundukkan untuk kami hewan ini, dan tidaklah kami dapat memaksakannya, dan kepada Tuhan kami niscaya kami akan kembali). Kemudian ia mengucapkan; AlHAMDULILLAAH tiga kali, WALLAAHU AKBAR tiga kali, SUBHAANAKA INNII ZHALAMTU NAFSII FAGHFIR LII, FAINNAHU LAA YAGHFIRUDZ DZUNUUBA ILLAA ANTA (Maha Suci Engkau, sesungguhnya aku telah menzhalimi diriku maka ampunilah aku. Karena sesungguhnya tidak ada yang dapat mengampuni dosa kecuali engkau). Kemudian ia tertawa. Kemudian ia ditanya; wahai Amirul mukminin, kenapa engkau tertawa? Ia berkata; aku melihat Rasulullah shallallahu 'alaihi wasallam melakukan seperti apa yang aku lakukan kemudian beliau tertawa dan aku katakan; wahai Rasulullah, kenapa engkau tertawa? Beliau bersabda: \"Sesungguhnya Tuhanmu sungguh merasa kagum kepada hambaNya apabila mengucapkan; ya Allah, ampunilah dosa-dosaku! Ia mengetahui bahwa tidak ada yang mengampuni dosa selainKu.\""},"2171":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا بَقِيَّةُ حَدَّثَنِي صَفْوَانُ حَدَّثَنِي شُرَيْحُ بْنُ عُبَيْدٍ عَنْ الزُّبَيْرِ بْنِ الْوَلِيدِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَافَرَ فَأَقْبَلَ اللَّيْلُ قَالَ يَا أَرْضُ رَبِّي وَرَبُّكِ اللَّهُ أَعُوذُ بِاللَّهِ مِنْ شَرِّكِ وَشَرِّ مَا فِيكِ وَشَرِّ مَا خُلِقَ فِيكِ وَمِنْ شَرِّ مَا يَدِبُّ عَلَيْكِ وَأَعُوذُ بِاللَّهِ مِنْ أَسَدٍ وَأَسْوَدَ وَمِنْ الْحَيَّةِ وَالْعَقْرَبِ وَمِنْ سَاكِنِ الْبَلَدِ وَمِنْ وَالِدٍ وَمَا وَلَدَ","id":"Telah menceritakan kepada kami ['Amr bin Utsman], telah menceritakan kepada kami [Baqiyyah], telah menceritakan kepadaku [Shafwan], telah menceritakan kepadaku [Syuraih bin 'Ubaid], dari [Az Zubair bin Al Walid] dari [Abdullah bin Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam apabila bersafar kemudian datang waktu malam, beliau berkata: \"YAA ARDHU, RABBII WA RABBUKALLAAH, A'UUDZU BILLAAHI MIN SYARIIKI WA SYARRI MAA FIIKI WA SYARRI MAA KHULIQA FIIKI, WA MIN SYARRI MAA YADIBBU 'ALAIKI, WA A'UUDZU BILLAAHI MIN ASADIN WA ASWAD, WA MINAL HAYYATI WAL 'AQRAB, WA MIN SAAKINIL BALADI WA MIN WAALIDIN WA MAA WALAD.\" (Wahai bumi, Tuhanku dan Tuhanmu adalah Allah, aku berlindung kepada Allah dari keburukanmu dan keburukan yang ada padamu, dan keburukan apa yang diciptakan padamu, dari keburukan apa yang merayap di atasmu. Dan aku berlindung kepada Allah dari Singa, dan sesuatu yang hitam, dari ular dan kalajengking, dan dari penghuni negeri serta dari orang yang melahirkan serta apa yang ia lahirkan). "},"2172":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ الْحَرَّانِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُرْسِلُوا فَوَاشِيَكُمْ إِذَا غَابَتْ الشَّمْسُ حَتَّى تَذْهَبَ فَحْمَةُ الْعِشَاءِ فَإِنَّ الشَّيَاطِينَ تَعِيثُ إِذَا غَابَتْ الشَّمْسُ حَتَّى تَذْهَبَ فَحْمَةُ الْعِشَاءِقَالَ أَبُو دَاوُد الْفَوَاشِي مَا يَفْشُو مِنْ كُلِّ شَيْءٍ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Syu'aib Al Harrani], telah menceritakan kepada kami [Zuhair?], telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian lepaskan ternak kalian yang tersebar apabila matahari telah tenggelam hingga hilang kegelapan malam sebelum 'Isyak, karena sesungguhnya syetan membuat kerusakan apabila matahari telah tenggelam hingga hilang kegelapan malam sebelum 'Isyak.\" Abu Daud berkata; fawasyi adalah segala sesuatu yang tersebar. "},"2173":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ كَعْبِ بْنِ مَالِكٍ قَالَقَلَّمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ فِي سَفَرٍ إِلَّا يَوْمَ الْخَمِيسِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Yunus bin Yazid?], dari [Zuhri] dari [Abdurrahman bin Ka'b bin bin Malik], dari [Ka'b bin Malik], ia berkata; seringkali Rasulullah shallallahu 'alaihi wasallam melakukan safar pada hari Kamis. "},"2174":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا يَعْلَى بْنُ عَطَاءٍ حَدَّثَنَا عُمَارَةُ بْنُ حَدِيدٍ عَنْ صَخْرٍ الْغَامِدِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ بَارِكْ لِأُمَّتِي فِي بُكُورِهَا وَكَانَ إِذَا بَعَثَ سَرِيَّةً أَوْ جَيْشًا بَعَثَهُمْ مِنْ أَوَّلِ النَّهَارِ وَكَانَ صَخْرٌ رَجُلًا تَاجِرًا وَكَانَ يَبْعَثُ تِجَارَتَهُ مِنْ أَوَّلِ النَّهَارِ فَأَثْرَى وَكَثُرَ مَالُهُقَالَ أَبُو دَاوُد وَهُوَ صَخْرُ بْنُ وَدَاعَةَ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur?], telah menceritakan kepada kami [Husyaim], telah menceritakan kepada kami [Ya'la bin 'Atho`], telah menceritakan kepada kami ['Umarah bin Hadid], dari [Shakhr Al Ghamidi], dari Nabi shallallahu 'alaihi wasallam, beliau mengucapkan: \"ALLAAHUMMA BAARIK LI UMMATII FII BUKUURIHAA (Ya Allah, berkahilah umatku di pagi hari mereka). Dan beliau apabila mengirim expedisi atau pasukan beliau mengirim mereka di awal siang. Dan Shakhr adalah seorang pedagang dan ia mengirim perdagangannya di awal siang, maka hartanya bertambah banyak. Abu Daud berkata; ia adalah Shakhr bin Wada'ah. "},"2175":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حَرْمَلَةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّاكِبُ شَيْطَانٌ وَالرَّاكِبَانِ شَيْطَانَانِ وَالثَّلَاثَةُ رَكْبٌ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik] dari [Abdurrahman bin Harmalah], dari ['Amr bin Syu'aib] dari [ayahnya], dari [kakeknya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang pergi sendirian seperti dua syetan, dua orang seperti dua syetan dan tiga orang lebih terjaga dari syetan.\""},"2176":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرِ بْنِ بَرِّيٍّ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ حَدَّثَنَا مُحَمَّدُ بْنُ عَجْلَانَ عَنْ نَافِعٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا خَرَجَ ثَلَاثَةٌ فِي سَفَرٍ فَلْيُؤَمِّرُوا أَحَدَهُمْ","id":"Telah menceritakan kepada kami [Ali bin Bahr bin Barri], Telah menceritakan kepada kami [Hatim bin Isma'il], telah menceritakan kepada kami [Muhammad bin 'Ajlan], dari [Nafi'], dari [Abu Salamah], dari [Abu Sa'id Al Khudri], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila ada tiga orang yang keluar dalam suatu perjalanan, maka hendaknya mereka menunjuk salah seorang dari mereka sebagai pemimpin!\""},"2177":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ حَدَّثَنَا مُحَمَّدُ بْنُ عَجْلَانَ عَنْ نَافِعٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ ثَلَاثَةٌ فِي سَفَرٍ فَلْيُؤَمِّرُوا أَحَدَهُمْقَالَ نَافِعٌ فَقُلْنَا لِأَبِي سَلَمَةَ فَأَنْتَ أَمِيرُنَا","id":"Telah menceritakan kepada kami [Ali bin Bahr], telah menceritakan kepada kami [Hatim bin Isma'il], telah menceritakan kepada kami [Muhammad bin 'Ajlan], dari [Nafi'], dari [Abu Salamah], dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila terdapat tiga orang dalam sebuah perjalanan, maka hendaknya mereka menunjuk salah seorang dari mereka sebagai pemimpin.\" Nafi' berkata; kemudian kami katakan kepada Abu Salamah; maka engkau adalah pemimpin kami. "},"2178":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُسَافَرَ بِالْقُرْآنِ إِلَى أَرْضِ الْعَدُوِّقَالَ مَالِكٌ أُرَاهُ مَخَافَةَ أَنْ يَنَالَهُ الْعَدُوُّ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik], dari [Nafi'], bahwa [Abdullah bin Umar] berkata; Rasulullah shallallahu 'alaihi wasallam melarang bersafar membawa Al Qur'an ke negeri musuh. Malik berkata; aku melihat hal tersebut karena dikhawatirkan Al Qur'an tersebut diambil oleh musuh. "},"2179":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ أَبُو خَيْثَمَةَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ الصَّحَابَةِ أَرْبَعَةٌ وَخَيْرُ السَّرَايَا أَرْبَعُ مِائَةٍ وَخَيْرُ الْجُيُوشِ أَرْبَعَةُ آلَافٍ وَلَنْ يُغْلَبَ اثْنَا عَشَرَ أَلْفًا مِنْ قِلَّةٍقَالَ أَبُو دَاوُد وَالصَّحِيحُ أَنَّهُ مُرْسَلٌ","id":"Telah menceritakan kepada kami [Zuhair bin Harb Abu Khaitsamah], telah menceritakan kepada kami [Wahb bin Jarir], telah menceritakan kepada kami [ayahku], ia berkata; saya mendengar [Yunus] dari [Az Zuhri], dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau berkata; sebaik-baik sahabat yang berjumlah empat orang, dan sebaik-baik satuan militer berjumlah seratus orang dan sebaik-baik pasukan berjumlah empat ribu. Dan tidak akan terkalahkan jumlah dua belas ribu karena sedikitnya jumlah. Abu Daud berkata; yang benar bahwa hadits tersebut adalah hadits mursal. "},"2180":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَعَثَ أَمِيرًا عَلَى سَرِيَّةٍ أَوْ جَيْشٍ أَوْصَاهُ بِتَقْوَى اللَّهِ فِي خَاصَّةِ نَفْسِهِ وَبِمَنْ مَعَهُ مِنْ الْمُسْلِمِينَ خَيْرًا وَقَالَ إِذَا لَقِيتَ عَدُوَّكَ مِنْ الْمُشْرِكِينَ فَادْعُهُمْ إِلَى إِحْدَى ثَلَاثِ خِصَالٍ أَوْ خِلَالٍ فَأَيَّتُهَا أَجَابُوكَ إِلَيْهَا فَاقْبَلْ مِنْهُمْ وَكُفَّ عَنْهُمْ ادْعُهُمْ إِلَى الْإِسْلَامِ فَإِنْ أَجَابُوكَ فَاقْبَلْ مِنْهُمْ وَكُفَّ عَنْهُمْ ثُمَّ ادْعُهُمْ إِلَى التَّحَوُّلِ مِنْ دَارِهِمْ إِلَى دَارِ الْمُهَاجِرِينَ وَأَعْلِمْهُمْ أَنَّهُمْ إِنْ فَعَلُوا ذَلِكَ أَنَّ لَهُمْ مَا لِلْمُهَاجِرِينَ وَأَنَّ عَلَيْهِمْ مَا عَلَى الْمُهَاجِرِينَ فَإِنْ أَبَوْا وَاخْتَارُوا دَارَهُمْ فَأَعْلِمْهُمْ أَنَّهُمْ يَكُونُونَ كَأَعْرَابِ الْمُسْلِمِينَ يُجْرَى عَلَيْهِمْ حُكْمُ اللَّهِ الَّذِي يَجْرِي عَلَى الْمُؤْمِنِينَ وَلَا يَكُونُ لَهُمْ فِي الْفَيْءِ وَالْغَنِيمَةِ نَصِيبٌ إِلَّا أَنْ يُجَاهِدُوا مَعَ الْمُسْلِمِينَ فَإِنْ هُمْ أَبَوْا فَادْعُهُمْ إِلَى إِعْطَاءِ الْجِزْيَةِ فَإِنْ أَجَابُوا فَاقْبَلْ مِنْهُمْ وَكُفَّ عَنْهُمْ فَإِنْ أَبَوْا فَاسْتَعِنْ بِاللَّهِ تَعَالَى وَقَاتِلْهُمْ وَإِذَا حَاصَرْتَ أَهْلَ حِصْنٍ فَأَرَادُوكَ أَنْ تُنْزِلَهُمْ عَلَى حُكْمِ اللَّهِ تَعَالَى فَلَا تُنْزِلْهُمْ فَإِنَّكُمْ لَا تَدْرُونَ مَا يَحْكُمُ اللَّهُ فِيهِمْ وَلَكِنْ أَنْزِلُوهُمْ عَلَى حُكْمِكُمْ ثُمَّ اقْضُوا فِيهِمْ بَعْدُ مَا شِئْتُمْقَالَ سُفْيَانُ بْنُ عُيَيْنَةَ قَالَ عَلْقَمَةُ فَذَكَرْتُ هَذَا الْحَدِيثَ لِمُقَاتِلِ بْنِ حَيَّانَ فَقَالَ حَدَّثَنِي مُسْلِمٌ قَالَ قَالَ أَبُو دَاوُد هُوَ ابْنُ هَيْصَمٍ عَنْ النُّعْمَانِ بْنِ مُقَرِّنٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ حَدِيثِ سُلَيْمَانَ بْنِ بُرَيْدَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari], telah menceritakan kepada kami [Waki'] dari [Sufyan] dari ['Alqamah bin Murtsad] dari [Sulaiman bin Buraidah], dari [ayahnya], ia berkata; Rasulullah shallallahu wa'alaihi wa sallam apabila mengutus seorang pemimpin dalam sebuah satuan militer atau sebuah pasukan maka beliau berwasiat kepadanya agar bertakwa kepada Allah pada dirinya secara khusus dan berbuat baik kepada orang-orang muslim yang bersamanya. Dan beliau berkata: \"Apabila engkau bertemu musuhmu dari kalangan orang-orang musyrik maka ajaklah ia kepada salah satu tiga perkara; apapun diantara ketiga perkara tersebut yang mereka penuhi untuk dilakukan maka terimalah dari mereka, dan tahanlah diri dari menyerang mereka, kemudian ajaklah mereka kepada Islam. Apabila mereka memenuhi seruanmu maka terimalah dari mereka dan tahanlah diri dari menyerang mereka, kemudian ajaklah mereka agar berpindah dari negeri mereka menuju negeri muhajirin, dan beritahukan kepada mereka apabila mereka melakukan hal tersebut maka bagi mereka apa yang menjadi hak orang-orang muhajirin dan kewajiban mereka adalah yang menjadi kewajiban orang-orang muhajirin. Kemudian apabila mereka menolak dan memilih negeri mereka maka beritahukan kepada mereka bahwa mereka seperti orang-orang badui muslim yang diberlakukan atas mereka hukum Allah sebagaimana yang berlaku terhadap orang-orang mukmin dan mereka tidak memiliki bagian fai` dan rampasan perang kecuali mereka berjihad bersama orang-orang muslim. Dan apabila mereka menolak untuk masuk Islam maka mintalah mereka untuk memberikan Jizyah dan apabila mereka melakukan hal tersebut maka terimalah dari mereka dan jangan menyerang mereka, kemudian apabila mereka menolak maka mintalah pertolongan kepada Allah dan perangilah mereka. Dan apabila engkau mengepung penghuni sebuah benteng kemudian mereka ingin agar engkau menempatkan mereka di atas hukum Allah ta'ala, maka janganlah engkau menempatkan mereka. Karena sesungguhnya engkau tidak mengetahui apa yang Allah putuskan terhadap mereka. Akan tetapi tempatkanlah di atas hukummu! Kemudian berilah keputusan terhadap mereka setelah itu sesuai apa yang engkau kehendaki.\" Sufyan bin 'Uyainah berkata; ['Alqamah] berkata; kemudian aku menceritakan hadits ini kepada [Muqatil bin Hayyan] lalu ia berkata; telah menceritakan kepadaku [Muslim] dari [An Nu'man bin Muqarrin] dari Nabi shallallahu 'alaihi wasallam seperti hadits Sulaiman bin Buraidah. "},"2181":{"ar":"حَدَّثَنَا أَبُو صَالِحٍ الْأَنْطَاكِيُّ مَحْبُوبُ بْنُ مُوسَى أَخْبَرَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اغْزُوا بِاسْمِ اللَّهِ وَفِي سَبِيلِ اللَّهِ وَقَاتِلُوا مَنْ كَفَرَ بِاللَّهِ اغْزُوا وَلَا تَغْدِرُوا وَلَا تَغُلُّوا وَلَا تُمَثِّلُوا وَلَا تَقْتُلُوا وَلِيدًا","id":"Telah menceritakan kepada kami [Abu Shalih Al Anthoki Mahbub bin Musa], telah mengabarkan kepada kami [Abu Ishaq Al Fazari], dari [Sufyan] dari ['Alqamah bin Martsad], dari [Sulaiman bin Buraidah], dari [ayahnya], bahwa Nabi shallallahu 'alaihi wasallam bersabda; \"Berperanglah dengan nama Allah, di jalan Allah, dan perangilah orang yang kafir kepada Allah! Berperanglah, janganlah mundur, jangan mengkhianati (dalam pembagian ghanimah), dan janganlah kalian mencincang (memotong anggota tubuh), serta jangan kalian bunuh anak kecil!\""},"2182":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ وَعُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ حَسَنِ بْنِ صَالِحٍ عَنْ خَالِدِ بْنِ الْفِزْرِ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ انْطَلِقُوا بِاسْمِ اللَّهِ وَبِاللَّهِ وَعَلَى مِلَّةِ رَسُولِ اللَّهِ وَلَا تَقْتُلُوا شَيْخًا فَانِيًا وَلَا طِفْلًا وَلَا صَغِيرًا وَلَا امْرَأَةً وَلَا تَغُلُّوا وَضُمُّوا غَنَائِمَكُمْ وَأَصْلِحُوا وَأَحْسِنُوا إِنَّ اللَّهَ يُحِبُّ الْمُح��سِنِينَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Yahya bin Adam], serta ['Ubaidullah bin Musa] dari [Hasan bin Shalih] dari [Khalid bin Al Fizr], telah menceritakan kepadaku [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pergilah dengan nama Allah, di atas agama Rasulullah, dan janganlah membunuh orang tua, anak kecil, dan wanita. Dan janganlah berkhianat (dalam pembagian ghanimah), dan kumpulkanlah rampasan perang kalian. Ciptakan perdamaian dan berbuatlah kebaikan, sesungguhnya Allah mencintai orang-orang yang berbuat kebaikan.\""},"2183":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ البُوَيْرَةُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id?], telah menceritakan kepada kami [Al Laits], dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam telah membakar pohon kurma milik Bani Nadhir, dan memotong pohon, yaitu di Buwairah. Kemudian Allah 'azza wajalla menurunkan ayat: \"Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) ……..\""},"2184":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ ابْنِ الْمُبَارَكِ عَنْ صَالِحِ بْنِ أَبِي الْأَخْضَرِ عَنْ الزُّهْرِيِّ قَالَ عُرْوَةُ فَحَدَّثَنِي أُسَامَةُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عَهِدَ إِلَيْهِ فَقَالَ أَغِرْ عَلَى أُبْنَى صَبَاحًا وَحَرِّقْ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَمْرٍو الْغَزِّيُّ سَمِعْتُ أَبَا مُسْهِرٍ قِيلَ لَهُ أُبْنَى قَالَ نَحْنُ أَعْلَمُ هِيَ يُبْنَى فِلَسْطِينَ","id":"Telah menceritakan kepada kami [Hannad bin As Sarri], dari [Ibnu Al Mubarak] dari [Shalih bin Abu Al Akhdhar], dari [Az Zuhri], ['Urwah] berkata; telah menceritakan kepadaku [Usamah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah berwasiat kepadanya, beliau berkata: \"Seranglah Ubna (tempat di Palestina antara Ramlah dan 'Asqalan) pada pagi hari dan bakarlah tanaman mereka!\""},"2185":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَ بَعَثَ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُسْبَسَةَ عَيْنًا يَنْظُرُ مَا صَنَعَتْ عِيرُ أَبِي سُفْيَانَ","id":"Telah menceritakan kepada kami [Harun bin Abdullah], telah menceritakan kepada kami [Hasyim bin Al Qasim], telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Anas], ia berkata; Nabi shallallahu 'alaihi wasallam mengirim Busbasah sebagai mata-mata untuk melihat apa yang dilakukan kafilah Abu Sufyan. "},"2186":{"ar":"حَدَّثَنَا عَيَّاشُ بْنُ الْوَلِيدِ الرَّقَّامُ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَتَى أَحَدُكُمْ عَلَى مَاشِيَةٍ فَإِنْ كَانَ فِيهَا صَاحِبُهَا فَلْيَسْتَأْذِنْهُ فَإِنْ أَذِنَ لَهُ فَلْيَحْتَلِبْ وَلْيَشْرَبْ فَإِنْ لَمْ يَكُنْ فِيهَا فَلْيُصَوِّتْ ثَلَاثًا فَإِنْ أَجَابَهُ فَلْيَسْتَأْذِنْهُ وَإِلَّا فَلْيَحْتَلِبْ وَلْيَشْرَبْ وَلَا يَحْمِلْ","id":"Telah menceritakan kepada kami ['Ayyasy bin Al Walid Ar Raqqam], telah menceritakan kepada kami [Abdul A'la], telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang diantara kalian datang kepada hewan ternak, apabila ada pemiliknya maka hendaknya ia meminta izin kepadanya, apabila ia mengizinkannya maka silahkan ia memeras susunya dan minum. Dan jika tidak ada pemiliknya maka hendaknya ia memanggil (pemiliknya) tiga kali, jika ia menjawabnya maka hendaknya ia meminta izin, jika tidak maka hendaknya ia memerah, minum dan tidak membawanya.\""},"2187":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ عَبَّادِ بْنِ شُرَحْبِيلَ قَالَ أَصَابَتْنِي سَنَةٌ فَدَخَلْتُ حَائِطًا مِنْ حِيطَانِ الْمَدِينَةِ فَفَرَكْتُ سُنْبُلًا فَأَكَلْتُ وَحَمَلْتُ فِي ثَوْبِي فَجَاءَ صَاحِبُهُ فَضَرَبَنِي وَأَخَذَ ثَوْبِي فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ مَا عَلَّمْتَ إِذْ كَانَ جَاهِلًا وَلَا أَطْعَمْتَ إِذْ كَانَ جَائِعًا أَوْ قَالَ سَاغِبًا وَأَمَرَهُ فَرَدَّ عَلَيَّ ثَوْبِي وَأَعْطَانِي وَسْقًا أَوْ نِصْفَ وَسْقٍ مِنْ طَعَامٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ أَبِي بِشْرٍ قَالَ سَمِعْتُ عَبَّادَ بْنَ شُرَحْبِيلَ رَجُلًا مِنَّا مِنْ بَنِي غُبَرَ بِمَعْنَاهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari ['Abbad bin Syurahbil], ia berkata; aku mengalami kelaparan, kemudian aku memasuki kebun Madinah, lalu aku memencet bulir lalu memakannya, dan aku membawa dalam bajuku. Kemudian pemilik kebun tersebut datang dan memukulku, serta mengambil bajuku. Kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau berkata kepadanya: \"Engkau tidak mengajarinya tatkala ia tidak mengetahui, dan engkau tidak memberinya makan tatkala ia lapar.\" Atau beliau berkata; saghiban (kelaparan). Beliau memerintahkan agar ia memberiku kurma dan mengembalikan pakaianku. Ia memberiku satu wasaq atau setengah wasaq makanan. Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Muhammad bin Ja'far], dari [Syu'bah], dari [Abu Bisyr] ia berkata; aku mendengar ['Abbad bin Syurahbil] yaitu seorang laki-laki dari Bani Ghubar dengan maknanya."},"2188":{"ar":"حَدَّثَنَا عُثْمَانُ وَأَبُو بَكْرٍ ابْنَا أَبِي شَيْبَةَ وَهَذَا لَفْظُ أَبِي بَكْرٍ عَنْ مُعْتَمِرِ بْنِ سُلَيْمَانَ قَالَ سَمِعْتُ ابْنَ أَبِي حَكَمٍ الْغِفَارِيَّ يَقُولُ حَدَّثَتْنِي جَدَّتِي عَنْ عَمِّ أَبِي رَافِعِ بْنِ عَمْرٍو الْغِفَارِيِّ قَالَ كُنْتُ غُلَامًا أَرْمِي نَخْلَ الْأَنْصَارِ فَأُتِيَ بِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا غُلَامُ لِمَ تَرْمِي النَّخْلَ قَالَ آكُلُ قَالَ فَلَا تَرْمِ النَّخْلَ وَكُلْ مِمَّا يَسْقُطُ فِي أَسْفَلِهَا ثُمَّ مَسَحَ رَأْسَهُ فَقَالَ اللَّهُمَّ أَشْبِعْ بَطْنَهُ","id":"Telah menceritakan kepada kami [Utsman] dan [Abu Bakr] keduanya adalah anak Abu Syaibah, dan ini adalah lafazh Abu Bakr, dari [Mu'tamir bin Sulaiman], ia berkata; saya mendengar [Ibnu Abu Hakam Al Ghifari], ia berkata; telah menceritakan kepadaku [nenekku], dari [paman Abu Rafi' bin 'Amr Al Ghifari], ia berkata; dahulu aku adalah anak kecil yang melempari pohon kurma milik orang-orang anshar, kemudian aku dihadapkan kepada Nabi shallallahu 'alaihi wasallam. Lalu beliau berkata: \"Wahai anak kecil, kenapa engkau melempari pohon kurma?\" aku katakan; aku makan, beliau berkata; Jangan engkau melempari pohon kurma, makanlah yang terjatuh di bawahnya!\" kemudian beliau mengusap kepala anak tersebut dan mengatakan: \"Ya Allah, kenyangkanlah perutnya!\""},"2189":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحْلِبَنَّ أَحَدٌ مَاشِيَةَ أَحَدٍ بِغَيْرِ إِذْنِهِ أَيُحِبُّ أَحَدُكُمْ أَنْ تُؤْتَى مَشْرَبَتُهُ فَتُكْسَرَ خِزَانَتُهُ فَيُنْتَثَلَ طَعَامُهُ فَإِنَّمَا تَخْزُنُ لَهُمْ ضُرُوعُ مَوَاشِيهِمْ أَطْعِمَتَهُمْ فَلَا يَحْلِبَنَّ أَحَدٌ مَاشِيَةَ أَحَدٍ إِلَّا بِإِذْنِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah], dari [Malik] dari [Nafi'], dari [Abdullah bin Umar], bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Janganlah seseorang memerah hewan ternak seseorang tanpa seizinnya. Apakah salah seorang diantara kalian ingin kamarnya yang tinggi didatangi kemudian tempat penyimpanan makanannya dipecah, dan makanannya diambil? Sesungguhnya yang menyimpan makanan untuk mereka adalah kantong-kantong susu hewan ternak mereka. Janganlah salah seorang diantara kalian memerah susu hewan ternak seseorang kecuali dengan seizinnya.\""},"2190":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ{ يَا أَيُّهَا الَّذِينَ آمَنُوا أَطِيعُوا اللَّهَ وَأَطِيعُوا الرَّسُولَ وَأُولِي الْأَمْرِ مِنْكُمْ }فِي عَبْدِ اللَّهِ بْنِ قَيْسِ بْنِ عَدِيٍّ بَعَثَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍأَخْبَرَنِيهِ يَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Zuhair bin Harb], telah menceritakan kepada kami [Hajjaj], ia berkata; [Ibnu Juraij] berkata; firman Allah: \"Wahai orang-orang yang beriman, taatilah Allah dan taatilah rasul, serta pemimpin kalian\" adalah mengenai Abdullah bin Qais bin 'Adi, Nabi shallallahu 'alaihi wasallam telah mengirimnya bersama dengan sebuah satuan militer. Telah mengabarkan kepadaku [Ya'la] dari [Sa'id bin Jubair], dari [Ibnu Abbas]. "},"2191":{"ar":"حَدَّثَنَا عَمْرُو بْنُ مَرْزُوقٍ أَخْبَرَنَا شُعْبَةُ عَنْ زُبَيْدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ جَيْشًا وَأَمَّرَ عَلَيْهِمْ رَجُلًا وَأَمَرَهُمْ أَنْ يَسْمَعُوا لَهُ وَيُطِيعُوا فَأَجَّجَ نَارًا وَأَمَرَهُمْ أَنْ يَقْتَحِمُوا فِيهَا فَأَبَى قَوْمٌ أَنْ يَدْخُلُوهَا وَقَالُوا إِنَّمَا فَرَرْنَا مِنْ النَّارِ وَأَرَادَ قَوْمٌ أَنْ يَدْخُلُوهَا فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَوْ دَخَلُوهَا أَوْ دَخَلُوا فِيهَا لَمْ يَزَالُوا فِيهَا وَقَالَ لَا طَاعَةَ فِي مَعْصِيَةِ اللَّهِ إِنَّمَا الطَّاعَةُ فِي الْمَعْرُوفِ","id":"Telah menceritakan kepada kami ['Amr bin Marzuq], telah mengabarkan kepada kami [Syu'bah] dari [Zubaid], dari [Sa'd bin 'Ubaidah], dari [Abu Abdurrahman As Sulami], dari [Ali] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam telah mengirim pasukan dan mengangkat seseorang sebagai pemimpin atas mereka, dan beliau memerintahkan mereka agar mendengar dan mentaati. Kemudian orang tersebut menyalakan api dan memerihtahkan mereka agar masuk dalam api tersebut. Kemudian mereka berkata; sesungguhnya kita lari darinya. Dan orang yang lainnya hendak memasukinya. Kemudian hal tersebut sampai kepada Nabi shallallahu 'alaihi wasallam, lalu beliau berkata: \"Seandainya mereka memasukinya atau masuk padanya maka mereka akan tetap ada padanya.\" Kemudian beliau bersabda: \"Tidak ada ketaatan dalam bermaksiat kepada Allah. Sesungguhnya ketaatan hanya ada dalam perkara yang baik.\""},"2192":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ السَّمْعُ وَالطَّاعَةُ عَلَى الْمَرْءِ الْمُسْلِمِ فِيمَا أَحَبَّ وَكَرِهَ مَا لَمْ يُؤْمَرْ بِمَعْصِيَةٍ فَإِذَا أُمِرَ بِمَعْصِيَةٍ فَلَا سَمْعَ وَلَا طَاعَةَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya] dan ['Ubaidullah], telah menceritakan kepadaku [Nafi'], dari [Abdullah] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Kewajiban seorang muslim adalah mendengar dan mentaati dalam perkara yang ia senangi maupun ia benci, selama ia tidak diperintahkan untuk bermaksiat. Apabila ia diperintakan untuk bermaksiat, maka tidak boleh mendengar dan mentaati.\""},"2193":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ عَنْ بِشْرِ بْنِ عَاصِمٍ عَنْ عُقْبَةَ بْنِ مَالِكٍ مِنْ رَهْطِهِ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً فَسَلَحْتُ رَجُلًا مِنْهُمْ سَيْفًا فَلَمَّا رَجَعَ قَالَ لَوْ رَأَيْتَ مَا لَامَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَال�� أَعَجَزْتُمْ إِذْ بَعَثْتُ رَجُلًا مِنْكُمْ فَلَمْ يَمْضِ لِأَمْرِي أَنْ تَجْعَلُوا مَكَانَهُ مَنْ يَمْضِي لِأَمْرِي","id":"Telah menceritakan kepada kami [Yahya bin Ma'in], telah menceritakan kepada kami [Abdushshamad bin Abdul Warits], telah menceritakan kepada kami [Sulaiman bin Al Mughirah], telah menceritakan kepada kami [Humaid bin Hilal], dari [Bisyr bin 'Ashim] dari ['Uqbah bin Malik] dari keluarganya, ia berkata; Nabi shallallahu 'alaihi wasallam telah mengirim satuan pasukan kemudian aku mempersenjatai seseorang diantara mereka dengan pedang, kemudian tatkala kembali ia berkata; seandainya engkau melihat celaan Rasulullah shallallahu 'alaihi wasallam kepada kita, beliau berkata: \"Apakah kalian mampu ketika aku mengirim seseorang (sebagai utusan) diantara kalian kemudian ia tidak menunaikan perintahku, lalu kalian menjadikannya sebagai orang yang menunaikan perintahku?\""},"2194":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ الْحِمْصِيُّ وَيَزِيدُ بْنُ قُبَيْسٍ مِنْ أَهْلِ جَبَلَةَ سَاحِلِ حِمْصَ وَهَذَا لَفْظُ يَزِيدَ قَالَا حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ عَبْدِ اللَّهِ بْنِ الْعَلَاءِ أَنَّهُ سَمِعَ مُسْلِمَ بْنَ مِشْكَمٍ أَبَا عُبَيْدِ اللَّهِ يَقُولُ حَدَّثَنَا أَبُو ثَعْلَبَةَ الْخُشَنِيُّ قَالَكَانَ النَّاسُ إِذَا نَزَلُوا مَنْزِلًا قَالَ عَمْرٌو كَانَ النَّاسُ إِذَا نَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْزِلًا تَفَرَّقُوا فِي الشِّعَابِ وَالْأَوْدِيَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ تَفَرُّقَكُمْ فِي هَذِهِ الشِّعَابِ وَالْأَوْدِيَةِ إِنَّمَا ذَلِكُمْ مِنْ الشَّيْطَانِ فَلَمْ يَنْزِلْ بَعْدَ ذَلِكَ مَنْزِلًا إِلَّا انْضَمَّ بَعْضُهُمْ إِلَى بَعْضٍ حَتَّى يُقَالَ لَوْ بُسِطَ عَلَيْهِمْ ثَوْبٌ لَعَمَّهُمْ","id":"Telah menceritakan kepada kami ['Amr bin Utsman Al Himshi], dan [Yazid bin Qubais] dari penduduk Jabalah, sebuah pesisir Himsh. Dan ini adalah lafazh Yazid, mereka berkata; telah menceritakan kepada kami [Al Walid bin Muslim], dari [Abdullah bin Al 'Ala`], bahwa ia mendengar [Muslim bin Misykam Abu 'Ubaidullah] berkata; telah menceritakan kepada kami [Abu Tsa'labah Al Khusyani], ia berkata; dahulu orang-orang apabila singgah di suatu tempat …. -sedangkan 'Amr berkata; dahulu apabila Rasulullah shallallahu 'alaihi wasallam singgah di suatu tempat- mereka menyebar di jalan-jalan lembah dan bukit. Rasulullah shallallahu 'alaihi wasallam berkata: \"Sesungguhnya menyebarnya kalian di jalan-jalan lembah dan bukit adalah berasal dari syetan.\" Kemudian beliau tidak singgah di suatu tempat melainkan sebagian mereka bergabung dengan sebagian yang lain hingga dikatakan bahwa apabila dihamparkan selembar kain niscaya dapat menampung mereka. "},"2195":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ أَسِيدِ بْنِ عَبْدِ الرَّحْمَنِ الْخَثْعَمِيِّ عَنْ فَرْوَةَ بْنِ مُجَاهِدٍ اللَّخْمِيِّ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ الْجُهَنِيِّ عَنْ أَبِيهِ قَالَغَزَوْتُ مَعَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةَ كَذَا وَكَذَا فَضَيَّقَ النَّاسُ الْمَنَازِلَ وَقَطَعُوا الطَّرِيقَ فَبَعَثَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنَادِيًا يُنَادِي فِي النَّاسِ أَنَّ مَنْ ضَيَّقَ مَنْزِلًا أَوْ قَطَعَ طَرِيقًا فَلَا جِهَادَ لَهُحَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا بَقِيَّةُ عَنْ الْأَوْزَاعِيِّ عَنْ أَسِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ فَرْوَةَ بْنِ مُجَاهِدٍ عَنْ سَهْلِ بْنِ مُعَاذٍ عَنْ أَبِيهِ قَالَ غَزَوْنَا مَعَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Isma'il bin 'Ayyasy], dari [Usaid bin Abdurrahman Al Khats'ami], dari [Farwah bin Mujahid Al Lakhmi], dari [Sahl bin Mu'adz bin Anas Al Juhani], dari [ayahnya], ia berkata; aku pernah berperang bersama Nabi shallallahu 'alaihi wasallam pada perang ini dan ini, kemudian orang-orang mempersempit tempat-tempat persinggahan, dan menghalangi jalan. Kemudian Nabi shallallahu 'alaihi wasallam mengutus orang yang menyeru kepada orang-orang; orang yang mempersempit tempat persinggahan atau menghalangi jalan maka tidak ada jihad baginya. Telah menceritakan kepada kami ['Amr bin Utsman], telah menceritakan kepada kami [Baqiyyah], dari [Al Auza'i], dari [Usaid bin Abdurrahman], dari [Farwah bin Mujahid] dari [Sahl bin Mu'adz], dari [ayahnya], ia berkata; kami pernah berperang bersama Nabi shallallahu 'alaihi wasallam ….. semakna dengan makna hadits tersebut. "},"2196":{"ar":"حَدَّثَنَا أَبُو صَالِحٍ مَحْبُوبُ بْنُ مُوسَى أَخْبَرَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ سَالِمٍ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ يَعْنِي ابْنَ مَعْمَرٍ وَكَانَ كَاتِبًا لَهُ قَالَ كَتَبَ إِلَيْهِ عَبْدُ اللَّهِ بْنُ أَبِي أَوْفَى حِينَ خَرَجَ إِلَى الْحَرُورِيَّةِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَيَّامِهِ الَّتِي لَقِيَ فِيهَا الْعَدُوَّ قَالَ يَا أَيُّهَا النَّاسُ لَا تَتَمَنَّوْا لِقَاءَ الْعَدُوِّ وَسَلُوا اللَّهَ تَعَالَى الْعَافِيَةَ فَإِذَا لَقِيتُمُوهُمْ فَاصْبِرُوا وَاعْلَمُوا أَنَّ الْجَنَّةَ تَحْتَ ظِلَالِ السُّيُوفِ ثُمَّ قَالَ اللَّهُمَّ مُنْزِلَ الْكِتَابِ وَمُجْرِي السَّحَابِ وَهَازِمَ الْأَحْزَابِ اهْزِمْهُمْ وَانْصُرْنَا عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Abu Shalih Mahbub bin Musa], telah mengabarkan kepada kami [Abu Ishaq Al Fazari], dari [Musa bin 'Uqbah] dari [Salim Abu An Nadhr] mantan budak Umar bin 'Ubaidullah bin Ma'mar, dan ia dahulu adalah sekretarisnya. Ia berkata; [Abdullah bin Abu Aufa] telah menulis surat kepadanya ketika ia keluar menuju Al Haruriyyah, bahwa Rasulullah shallallahu 'alaihi wasallam pada beberapa hari ketika bertemu dengan musuh beliau berkata: \"Wahai manusia, janganlah kalian berharap bertemu dengan musuh, dan mohonlah keselamatan kepada Allah ta'ala. Apabila kalian telah bertemu dengan mereka maka bersabarlah, dan ketahuilah bahwa Surga di bawah naungan pedang.\" Kemudian beliau berdoa: \"Ya Allah, Yang menurunkan Al Qur'an, Yang menjalankan awan, dan Yang mengalahkan kelompok-kelompok musuh, kalahkan mereka dan menangkan kami atas mereka!\""},"2197":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا أَبِي حَدَّثَنَا الْمُثَنَّى بْنُ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا غَزَا قَالَ اللَّهُمَّ أَنْتَ عَضُدِي وَنَصِيرِي بِكَ أَحُولُ وَبِكَ أَصُولُ وَبِكَ أُقَاتِلُ","id":"Telah menceritakan kepada kami [Nashr bin Ali], telah mengabarkan kepada kami [Bapakku] telah menceritakan kepada kami [Al Mutsanna bin Sa'id] dari [Qatadah] dari [Anas bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam apabila berperang beliau berdoa: \"ALLAAHUMMA ANTA 'ADHUDII WA NASHIIRII, BIKA AHUULU WA BIKA ASHUULU WA BIKA UQAATILU (Ya Allah, Engkau adalah Penolongku, dan Yang memberikan kemenangan kepadaku, denganMu aku menghalangi musuh, dan denganMu aku menyerang serta denganMu aku berperang.\""},"2198":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا ابْنُ عَوْنٍ قَالَ كَتَبْتُ إِلَى نَافِعٍأَسْأَلُهُ عَنْ دُعَاءِ الْمُشْرِكِينَ عِنْدَ الْقِتَالِ فَكَتَبَ إِلَيَّ أَنَّ ذَلِكَ كَانَ فِي أَوَّلِ الْإِسْلَامِ وَقَدْ أَغَارَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَنِي الْمُصْطَلِقِ وَهُمْ غَارُّونَ وَأَنْعَامُهُمْ تُسْقَى عَلَى الْمَاءِ فَقَتَلَ مُقَاتِلَتَهُمْ وَسَبَى سَبْيَهُمْ وَأَصَابَ يَوْمَئِذٍ جُوَيْرِيَةَ بِنْتَ الْحَارِثِحَدَّثَنِي بِذَلِكَ عَبْدُ اللَّهِ وَكَانَ فِي ذَلِكَ الْجَيْشِ قَالَ أَبُو دَاوُد هَذَا حَدِيثٌ نَبِيلٌ رَوَاهُ ابْنُ عَوْنٍ عَنْ نَافِعٍ وَلَمْ يُشْرِكْهُ فِيهِ أَحَدٌ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Isma'il bin Ibrahim], telah mengabarkan kepada kami [Ibnu 'Aun], ia berkata; aku menulis surat kepada [Nafi'], aku bertanya kepadanya mengenai doa orang-orang musyrik ketika berperang, kemudian ia menulis surat kepadaku bahwa hal tersebut terjadi pada awal Islam. Nabi shallallahu 'alaihi wasallam telah menyerang Bani Al Mushthaliq sementara mereka sedang lalai, dan hewan-hewan ternak mereka sedang diberi minum. Kemudian beliau membunuh wanita yang berperang diantara mereka dan menawan tawanan mereka, dan pada saat itu beliau menawan Juwairiyah binti Al Harits. Telah menceritakan kepadaku dengan hal tersebut Abdullah, dan pada saat itu ia berada diantara pasukan tersebut. Abu Daud berkata; hadits ini adalah hadits yang sangat baik, diriwayatkan oleh Ibnu 'Aun, dari [Nafi'] dan tidak ada seorangpun yang bersamanya dalam hadits tersebut. "},"2199":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُغِيرُ عِنْدَ صَلَاةِ الصُّبْحِ وَكَانَ يَتَسَمَّعُ فَإِذَا سَمِعَ أَذَانًا أَمْسَكَ وَإِلَّا أَغَارَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami [Tsabit] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam pernah menyerang pada waktu Shalat Subuh, dan beliau berusaha untuk mendengar, apabila beliau mendengar adzan maka beliau menahan serangan, apabila tidak mendengar adzan maka beliau menyerang. "},"2200":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ أَخْبَرَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ نَوْفَلِ بْنِ مُسَاحِقٍ عَنْ ابْنِ عِصَامٍ الْمُزَنِيِّ عَنْ أَبِيهِ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ فَقَالَ إِذَا رَأَيْتُمْ مَسْجِدًا أَوْ سَمِعْتُمْ مُؤَذِّنًا فَلَا تَقْتُلُوا أَحَدًا","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah mengabarkan kepada kami [Sufyan] dari [Abdul Malik bin Naufal bin Musahiq], dari [Ibnu 'Isham Al Muzani], dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam mengirim kami dalam satuan pasukan. Kemudian beliau berkata: \"Apabila kalian melihat masjid atau mendengar orang yang beradzan, maka janganlah kalian membunuh seorangpun!\""},"2201":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو أَنَّهُ سَمِعَ جَابِرًاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحَرْبُ خُدَعَةٌ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Sufyan] dari ['Amr] bahwa ia mendengar [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Perang adalah tipu muslihat.\""},"2202":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا ابْنُ ثَوْرٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَرَادَ غَزْوَةً وَرَّى غَيْرَهَا وَكَانَ يَقُولُ الْحَرْبُ خَدْعَةٌقَالَ أَبُو دَاوُد لَمْ يَجِئْ بِهِ إِلَّا مَعْمَرٌ يُرِيدُ قَوْلَهُ الْحَرْبُ خَدْعَةٌ بِهَذَا الْإِسْنَادِ إِنَّمَا يُرْوَى مِنْ حَدِيثِ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرٍ وَمِنْ حَدِيثِ مَعْمَرٍ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid], telah menceritakan kepada kami [Ibnu Tsaur] dari [Ma'mar] dari [Az Zuhri], dari [Abdurrahman bin Ka'b bin Malik] dari [ayahnya], bahwa Nabi shallallahu 'alaihi wasallam apabila hendak berperang beliau menyembunyikan tujuan sebenarnya, dan beliau berkata: \"Perang adalah tipu muslihat.\" Abu Daud berkata; tidak ada yang membawa hadits tersebut selain Ma'mar. -yang ia maksudkan adalah ucapan \"Perang adalah tipu muslihat\" dengan sanad ini. Sesungguhnya ucapan tersebut diriwayatkan dari hadits ['Amr bin Dinar] dari [Jabir] dan dari hadits [Ma'mar], dari [Hammam bin Munabbih], dari [Abu Hurairah]. "},"2203":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الصَّمَدِ وَأَبُو عَامِرٍ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ حَدَّثَنَا إِيَاسُ بْنُ سَلَمَةَ عَنْ أَبِيهِ قَالَ أَمَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْنَا أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَغَزَوْنَا نَاسًا مِنْ الْمُشْرِكِينَ فَبَيَّتْنَاهُمْ نَقْتُلُهُمْ وَكَانَ شِ��َارُنَا تِلْكَ اللَّيْلَةَ أَمِتْ أَمِتْ قَالَ سَلَمَةُ فَقَتَلْتُ بِيَدِي تِلْكَ اللَّيْلَةَ سَبْعَةَ أَهْلِ أَبْيَاتٍ مِنْ الْمُشْرِكِينَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdushshamad] dan [Abu 'Amir], dari [Ikrimah bin 'Ammar], telah menceritakan kepada kami [Iyas bin Salamah], dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah menunjuk Abu Bakr radliallahu 'anhu sebagai pemimpin atas kami, kemudian kami memerangi orang-orang musyrik, kami menyerang mereka pada malam hari dan kami membunuh mereka. Dan slogan kami pada malam tersebut adalah \"bunuh, bunuh\". Salamah berkata; pada malam itu aku telah membunuh tujuh orang musyrik dengan tanganku. "},"2204":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ شَوْكَرٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ حَدَّثَنَا الْحَجَّاجُ بْنُ أَبِي عُثْمَانَ عَنْ أَبِي الزُّبَيْرِ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ حَدَّثَهُمْ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَلَّفُ فِي الْمَسِيرِ فَيُزْجِي الضَّعِيفَ وَيُرْدِفُ وَيَدْعُو لَهُمْ","id":"Telah menceritakan kepada kami [Al Hasan bin Syaukar], telah menceritakan kepada kami [Isma'il bin 'Ulayyah], telah menceritakan kepada kami [Al Hajjaj bin Abu Utsman] dari [Abu Az Zubair] bahwa [Jabir bin Abdullah] telah menceritakan kepada mereka, ia berkata; Rasulullah shallallahu 'alaihi wasallam berjalan di belakang, beliau menuntun orang yang lemah, memboncengkan, serta menyeru untuk membantu mereka. "},"2205":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَقَال قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَإِذَا قَالُوهَا مَنَعُوا مِنِّي دِمَاءَهُمْ وَأَمْوَالَهُمْ إِلَّا بِحَقِّهَا وَحِسَابُهُمْ عَلَى اللَّهِ تَعَالَى","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih], dari [Abu Hurairah], ia berkata; Rasulullah shallallahu wa'alaihi wa sallam bersabda: \"Aku diperintahkan untuk memerangi manusia hingga mereka mengucapkan LAA ILAAHA ILLALLAAH (tiada tuhan yang haq disembah selian Allah), apabila telah mengucapkannya maka mereka telah melindungi darah dan harta mereka dariku kecuali dengan haknya dan perhitungan mereka kepada Allah ta'ala.\""},"2206":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَعْقُوبَ الطَّالْقَانِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَشْهَدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَأَنْ يَسْتَقْبِلُوا قِبْلَتَنَا وَأَنْ يَأْكُلُوا ذَبِيحَتَنَا وَأَنْ يُصَلُّوا صَلَاتَنَا فَإِذَا فَعَلُوا ذَلِكَ حَرُمَتْ عَلَيْنَا دِمَاؤُهُمْ وَأَمْوَالُهُمْ إِلَّا بِحَقِّهَا لَهُمْ مَا لِلْمُسْلِمِينَ وَعَلَيْهِمْ مَا عَلَى الْمُسْلِمِينَحَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يَحْيَى بْنُ أَيُّوبَ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ الْمُشْرِكِينَ بِمَعْنَاهُ","id":"Telah menceritakan kepada kami [Sa'id? bin Ya'qub Ath Thalqani], telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Humaid] dari [Anas], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata: \"Aku diperintahkan agar memerangi manusia hingga mereka bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah, dan Muhammad adalah hamba dan rasulNya, menghadap ke kiblat kita, makan sembelihan kita, dan melakukan shalat kita. Apabila mereka melakukan hal tersebut maka telah haram atas kita darah dan harta mereka kecuali dengan haknya. Bagi mereka apa yang menjadi hak orang-orang muslim, dan kewajiban mereka apa yang menjadi kewajiban orang-orang muslim.\" Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri], telah mengabarkan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Yahya bin Ayyub], dari [Humaid Ath Thawil], dari [Anas bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diperintahkan untuk memerangi orang-orang musyrik…. Seperti makna hadits tersebut. "},"2207":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى قَالَا حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ عَنْ الْأَعْمَشِ عَنْ أَبِي ظَبْيَانَ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً إِلَى الْحُرَقَاتِ فَنَذِرُوا بِنَا فَهَرَبُوا فَأَدْرَكْنَا رَجُلًا فَلَمَّا غَشِينَاهُ قَالَ لَا إِلَهَ إِلَّا اللَّهُ فَضَرَبْنَاهُ حَتَّى قَتَلْنَاهُ فَذَكَرْتُهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ لَكَ بِلَا إِلَهَ إِلَّا اللَّهُ يَوْمَ الْقِيَامَةِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا قَالَهَا مَخَافَةَ السِّلَاحِ قَالَ أَفَلَا شَقَقْتَ عَنْ قَلْبِهِ حَتَّى تَعْلَمَ مِنْ أَجْلِ ذَلِكَ قَالَهَا أَمْ لَا مَنْ لَكَ بِلَا إِلَهَ إِلَّا اللَّهُ يَوْمَ الْقِيَامَةِ فَمَا زَالَ يَقُولُهَا حَتَّى وَدِدْتُ أَنِّي لَمْ أُسْلِمْ إِلَّا يَوْمَئِذٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] dan [Utsman bin Abu Syaibah], secara makna, mereka berkata; telah menceritakan kepada kami [Ya'la bin 'Ubaid] dari [Al A'masy] dari [Abu Zhabyan], telah menceritakan kepada kami [Usamah bin Zaid], ia berkata; Rasulullah shallallahu 'alaihi wasallam mengutus kami dalam kesatuan militer menuju Al Huraqat. Kemudian mereka mengetahui kedatangan kami, lalu mereka melarikan diri. Kemudian kami mendapati seorang laki-laki, dan tatkala kami mengepungnya ia mengucapkan: LAA ILAAHA ILLALLAAH kemudian kami menebasnya hingga kami membunuhnya. Lalu hal tersebut aku ceritakan kepada Nabi shallallahu 'alaihi wasallam, lalu beliau berkata: \"Siapakah yang akan menolongmu apabila LAA ILAAHA ILLALLAAH telah datang pada Hari Kiamat?\" Lalu aku katakan; wahai Rasulullah, sesungguhnya ia mengucapkannya karena takut kepada senjata. Beliau berkata: \"Apakah engkau telah membelah hatinya hingga engkau mengetahui apakah ia mengucapkannya atau tidak? Siapakah yang akan menolongmu apabila LAA ILAAHA ILLALLAAH telah datang pada Hari Kiamat?\" Beliau terus mengucapkan hal tersebut hingga aku berharap bahwa aku belum masuk Islam kecuali pada saat itu. "},"2208":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ اللَّيْثِ عَنْ ابْنِ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَدِيِّ بْنِ الْخِيَارِ عَنْ الْمِقْدَادِ بْنِ الْأَسْوَدِ أَنَّهُ أَخْبَرَهُ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ لَقِيتُ رَجُلًا مِنْ الْكُفَّارِ فَقَاتَلَنِي فَضَرَبَ إِحْدَى يَدَيَّ بِالسَّيْفِ ثُمَّ لَاذَ مِنِّي بِشَجَرَةٍ فَقَالَ أَسْلَمْتُ لِلَّهِ أَفَأَقْتُلُهُ يَا رَسُولَ اللَّهِ بَعْدَ أَنْ قَالَهَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقْتُلْهُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّهُ قَطَعَ يَدِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقْتُلْهُ فَإِنْ قَتَلْتَهُ فَإِنَّهُ بِمَنْزِلَتِكَ قَبْلَ أَنْ تَقْتُلَهُ وَأَنْتَ بِمَنْزِلَتِهِ قَبْلَ أَنْ يَقُولَ كَلِمَتَهُ الَّتِي قَالَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Al Laits] dari [Ibnu Syihab] dari ['Atha` bin Yazid? Al Laitsi] dari ['Ubaidullah bin Adi bin Al Khiyar], dari [Al Miqdad bin Al Aswad] bahwa ia telah mengabarkan kepadanya bahwa ia berkata; wahai Rasulullah, bagaimana pendapat engkau apabila aku bertemu orang kafir kemudian ia memerangiku, lalu ia menebas salah satu tanganku dengan pedang, kemudian ia berlindung dariku di sebuah pohon, lalu ia berkata; aku masuk Islam karena Allah. Apakah aku boleh membunuhnya setelah ia mengucapkan hal tersebut wahai Rasulullah? Rasulullah shallallahu 'alaihi wasallam berkata: \"Jangan engkau membunuhnya!\" Kemudian aku katakan; tapi ia telah memotong tanganku. Rasulullah shallallahu 'alaihi wasallam berkata: \"Jangan engkau membunuhnya!\" Karena apabila engkau membunuhnya maka ia akan menempati posisimu sebelum engkau membunuhnya dan engkau menempati posisinya sebelum ia mengucapkan kalimat tersebut. "},"2209":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ إِسْمَعِيلَ عَنْ قَيْسٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً إِلَى خَثْعَمٍ فَاعْتَصَمَ نَاسٌ مِنْهُمْ بِالسُّجُودِ فَأَسْرَعَ فِيهِمْ الْقَتْلَ قَالَ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ لَهُمْ بِنِصْفِ الْعَقْلِ وَقَالَ أَنَا بَرِيءٌ مِنْ كُلِّ مُسْلِمٍ يُقِيمُ بَيْنَ أَظْهُرِ الْمُشْرِكِينَ قَالُوا يَا رَسُولَ اللَّهِ لِمَ قَالَ لَا تَرَاءَى نَارَاهُمَاقَالَ أَبُو دَاوُد رَوَاهُ هُشَيْمٌ وَمَعْمَرٌ وَخَالِدٌ الْوَاسِطِيُّ وَجَمَاعَةٌ لَمْ يَذْكُرُوا جَرِيرًا","id":"Telah menceritakan kepada kami [Hannad bin As Sarri], telah menceritakan kepada kami [Abu Mu'awiyah], dari [Isma'il], dari [Qais] dari [Jarir bin Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah mengirim kami dalam sebuah kesatuan militer menuju Khats'am, kemudian orang-orang diantara mereka berlindung dengan bersujud, kemudian cepat terjadi pembunuhan diantara mereka. Lalu hal tersebut sampai kepada Nabi shallallahu 'alaihi wasallam, dan beliau memerintahkan agar mereka diberi setengah diyah. Dan beliau berkata: \"Aku berlepas diri dari setiap muslim yang bermukim di antara orang-orang musyrik.\" Mereka bertanya; kenapa wahai Rasulullah? Beliau berkata: kedua api peperangan mereka saling melihat. Abu Daud berkata; hadits tersebut diriwayatkan oleh Husyaim dan Ma'mar, Khalid Al Wasithi, serta beberapa orang-orang, mereka tidak menyebutkan Jarir. "},"2210":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ جَرِيرِ بْنِ حَازِمٍ عَنْ الزُّبَيْرِ بْنِ خِرِّيتٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَنَزَلَتْ{ إِنْ يَكُنْ مِنْكُمْ عِشْرُونَ صَابِرُونَ يَغْلِبُوا مِائَتَيْنِ }فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ حِينَ فَرَضَ اللَّهُ عَلَيْهِمْ أَنْ لَا يَفِرَّ وَاحِدٌ مِنْ عَشَرَةٍ ثُمَّ إِنَّهُ جَاءَ تَخْفِيفٌ فَقَالَ{ الْآنَ خَفَّفَ اللَّهُ عَنْكُمْ }قَرَأَ أَبُو تَوْبَةَ إِلَى قَوْلِهِ{ يَغْلِبُوا مِائَتَيْنِ }قَالَ فَلَمَّا خَفَّفَ اللَّهُ تَعَالَى عَنْهُمْ مِنْ الْعِدَّةِ نَقَصَ مِنْ الصَّبْرِ بِقَدْرِ مَا خَفَّفَ عَنْهُمْ","id":"Telah menceritakan kepada kami [Abu Taubah Ar Rabi' bin Nafi'], telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Jarir bin Hazim] dari [Az Zubair bin Khirrit] dari [Ikrimah], dari [Ibnu Abbas], ia berkata; telah turun ayat: \"Jika ada dua puluh orang yang sabar diantaramu, niscaya mereka akan dapat mengalahkan dua ratus orang musuh.\" Maka hal tersebut terasa berat atas orang-orang muslim di saat Allah mewajibkan kepada mereka agar tidak seorang pun lari dari sepuluh orang musuh. Kemudian datang keringanan, Allah berfirman: \"Sekarang Allah telah meringankan kepadamu…..\" Abu Taubah membacanya hingga firmanNya: \"…. dapat mengalahkan dua ratus orang kafir.\" Abu Taubah berkata; tatkala Allah memberikan keringanan kepada mereka dalam hal jumlah maka berkuranglah kesabaran sesuai kadar keringan yang Allah berikan kepada mereka. "},"2211":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا يَزِيدُ بْنُ أَبِي زِيَادٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ أَبِي لَيْلَى حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ حَدَّثَهُ أَنَّهُ كَانَ فِي سَرِيَّةٍ مِنْ سَرَايَا رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَحَاصَ النَّاسُ حَيْصَةً فَكُنْتُ فِيمَنْ حَاصَ قَالَ فَلَمَّا بَرَزْنَا قُلْنَا كَيْفَ نَصْنَعُ وَقَدْ فَرَرْنَا مِنْ الزَّحْفِ وَبُؤْنَا بِالْغَضَبِ فَقُلْنَا نَدْخُلُ الْمَدِينَةَ فَنَتَثَبَّتُ فِيهَا وَنَذْهَبُ وَلَا يَرَانَا أَحَدٌ قَالَ فَدَخَلْنَا فَقُلْنَا لَوْ عَرَضْنَا أَنْفُسَنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنْ كَانَتْ لَنَا تَوْبَةٌ أَقَمْنَا وَإِنْ كَانَ غَيْرَ ذَلِكَ ذَهَبْنَا قَالَ فَجَلَسْنَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ صَلَاةِ الْفَجْرِ فَلَمَّا خَرَجَ قُمْنَا إِلَيْهِ فَقُلْنَا نَحْنُ الْفَرَّارُونَ فَأَقْبَلَ إِلَيْنَا فَقَالَ لَا بَلْ أَنْتُمْ الْعَكَّارُونَ قَالَ فَدَنَوْنَا فَقَبَّلْنَا يَدَهُ فَقَالَ إِنَّا فِئَةُ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Yazid? bin Abu Ziyad], bahwa [Abdurrahman bin Abu Laila] telah menceritakan kepadanya bahwa [Abdullah bin Umar] telah menceritakan kepadanya bahwa ia pernah berada dalam kesatuan militer diantara kesatuan-kesatuan militer Rasulullah shallallahu 'alaihi wasallam. Ia berkata; kemudian orang-orang melarikan diri, dan aku termasuk orang-orang yang melarikan diri. Kemudian tatkala kami nampak, maka kami mengatakan; apa yang akan kita lakukan? Sungguh kita telah lari dari peperangan dan kita kembali dengan kemurkaan. Lalu kami katakan; kita akan masuk Madinah kemudian kita tinggal padanya dan pergi sementara tidak ada seorangpun yang melihat kita. Kemudian kami masuk Madinah, lalu kami katakan; seandainya kita menyerahkan diri kepada Rasulullah shallallahu 'alaihi wasallam, apabila kita mendapatkan taubat maka kita tinggal di Madinah dan seandainya tidak demikian maka kita akan pergi. Ibnu Umar berkata; kemudian kami duduk menunggu Rasulullah shallallahu 'alaihi wasallam sebelum Shalat Subuh. Kemudian tatkala beliau keluar maka kami berdiri menuju kepadanya dan kami katakan; kami adalah orang-orang yang melarikan diri. Lalu beliau menghadap kepada kami dan berkata: \"Tidak, melainkan kalian adalah orang-orang yang kembali berperang.\" Ibnu Umar berkata; kemudian kami mendekat dan mencium tangan beliau. Lalu beliau berkata: \"Kami adalah kelompok orang-orang muslimin.\""},"2212":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ هِشَامٍ الْمِصْرِيُّ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا دَاوُدُ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَ نَزَلَتْ فِي يَوْمِ بَدْرٍ وَمَنْ يُوَلِّهِمْ يَوْمَئِذٍ دُبُرَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Hisyam Al Mishri], telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal], telah menceritakan kepada kami [Daud], dari [Abu Nadhrah], dari [Abu Sa'id], ia berkata; telah turun mengenai waktu perang Badr ayat: \"Barangsiapa yang membelakangi mereka (mundur) di waktu itu…..\""},"2213":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا هُشَيْمٌ وَخَالِدٌ عَنْ إِسْمَعِيلَ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ خَبَّابٍ قَالَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُتَوَسِّدٌ بُرْدَةً فِي ظِلِّ الْكَعْبَةِ فَشَكَوْنَا إِلَيْهِ فَقُلْنَا أَلَا تَسْتَنْصِرُ لَنَا أَلَا تَدْعُو اللَّهَ لَنَا فَجَلَسَ مُحْمَرًّا وَجْهُهُ فَقَالَ قَدْ كَانَ مَنْ قَبْلَكُمْ يُؤْخَذُ الرَّجُلُ فَيُحْفَرُ لَهُ فِي الْأَرْضِ ثُمَّ يُؤْتَى بِالْمِنْشَارِ فَيُجْعَلُ عَلَى رَأْسِهِ فَيُجْعَلُ فِرْقَتَيْنِ مَا يَصْرِفُهُ ذَلِكَ عَنْ دِينِهِ وَيُمْشَطُ بِأَمْشَاطِ الْحَدِيدِ مَا دُونَ عَظْمِهِ مِنْ لَحْمٍ وَعَصَبٍ مَا يَصْرِفُهُ ذَلِكَ عَنْ دِينِهِ وَاللَّهِ لَيُتِمَّنَّ اللَّهُ هَذَا الْأَمْرَ حَتَّى يَسِيرَ الرَّاكِبُ مَا بَيْنَ صَنْعَاءَ وَحَضْرَمُوتَ مَا يَخَافُ إِلَّا اللَّهَ تَعَالَى وَالذِّئْبَ عَلَى غَنَمِهِ وَلَكِنَّكُمْ تَعْجَلُونَ","id":"Telah menceritakan kepada kami ['Amr bin 'Aun], telah mengabarkan kepada kami [Husyaim], dan [Khalid], dari [Isma'il], dari [Qais bin Abu Hazim], dari [Khabbab], ia berkata; kami datang kepada Rasulullah shallallahu 'alaihi wasallam sementara beliau berbantalkan burdah di bawah naungan Ka'bah, kami mengeluhkan kepada beliau, kami katakan; tidakkah anda memintakan kemenangan untuk kami? Tidakkah engkau berdoa kepada Allah untuk kami? Kemudian beliau duduk dalam keadaan memerah wajahnya, lalu berkata: \"Sungguh orang-orang sebelum kalian diantara mereka ada yang dikubur di tanah kemudian didatangkan gergaji kemudian diletakkan di atas kepalanya dan ia dibelah menjadi dua bagian, hal tersebut tidaklah membuatnya berpaling dari agamanya, dan ada yang disisir daging dan sarafnya menggukan sisir besi mendekati tulangnya, tidaklah hal tersebut menjadikannya berpaling dari agamanya. Demi Allah, sungguh Allah akan menyempurnakan perkara ini hingga orang yang berkendaraan berjalan antara Shan'a` dan Hadhramut dalam keadaan tidak takut kecuali kepada Allah ta'ala serta serigala yang akan memangsa dombanya, akan tetapi kalian tergesa-gesa.\""},"2214":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو حَدَّثَهُ الْحَسَنُ بْنُ مُحَمَّدِ بْنِ عَلِيٍّ أَخْبَرَهُ عُبَيْدُ اللَّهِ بْنُ أَبِي رَافِعٍ وَكَانَ كَاتِبًا لِعَلِيِّ بْنِ أَبِي طَالِبٍ قَالَ سَمِعْتُ عَلِيًّا يَقُولُبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَالزُّبَيْرُ وَالْمِقْدَادُ فَقَالَ انْطَلِقُوا حَتَّى تَأْتُوا رَوْضَةَ خَاخٍ فَإِنَّ بِهَا ظَعِينَةً مَعَهَا كِتَابٌ فَخُذُوهُ مِنْهَا فَانْطَلَقْنَا تَتَعَادَى بِنَا خَيْلُنَا حَتَّى أَتَيْنَا الرَّوْضَةَ فَإِذَا نَحْنُ بِالظَّعِينَةِ فَقُلْنَا هَلُمِّي الْكِتَابَ قَالَتْ مَا عِنْدِي مِنْ كِتَابٍ فَقُلْتُ لَتُخْرِجِنَّ الْكِتَابَ أَوْ لَنُلْقِيَنَّ الثِّيَابَ فَأَخْرَجَتْهُ مِنْ عِقَاصِهَا فَأَتَيْنَا بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا هُوَ مِنْ حَاطِبِ بْنِ أَبِي بَلْتَعَةَ إِلَى نَاسٍ مِنْ الْمُشْرِكِينَ يُخْبِرُهُمْ بِبَعْضِ أَمْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا هَذَا يَا حَاطِبُ فَقَالَ يَا رَسُولَ اللَّهِ لَا تَعْجَلْ عَلَيَّ فَإِنِّي كُنْتُ امْرَأً مُلْصَقًا فِي قُرَيْشٍ وَلَمْ أَكُنْ مِنْ أَنْفُسِهَا وَإِنَّ قُرَيْشًا لَهُمْ بِهَا قَرَابَاتٌ يَحْمُونَ بِهَا أَهْلِيهِمْ بِمَكَّةَ فَأَحْبَبْتُ إِذْ فَاتَنِي ذَلِكَ أَنْ أَتَّخِذَ فِيهِمْ يَدًا يَحْمُونَ قَرَابَتِي بِهَا وَاللَّهِ يَا رَسُولَ اللَّهِ مَا كَانَ بِي مِنْ كُفْرٍ وَلَا ارْتِدَادٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَكُمْ فَقَالَ عُمَرُ دَعْنِي أَضْرِبُ عُنُقَ هَذَا الْمُنَافِقِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ شَهِدَ بَدْرًا وَمَا يُدْرِيكَ لَعَلَّ اللَّهَ اطَّلَعَ عَلَى أَهْلِ بَدْرٍ فَقَالَ اعْمَلُوا مَا شِئْتُمْ فَقَدْ غَفَرْتُ لَكُمْحَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ عَنْ حُصَيْنٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيٍّ بِهَذِهِ الْقِصَّةِ قَالَ انْطَلَقَ حَاطِبٌ فَكَتَبَ إِلَى أَهْلِ مَكَّةَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ سَارَ إِلَيْكُمْ وَقَالَ فِيهِ قَالَتْ مَا مَعِي كِتَابٌ فَانْتَحَيْنَاهَا فَمَا وَجَدْنَا مَعَهَا كِتَابًا فَقَالَ عَلِيٌّ وَالَّذِي يُحْلَفُ بِهِ لَأَقْتُلَنَّكِ أَوْ لَتُخْرِجِنَّ الْكِتَابَ وَسَاقَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Sufyan] dari ['Amr], telah menceritakan kepadanya [Al Hasan bin Muhammad bin Ali], telah mengabarkan kepadanya ['Ubaidullah bin Abu Rafi'], dan dahulu ia adalah sekretaris Ali bin Abu Thalib, ia berkata; saya telah mendengar [Ali] berkata; Rasulullah shallallahu 'alaihi wasallam telah mengirimku bersama dengan Az Zubair dan Al Miqdad, kemudian beliau berkata: \"Pergilah kalian ke taman Khakh, sesungguhnya di sana terdapat seorang wanita yang membawa surat. Ambillah surat tersebut darinya.\" Kemudian kami pergi dan kuda kami berlari kencang hingga sampai taman tersebut. Tiba-tiba kami mendapati seorang wanita, lalu kami katakan; serahkan surat tersebut! Wanita tersebut berkata; aku tidak memiliki surat. Lalu aku katakan; sungguh engkau keluarkan surat tersebut atau kami akan melucuti pakaianmu! Kemudian wanita tersebut mengeluarkannya dari bawah sanggulnya. Kemudian kami membawanya kepada Nabi shallallahu 'alaihi wasallam, ternyata surat tersebut berasal dari Hathib bin Abu Balta'ah kepada beberapa orang musyriki, ia memberitahukan kepada mereka sebagian urusan Rasulullah shallallahu 'alaihi wasallam. Kemudian beliau berkata: \"Apa ini wahai Hathib?\" Hathib berkata; jangan terburu menghukumku wahai Rasulullah! Sesungguhnya dahulu aku adalah orang yang tinggal di antara orang-orang Quraisy dan bukan dari mereka, sementara orang-orang Quraisy memiliki kerabat di sana, yang dengan kekerabatan tersebut mereka melindungi keluarga mereka di Mekkah. Dan disaat aku tidak memiliki hal itu aku ingin untuk memberikan suatu pemberian yang dengannya mereka dapat melindungi kerabatku di sana. Demi Allah wahai Rasulullah, aku melakukan hal itu bukan lantaran aku kafir serta keluar dari agamaku. Kemudian Nabi shallallahu 'alaihi wasallam berkata: ia benar. Lalu Umar bin Al Khathab radliallahu 'anhu berkata; biarkan aku memenggal leher orang munafik ini wahai Rasulullah! Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Sesungguhnya ia telah mengikuti perang Badr, tahukah kamu sungguh Allah telah melihat kepada Ahli Badr dan berkata: \"Lakukan sesuka kalian, sungguh Aku telah mengampuni dosa kalian.\" Telah menceritakan kepada kami [Wahb bin Baqiyyah], dari [Khalid] dari [Hushain], dari [Sa'd bin 'Ubaidah], dari [Abu Abdurrahman As Sulami], dari [Ali] dengan kisah ini. Ia berkata; Hathib pergi dan menulis surat kepada penduduk Mekkah bahwa Muhammad shallallahu 'alaihi wasallam telah berjalan menuju kepada kalian. Wahb berkata dalam hadits tersebut; wanita tersebut berkata; aku tidak memiliki surat. Kemudian kami memeriksanya dan kami tidak mendapatkan surat bersamanya. Kemudian Ali berkata; demi Dzat yang dengan dilakukan sumpah, sungguh aku akan membunuhmu atau engkau keluarkan surat tersebut. Dan Wahb menyebutkan hadits tersebut. "},"2215":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنِي مُحَمَّدُ بْنُ مُحَبَّبٍ أَبُو هَمَّامٍ الدَّلَّالُ حَدَّثَنَا سُفْيَانُ بْنُ سَعِيدٍ عَنْ أَبِي إِسْحَقَ عَنْ حَارِثَةَ بْنِ مُضَرِّبٍ عَنْ فُرَاتِ بْنِ حَيَّانَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلِهِ وَكَانَ عَيْنًا لِأَبِي سُفْيَانَ وَكَانَ حَلِيفًا لِرَجُلٍ مِنْ الْأَنْصَارِ فَمَرَّ بِحَلَقَةٍ مِنْ الْأَنْصَارِ فَقَالَ إِنِّي مُسْلِمٌ فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ يَا رَسُولَ اللَّهِ إِنَّهُ يَقُولُ إِنَّى مُسْلِمٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْكُمْ رِجَالًا نَكِلُهُمْ إِلَى إِيمَانِهِمْ مِنْهُمْ فُرَاتُ بْنُ حَيَّانَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepadaku [Muhammad bin Muhabbab Abu Hammam Ad Dallal], telah menceritakan kepada kami [Sufyan bin Sa'id], dari [Abu Ishaq], dari [Haritsah bin Mudharrib], dari [Furat bin Hayyan] bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membunuhnya, dan ia adalah mata-mata Abu Sufyan. Dan ia adalah sekutu seorang anshor, kemudian ia berkata; sesungguhnya aku adalah seorang muslim. Kemudian seorang anshar berkata; wahai Rasulullah, sesungguhnya ia berkata; aku adalah seorang muslim. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Sesungguhnya diantara kalian terdapat orang-orang yang kami serahkan mereka kepada keimanan mereka, diantara mereka adalah Furat bin Hayyan.\""},"2216":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا قَالَ أَبُو نُعَيْمٍ حَدَّثَنَا أَبُو عُمَيْسٍ عَنْ ابْنِ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَيْنٌ مِنْ الْمُشْرِكِينَ وَهُوَ فِي سَفَرٍ فَجَلَسَ عِنْدَ أَصْحَابِهِ ثُمَّ انْسَلَّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اطْلُبُوهُ فَاقْتُلُوهُ قَالَ فَسَبَقْتُهُمْ إِلَيْهِ فَقَتَلْتُهُ وَأَخَذْتُ سَلَبَهُ فَنَفَّلَنِي إِيَّاهُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abu Nu'aim], telah menceritakan kepada kami [Abu 'Umais] dari [Salamah bin Al Akwa'] dari [ayahnya], ia berkata; telah datang seorang mata-mata dari orang-orang musyrik kepada Nabi shallallahu 'alaihi wasallam dan ia sedang dalam perjalanannya, kemudian ia duduk disisi para sahabatnya kemudian ia pergi. Nabi shallallahu 'alaihi wasallam berkata: \"Carilah dia dan bunuhlah!\" Salamah bin Al Akwa' berkata; kemudian aku mendahului mereka dan membunuhnya serta mengambil barang yang ada di badannya. Lalu beliau memberiku tambahan. "},"2217":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ أَنَّ هَاشِمَ بْنَ الْقَاسِمِ وَهِشَامًا حَدَّثَاهُمْ قَالَا حَدَّثَنَا عِكْرِمَةُ قَالَ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ قَالَ حَدَّثَنِي أَبِي قَالَغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَوَازِنَ قَالَ فَبَيْنَمَا نَحْنُ نَتَضَحَّى وَعَامَّتُنَا مُشَاةٌ وَفِينَا ضَعَفَةٌ إِذْ جَاءَ رَجُلٌ عَلَى جَمَلٍ أَحْمَرَ فَانْتَزَعَ طَلَقًا مِنْ حَقْوِ الْبَعِيرِ فَقَيَّدَ بِهِ جَمَلَهُ ثُمَّ جَاءَ يَتَغَدَّى مَعَ الْقَوْمِ فَلَمَّا رَأَى ضَعَفَتَهُمْ وَرِقَّةَ ظَهْرِهِمْ خَرَجَ يَعْدُو إِلَى جَمَلِهِ فَأَطْلَقَهُ ثُمَّ أَنَاخَهُ فَقَعَدَ عَلَيْهِ ثُمَّ خَرَجَ يَرْكُضُهُ وَاتَّبَعَهُ رَجُلٌ مِنْ أَسْلَمَ عَلَى نَاقَةٍ وَرْقَاءَ هِيَ أَمْثَلُ ظَهْرِ الْقَوْمِ قَالَ فَخَرَجْتُ أَعْدُو فَأَدْرَكْتُهُ وَرَأْسُ النَّاقَةِ عِنْدَ وَرِكِ الْجَمَلِ وَكُنْتُ عِنْدَ وَرِكِ النَّاقَةِ ثُمَّ تَقَدَّمْتُ حَتَّى كُنْتُ عِنْدَ وَرِكِ الْجَمَلِ ثُمَّ تَقَدَّمْتُ حَتَّى أَخَذْتُ بِخِطَامِ الْجَمَلِ فَأَنَخْتُهُ فَلَمَّا وَضَعَ رُكْبَتَهُ بِالْأَرْضِ اخْتَرَطْتُ سَيْفِي فَأَضْرِبُ رَأْسَهُ فَنَدَرَ فَجِئْتُ بِرَاحِلَتِهِ وَمَا عَلَيْهَا أَقُودُهَا فَاسْتَقْبَلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّاسِ مُقْبِلًا فَقَالَ مَنْ قَتَلَ الرَّجُلَ فَقَالُوا سَلَمَةُ بْنُ الْأَكْوَعِ فَقَالَ لَهُ سَلَبُهُ أَجْمَعُقَالَ هَارُونُ هَذَا لَفْظُ هَاشِمٍ","id":"Telah menceritakan kepada kami [Harun bin Abdullah], bahwa [Hasyim bin Al Qasim], dan [Hisyam] telah menceritakan kepada mereka; telah menceritakan kepada kami [Ikrimah], telah menceritakan kepada kami [Iyas bin Salamah], ia berkata; telah menceritakan kepadaku [ayahku], ia berkata; aku pernah memerangi Hawazin bersama Rasulullah shallallahu 'alaihi wasallam, kemudian tatkala kami sedang makan pada waktu dhuha dan kebanyakan kami berjalan kaki, serta diantara kami terdapat orang yang lemah tiba-tiba seseorang datang dengan mengendarai unta. Lalu ia melepas tali dari pinggang unta, lalu ia gunakan untuk mengikat untanya. Kemudian ia datang dan makan siang bersama orang-orang. Kemudian tatkala ia melihat orang-orang lemah mereka dan punggung mereka yang lemas, maka ia keluar menuju kepada untanya lalu melepaskannya kemudian menderumkannya. Orang tersebut duduk di atas unta tersebut kemudian keluar dan memukul unta dengan kakinya. Ia diikuti seseorang dari Aslam yang mengendarai unta Abu-Abu yang sama dengan punggung orang-orang tersebut. Ia berkata; kemudian aku keluar mengejarnya, lalu aku mendapatkannya, sementara kepala untaku ada di sisi pantat untanya, kemudian aku maju hingga dapat memegang tali kendali untanya. Lalu aku menderumkannya. Tatkala ia telahmeletakkan lututnya di tanah aku mencabut pedangku lalu menebas kepalanya hingga ia terjatuh. Kemudian aku datang dengan membawa kendaraannya dan apa yang ada di atasnya. Aku menuntunnya, kemudian Rasulullah shallallahu 'alaihi wasallam menyambutku diantara orang-orang. Kemudian ia berkata; siapakah yang membunuh orang tersebut? Mereka berkata; Salamah bin Al Akwa'. Lalu beliau berkata: \"Baginya salabnya semua.\" Harun berkata; ini adalah lafazh Hasyim. "},"2218":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ عَلْقَمَةَ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ عَنْ مَعْقِلِ بْنِ يَسَارٍ أَنَّ النُّعْمَانَ يَعْنِي ابْنَ مُقَرِّنٍ قَالَشَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا لَمْ يُقَاتِلْ مِنْ أَوَّلِ النَّهَارِ أَخَّرَ الْقِتَالَ حَتَّى تَزُولَ الشَّمْسُ وَتَهُبَّ الرِّيَاحُ وَيَنْزِلَ النَّصْرُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami [Abu Imran Al Jauni], dari ['Alqamah bin Abdullah Al Muzani], dari [Ma'qil bin Yasar] bahwa [An Nu'man bin Muqarrin] berkata; aku menyaksikan Rasulullah shallallahu 'alaihi wasallam apabila tidak berperang pada awal siang maka beliau menunda perang hingga matahari tergelincir dan angin berhembus kencang dan turunlah kemenangan. "},"2219":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ الْحَسَنِ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَكَانَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْرَهُونَ الصَّوْتَ عِنْدَ الْقِتَالِحَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ هَمَّامٍ حَدَّثَنِي مَطَرٌ عَنْ قَتَادَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ ذَلِكَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Hisyam], dan telah diriwayat dari jalur yang lain: Telah menceritakan kepada kami ['Ubaidullah bin Umar], telah menceritakan kepada kami [Abdurrahman bin Mahdi], telah menceritakan kepada kami [Hisyam], telah menceritakan kepada kami [Qatadah], dari [Al Hasan], dari [Qais bin 'Ubad], ia berkata; para sahabat Nabi shallallahu 'alaihi wasallam tidak menyukai bersuara ketika berperang. Telah menceritakan kepada kami ['Ubaidullah bin Umar], telah menceritakan kepada kami [Abdurrahman] dari [Hammam], telah menceritakan kepadaku [Mathar], dari [Qatadah] dari [Abu Burdah], dari [ayahnya], dari Nabi shallallahu 'alaihi wasallam seperti hadits tersebut. "},"2220":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَلَمَّا لَقِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُشْرِكِينَ يَوْمَ حُنَيْنٍ فَانْكَشَفُوا نَزَلَ عَنْ بَغْلَتِهِ فَتَرَجَّلَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Waki'], dari [Israil] dari [Abu Ishaq], dari [Al Bara`], ia berkata; tatkala Rasulullah shallallahu 'alaihi wasallam bertemu dengan orang-orang musyrik pada saat perang Hunain kemudian mereka terkalahkan, beliau turun dari Bighalnya dan berjalan kaki. "},"2221":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ وَمُوسَى بْنُ إِسْمَعِيلَ الْمَعْنَى وَاحِدٌ قَالَا حَدَّثَنَا أَبَانُ قَالَ حَدَّثَنَا يَحْيَى عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ ابْنِ جَابِرِ بْنِ عَتِيكٍ عَنْ جَابِرِ بْنِ عَتِيكٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ مِنْ الْغَيْرَةِ مَا يُحِبُّ اللَّهُ وَمِنْهَا مَا يُبْغِضُ اللَّهُ فَأَمَّا الَّتِي يُحِبُّهَا اللَّهُ فَالْغَيْرَةُ فِي الرِّيبَةِ وَأَمَّا الْغَيْرَةُ الَّتِي يُبْغِضُهَا اللَّهُ فَالْغَيْرَةُ فِي غَيْرِ رِيبَةٍ وَإِنَّ مِنْ الْخُيَلَاءِ مَا يُبْغِضُ اللَّهُ وَمِنْهَا مَا يُحِبُّ اللَّهُ فَأَمَّا الْخُيَلَاءُ الَّتِي يُحِبُّ اللَّهُ فَاخْتِيَالُ الرَّجُلِ نَفْسَهُ عِنْدَ الْقِتَالِ وَاخْتِيَالُهُ عِنْدَ الصَّدَقَةِ وَأَمَّا الَّتِي يُبْغِضُ اللَّهُ فَاخْتِيَالُهُ فِي الْبَغْيِ قَالَ مُوسَى وَالْفَخْرِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], dan [Musa bin Isma'il] dan maknanya adalah satu. Mereka berkata; telah menceritakan kepada kami [Aban], ia berkata; telah menceritakan kepada kami [Yahya], dari [Muhammad bin Ibrahim], dari [Ibnu Jabir 'Atik] dari [Jabir bin 'Atik] bahwa Nabi Rasulullah shallallahu 'alaihi wasallam berkata: \"Diantara rasa cemburu ada yang dicintai Allah, dan diantara rasa cemburu tersebut ada yang dibenci Allah.\" Adapun rasa cemburu yang Allah 'azza wajalla cintai adalah cemburu dalam keraguan, adapun rasa cemburu yang Allah 'azza wajalla benci adalah kecemburuan yang tidak dalam keraguan. Dan diantara rasa bangga ada yang Allah benci dan diantara rasa bangga ada yang Allah benci, adapun rasa bangga yang Allah 'azza wajalla cintai adalah rasa bangga seseorang kepada dirinya ketika berperang dan bersedekah, sedangkan rasa bangga yang Allah 'azza wajalla benci adalah rasa bangga dalam kebatilan.\" Musa berkata; dan rasa sombong. "},"2222":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا إِبْرَاهِيمُ يَعْنِي ابْنَ سَعْدٍ أَخْبَرَنَا ابْنُ شِهَابٍ أَخْبَرَنِي عَمْرُو بْنُ جَارِيَةَ الثَّقَفِيُّ حَلِيفُ بَنِي زُهْرَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشَرَةً عَيْنًا وَأَمَّرَ عَلَيْهِمْ عَاصِمَ بْنَ ثَابِتٍ فَنَفَرُوا لَهُمْ هُذَيْلٌ بِقَرِيبٍ مِنْ مِائَةِ رَجُلٍ رَامٍ فَلَمَّا أَحَسَّ بِهِمْ عَاصِمٌ لَجَئُوا إِلَى قَرْدَدٍ فَقَالُوا لَهُمْ انْزِلُوا فَأَعْطُوا بِأَيْدِيكُمْ وَلَكُمْ الْعَهْدُ وَالْمِيثَاقُ أَنْ لَا نَقْتُلَ مِنْكُمْ أَحَدًا فَقَالَ عَاصِمٌ أَمَّا أَنَا فَلَا أَنْزِلُ فِي ذِمَّةِ كَافِرٍ فَرَمَوْهُمْ بِالنَّبْلِ فَقَتَلُوا عَاصِمًا فِي سَبْعَةِ نَفَرٍ وَنَزَلَ إِلَيْهِمْ ثَلَاثَةُ نَفَرٍ عَلَى الْعَهْدِ وَالْمِيثَاقِ مِنْهُمْ خُبَيْبٌ وَزَيْدُ بْنُ الدَّثِنَةِ وَرَجُلٌ آخَرُ فَلَمَّا اسْتَمْكَنُوا مِنْهُمْ أَطْلَقُوا أَوْتَارَ قِسِيِّهِمْ فَرَبَطُوهُمْ بِهَا فَقَالَ الرَّجُلُ الثَّالِثُ هَذَا أَوَّلُ الْغَدْرِ وَاللَّهِ لَا أَصْحَبُكُمْ إِنَّ لِي بِهَؤُلَاءِ لَأُسْوَةً فَجَرُّوهُ فَأَبَى أَنْ يَصْحَبَهُمْ فَقَتَلُوهُ فَلَبِثَ خُبَيْبٌ أَسِيرًا حَتَّى أَجْمَعُوا قَتْلَهُ فَاسْتَعَارَ مُوسَى يَسْتَحِدُّ بِهَا فَلَمَّا خَرَجُوا بِهِ لِيَقْتُلُوهُ قَالَ لَهُمْ خُبَيْبٌ دَعُونِي أَرْكَعُ رَكْعَتَيْنِ ثُمَّ قَالَ وَاللَّهِ لَوْلَا أَنْ تَحْسَبُوا مَا بِي جَزَعًا لَزِدْتُحَدَّثَنَا ابْنُ عَوْفٍ حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عَمْرُو بْنُ أَبِي سُفْيَانَ بْنِ أَسِيدِ بْنِ جَارِيَةَ الثَّقَفِيُّ وَهُوَ حَلِيفٌ لِبَنِي زُهْرَةَ وَكَانَ مِنْ أَصْحَابِ أَبِي هُرَيْرَةَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Ibrahim bin Sa'd], telah mengabarkan kepada kami [Ibnu Syihab] telah mengabarkan kepadaku ['Amr bin Jariyah Ats Tsaqafi], sekutu Bani Zuhrah, dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, ia berkata; Rasulullah shallallahu 'alaihi wasallam mengutus sepuluh orang mata-mata dan menganggkat 'Ashim bin Tsabit sebagai pemimpin. Kemudian orang-orang Hudzail keluar untuk memerangi mereka jumlah mereka sekitar seratus orang pemanah. Kemudian tatkala 'Ashim merasakan kedatangan orang-orang Hudzail tersebut maka mereka berlindung ke dataran tinggi. Kemudian orang-orang Hudzail tersebut berkata; turunlah, dan berikan tangan kalian. Untuk kalian perjanjian agar kami tidak membunuh seorangpun diantara kalian. Kemudian 'Ashim berkata; adapun aku, maka aku tidak akan turun dengan perlindungan orang kafir. Kemudian mereka memanah mereka dan membunuh 'Ashim diantara tujuh orang yang terbunuh. Dan tiga orang turun kepada mereka dengan perjanjian tersebut. Diantara ketiga orang tersebut adalah Khubaib, Zaid bin Ad Datsanah, seseorang yang lain. Kemudian tatkala orang-orang tersebut menguasai mereka maka mereka melepaskan tali busur mereka dan mengikat ketiga orang tersebut. Orang yang ketiga berkata; ini adalah awal pengingkaran janji. Demi Allah aku tidak akan menyertai kalian, sesungguhnya mereka adalah teladanku. Kemudian mereka menariknya namun ia menolak untuk mengikut mereka. Lalu mereka membunuhnya. Dan Khubaib tetap menjadi tawanan hingga mereka bersepakat untuk membunuhnya. Lalu ia meminjam pisau untuk mencukur rambut kemaluannya. Kemudian tatkala mereka keluar membawanya untuk mereka bunuh Khubaib berkata kepada mereka; biarkan aku untuk melakukan shalat dua raka'at! Kemudian ia berkata; demi Allah, seandainya kalian tidak menyangka bahwa aku takut niscaya aku akan menambahnya. Telah menceritakan kepada kami [Ibnu 'Auf], telah menceritakan kepada kami [Abu Al Yaman], telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri], telah mengabarkan kepadaku ['Amr bin Sufyan bin Asid bin Jariyah Ats Tsaqafi] ia adalah sekutu Bani Zuhrah, dan ia termasuk sahabat Abu Hurairah. Kemudian ia menyebutkan hadits. "},"2223":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَقَ قَالَ سَمِعْتُ الْبَرَاءَ يُحَدِّثُ قَالَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الرُّمَاةِ يَوْمَ أُحُدٍ وَكَانُوا خَمْسِينَ رَجُلًا عَبْدَ اللَّهِ بْنَ جُبَيْرٍ وَقَالَ إِنْ رَأَيْتُمُونَا تَخْطِفُنَا الطَّيْرُ فَلَا تَبْرَحُوا مِنْ مَكَانِكُمْ هَذَا حَتَّى أُرْسِلَ لَكُمْ وَإِنْ رَأَيْتُمُونَا هَزَمْنَا الْقَوْمَ وَأَوْطَأْنَاهُمْ فَلَا تَبْرَحُوا حَتَّى أُرْسِلَ إِلَيْكُمْ قَالَ فَهَزَمَهُمْ اللَّهُ قَالَ فَأَنَا وَاللَّهِ رَأَيْتُ النِّسَاءَ يُسْنِدْنَ عَلَى الْجَبَلِ فَقَالَ أَصْحَابُ عَبْدِ اللَّهِ بْنِ جُبَيْرٍ الْغَنِيمَةَ أَيْ قَوْمِ الْغَنِيمَةَ ظَهَرَ أَصْحَابُكُمْ فَمَا تَنْتَظِرُونَ فَقَالَ عَبْدُ اللَّهِ بْنُ جُبَيْرٍ أَنَسِيتُمْ مَا قَالَ لَكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا وَاللَّهِ لَنَأْتِيَنَّ النَّاسَ فَلَنُصِيبَنَّ مِنْ الْغَنِيمَةِ فَأَتَوْهُمْ فَصُرِفَتْ وُجُوهُهُمْ وَأَقْبَلُوا مُنْهَزِمِينَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Abu Ishaq], ia berkata; saya mendengar [Al Bara`] bercerita; ia berkata; Rasulullah shallallahu 'alaihi wasallam menunjuk Abdullah bin Jubair sebagai pemimpin para pemanah pada saat perang Uhud, dan jumlah mereka adalah lima puluh orang. Beliau bersabda: \"Apabila kalian melihat kami disambar burung, maka janganlah kalian meninggalkan tempat kalian ini hingga aku mengirimkan utusan kepada kalian. Dan apabila kalian melihat kami telah mengalahkan musuh dan kami memukul mereka, maka janganlah kalian meninggalkan tempat hingga aku mengirim utusan kepada kalian.\" Kemudian Allah mengalahkan mereka. Al Bara` berkata; demi Allah aku melihat para wanita menaiki gunung. Kemudian para sahabat Abdullah bin Jubair berkata; rampasan perang wahai kaum! Para sahabat kalian telah mendapat kemenangan, maka apa yang kalian tunggu? Kemudian Abdullah bin Jubair berkata; apakah kalian lupa apa yang dikatakan Rasulullah shallallahu 'alaihi wasallam kepada kalian? Kemudian mereka berkata; demi Allah, kami akan datang kepada orang-orang tersebut dan mendapatkan sebagian harta rampasan. Lalu mereka datang dengan wajah-wajah mereka dipalingkan (langkah tak menetu) dan dalam keadaan kalah."},"2224":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سُلَيْمَانَ بْنِ الْغَسِيلِ عَنْ حَمْزَةَ بْنِ أَبِي أُسَيْدٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ اصْطَفَفْنَا يَوْمَ بَدْرٍ إِذَا أَكْثَبُوكُمْ يَعْنِي إِذَا غَشُوكُمْ فَارْمُوهُمْ بِالنَّبْلِ وَاسْتَبْقُوا نَبْلَكُمْ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan], telah menceritakan kepada kami [Abu Ahmad Az Zubairi], telah menceritakan kepada kami [Abdurrahman bin Sulaiman bin Al Ghasil] dari [Hamzah bin Abu Usaid], dari [ayahnya], ia berkata; pada waktu perang Badr, disaat kami berbaris, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila (musuh) kalian telah mendekat kepada kalian, maka panahlah mereka dan sisakan anak panah kalian.\""},"2225":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا إِسْحَقُ بْنُ نَجِيحٍ وَلَيْسَ بِالْمَلْطِيِّ عَنْ مَالِكِ بْنِ حَمْزَةَ بْنِ أَبِي أُسَيْدٍ السَّاعِدِيِّ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ بَدْرٍ إِذَا أَكْثَبُوكُمْ فَارْمُوهُمْ بِالنَّبْلِ وَلَا تَسُلُّوا السُّيُوفَ حَتَّى يَغْشَوْكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Isa], telah menceritakan kepada kami [Ishaq bin Najih], bukan Al Malthi, dari [Malik bin Hamzah bin Abu Usaid As Sa'idi], dari [ayahnya], dari [kakeknya], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda pada saat perang Badr: \"Apabila mereka telah mendekat kepada kalian, maka panahlah mereka dan jangan kalian menghunus pedang hingga mereka telah dekat.\""},"2226":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَ��َا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ حَارِثَةَ بْنِ مُضَرِّبٍ عَنْ عَلِيٍّ قَالَتَقَدَّمَ يَعْنِي عُتْبَةَ بْنَ رَبِيعَةَ وَتَبِعَهُ ابْنُهُ وَأَخُوهُ فَنَادَى مَنْ يُبَارِزُ فَانْتَدَبَ لَهُ شَبَابٌ مِنْ الْأَنْصَارِ فَقَالَ مَنْ أَنْتُمْ فَأَخْبَرُوهُ فَقَالَ لَا حَاجَةَ لَنَا فِيكُمْ إِنَّمَا أَرَدْنَا بَنِي عَمِّنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُمْ يَا حَمْزَةُ قُمْ يَا عَلِيُّ قُمْ يَا عُبَيْدَةَ بْنَ الْحَارِثِ فَأَقْبَلَ حَمْزَةُ إِلَى عُتْبَةَ وَأَقْبَلْتُ إِلَى شَيْبَةَ وَاخْتُلِفَ بَيْنَ عُبَيْدَةَ وَالْوَلِيدِ ضَرْبَتَانِ فَأَثْخَنَ كُلُّ وَاحِدٍ مِنْهُمَا صَاحِبَهُ ثُمَّ مِلْنَا عَلَى الْوَلِيدِ فَقَتَلْنَاهُ وَاحْتَمَلْنَا عُبَيْدَةَ","id":"Telah menceritakan kepada kami [Harun bin Abdullah], telah menceritakan kepada kami [Utsman bin Umar], telah mengabarkan kepada kami [Israil] dari [Abu Ishaq] dari [Haritsah bin Mudharrib], dari [Ali], ia berkata; 'Utbah bin Rabi'ah telah datang dan diikuti anak dan saudaranya, kemudian ia berteriak; siapakah yang akan berperang tanding? Kemudian beberapa pemuda anshar menyambutnya. Kemudian ia berkata; siapakah kalian? Kemudian mereka memberitahukan kepadanya, lalu ia berkata; kami tidak butuh kepada kalian, kami hanya menghendaki anak-anak paman kami. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Berdirilah wahai Hamzah, berdirilah wahai Ali, berdirilah wahai 'Ubaidah bin Al Harits!\" Kemudian Hamzah menghadapi Utbah, dan aku menghadapi Syaibah. Dan 'Ubaidah serta Al Walid saling bergantian menebaskan pedang, dan masing-masing melukai serta melemahkan lawannya. Kemudian kami mendatangi Al Walid lalu kami membunuhnya dan kami membawa 'Ubaidah. "},"2227":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى وَزِيَادُ بْنُ أَيُّوبَ قَالَا حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا مُغِيرَةُ عَنْ شِبَاكٍ عَنْ إِبْرَاهِيمَ عَنْ هُنَيِّ بْنِ نُوَيْرَةَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعَفُّ النَّاسِ قِتْلَةً أَهْلُ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa], serta [Ziyad bin Ayyub], mereka berkata; telah menceritakan kepada kami [Husyaim], telah mengabarkan kepada kami [Mughirah] dari [Syibak] dari [Ibrahim] dari [Hunai bin Nuwairah], dari ['Al Qamah] dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang paling dapat menahan diri dalam membunuh adalah orang yang beriman.\""},"2228":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ الْهَيَّاجِ بْنِ عِمْرَانَأَنَّ عِمْرَانَ أَبَقَ لَهُ غُلَامٌ فَجَعَلَ لِلَّهِ عَلَيْهِ لَئِنْ قَدَرَ عَلَيْهِ لَيَقْطَعَنَّ يَدَهُ فَأَرْسَلَنِي لِأَسْأَلَ لَهُ فَأَتَيْتُ سَمُرَةَ بْنَ جُنْدُبٍ فَسَأَلْتُهُ فَقَالَ كَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحُثُّنَا عَلَى الصَّدَقَةِ وَيَنْهَانَا عَنْ الْمُثْلَةِ فَأَتَيْتُ عِمْرَانَ بْنَ حُصَيْنٍ فَسَأَلْتُهُ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحُثُّنَا عَلَى الصَّدَقَةِ وَيَنْهَانَا عَنْ الْمُثْلَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Mu'adz bin Hisyam], telah menceritakan kepadaku [ayahku], dari [Qatadah], dari [Al Hasan] dari [Al Hayyaj bin 'Imran] bahwa budak Imrah telah melarikan diri, dan ia bersumpah bahwa apabila ia mampu untuk menangkapnya maka niscaya ia akan memotong tangannya. Kemudian ia mengutusku agar bertanya untuknya, kemudian aku datang kepada [Samurah bin Jundub], dan menanyakan hal tersebut kepadanya. Kemudian ia berkata; Nabi shallallahu 'alaihi wasallam menganjurkan kami untuk bersedekah dan melarang kami dari mencincang. Lalu aku datang kepada [Imran bin Hushain] dan menanyakan hal tersebut kepadanya. Kemudian ia berkata; Rasulullah shallallahu 'alaihi wasallam menganjurkan kami untuk bersedekah dan melarang kami dari mencincang (memotong-motong bagian anggota tubuh). "},"2229":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ مَوْهَبٍ وَقُتَيْبَةُ يَعْنِي ابْنَ سَعِيدٍ قَالَا حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِأَنَّ امْرَأَةً وُجِدَتْ فِي بَعْضِ مَغَازِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَقْتُولَةً فَأَنْكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَتْلَ النِّسَاءِ وَالصِّبْيَانِ","id":"Telah menceritakan kepada kami [Yazid? bin Khalid bin Mauhib], serta [Qutaibah bin Sa'id], mereka berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'], dari [Abdullah] bahwa seorang wanita telah didapati terbunuh dalam sebagian peperangan yang diikuti Rasulullah shallallahu wa'alaihi wa sallam, kemudian Rasulullah shallallahu 'alaihi wasallam mengingkari pembunuhan wanita dan anak-anak. "},"2230":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا عُمَرُ بْنُ الْمُرَقَّعِ بْنِ صَيْفِيِّ بْنِ رَبَاحٍ قَالَ حَدَّثَنِي أَبِي عَنْ جَدِّهِ رَبَاحِ بْنِ رَبِيعٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ فَرَأَى النَّاسَ مُجْتَمِعِينَ عَلَى شَيْءٍ فَبَعَثَ رَجُلًا فَقَالَ انْظُرْ عَلَامَ اجْتَمَعَ هَؤُلَاءِ فَجَاءَ فَقَالَ عَلَى امْرَأَةٍ قَتِيلٍ فَقَالَ مَا كَانَتْ هَذِهِ لِتُقَاتِلَ قَالَ وَعَلَى الْمُقَدِّمَةِ خَالِدُ بْنُ الْوَلِيدِ فَبَعَثَ رَجُلًا فَقَالَ قُلْ لِخَالِدٍ لَا يَقْتُلَنَّ امْرَأَةً وَلَا عَسِيفًا","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi], telah menceritakan kepada kami [Umar bin Al Muraqqa' bin Shaifi bin Rabah], ia berkata; telah menceritakan kepadaku [ayahku], dari [kakekku yaitu Rabah bin Rabi'], ia berkata; kami pernah bersama dalam sebuah pertempuran. Kemudian beliau melihat orang-orang berkumpul mengerumuni sesuatu. Kemudian beliau mengirim seseorang dan berkata: \"Lihatlah, apakah yang mereka kerumuni?\" kemudian orang tersebut datang dan berkata; mengerumuni seorang wanita yang terbunuh. Kemudian beliau berkata; tidak sepantasnya orang ini untuk berperang. Sementara baris depan Khalid bin Al Walid. Kemudian beliau mengutus seseorang dan beliau berkata; katakan kepada Khalid; agar ia tidak membunuh wanita dan orang utusan. "},"2231":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا قَتَادَةُ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْتُلُوا شُيُوخَ الْمُشْرِكِينَ وَاسْتَبْقُوا شَرْخَهُمْ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Husyaim], telah menceritakan kepada kami [Hajjaj], telah menceritakan kepada kami [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bunuhlah orang-orang tua yang musyrik, dan biarkan anak-anak kecil.\""},"2232":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي مُحَمَّدُ بْنُ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْلَمْ يُقْتَلْ مِنْ نِسَائِهِمْ تَعْنِي بَنِي قُرَيْظَةَ إِلَّا امْرَأَةٌ إِنَّهَا لَعِنْدِي تُحَدِّثُ تَضْحَكُ ظَهْرًا وَبَطْنًا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْتُلُ رِجَالَهُمْ بِالسُّيُوفِ إِذْ هَتَفَ هَاتِفٌ بِاسْمِهَا أَيْنَ فُلَانَةُ قَالَتْ أَنَا قُلْتُ وَمَا شَأْنُكِ قَالَتْ حَدَثٌ أَحْدَثْتُهُ قَالَتْ فَانْطَلَقَ بِهَا فَضُرِبَتْ عُنُقُهَا فَمَا أَنْسَى عَجَبًا مِنْهَا أَنَّهَا تَضْحَكُ ظَهْرًا وَبَطْنًا وَقَدْ عَلِمَتْ أَنَّهَا تُقْتَلُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Muhammad bin Salamah], dari [Muhammad bin Ishaq], telah menceritakan kepadaku [Muhammad bin Ja'far bin Az Zubair] dari ['Urwah bin Az Zubair] dari [Aisyah], ia berkata; tidak ada yang terbunuh diantara para wanita Bani Quraizhah kecuali seorang wanita, sesungguhnya ia di sisiku berbicara dan tertawa luar dalam. Dan Rasulullah shallallahu 'alaihi wasallam membunuh laki-laki mereka dengan pedang, tiba-tiba terdapat orang yang menyebutkan namanya; dimanakah Fulanah? Ia berkata; aku. Maka aku katakan; ada apa denganmu? Wanita tersebut berkata; ada suatu kejadian yang telah aku lakukan. Aisyah berkata; kemudian orang tersebut pergi membawa wanita tersebut kemudian leher wanita tersebut dipenggal. Aku tidak melupakan sesuatu yang aneh. Bahwa ia tertawa luar dalam sementara ia mengetahui bahwa ia akan dibunuh. "},"2233":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ يَعْنِي ابْنَ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ الصَّعْبِ ابْنِ جَثَّامَةَأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدَّارِ مِنْ الْمُشْرِكِينَ يُبَيَّتُونَ فَيُصَابُ مِنْ ذَرَارِيِّهِمْ وَنِسَائِهِمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُمْ مِنْهُمْ وَكَانَ عَمْرٌو يَعْنِي ابْنَ دِينَارٍ يَقُولُ هُمْ مِنْ آبَائِهِمْ قَالَ الزُّهْرِيُّ ثُمَّ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ عَنْ قَتْلِ النِّسَاءِ وَالْوِلْدَانِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amr bin As Sarh], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri], dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Ash Sha'bin bin Jatstsamah] bahwa ia telah bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai sebuah kampung orang-orang musyrikin yang diserang pada malam hari. Kemudian ditawan anak-anak dan wanita mereka. Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Mereka merupakan bagian dari mereka.\" 'Amr bin Dinar berkata; beliau berkata: \"Mereka merupakan bagian dari bapak-bapak mereka.\" Az Zuhri berkata; kemudian setelah itu Rasulullah shallallahu 'alaihi wasallam melarang membunuh para wanita dan anak-anak. "},"2234":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا مُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ الْحِزَامِيُّ عَنْ أَبِي الزِّنَادِ حَدَّثَنِي مُحَمَّدُ بْنُ حَمْزَةَ الْأَسْلَمِيُّ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّرَهُ عَلَى سَرِيَّةٍ قَالَ فَخَرَجْتُ فِيهَا وَقَالَ إِنْ وَجَدْتُمْ فُلَانًا فَأَحْرِقُوهُ بِالنَّارِ فَوَلَّيْتُ فَنَادَانِي فَرَجَعْتُ إِلَيْهِ فَقَالَ إِنْ وَجَدْتُمْ فُلَانًا فَاقْتُلُوهُ وَلَا تُحْرِقُوهُ فَإِنَّهُ لَا يُعَذِّبُ بِالنَّارِ إِلَّا رَبُّ النَّارِحَدَّثَنَا يَزِيدُ بْنُ خَالِدٍ وَقُتَيْبَةُ أَنَّ اللَّيْثَ بْنَ سَعْدٍ حَدَّثَهُمْ عَنْ بُكَيْرٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَ بَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْثٍ فَقَالَ إِنْ وَجَدْتُمْ فُلَانًا وَفُلَانًا فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Mughirah bin Abdurrahman Al Hizami], dari [Abu Az Zinad], telah menceritakan kepadaku [Muhammad bin Hamzah Al Aslami], dari [ayahnya], bahwa Rasulullah shallallahu wa'alaihi wa sallam telah menunjuknya sebagai pemimpin sebuah kesatuan militer. Hamzah Al Aslami berkata; kemudian aku keluar diantara pasukan tersebut. Beliau berkata: \"Apabila kalian mendapatkan Fulan, maka bakarlah dia dengan api.\" Kemudian aku pergi, lalu beliau memanggilku lalu aku kembali kepada beliau. Beliau berkata: \"Apabila kalian mendapatkan Fulan maka bunuhlah dia, dan jangan kalian bakar! Sesungguhnya tidak ada yang boleh menyiksa dengan api kecuali Tuhan Penguasa api.\" Telah menceritakan kepada kami [Yazid? bin Khalid], dan [Qutaibah] bahwa [Al Laits bin Sa'd] telah menceritakan kepada mereka dari [Bukair] dari [Sulaiman bin Yasar] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam mengirim kami dalam sebuah pasukan. Kemudian beliau berkata: \"Apabila kalian mendapatkan Fulan dan Fulan ….. kemudian Yazid bin Khalid menyebutkan hadits semakna dengan hadits tersebut. "},"2235":{"ar":"حَدَّثَنَا أَبُو صَالِحٍ مَحْبُوبُ بْنُ مُوسَى أَخْبَرَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ أَبِي إِسْحَقَ الشَّيْبَانِيِّ عَنْ ابْنِ سَعْدٍ قَالَ غَيْرُ أَبِي صَالِحٍ عَنْ الْحَسَنِ بْنِ سَعْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَانْطَلَقَ لِحَاجَتِهِ فَرَأَيْنَا حُمَرَةً مَعَهَا فَرْخَانِ فَأَخَذْنَا فَرْخَيْهَا فَجَاءَتْ الْحُمَرَةُ فَجَعَلَتْ تَفْرِشُ فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ��َقَالَ مَنْ فَجَعَ هَذِهِ بِوَلَدِهَا رُدُّوا وَلَدَهَا إِلَيْهَا وَرَأَى قَرْيَةَ نَمْلٍ قَدْ حَرَّقْنَاهَا فَقَالَ مَنْ حَرَّقَ هَذِهِ قُلْنَا نَحْنُ قَالَ إِنَّهُ لَا يَنْبَغِي أَنْ يُعَذِّبَ بِالنَّارِ إِلَّا رَبُّ النَّارِ","id":"Telah menceritakan kepada kami [Abu Shalih Mahbub bin Musa], telah mengabarkan kepada kami [Abu Ishaq Al Fazari], dari [Abu Ishaq Asy Syaibani], dari [Ibnu Sa'd], telah berkata selain Shalih, dari Al Hasan bin Sa'd dari [Abdurrahman bin Abdullah] dari [ayahnya], ia berkata; kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, kemudian beliau pergi untuk suatu keperluannya, kemudian kami melihat seekor burung bersama kedua anaknya. Lalu kami mengambil kedua anaknya, kemudian burung tersebut datang dan mengepak-ngepakkan sayapnya. Kemudian Nabi shallallahu 'alaihi wasallam datang dan berkata: \"Siapakah yang menyakiti burung ini dengan mengambil anaknya? Kembalikan anaknya kepadanya.\" Dan Rasulullah shallallahu 'alaihi wasallam melihat kelompok semut yang telah kami bakar, kemudian beliau bersabda: \"Siapakah yang telah membakar semut ini?\" Kami katakan; kami. Beliau berkata: \"Sesungguhnya tidak layak untuk menyiksa dengan api kecuali Tuhan Penguasa api.\""},"2236":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ أَبُو النَّضْرِ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ أَخْبَرَنِي أَبُو زَرْعَةَ يَحْيَى بْنُ أَبِي عَمْرٍو السَّيْبَانِيُّ عَنْ عَمْرِو بْنِ عَبْدِ اللَّهِ أَنَّهُ حَدَّثَهُ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ فَخَرَجْتُ إِلَى أَهْلِي فَأَقْبَلْتُ وَقَدْ خَرَجَ أَوَّلُ صَحَابَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَفِقْتُ فِي الْمَدِينَةِ أُنَادِي أَلَا مَنْ يَحْمِلُ رَجُلًا لَهُ سَهْمُهُ فَنَادَى شَيْخٌ مِنْ الْأَنْصَارِ قَالَ لَنَا سَهْمُهُ عَلَى أَنْ نَحْمِلَهُ عَقَبَةً وَطَعَامُهُ مَعَنَا قُلْتُ نَعَمْ قَالَ فَسِرْ عَلَى بَرَكَةِ اللَّهِ تَعَالَى قَالَ فَخَرَجْتُ مَعَ خَيْرِ صَاحِبٍ حَتَّى أَفَاءَ اللَّهُ عَلَيْنَا فَأَصَابَنِي قَلَائِصُ فَسُقْتُهُنَّ حَتَّى أَتَيْتُهُ فَخَرَجَ فَقَعَدَ عَلَى حَقِيبَةٍ مِنْ حَقَائِبِ إِبِلِهِ ثُمَّ قَالَ سُقْهُنَّ مُدْبِرَاتٍ ثُمَّ قَالَ سُقْهُنَّ مُقْبِلَاتٍ فَقَالَ مَا أَرَى قَلَائِصَكَ إِلَّا كِرَامًا قَالَ إِنَّمَا هِيَ غَنِيمَتُكَ الَّتِي شَرَطْتُ لَكَ قَالَ خُذْ قَلَائِصَكَ يَا ابْنَ أَخِي فَغَيْرَ سَهْمِكَ أَرَدْنَا","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Ad Damasyqi Abu An Nadhr], telah menceritakan kepada kami [Muhammad bin Syu'aib], telah mengabarkan kepadaku [Abu Zar'ah bin Abu 'Amr As Saibani], dari ['Amr bin Abdullah] bahwa ia telah menceritakan kepadanya dari [Watsilah bin Al Asqa'], ia berkata; Rasulullah shallallahu 'alaihi wasallam berada pada perang Tabuk, kemudian aku keluar kepada keluargaku lalu datang, sementara sahabat Rasulullah shallallahu 'alaihi wasallam yang pertama telah keluar, kemudian aku berseru di Madinah; adakah orang yang mau membawa seseorang dan untuknya sahamnya? Kemudian terdapat orang tua dari kalangan anshar berseru; untuk kami saham (bagian) nya, dengan kami memboncengkannya di belakang, dan makanannya bersama kami. Aku katakan; ya. Watsilah berkata; lalu aku berjalan dengan berkah Allah ta'ala. Ia berkata; aku keluar bersama teman terbaik hingga Allah memberikan harta fai` (rampasan perang) kepada kami. Aku mendapatkan beberapa unta, kemudian aku menggiringnya hingga aku datang kepadanya. Lalu ia keluar dan duduk di atas ransel diantara ransel-ransel untanya kemudian ia berkata; giringlah unta-unta tersebut mundur! Kemudian ia berkata; giringlah unta-unta tersebut maju! Lalu ia berkata; aku tidak mengetahui unta-untamu melainkan adalah unta-unta yang mulia. Ia berkata; sesungguhnya unta-unta tersebut adalah ghanimahmu yang telah aku syaratkan kepadamu. Ia berkata; ambillah unta-untamu wahai saudaraku. Kami menginginkan selain saham (bagian) mu. "},"2237":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ أَخْبَرَنَا مُحَمَّدُ بْنُ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَجِبَ رَبُّنَا عَزَّ وَجَلَّ مِنْ قَوْمٍ يُقَادُونَ إِلَى الْجَنَّةِ فِي السَّلَاسِلِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad bin Salamah], telah mengabarkan kepada kami [Muhammad bin Ziyad], ia berkata; saya mendengar [Abu Hurairah] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam berkata; Tuhan kita 'azza wajalla kagum kepada sebuah kaum yang digiring menuju Surga dalam rantai. "},"2238":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ أَبِي الْحَجَّاجِ أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ يَعْقُوبَ بْنِ عُتْبَةَ عَنْ مُسْلِمِ بْنِ عَبْدِ اللَّهِ عَنْ جُنْدُبِ بْنِ مَكِيثٍ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدَ اللَّهِ بْنَ غَالِبٍ اللَّيْثِيَّ فِي سَرِيَّةٍ وَكُنْتُ فِيهِمْ وَأَمَرَهُمْ أَنْ يَشُنُّوا الْغَارَةَ عَلَى بَنِي الْمُلَوِّحِ بِالْكَدِيدِ فَخَرَجْنَا حَتَّى إِذَا كُنَّا بِالْكَدِيدِ لَقِينَا الْحَارِثَ بْنَ الْبَرْصَاءِ اللَّيْثِيَّ فَأَخَذْنَاهُ فَقَالَ إِنَّمَا جِئْتُ أُرِيدُ الْإِسْلَامَ وَإِنَّمَا خَرَجْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْنَا إِنْ تَكُنْ مُسْلِمًا لَمْ يَضُرَّكَ رِبَاطُنَا يَوْمًا وَلَيْلَةً وَإِنْ تَكُنْ غَيْرَ ذَلِكَ نَسْتَوْثِقُ مِنْكَ فَشَدَدْنَاهُ وِثَاقًا","id":"Telah menceritakan kepada kami [Abdullah bin 'Amr bin Abu Al Hajjaj Abu Ma'mar], telah menceritakan kepada kami [Abdul Warits], telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Ya'qub bin 'Utbah], dari [Muslim bin Abdullah] dari [Jundub bin Makits], ia berkata; Rasulullah shallallahu 'alaihi wasallam mengirim Abdullah bin Ghalib Al Laits dalam sebuah kesatuan militer, dan aku berada diantara mereka. Dan beliau memerintahkan mereka agar menyebar dalam menyerang Bani Al Mulawwih di Al Kadid. Kemudian kami keluar hingga kami sampai di Al Kadid kami bertemu dengan Al Harits bin Al Barsha` Al Laitsi lalu kami menangkapnya. Kemudian ia berkata; sesungguhnya saya datang untuk masuk Islam. Sesungguhnya aku keluar kepada Rasulullah shallallahu 'alaihi wasallam. Maka kami katakan; apabila engkau adalah seorang muslim maka para penjaga kami tidak akan membahayakanmu selama satu hari satu malam. Dan jika engkau tidak demikian maka kami akan mengikatmu dan akan kami kencangkan ikatanmu. "},"2239":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ الْمِصْرِيُّ وَقُتَيْبَةُ قَالَ قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْلًا قِبَلَ نَجْدٍ فَجَاءَتْ بِرَجُلٍ مِنْ بَنِي حَنِيفَةَ يُقَالُ لَهُ ثُمَامَةُ بْنُ أُثَالٍ سَيِّدُ أَهْلِ الْيَمَامَةِ فَرَبَطُوهُ بِسَارِيَةٍ مِنْ سَوَارِي الْمَسْجِدِ فَخَرَجَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَاذَا عِنْدَكَ يَا ثُمَامَةُ قَالَ عِنْدِي يَا مُحَمَّدُ خَيْرٌ إِنْ تَقْتُلْ تَقْتُلْ ذَا دَمٍ وَإِنْ تُنْعِمْ تُنْعِمْ عَلَى شَاكِرٍ وَإِنْ كُنْتَ تُرِيدُ الْمَالَ فَسَلْ تُعْطَ مِنْهُ مَا شِئْتَ فَتَرَكَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كَانَ الْغَدُ ثُمَّ قَالَ لَهُ مَا عِنْدَكَ يَا ثُمَامَةُ فَأَعَادَ مِثْلَ هَذَا الْكَلَامِ فَتَرَكَهُ حَتَّى كَانَ بَعْدَ الْغَدِ فَذَكَرَ مِثْلَ هَذَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَطْلِقُوا ثُمَامَةَ فَانْطَلَقَ إِلَى نَخْلٍ قَرِيبٍ مِنْ الْمَسْجِدِ فَاغْتَسَلَ فِيهِ ثُمَّ دَخَلَ الْمَسْجِدَ فَقَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَسَاقَ الْحَدِيثَ قَالَ عِيسَى أَخْبَرَنَا اللَّيْثُ وَقَالَ ذَا ذِمٍّ","id":"Telah menceritakan kepada kami [Isa bin Hammad Al Mishri], dan [Qutaibah], Qutaibah berkata; telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Sa'id bin Abu Sa'id] bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam mengirimkan pasukan penunggang kuda menuju Najd, kemudian pasukan tersebut membawa seorang laki-laki dari Bani Hanifah yang bernama Tsumamah bin Utsal pemimpin penduduk Yamamah. Kemudian mereka mengikatnya pada sebuah tiang masjid, kemudian Rasulullah shallallahu 'alaihi wasallam keluar kepadanya. Lalu beliau berkata: \"Bagaimana keadaanmu wahai Tsumamah?\" Ia berkata; keadaanku baik wahai Muhammad. Apabila engkau membunuh maka engkau membunuh orang yang memiliki darah, dan apabila engkau memberi kenikmatan maka engkau memberi kenikmatan kepada orang yang akan berterima kasih. Dan apabila engkau menghendaki harta, mintalah maka engkau akan diber apa yang engkau kehendaki. Kemudian Rasulullah shallallahu 'alaihi wasallam meninggalkannya. Kemudian keesokan harinya beliau berkata: \"Bagaimana keadaanmu wahai Tsumamah?\" kemudian ia mengulangi seperti perkataan ini. Lalu beliau meninggalkannya. Kemudian keesokan harinya, lalu beliau menyebutkan seperti ini. Lalu beliau berkata: \"Lepaskan Tsumamah!\" Kemudian ia pergi ke sebuah pohon kurma dekat masjid, lalu ia mandi padanya kemudian memasuki masjid dan berkata; aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah dan aku bersaksi bahwa Muhammad adalah hamba dan utusanNya. Dan Abu Hurairah menyebutkan hadits tersebut. Isa berkata; telah mengabarkan kepada kami [Al Laits] dan ia mengatakan; orang yang memiliki celaan. "},"2240":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو الرَّازِيُّ قَالَ حَدَّثَنَا سَلَمَةُ يَعْنِي ابْنَ الْفَضْلِ عَنْ ابْنِ إِسْحَقَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ قَالَقُدِمَ بِالْأُسَارَى حِينَ قُدِمَ بِهِمْ وَسَوْدَةُ بِنْتُ زَمْعَةَ عِنْدَ آلِ عَفْرَاءَ فِي مُنَاخِهِمْ عَلَى عَوْفٍ وَمُعَوِّذٍ ابْنَيْ عَفْرَاءَ قَالَ وَذَلِكَ قَبْلَ أَنْ يُضْرَبَ عَلَيْهِنَّ الْحِجَابُ قَالَ تَقُولُ سَوْدَةُ وَاللَّهِ إِنِّي لَعِنْدَهُمْ إِذْ أَتَيْتُ فَقِيلَ هَؤُلَاءِ الْأُسَارَى قَدْ أُتِيَ بِهِمْ فَرَجَعْتُ إِلَى بَيْتِي وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِ وَإِذَا أَبُو يَزِيدَ سُهَيْلُ بْنُ عَمْرٍو فِي نَاحِيَةِ الْحُجْرَةِ مَجْمُوعَةٌ يَدَاهُ إِلَى عُنُقِهِ بِحَبْلٍ ثُمَّ ذَكَرَ الْحَدِيثَقَالَ أَبُو دَاوُد وَهُمَا قَتَلَا أَبَا جَهْلِ بْنَ هِشَامٍ وَكَانَا انْتَدَبَا لَهُ وَلَمْ يَعْرِفَاهُ وَقُتِلَا يَوْمَ بَدْرٍ","id":"Telah menceritakan kepada kami [Muhammad bin 'Amr Ar Razi], ia berkata; telah menceritakan kepada kami [Salamah bin Al Fadhl] dari [Ibnu Ishaq], ia berkata; telah menceritakan kepadaku [Abdullah bin Abu Bakr] dari [Yahya bin Abdullah bin Abdurrahman bin Sa'd bin Zurarah], ia berkata; telah di hadapkan beberapa tawanan kepada 'Auf dan 'Mu'awwidz kedua anak 'Afra` ketika [Saudah binti Zam'ah] berada di rumah keluarga 'Afra` di tempat penambatan unta mereka, dan hal tersebut sebelum diwajibkannya berhijab. Yahya berkata; Saudah berkata; demi Allah, aku berada di rumah mereka tatkala aku datang. Kemudian dikatakan; para tawanan ini telah dibawa. Kemudian aku kembali ke rumahku dan Rasulullah shallallahu 'alaihi wasallam berada di dalamnya. Dan ternyata Abu Yazid Suhail bin 'Amr berada di pojok ruangan tangannya terikat di lehernya dengan sebuah tali. Kemudian Yahya menyebutkan hadits tersebut. Abu Daud berkata; dan keduanya telah membunuh Abu Jahl bin Hisyam, dan keduanya telah menyambutnya dan tidak mengenalnya, dan mereka berdua terbunuh pada saat perang Badr. "},"2241":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَدَبَ أَصْحَابَهُ فَانْطَلَقُوا إِلَى بَدْرٍ فَإِذَا هُمْ بِرَوَايَا قُرَيْشٍ فِيهَا عَبْدٌ أَسْوَدُ لِبَنِي الْحَجَّاجِ فَأَخَذَهُ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلُوا يَسْأَلُونَهُ أَيْنَ أَبُو سُفْيَانَ فَيَقُولُ وَاللَّهِ مَالِي بِشَيْءٍ مِنْ أَمْرِهِ عِلْمٌ وَلَكِ��ْ هَذِهِ قُرَيْشٌ قَدْ جَاءَتْ فِيهِمْ أَبُو جَهْلٍ وَعُتْبَةُ وَشَيْبَةُ ابْنَا رَبِيعَةَ وَأُمَيَّةُ بْنُ خَلَفٍ فَإِذَا قَالَ لَهُمْ ذَلِكَ ضَرَبُوهُ فَيَقُولُ دَعُونِي دَعُونِي أُخْبِرْكُمْ فَإِذَا تَرَكُوهُ قَالَ وَاللَّهِ مَالِي بِأَبِي سُفْيَانَ مِنْ عِلْمٍ وَلَكِنْ هَذِهِ قُرَيْشٌ قَدْ أَقْبَلَتْ فِيهِمْ أَبُو جَهْلٍ وَعُتْبَةُ وَشَيْبَةُ ابْنَا رَبِيعَةَ وَأُمَيَّةُ بْنُ خَلَفٍ قَدْ أَقْبَلُوا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَهُوَ يَسْمَعُ ذَلِكَ فَلَمَّا انْصَرَفَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنَّكُمْ لَتَضْرِبُونَهُ إِذَا صَدَقَكُمْ وَتَدَعُونَهُ إِذَا كَذَبَكُمْ هَذِهِ قُرَيْشٌ قَدْ أَقْبَلَتْ لِتَمْنَعَ أَبَا سُفْيَانَ قَالَ أَنَسٌ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا مَصْرَعُ فُلَانٍ غَدًا وَوَضَعَ يَدَهُ عَلَى الْأَرْضِ وَهَذَا مَصْرَعُ فُلَانٍ غَدًا وَوَضَعَ يَدَهُ عَلَى الْأَرْضِ وَهَذَا مَصْرَعُ فُلَانٍ غَدًا وَوَضَعَ يَدَهُ عَلَى الْأَرْضِ فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ مَا جَاوَزَ أَحَدٌ مِنْهُمْ عَنْ مَوْضِعِ يَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُخِذَ بِأَرْجُلِهِمْ فَسُحِبُوا فَأُلْقُوا فِي قَلِيبِ بَدْرٍ","id":"Telah menceritakan kepada kami [Musa bin Ismai'i], ia berkata; telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam memanggil para sahabatnya, kemudian mereka pergi ke Badr, dan ternyata mereka mendapatkan beberapa unta Quraisy padanya terdapat seorang budak hitam milik Bani Hajjaj, kemudian ia ditangkap para sahabat Rasulullah shallallahu 'alaihi wasallam. Kemudian mereka menginterogasinya; dimanakah Abu Sufyan? Kemudian budak tersebut berkata; demi Allah, aku tidak tahu mengenainya sama sekali. Akan tetapi orang-orang Quraisy telah datang, diantara mereka terdapat Abu Jahl dan 'Utbah serta Syaibah dua anak Rabi'ah, dan Umayyah bin Khalaf. Ketika ia berkata demikian kepada mereka maka mereka memukulinya, lalu ia berkata; biarkan aku, biarkan aku! Aku akan beritahu kalian. Kemudian tatkala mereka membiarkannya ia berkata; demi Allah aku tidak mengetahui mengenai Abu Sufyan sama sekali. Akan tetapi orang-orang Quraisy telah datang, diantara mereka terdapat Abu Jahl dan 'Utbah serta Syaibah dua anak Rabi'ah, dan Umayyah bin Khalaf. Mereka telah datang. Sementera Nabi shallallahu 'alaihi wasallam melakukan shalat dan mendengar hal tersebut, kemudian tatkala pergi beliau mengatakan; demi Dzat yang jiwaku ada di tanganNya, sesungguhnya kalian akan memukulnya apabila ia berkata jujur kepada kalian, dan kalian akan membiarkannya apabila ia berdusta kepada kalian. Inilah orang-orang Quraisy, mereka telah datang untuk mencegah Abu Sufyan. Anas berkata; Rasulullah shallallahu 'alaihi wasallam berkata: \"Ini adalah tempat terbunuhnya Fulan besok.\" Dan beliau meletakkan tangannya di atas tanah.\"Dan ini adalah tempat terbunuhnya Fulan besok.\" Dan beliau meletakkan tangannya di atas tanah.\"Dan ini adalah tempat terbunuhnya Fulan besok.\" Dan beliau meletakkan tangannya di atas tanah. Anas berkata; demi Allah tidak ada seorangpun diantara mereka yang melewati tempat tangan Rasulullah shallallahu 'alaihi wasallam. Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan agar mereka dikumpulkan, lalu dipegang kaki mereka dan diseret dan dilemparkan ke dalam lubang Badr. "},"2242":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ عَلِيٍّ الْمُقَدَّمِيُّ قَالَ حَدَّثَنَا أَشْعَثُ بْنُ عَبْدِ اللَّهِ يَعْنِي السِّجِسْتَانِيَّ ح و حَدَّثَنَا ابْنُ بَشَّارٍ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ وَهَذَا لَفْظُهُ ح و حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ عَنْ شُعْبَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَتْ الْمَرْأَةُ تَكُونُ مِقْلَاتًا فَتَجْعَلُ عَلَى نَفْسِهَا إِنْ عَاشَ لَهَا وَلَدٌ أَنْ تُهَوِّدَهُ فَلَمَّا أُجْلِيَتْ بَنُو النَّضِيرِ كَانَ فِيهِمْ مِنْ أَبْنَاءِ الْأَنْصَارِ فَقَالُوا لَا نَدَعُ أَبْنَاءَنَا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَا إِكْرَاهَ فِي الدِّينِ قَدْ تَبَيَّنَ الرُّشْدُ مِنْ الْغَيِّ }قَالَ أَبُو دَاوُد الْمِقْلَاتُ الَّتِي لَا يَعِيشُ لَهَا وَلَدٌ","id":"Telah menceritakan kepada kami [Muhammad bin Umar bin Ali Al Muqaddami], ia berkata; telah menceritakan kepada kami [Asy'ats bin Abdullah As Sijistani], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ibnu Basysyar], ia berkata; telah menceritakan kepada kami [Ibnu Abu Adi], dan ini adalah lafazhnya. Dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Al Hasan bin Ali], ia berkata; telah menceritakan kepada kami [Wahb bin Jarir], dari [Syu'bah] dari [Abu Bisyr] dari [Sa'id? bin Jubair] dari [Ibnu Abbas], ia berkata; terdapat seorang wanita yang tidak memiliki anak karena terus meninggal, kemudian ia bersumpah atas dirinya bahwa apabila ia memiliki anak yang hidup maka ia akan menjadikannya seorang Yahudi. Kemudian tatkala Bani Nadhir diusir, diantara mereka terdapat anak-anak orang anshar, kemudian mereka mengatakan; kita tidak akan meninggalkan anak-anak kita. Kemudian Allah menurunkan ayat: \"Tidak ada paksaan untuk (memasuki) agama (Islam); sesungguhnya telah jelas jalan yang benar daripada jalan yang sesat.\" Abu Daud berkata; Miqlat adalah wanita yang tidak memiliki anak yang hidup. "},"2243":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا أَسْبَاطُ بْنُ نَصْرٍ قَالَ زَعَمَ السُّدِّيُّ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ سَعْدٍ قَالَلَمَّا كَانَ يَوْمُ فَتْحِ مَكَّةَ أَمَّنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسَ إِلَّا أَرْبَعَةَ نَفَرٍ وَامْرَأَتَيْنِ وَسَمَّاهُمْ وَابْنُ أَبِي سَرْحٍ فَذَكَرَ الْحَدِيثَ قَالَ وَأَمَّا ابْنُ أَبِي سَرْحٍ فَإِنَّهُ اخْتَبَأَ عِنْدَ عُثْمَانَ بْنِ عَفَّانَ فَلَمَّا دَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسَ إِلَى الْبَيْعَةِ جَاءَ بِهِ حَتَّى أَوْقَفَهُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا نَبِيَّ اللَّهِ بَايِعْ عَبْدَ اللَّهِ فَرَفَعَ رَأْسَهُ فَنَظَرَ إِلَيْهِ ثَلَاثًا كُلُّ ذَلِكَ يَأْبَى فَبَايَعَهُ بَعْدَ ثَلَاثٍ ثُمَّ أَقْبَلَ عَلَى أَصْحَابِهِ فَقَالَ أَمَا كَانَ فِيكُمْ رَجُلٌ رَشِيدٌ يَقُومُ إِلَى هَذَا حَيْثُ رَآنِي كَفَفْتُ يَدِي عَنْ بَيْعَتِهِ فَيَقْتُلُهُ فَقَالُوا مَا نَدْرِي يَا رَسُولَ اللَّهِ مَا فِي نَفْسِكَ أَلَا أَوْمَأْتَ إِلَيْنَا بِعَيْنِكَ قَالَ إِنَّهُ لَا يَنْبَغِي لِنَبِيٍّ أَنْ تَكُونَ لَهُ خَائِنَةُ الْأَعْيُنِقَالَ أَبُو دَاوُد كَانَ عَبْدُ اللَّهِ أَخَا عُثْمَانَ مِنْ الرِّضَاعَةِ وَكَانَ الْوَلِيدُ بْنُ عُقْبَةَ أَخَا عُثْمَانَ لِأُمِّهِ وَضَرَبَهُ عُثْمَانُ الْحَدَّ إِذْ شَرِبَ الْخَمْرَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], ia berkata; telah menceritakan kepada kami [Ahmad bin Al Mufadhdhal], ia berkata; telah menceritakan kepada kami [Asbath bin Nashr], ia berkata; [As Suddi] mengaku dari [Mush'ab bin Sa'd], dari [Sa'id], ia berkata; tatkala terjadi penaklukan Mekkah Rasulullah shallallahu 'alaihi wasallam memberikan keamanan kepada semua orang kecuali empat orang laki-laki dan dua orang wanita, dan beliau menyebutkan mereka, serta Ibnu Abu Sarh. Kemudian Sa'id menyebutkan hadits tersebut, ia berkata; adapun Ibnu Abu Sarh, ia bersembunyi di rumah Utsman bin Affan, kemudian tatkala Rasulullah shallallahu 'alaihi wasallam menyeru untuk berbai'ah, Utsman membawanya ke hadapan Rasulullah shallallahu wa'alaihi wa sallam dan berkata; wahai Nabi Allah, bai'atlah Abdullah. Kemudian beliau mengangkat kepalanya dan melihat kepadanya tiga kali, setiap melakukan tersebut beliau enggan untuk memba'iatnya. Kemudian setelah tiga kali beliau membai'atnya lalu beliau menghadap kepada para sahabatnya dan berkata: \"Bukankah diantara kalian ada orang yang berakal yang mendatangi orang ini dimana ia melihatku. Aku menahan diri dari memba'iatnya, lalu ia membunuhnya?\" Mereka berkata; kami tidak mengetahui wahai Rasulullah, apa yang ada di dalam hati anda. Bukankah anda telah memberi isyarat kepada kami dengan mata anda? Beliau berkata: \"Sesungguhnya tidak selayaknya seorang nabi memiliki mata khianat.\" Abu Daud berkata; Abdullah adalah saudara Utsman sepersusuan. Al Walid bin 'Uqbah adalah saudara Utsman seibu, dan Utsman telah mencambuknya tatkala ia meminum arak. "},"2244":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَعِيدِ بْنِ يَرْبُوعٍ الْمَخْزُومِيُّ قَالَ حَدَّثَنِي جَدِّي عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَوْمَ فَتْحِ مَكَّةَ أَرْبَعَةٌ لَا أُؤَمِّنُهُمْ فِي حِلٍّ وَلَا حَرَمٍ فَسَمَّاهُمْ قَالَ وَقَيْنَتَيْنِ كَانَتَا لِمِقْيَسٍ فَقُتِلَتْ إِحْدَاهُمَا وَأَفْلَتَتْ الْأُخْرَى فَأَسْلَمَتْقَالَ أَبُو دَاوُد لَمْ أَفْهَمْ إِسْنَادَهُ مِنْ ابْنِ الْعَلَاءِ كَمَا أُحِبُّ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], ia berkata; telah menceritakan kepada kami [Zaid bin Al Hubab], ia berkata; telah mengabarkan kepada kami ['Amr bin Utsman bin Abdurrahman bin Sa'id bin Yarbu' Al Makhzumi], ia berkata; telah menceritakan kepadaku [kakekku], dari [ayahku] bahwa Rasulullah shallallahu wa'alaihi wa sallam berkata pada saat penaklukan Mekkah: \"Ada empat orang yang tidak aku beri mereka jaminan baik di luar tanah haram maupun di tanah haram.\" Kemudian beliau menyebutkan mereka dan berkata: serta dua orang budak penyanyi milik Miqyas. Kemudian salah seorang diantara mereka dibunuh dan yang lainnya dilepaskan, kemudian ia masuk Islam. Abu Daud berkata; aku tidak faham sanadnya dari Ibnu Al 'Ala` sebagaimana yang aku inginkan. "},"2245":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ عَامَ الْفَتْحِ وَعَلَى رَأْسِهِ الْمِغْفَرُ فَلَمَّا نَزَعَهُ جَاءَهُ رَجُلٌ فَقَالَ ابْنُ خَطَلٍ مُتَعَلِّقٌ بِأَسْتَارِ الْكَعْبَةِ فَقَالَ اقْتُلُوهُقَالَ أَبُو دَاوُد ابْنُ خَطَلٍ اسْمُهُ عَبْدُ اللَّهِ وَكَانَ أَبُو بَرْزَةَ الْأَسْلَمِيُّ قَتَلَهُ","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Ibnu Syihab] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam memasuki Mekkah pada saat penaklukan Mekkah, dan beliau memakai penutup kepala. Kemudian tatkala beliau melepasnya terdapat seorang laki-laki yang datang kepada beliau dan berkata; Ibnu Khathal bergantungan pada tabir Ka'bah. Lalu beliau berkata: \"Bunuhlah dia!\" Abu Daud berkata; Ibnu Khathal namanya adalah Abdullah, dan Abu Barzah Al Aslami adalah yang membunuhnya. "},"2246":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ الرَّقِّيُّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الرَّقِّيُّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ إِبْرَاهِيمَ قَالَأَرَادَ الضَّحَّاكُ بْنُ قَيْسٍ أَنْ يَسْتَعْمِلَ مَسْرُوقًا فَقَالَ لَهُ عُمَارَةُ بْنُ عُقْبَةَ أَتَسْتَعْمِلُ رَجُلًا مِنْ بَقَايَا قَتَلَةِ عُثْمَانَ فَقَالَ لَهُ مَسْرُوقٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْعُودٍ وَكَانَ فِي أَنْفُسِنَا مَوْثُوقَ الْحَدِيثِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا أَرَادَ قَتْلَ أَبِيكَ قَالَ مَنْ لِلصِّبْيَةِ قَالَ النَّارُ فَقَدْ رَضِيتُ لَكَ مَا رَضِيَ لَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ali bin Al Husain Ar Raqqi], ia berkata; telah menceritakan kepada kami [Abdullah bin Ja'far Ar Raqqi], ia berkata; telah mengabarkan kepadaku ['Ubaidullah bin 'Amr], dari [Zaid bin Abu Unaisah] dari ['Amr bin Murrah] dari [Ibrahim], ia berkata; [Adh Dhahhak bin Qais] berkeinginan untuk memberikan jabatan kepada Masruq, kemudian 'Umarah bin 'Uqbah berkata kepadanya; apakah engkau akan memberikan jabatan kepada orang yang merupakan diantara sisa pembunuh Utsman? Maka Masruq berkata kepadanya; telah menceritakan kepada kami [Abdullah bin Mas'ud], ia menurut kami adalah orang yang dipercaya haditsnya, bahwa Nabi shallallahu 'alaihi wasallam tatkala hendak membunuh ayahmu beliau berkata; siapakah yang akan mengurus anak ini? Beliau berkata; api. Aku telah ridha sebagaimana keridhaan Rasulullah shallallahu 'alaihi wasallam. "},"2247":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ ابْنِ تِعْلَى قَالَغَزَوْنَا مَعَ عَبْدِ الرَّحْمَنِ بْنِ خَالِدِ بْنِ الْوَلِيدِ فَأُتِيَ بِأَرْبِعَةِ أَعْلَاجٍ مِنْ الْعَدُوِّ فَأَمَرَ بِهِمْ فَقُتِلُوا صَبْرًاقَالَ أَبُو دَاوُد قَالَ لَنَا غَيْرُ سَعِيدٍ عَنْ ابْنِ وَهْبٍ فِي هَذَا الْحَدِيثِ قَالَ بِالنَّبْلِ صَبْرًا فَبَلَغَ ذَلِكَ أَبَا أَيُّوبَ الْأَنْصَارِيَّ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ قَتْلِ الصَّبْرِ فَوَالَّذِي نَفْسِي بِيَدِهِ لَوْ كَانَتْ دَجَاجَةٌ مَا صَبَرْتُهَا فَبَلَغَ ذَلِكَ عَبْدَ الرَّحْمَنِ بْنَ خَالِدِ بْنِ الْوَلِيدِ فَأَعْتَقَ أَرْبَعَ رِقَابٍ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], ia berkata; telah menceritakan kepada kami [Abdullah bin Wahb], ia berkata; telah mengabarkan kepadaku ['Amr bin Al Harits] dari [Bukair bin Abdullah bin Al Asyajj], dari [Ibnu Ya'la], ia berkata; kami pernah berperang bersama Abdurrahman bin Khalid bin Al Walid, kemudian ia diberi empat orang musuh yang kuat, kemudian ia memerintahkan untuk membunuh mereka. Kemudian mereka di bunuh dengan ditahan dan dilempari. Abu Daud berkata; selain Sa'id telah berkata kepadaku dari Ibnu Wahb dalam hadits ini, ia berkata; dengan melempari anak panah. Kemudian hal tersebut sampai kepada [Abu Ayyub Al Anshari], lalu ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam melarang dari membunuh dengan cara menahan dan melemparinya. Demi Dzat yang jiwaku ada di tanganku, seandainya hal tersebut adalah ayam betina, maka aku tidak akan menjadikannya sasaran. Kemudian hal tersebut sampai kepada Abdurrahman bin Khalid bin Al Walid, kemudian ia memerdekakan empat orang budak. "},"2248":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ أَخْبَرَنَا ثَابِتٌ عَنْ أَنَسٍأَنَّ ثَمَانِينَ رَجُلًا مِنْ أَهْلِ مَكَّةَ هَبَطُوا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابِهِ مِنْ جِبَالِ التَّنْعِيمِ عِنْدَ صَلَاةِ الْفَجْرِ لِيَقْتُلُوهُمْ فَأَخَذَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِلْمًا فَأَعْتَقَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَهُوَ الَّذِي كَفَّ أَيْدِيَهُمْ عَنْكُمْ وَأَيْدِيَكُمْ عَنْهُمْ بِبَطْنِ مَكَّةَ }إِلَى آخِرِ الْآيَةِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], ia berkata; telah mengabarkan kepada kami [Tsabit] dari [Anas] bahwa delapan puluh orang penduduk Mekkah telah turun kepada Nabi shallallahu 'alaihi wasallam dan para sahabatnya dari gunung di Tan'im pada saat shalat Fajar untuk membunuh mereka. Kemudian Rasulullah shallallahu 'alaihi wasallam menangkap mereka dalam karena menyerahkan diri, kemudian Rasulullah shallallahu 'alaihi wasallam membebaskan mereka. Lalu Allah menurunkan ayat: \"Dan Dia-lah yang menahan tangan mereka dari (membinasakan) kamu dan (menahan) tangan kamu dari (membinasakan) mereka di tengah kota Mekah sesudah Allah memenangkan kamu atas mereka, dan adalah Allah Maha Melihat apa yang kamu kerjakan.\""},"2249":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأُسَارَى بَدْرٍ لَوْ كَانَ مُطْعِمُ بْنُ عَدِيٍّ حَيًّا ثُمَّ كَلَّمَنِي فِي هَؤُلَاءِ النَّتْنَى لَأَطْلَقْتُهُمْ لَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris], ia berkata; telah menceritakan kepada kami [Abdurrazzaq], ia berkata; telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri], dari [Muhammad bin Jubair bin Muth'im] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam berkata kepada para tawanan Badr; seandainya Muth'im bin 'Adi hidup kemudian berbicara kepadaku mengenai orang-orang kafir ini sungguh aku akan membebaskan mereka untuknya. "},"2250":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ قَالَ حَدَّثَنَا أَبُو نُوحٍ قَالَ أَخْبَرَنَا عِكْرِمَةُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا سِمَاكٌ الْحَنَفِيُّ قَالَ حَدَّثَنِي ابْنُ عَبَّاسٍ قَالَ حَدَّثَنِي عُمَرُ بْنُ الْخَطَّابِ قَالَلَمَّا كَانَ يَوْمُ بَدْرٍ فَأَخَذَ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفِدَاءَ أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ مَا كَانَ لِنَبِيٍّ أَنْ يَكُونَ لَهُ أَسْرَى حَتَّى يُثْخِنَ فِي الْأَرْضِ إِلَى قَوْلِهِ لَمَسَّكُمْ فِيمَا أَخَذْتُمْ }مِنْ الْفِدَاءِ ثُمَّ أَحَلَّ لَهُمْ اللَّهُ الْغَنَائِمَقَالَ أَبُو دَاوُد سَمِعْت أَحْمَدَ بْنَ حَنْبَلٍ يُسْأَلُ عَنْ اسْمِ أَبِي نُوحٍ فَقَالَ إِيشْ تَصْنَعُ بِاسْمِهِ اسْمُهُ اسْمٌ شَنِيعٌ قَالَ أَبُو دَاوُد اسْمُ أَبِي نُوحٍ قُرَادٌ وَالصَّحِيحُ عَبْدُ الرَّحْمَنِ بْنُ غَزْوَانَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal], ia berkata; telah menceritakan kepada kami [Abu Nuh], ia berkata; telah mengabarkan kepada kami [Ikrimah bin 'Ammar], ia berkata; telah menceritakan kepada kami [Simak Al Hanafi], ia berkata; telah menceritakan kepadaku [Ibnu Abbas], ia berkata; telah menceritakan kepadaku [Umar bin Al Khathab], ia berkata; pada saat perang Badr dan Nabi shallallahu 'alaihi wasallam mengambil tebusan maka Allah 'azza wajalla menurunkan ayat: \"Tidak patut, bagi seorang Nabi mempunyai tawanan sebelum ia dapat melumpuhkan musuhnya di muka bumi.\" Hingga firmanNya: \"niscaya kamu ditimpa siksaan yang besar karena tebusan yang kamu ambil.\" Karena tebusan tersebut, kemudian Allah menghalalkan bagi mereka rampasan perang. Abu Daud berkata; saya mendengar Ahmad bin Hanbal ditanya mengenai nama Abu Nuh, kemudian ia berkata; apa yang akan engkau lakukan dengan namanya? Namanya adalah nama buruk. Abu Daud berkata; nama Abu Nuh adalah Qurad, dan yang benar adalah Abdurrahman bin Ghazwan. "},"2251":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْمُبَارَكِ الْعَيْشِيُّ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ حَبِيبٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي الْعَنْبَسِ عَنْ أَبِي الشَّعْثَاءِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَعَلَ فِدَاءَ أَهْلِ الْجَاهِلِيَّةِ يَوْمَ بَدْرٍ أَرْبَعَ مِائَةٍ","id":"Telah menceritakan kepada kami [Abdurrahman bin Al Mubarak Al 'Aisyi], ia berkata; telah menceritakan kepada kami [Sufyan bin Habib], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Al 'Anbas], dari [Abu Asy Sya'tsa`] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam telah menjadikan tebusan penduduk jahiliyah pada saat perang Badr empat ratus. "},"2252":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَحْيَى بْنِ عَبَّادٍ عَنْ أَبِيهِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْلَمَّا بَعَثَ أَهْلُ مَكَّةَ فِي فِدَاءِ أَسْرَاهُمْ بَعَثَتْ زَيْنَبُ فِي فِدَاءِ أَبِي الْعَاصِ بِمَالٍ وَبَعَثَتْ فِيهِ بِقِلَادَةٍ لَهَا كَانَتْ عِنْدَ خَدِيجَةَ أَدْخَلَتْهَا بِهَا عَلَى أَبِي الْعَاصِ قَالَتْ فَلَمَّا رَآهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَقَّ لَهَا رِقَّةً شَدِيدَةً وَقَالَ إِنْ رَأَيْتُمْ أَنْ تُطْلِقُوا لَهَا أَسِيرَهَا وَتَرُدُّوا عَلَيْهَا الَّذِي لَهَا فَقَالُوا نَعَمْ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ عَلَيْهِ أَوْ وَعَدَهُ أَنْ يُخَلِّيَ سَبِيلَ زَيْنَبَ إِلَيْهِ وَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدَ بْنَ حَارِثَةَ وَرَجُلًا مِنْ الْأَنْصَارِ فَقَالَ كُونَا بِبَطْنِ يَأْجَجَ حَتَّى تَمُرَّ بِكُمَا زَيْنَبُ فَتَصْحَبَاهَا حَتَّى تَأْتِيَا بِهَا","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq], dari [Yahya bin 'Abbad] dari [ayahnya yaitu 'Abbad bin Abdullah bin Az Zubair], dari [Aisyah], ia berkata; tatkala penduduk Quraisy mengirimkan tebusan para tawanan mereka maka Zainab mengirimkan tebusan Abu Al 'Ash, dan ia mengirimkan kalungnya yang dahulu ada pada Khadijah, ketika ia mempertemukannya dengan Abu Al 'Ash dengan memakai kalung tersebut. Aisyah berkata; kemudian tatkala Rasulullah shallallahu 'alaihi wasallam melihatnya beliau sangat tersentuh dan berkata: \"Apabila menurut kalian agar melepaskan tawanannya dan kalian kembalikan miliknya kepadanya?\" Mereka mengatakan; ya. Dan Rasulullah shallallahu 'alaihi wasallam telah mengambil kesepakatan dengannya atau berjanji kepadanya untuk membiarkan Zainab kembali kepadanya. Dan Rasulullah shallallahu 'alaihi wasallam telah mengutus Zaid bin Haritsah dan seorang laki-laki anshor. Beliau berkata: \"Hendaknya kalian berada di tengah Ya`jaj (tempat berjarak delapan mil dari Mekkah) hingga Zainab melewati kalian, lalu temanilah ia hingga kalian datang bersamanya.\""},"2253":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا عَمِّي يَعْنِي سَعِيدَ بْنَ الْحَكَمِ قَالَ أَخْبَرَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ وَذَكَرَ عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ مَرْوَانَ وَالْمِسْوَرَ بْنَ مَخْرَمَةَ أَخْبَرَاهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حِينَ جَاءَهُ وَفْدُ هَوَازِنَ مُسْلِمِينَ فَسَأَلُوهُ أَنْ يَرُدَّ إِلَيْهِمْ أَمْوَالَهُمْ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعِي مَنْ تَرَوْنَ وَأَحَبُّ الْحَدِيثِ إِلَيَّ أَصْدَقُهُ فَاخْتَارُوا إِمَّا السَّبْيَ وَإِمَّا الْمَالَ فَقَالُوا نَخْتَارُ سَبْيَنَا فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَثْنَى عَلَى اللَّهِ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّ إِخْوَانَكُمْ هَؤُلَاءِ جَاءُوا تَائِبِينَ وَإِنِّي قَدْ رَأَيْتُ أَنْ أَرُدَّ إِلَيْهِمْ سَبْيَهُمْ فَمَنْ أَحَبَّ مِنْكُمْ أَنْ يُطَيِّبَ ذَلِكَ فَلْيَفْعَلْ وَمَنْ أَحَبَّ مِنْكُمْ أَنْ يَكُونَ عَلَى حَظِّهِ حَتَّى نُعْطِيَهُ إِيَّاهُ مِنْ أَوَّلِ مَا يُفِيءُ اللَّهُ عَلَيْنَا فَلْيَفْعَلْ فَقَالَ النَّاسُ قَدْ طَيَّبْنَا ذَلِكَ لَهُمْ يَا رَسُولَ اللَّهِ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا لَا نَدْرِي مَنْ أَذِنَ مِنْكُمْ مِمَّنْ لَمْ يَأْذَنْ فَارْجِعُوا حَتَّى يَرْفَعَ إِلَيْنَا عُرَفَاؤُكُمْ أَمْرَكُمْ فَرَجَعَ النَّاسُ وَكَلَّمَهُمْ عُرَفَاؤُهُمْ فَأَخْبَرُوهُمْ أَنَّهُمْ قَدْ طَيَّبُوا وَأَذِنُوا","id":"Telah menceritakan kepada kami [Ahmad bin Abu Maryam], telah menceritakan kepada kami [pamanku yaitu Sa'id bin Al Hakam], ia berkata; telah mengabarkan kepada kami [Al Laits bin Sa'd] dari ['Uqail] dari [Ibnu Syihab], ia berkata; dan ['Urwah bin Az Zubair] menyebutkan bahwa [Marwan] serta [Al Miswar bin Makhramah] telah mengabarkan kepadanya bahwa ketika utusan orang-orang muslim Hawazin datang kepada Rasulullah shallallahu 'alaihi wasallam dan meminta agar beliau mengembalikan harta mereka, maka beliau berkata kepada mereka: \"Bersamaku orang-orang yang kalian lihat, dan perkataan yang paling aku senangi adalah yang paling benar. Maka pilihlah tawanan atau harta!\" Lalu mereka berkata; kami memilih tawanan kami. Lalu Rasulullah shallallahu 'alaihi wasallam berdiri dan memuji Allah, kemudian beliau berkata: \"Adapun selanjutnya, sesungguhnya saudara-saudara kalian ini telah datang dalam keadaan bertaubat dan aku ingin mengembalikan tawanan kepada mereka. Maka barangsiapa diantara kalian yang ingin merelakan hal tersebut, silahkan ia melakukannya, dan barangsiapa yang hendak mengambil bagiannya hingga kami berikan kepadanya dari pertama kali Allah memberikan fai` kepada kita, maka silahkan ia melakukannya.\" Kemudian orang-orang berkata; kami telah merelakan hal tersebut untuk mereka wahai Rasulullah! Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepada mereka: \"Sesungguhnya kami tidak mengetahui siapakah diantara kalian yang mengizinkan dan siapakah diantara kalian yang tidak mengizinkan. Maka kembalilah, hingga para pemimpin kalian mengadukan perkara kalian kepada kami!\" Lalu orang-orang tersebut kembali dan berbicara dengan para pemimpin mereka. Kemudian memereka mengabarkan kepada mereka bahwa mereka telah merelakan dan mengizinkan. "},"2254":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ فِي هَذِهِ الْقِصَّةِ قَالَفَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُدُّوا عَلَيْهِمْ نِسَاءَهُمْ وَأَبْنَاءَهُمْ فَمَنْ مَسَكَ بِشَيْءٍ مِنْ هَذَا الْفَيْءِ فَإِنَّ لَهُ بِهِ عَلَيْنَا سِتَّ فَرَائِضَ مِنْ أَوَّلِ شَيْءٍ يُفِيئُهُ اللَّهُ عَلَيْنَا ثُمَّ دَنَا يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَعِيرٍ فَأَخَذَ وَبَرَةً مِنْ سَنَامِهِ ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ إِنَّهُ لَيْسَ لِي مِنْ هَذَا الْفَيْءِ شَيْءٌ وَلَا هَذَا وَرَفَعَ أُصْبُعَيْهِ إِلَّا الْخُمُسَ وَالْخُمُسُ مَرْدُودٌ عَلَيْكُمْ فَأَدُّوا الْخِيَاطَ وَالْمِخْيَطَ فَقَامَ رَجُلٌ فِي يَدِهِ كُبَّةٌ مِنْ شَعْرٍ فَقَالَ أَخَذْتُ هَذِهِ لِأُصْلِحَ بِهَا بَرْذَعَةً لِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا مَا كَانَ لِي وَلِبَنِي عَبْدِ الْمُطَّلِبِ فَهُوَ لَكَ فَقَالَ أَمَّا إِذْ بَلَغَتْ مَا أَرَى فَلَا أَرَبَ لِي فِيهَا وَنَبَذَهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il], ia berkata; telah menceritakan kepada kami [Hammad] dari [Muhammad bin Ishaq], dari ['Amr bin Syu'aib] dari [ayahnya], dari [kakeknya], dalam kisah ini ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kembalikan kepada mereka para wanita dan anak-anak mereka! Barangsiapa yang menahan sebagian dari fai` ini, maka baginya enam unta dari pertama kali Allah memberikan fai` kepada kita.\" Kemudian Nabi shallallahu 'alaihi wasallam mendekat kepada unta dan mengambil sehelai bulu dari punuknya kemudian berkata: \"Wahai manusia, sesungguhnya aku tidak mendapatkan sesuatupun dari fai` ini, tidak pula ini, -beliau mengangkat kedua jarinya- kecuali seperlima, dan seperlima dikembalikan kepada kalian, maka tunaikanlah benang dan jarum!\" kemudian terdapat seorang laki-laki yang berdiri, di tangannya terdapat segulung rambut, ia berkata; aku mengambil ini untuk memperbaiki alas pelanaku. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Adapun bagianku dan bagian Bani Abdul Muththalib adalah untukmu, adapun apabila telah mencapai apa yang aku lihat, maka aku tidak membutuhkannya.\" Dan beliau membuang bulu tersebut. "},"2255":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ ح و حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا رَوْحٌ قَالَا حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ أَبِي طَلْحَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا غَلَبَ عَلَى قَوْمٍ أَقَامَ بِالْعَرْصَةِ ثَلَاثًا قَالَ ابْنُ المُثَنَّى إِذَا غَلَبَ قَوْمًا أَحَبَّ أَنْ يُقِيمَ بِعَرْصَتِهِمْ ثَلَاثًاقَالَ أَبُو دَاوُد كَانَ يَحْيَى بْنُ سَعِيدٍ يَطْعَنُ فِي هَذَا الْحَدِيثِ لِأَنَّهُ لَيْسَ مِنْ قَدِيمِ حَدِيثِ سَعِيدٍ لِأَنَّهُ تَغَيَّرَ سَنَةَ خَمْسٍ وَأَرْبَعِينَ وَلَمْ يُخْرِجْ هَذَا الْحَدِيثَ إِلَّا بِأَخَرَةٍ قَالَ أَبُو دَاوُد يُقَالُ إِنَّ وَكِيعًا حَمَلَ عَنْهُ فِي تَغَيُّرِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], ia berkata; telah menceritakan kepada kami [Mu'adz bin Mu'adz], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Rauh], mereka berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] dari [Abu Thalhah], ia berkata; Rasulullah shallallahu 'alaihi wasallam apabila menundukkan suatu kaum beliau tinggal di sebidang tanah mereka yang luas selama tiga hari. Ibnu Al Mutsanna berkata; apabila beliau menundukkan suatu kaum, maka beliau senang untuk tinggal di sebidang tanah mereka yang luas mereka selama tiga hari. Abu Daud berkata; Yahya bin Sa'id mengkritik hadits ini karena bukan termasuk hadits Sa'id yang terdahulu sebelum mengalami perubahan, karena ia mengalami perubahan pada tahun empat puluh lima, dan ia tidak mengeluarkan hadits ini kecuali pada tahun terakhir. Abu Daud berkata; ada yang mengatakan bahwa Waki' meriwayatkan hadits tersebut darinya di saat ia mengalami perubahan. "},"2256":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ يَزِيدَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ الْحَكَمِ عَنْ مَيْمُونِ بْنِ أَبِي شَبِيبٍ عَنْ عَلِيٍّأَنَّهُ فَرَّقَ بَيْنَ جَارِيَةٍ وَوَلَدِهَا فَنَهَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ وَرَدَّ الْبَيْعَقَالَ أَبُو دَاوُد وَمَيْمُونٌ لَمْ يُدْرِكْ عَلِيًّا قُتِلَ بِالْجَمَاجِمِ وَالْجَمَاجِمُ سَنَةُ ثَلَاثٍ وَثَمَانِينَ قَالَ أَبُو دَاوُد وَالْحَرَّةُ سَنَةُ ثَلَاثٍ وَسِتِّينَ وَقُتِلَ ابْنُ الزُّبَيْرِ سَنَةَ ثَلَاثٍ وَسَبْعِينَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], ia berkata; telah menceritakan kepada kami [Ishaq bin Manshur], telah menceritakan kepada kami [Abdussalam bin Harb] dari [Yazid bin Abdurrahman] dari [Al Hakam] dari [Maimun bin Abu Syabib] dari [Ali] bahwa ia telah memisahkan antara seorang budak wanita dan anaknya. Kemudian Nabi shallallahu 'alaihi wasallam melarangnya dari melakukan hal tersebut, dan beliau mengembalikan jual beli. Abu Daud berkata; dan Maimun tidak mendapati Ali. Ia terbunuh menggunakan jamjamah (kayu yang di ujungnya terdapat besi yang digunakan untuk membajak tanah), dan kejadian jamjamah tersebut pada tahun delapan puluh tiga. Abu Daud berkata; dan kejadian harrah (tempat yang berbatu hitam di Madinah) pada tahun enam puluh tiga. Dan Ibnu Az Zubair terbunuh pada tahun tujuh puluh tiga. "},"2257":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا عِكْرِمَةُ قَالَ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ قَالَ حَدَّثَنِي أَبِي قَالَخَرَجْنَا مَعَ أَبِي بَكْرٍ وَأَمَّرَهُ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَغَزَوْنَا فَزَارَةَ فَشَنَنَّا الْغَارَةَ ثُمَّ نَظَرْتُ إِلَى عُنُقٍ مِنْ النَّاسِ فِيهِ الذُّرِّيَّةُ وَالنِّسَاءُ فَرَمَيْتُ بِسَهْمٍ فَوَقَعَ بَيْنَهُمْ وَبَيْنَ الْجَبَلِ فَقَامُوا فَجِئْتُ بِهِمْ إِلَى أَبِي بَكْرٍ فِيهِمْ امْرَأَةٌ مِنْ فَزَارَةَ وَعَلَيْهَا قِشْعٌ مَنْ أَدَمٍ مَعَهَا بِنْتٌ لَهَا مِنْ أَحْسَنِ الْعَرَبِ فَنَفَّلَنِي أَبُو بَكْرٍ ابْنَتَهَا فَقَدِمْتُ الْمَدِينَةَ فَلَقِيَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي يَا سَلَمَةُ هَبْ لِي الْمَرْأَةَ فَقُلْتُ وَاللَّهِ لَقَدْ أَعْجَبَتْنِي وَمَا كَشَفْتُ لَهَا ثَوْبًا فَسَكَتَ حَتَّى إِذَا كَانَ مِنْ الْغَدِ لَقِيَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السُّوقِ فَقَالَ يَا سَلَمَةُ هَبْ لِي الْمَرْأَةَ لِلَّهِ أَبُوكَ فَقُلْتُ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا كَشَفْتُ لَهَا ثَوْبًا وَهِيَ لَكَ فَبَعَثَ بِهَا إِلَى أَهْلِ مَكَّةَ وَفِي أَيْدِيهِمْ أَسْرَى فَفَادَاهُمْ بِتِلْكَ الْمَرْأَةِ","id":"Telah menceritakan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Hisyam bin Al Qasim], ia berkata; telah menceritakan kepada kami [Ikrimah], ia berkata; telah menceritakan kepadaku [Iyas bin Salamah], ia berkata; telah menceritakan kepadaku [ayahku], ia berkata; kami keluar bersama Abu Bakr dan Rasulullah shallallahu 'alaihi wasallam telah menjadikannya pemimpin atas kami. Kemudian kami memerangi Fazarah dan kami menyerbu dari setiap penjuru. Kemudian aku melihat kepada sekelompok orang padanya terdapat anak-anak dan wanita. Lalu aku memanah dan jatuh diantara mereka dan gunung, kemudian mereka berdiri. Lalu aku datang membawa mereka kepada Abu Bakr, dan diantara mereka terdapat seorang wanita dari Fazarah di atasnya terdapat keranjang dari kulit, dan ia membawa seorang anak wanita yang merupakan diantara wanita Arab yang tercantik. Lalu Abu Bakr memberikan anaknya kepadaku, kemudian aku datang ke Madinah dan bertemu dengan Rasulullah shallallahu 'alaihi wasallam. Beliau berkata: \"Wahai Salamah, berikan wanita tersebut kepadaku!\" Lalu aku katakan; wahai Rasulullah, ia telah membuatku terkagum dan aku belum menggaulinya. Lalu beliau terdiam hingga keesokan harinya Rasulullah shallallahu 'alaihi wasallam bertemu denganku di pasar dan beliau berkata; wahai Salamah, berikan wanita tersebut kepadaku, semoga engkau beruntung. Lalu aku katakan; wahai Rasulullah, demi Allah, aku belum mengaulinya, ia untuk engkau. Kemudian beliau mengirim wanita tersebut kepada penduduk Mekkah yang membawa beberapa orang tawanan, dan beliau menebus mereka dengan wanita tersebut. "},"2258":{"ar":"حَدَّثَنَا صَالِحُ بْنُ سُهَيْلٍ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ أَبِي زَائِدَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ غُلَامًا لِابْنِ عُمَرَ أَبَقَ إِلَى الْعَدُوِّ فَظَهَرَ عَلَيْهِ الْمُسْلِمُونَ فَرَدَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى ابْنِ عُمَرَ وَلَمْ يَقْسِمْقَالَ أَبُو دَاوُد وَقَالَ غَيْرُهُ رَدَّهُ عَلَيْهِ خَالِدُ بْنُ الْوَلِيدِ","id":"Telah menceritakan kepada kami [Shalih bin Suhail], telah menceritakan kepada kami [Yahya bin Abu Zaidah], dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa budak Ibnu Umar telah melarikan diri, kemudian orang-orang muslim menangkapnya lalu Rasulullah shallallahu 'alaihi wasallam mengembalikannya kepada Ibnu Umar dan tidak membagikannya. Abu Daud berkata; dan yang lainnya berkata; Khalid bin Al Walid mengembalikan budak tersebut kepada Ibnu Umar. "},"2259":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ وَالْحَسَنُ بْنُ عَلِيٍّ الْمَعْنَى قَالَا حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَذَهَبَ فَرَسٌ لَهُ فَأَخَذَهَا الْعَدُوُّ فَظَهَرَ عَلَيْهِمْ الْمُسْلِمُونَ فَرُدَّ عَلَيْهِ فِي زَمَنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَقَ عَبْدٌ لَهُ فَلَحِقَ بِأَرْضِ الرُّومِ فَظَهَرَ عَلَيْهِمْ الْمُسْلِمُونَ فَرَدَّهُ عَلَيْهِ خَالِدُ بْنُ الْوَلِيدِ بَعْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaim Al Anbari], dan [Al Hasan bin Ali] secara makna, mereka berkata; telah menceritakan kepada kami [Ibnu Umair] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar], ia berkata; kudanya telah lari, kemudian musuh menangkapnya. Lalu orang-orang muslim menaklukkan mereka dan kuda tersebut dikembalikan kepadanya pada zaman Rasulullah shallallahu 'alaihi wasallam. Dan budaknya telah kabur dan masuk ke negeri Romawi, kemudian orang-orang muslim menaklukkan mereka dan Khalid mengembalikan budak tersebut kepadanya setelah Nabi shallallahu 'alaihi wasallam meninggal. "},"2260":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ يَحْيَى الْحَرَّانِيُّ حَدَّثَنِي مُحَمَّدٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ أَبَانَ بْنِ صَالِحٍ عَنْ مَنْصُورِ بْنِ الْمُعْتَمِرِ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَخَرَجَ عِبْدَانٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي يَوْمَ الْحُدَيْبِيَةِ قَبْلَ الصُّلْحِ فَكَتَبَ إِلَيْهِ مَوَالِيهُمْ فَقَالُوا يَا مُحَمَّدُ وَاللَّهِ مَا خَرَجُوا إِلَيْكَ رَغْبَةً فِي دِينِكَ وَإِنَّمَا خَرَجُوا هَرَبًا مِنْ الرِّقِّ فَقَالَ نَاسٌ صَدَقُوا يَا رَسُولَ اللَّهِ رُدَّهُمْ إِلَيْهِمْ فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ مَا أُرَاكُمْ تَنْتَهُونَ يَا مَعْشَرَ قُرَيْشٍ حَتَّى يَبْعَثَ اللَّهُ عَلَيْكُمْ مَنْ يَضْرِبُ رِقَابَكُمْ عَلَى هَذَا وَأَبَى أَنْ يَرُدَّهُمْ وَقَالَ هُمْ عُتَقَاءُ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Yahya Al Harrani], telah menceritakan kepadaku [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Aban bin Shalih], dari [Manshur bin Al Mu'tamir], dari [Rib'I bin Hirasy] dari [Ali bin Abu Thalib], ia berkata; terdapat bebeorang orang budak keluar menemui Rasulullah shallallahu 'alaihi wasallam pada saat terjadinya perjanjian Hudaibiyah sebelum terjadinya perdamaian, kemudian tuan-tuan mereka menulis surat kepada beliau dan berkata; wahai Muhammad! Demi Allah, tidaklah mereka keluar kepadamu karena senang kepada agamu, melainkan mereka keluar karena kabur dari perbudakan. Kemudian orang-orang berkata; mereka benar wahai Rasulullah! Kembalikan budak-budak tersebut kepada mereka! Maka Rasulullah shallallahu 'alaihi wasallam marah dan berkata: \"Aku melihat kalian tidak akan berhenti wahai orang-orang Quraisy hingga Allah mengutus orang yang akan memenggal leher kalian.\" Dan beliau menolak untuk mengembalikan mereka, dan beliau berkata: \"Mereka adalah orang-orang telah Allah 'azza wajalla bebaskan.\""},"2261":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ الزُّبَيْرِيُّ قَالَ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ جَيْشًا غَنِمُوا فِي زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا وَعَسَلًا فَلَمْ يُؤْخَذْ مِنْهُمْ الْخُمُسُ","id":"Telah menceritakan kepada kami [Ibrahim bin Hamzah Az Zubairi], ia berkata; telah menceritakan kepada kami [Anas bin 'Iyadh] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa sebuah pasukan telah mendapatkan rampasan perang pada zaman Rasulullah shallallahu 'alaihi wasallam berupa makanan, serta madu dan tidak diambil dari mereka zakat seperlima. "},"2262":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ وَالْقَعْنَبِيُّ قَالَا حَدَّثَنَا سُلَيْمَانُ عَنْ حُمَيْدٍ يَعْنِي ابْنَ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَدُلِّيَ جِرَابٌ مِنْ شَحْمٍ يَوْمَ خَيْبَرَ قَالَ فَأَتَيْتُهُ فَالْتَزَمْتُهُ قَالَ ثُمَّ قُلْتُ لَا أُعْطِي مِنْ هَذَا أَحَدًا الْيَوْمَ شَيْئًا قَالَ فَالْتَفَتُّ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَبَسَّمُ إِلَيَّ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] dan [Al Qa'nabi], mereka berkata; telah menceritakan kepada kami [Sulaiman] dari [Humaid bin Hilal] dari [Abdullah bin Mughaffal], ia berkata; telah diambilkan satu kantong lemak pada saat perang Khaibar. Ia berkata; kemudian aku mendatanginya dan menjaganya. Kemudian aku katakan; hari ini aku tidak akan memberikan sedikit pun dari lemak ini kepada seorang pun. "},"2263":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ عَنْ يَعْلَى بْنِ حَكِيمٍ عَنْ أَبِي لَبِيدٍ قَالَكُنَّا مَعَ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ بِكَابُلَ فَأَصَابَ النَّاسُ غَنِيمَةً فَانْتَهَبُوهَا فَقَامَ خَطِيبًا فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ النُّهْبَى فَرَدُّوا مَا أَخَذُوا فَقَسَمَهُ بَيْنَهُمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], ia berkata; telah menceritakan kepada kami [Jarir bin Hazim] dari [Ya'la bin Hakim] dari [Abu Labid], ia berkata; kami pernah bersama [Abdurrahman bin Samurah] di Kabul, kemudian orang-orang mendapatkan rampasan perang, lalu mereka mengambilnya sebelum dibagi. Kemudian ia berkhutbah, ia berkata; saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam melarang dari mengambil rampasan perang sebelum dibagi. Lalu mereka mengembalikan apa yang telah mereka ambil, kemudian ia membaginya diantara mereka. "},"2264":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا أَبُو إِسْحَقَ الشَّيْبَانِيُّ عَنْ مُحَمَّدِ بْنِ أَبِي مُجَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَ قُلْتُهَلْ كُنْتُمْ تُخَمِّسُونَ يَعْنِي الطَّعَامَ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَصَبْنَا طَعَامًا يَوْمَ خَيْبَرَ فَكَانَ الرَّجُلُ يَجِيءُ فَيَأْخُذُ مِنْهُ مِقْدَارَ مَا يَكْفِيهِ ثُمَّ يَنْصَرِفُ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], telah menceritakan kepada kami [Abu Mu'awiyah], telah menceritakan kepada kami [Abu Ishaq Asy Syaibani], dari [Muhammad bin Abu Mujalid] dari [Abdullah bin Abu Aufa], ia berkata; aku katakan; apakah kalian membagi makanan menjadi lima pada zaman Rasulullah shallallahu 'alaihi wasallam? Kemudian ia berkata; kami pernah mendapatkan makanan pada saat perang Khaibar, dan terdapat seseorang yang datang dan mengambil sebagian makanan tersebut seukuran yang cukup baginya kemudian ia pergi. "},"2265":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَاصِمٍ يَعْنِي ابْنَ كُلَيْبٍ عَنْ أَبِيهِ عَنْ رَجُلٍ مِنْ الْأَنْصَارِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأَصَابَ النَّاسَ حَاجَةٌ شَدِيدَةٌ وَجَهْدٌ وَأَصَابُوا غَنَمًا فَانْتَهَبُوهَا فَإِنَّ قُدُورَنَا لَتَغْلِي إِذْ جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي عَلَى قَوْسِهِ فَأَكْفَأَ قُدُورَنَا بِقَوْسِهِ ثُمَّ جَعَلَ يُرَمِّلُ اللَّحْمَ بِالتُّرَابِ ثُمَّ قَالَ إِنَّ النُّهْبَةَ لَيْسَتْ بِأَحَلَّ مِنْ الْمَيْتَةِ أَوْ إِنَّ الْمَيْتَةَ لَيْسَتْ بِأَحَلَّ مِنْ النُّهْبَةِ الشَّكُّ مِنْ هَنَّادٍ","id":"Telah menceritakan kepada kami [Hannad bin As Sarri], telah menceritakan kepada kami [Abu Al Ahwash] dari ['Ashim bin Kulaib], dari [ayahnya] dari [seorang anshar], ia berkata; kami keluar bersama Rasulullah shallallahu 'alaihi wasallam dalam sebuah perjalanan, kemudian orang-orang memiliki kebutuhan dan kesusahan yang sangat, kemudian mereka memperoleh kambing dan mereka mengambilnya sebelum dibagi. Dan periuk-periuk kami mendidih, tiba-tiba Rasulullah shallallahu 'alaihi wasallam datang, beliau berjalan dengan membawa busurnya, lalu beliau menggulingkan periuk-periuk kami dengan busur beliau dan memasukkan ke dalam daging yang dimasak tersebut dengan tanah seraya bersabda: \"Sesungguhnya mengambil bagian dari rampasan perang sebelum dibagi tidaklah lebih halal daripada bangkai atau tidaklah bangkai lebih halal daripada mengambil rampasan perang sebelum dibagi.\" Terdapat keraguan dari Hannad. "},"2266":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ ابْنَ حَرْشَفٍ الْأَزْدِيَّ حَدَّثَهُ عَنْ الْقَاسِمِ مَوْلَى عَبْدِ الرَّحْمَنِ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكُنَّا نَأْكُلُ الْجَزَرَ فِي الْغَزْوِ وَلَا نَقْسِمُهُ حَتَّى إِنْ كُنَّا لَنَرْجِعُ إِلَى رِحَالِنَا وَأَخْرِجَتُنَا مِنْهُ مُمْلَأَةٌ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], ia berkata; telah menceritakan kepada kami [Abdullah bin Wahb], ia berkata; telah mengabarkan kepadaku ['Amr bin Al Harits] bahwa [Ibnu Harsyaf Al Azdi] telah menceritakan kepadanya dari [Al Qasim] mantan budak Abdurrahman dari [sebagian sahabat Nabi shallallahu 'alaihi wasallam], beliau bersabda: \"Kami pernah makan unta dan kami tidak membaginya hingga kami kembali ke tempat-tempat tinggal kami, sementara bejana kami penuh dengan daging unta.\""},"2267":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى حَدَّثَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ حَمْزَةَ قَالَ حَدَّثَنَا أَبُو عَبْدِ الْعَزِيزِ شَيْخٌ مِنْ أَهْلِ الْأُرْدُنِّ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ قَالَرَابَطْنَا مَدِينَةَ قِنَّسْرِينَ مَعَ شُرَحْبِيلَ بْنِ السِّمْطِ فَلَمَّا فَتَحَهَا أَصَابَ فِيهَا غَنَمًا وَبَقَرًا فَقَسَمَ فِينَا طَائِفَةً مِنْهَا وَجَعَلَ بَقِيَّتَهَا فِي الْمَغْنَمِ فَلَقِيتُ مُعَاذَ بْنَ جَبَلٍ فَحَدَّثْتُهُ فَقَالَ مُعَاذٌ غَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ فَأَصَبْنَا فِيهَا غَنَمًا فَقَسَمَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَائِفَةً وَجَعَلَ بَقِيَّتَهَا فِي الْمَغْنَمِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa], telah menceritakan kepada kami [Muhammad bin Al Mubarak] dari [Yahya bin Hamzah], ia berkata; telah menceritakan kepada kami [Abu Abdul Aziz] syekh dari penduduk Yordania dari ['Ubadah bin Nusai] dari [Abdurrahman bin Ghanm], ia berkata; kami memerangi Kota Qannasrin bersama Syarahbil bin As Simth, kemudian tatkala ia telah menaklukkannya ia memperoleh kambing dan sapi, kemudian ia membagikan sebagian darinya, dan menjadikan sisanya bagian dari harta rampasan perang. Kemudian aku bertemu dengan [Mu'adz bin Jabal], lalu aku ceritakan hal tersebut kepadanya. Lalu Mu'adz berkata; kami pernah memerangi khaibar bersama Rasulullah shallallahu 'alaihi wasallam, lalu kami memperoleh kambing, lalu Rasulullah shallallahu 'alaihi wasallam membagi sebagiannya diantara kami dan menjadikan sisanya bagian dari rampasan perang. "},"2268":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى قَالَ أَبُو دَاوُد وَأَنَا لِحَدِيثِهِ أَتْقَنُ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي مَرْزُوقٍ مَوْلَى تُجِيبَ عَنْ حَنَشٍ الصَّنْعَانِيِّ عَنْ رُوَيْفِعِ بْنِ ثَابِتٍ الْأَنْصَارِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَبِالْيَوْمِ الْآخِرِ فَلَا يَرْكَبْ دَابَّةً مِنْ فَيْءِ الْمُسْلِمِينَ حَتَّى إِذَا أَعْجَفَهَا رَدَّهَا فِيهِ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَبِالْيَوْمِ الْآخِرِ فَلَا يَلْبَسْ ثَوْبًا مِنْ فَيْءِ الْمُسْلِمِينَ حَتَّى إِذَا أَخْلَقَهُ رَدَّهُ فِيهِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], dan [Utsman bin Abu Syaibah] secara makna, Abu Daud berkata; dan aku lebih yakin kepada haditsnya. Ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Muhammad bin Ishaq] dari [Yazid? bin Abu Habib] dari [Abu Marzuq] mantan budak Tujib, dari [Hanasy Ash Shan'ani], dari [Ruwaifi' bin Tsabit Al Anshari] bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Barangsiapa yang beriman kepada Allah dan Hari Akhir, maka janganlah ia menaiki unta yang berasal dari fai` orang-orang muslim hingga apabila ia telah menjadikannya kurus maka ia mengembalikannya. Dan barangsiapa yang beriman kepada Allah dan Hari Akhir, maka janganlah ia memakai pakaian yang berasal dari fai` orang-orang muslim hingga apabila ia telah menjadikannya usang, maka ia mengembalikannya.\""},"2269":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ أَخْبَرَنَا إِبْرَاهِيمُ يَعْنِي ابْنَ يُوسُفَ قَالَ قَالَ أَبُو دَاوُد هُوَ إِبْرَاهِيمُ بْنُ يُوسُفَ بْنِ إِسْحَقَ بْنِ أَبِي إِسْحَقَ السُّبَيْعِيُّ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَقَ السُّبَيْعِيِّ قَالَ حَدَّثَنِي أَبُو عُبَيْدَةَ عَنْ أَبِيهِ قَالَمَرَرْتُ فَإِذَا أَبُو جَهْلٍ صَرِيعٌ قَدْ ضُرِبَتْ رِجْلُهُ فَقُلْتُ يَا عَدُوَّ اللَّهِ يَا أَبَا جَهْلٍ قَدْ أَخْزَى اللَّهُ الْأَخِرَ قَالَ وَلَا أَهَابُهُ عِنْدَ ذَلِكَ فَقَالَ أَبْعَدُ مِنْ رَجُلٍ قَتَلَهُ قَوْمُهُ فَضَرَبْتُهُ بِسَيْفٍ غَيْرِ طَائِلٍ فَلَمْ يُغْنِ شَيْئًا حَتَّى سَقَطَ سَيْفُهُ مِنْ يَدِهِ فَضَرَبْتُهُ بِهِ حَتَّى بَرَدَ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], ia berkata; telah mengabarkan kepada kami [Ibrahim bin Yusuf], ia berkata; Abu Daud berkata; ia adalah Ibrahim bin Yusuf bin Ishaq bin Abu Ishaq As Subai'i, dari [ayahnya], dari [Abu Ishaq As Subai'i], ia berkata; telah menceritakan kepadaku [Abu 'Ubaidah] dari [ayahnya], ia berkata; aku lewat, ternyata Abu Jahl telah terkapar dengan kaki yang telah terkena sabetan pedang, kemudian aku katakan; wahai musuh Allah, wahai Abu Jahl, akhirnya Allah telah membalasmu. Ia berkata; pada saat itu aku tidak takut kepadanya. Kemudian ia berkata; hal itu sangat jauh dari seseorang yang dibunuh oleh kaumnya. Lalu aku menebasnya dengan pedang dan tidak memutuskan, maka hal tersebut tidaklah berarti sedikitpun kecuali pedangnya yang terjatuh dari tangannya. Kemudian aku menebasnya menggunakan pedang tersebut hingga ia mati. "},"2270":{"ar":"حَدَّثَنَا مُسَدَّدٌ أَنَّ يَحْيَى بْنَ سَعِيدٍ وَبِشْرَ بْنَ الْمُفَضَّلِ حَدَّثَاهُمْ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ أَبِي عَمْرَةَ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُوُفِّيَ يَوْمَ خَيْبَرَ فَذَكَرُوا ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ صَلُّوا عَلَى صَاحِبِكُمْ فَتَغَيَّرَتْ وُجُوهُ النَّاسِ لِذَلِكَ فَقَالَ إِنَّ صَاحِبَكُمْ غَلَّ فِي سَبِيلِ اللَّهِ فَفَتَّشْنَا مَتَاعَهُ فَوَجَدْنَا خَرَزًا مِنْ خَرَزِ يَهُودَ لَا يُسَاوِي دِرْهَمَيْنِ","id":"Telah menceritakan kepada kami [Musaddad] bahwa [Yahya bin Sa'id], dan [Bisyr bin Al Mufadhdhal] telah menceritakan kepada mereka dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Hibban] dari [Abu Amrah] dari [Zaid bin Khalid Al Juhani] bahwa seorang sahabat Nabi shallallahu 'alaihi wasallam meninggal pada saat perang Khaibar. Kemudian para sahabat menceritakan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Lalu beliau berkata: \"Shalatkan sahabat kalian!\" kemudian roman wajah orang-orang berubah karena hal tersebut. Lalu beliau berkata: \"Sesungguhnya sahabat kalian telah berbuat berkhianat di jalan Allah.\" Kemudian kami memeriksa barangnya, dan kami dapati butiran mutiara Yahudi yang tidak sampai senilai dua dirham. "},"2271":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ثَوْرِ بْنِ زَيْدٍ الدَّيْلِيِّ عَنْ أَبِي الْغَيْثِ مَوْلَى ابْنِ مُطِيعٍ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ خَيْبَرَ فَلَمْ نَغْنَمْ ذَهَبًا وَلَا وَرِقًا إِلَّا الثِّيَابَ وَالْمَتَاعَ وَالْأَمْوَالَ قَالَ فَوَجَّهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ وَادِي الْقُرَى وَقَدْ أُهْدِيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدٌ أَسْوَدُ يُقَالُ لَهُ مِدْعَمٌ حَتَّى إِذَا كَانُوا بِوَادِي الْقُرَى فَبَيْنَا مِدْعَمٌ يَحُطُّ رَحْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ سَهْمٌ فَقَتَلَهُ فَقَالَ النَّاسُ هَنِيئًا لَهُ الْجَنَّةُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلَّا وَالَّذِي نَفْسِي بِيَدِهِ إِنَّ الشَّمْلَةَ الَّتِي أَخَذَهَا يَوْمَ خَيْبَرَ مِنْ الْمَغَانِمِ لَمْ تُصِبْهَا الْمَقَاسِمُ لَتَشْتَعِلُ عَلَيْهِ نَارًا فَلَمَّا سَمِعُوا ذَلِكَ جَاءَ رَجُلٌ بِشِرَاكٍ أَوْ شِرَاكَيْنِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شِرَاكٌ مِنْ نَارٍ أَوْ قَالَ شِرَاكَانِ مِنْ نَارٍ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Tsaur bin Zaid Ad Dili] dari [Abu Al Ghaits] mantan budak Ibnu Muthi', dari [Abu Hurairah] bahwa ia berkata; kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam pada tahun terjadinya perang Khaibar. Kami tidak memperoleh rampasan emas dan perak, kecuali pakaian dan barang, serta harta. Abu Hurairah berkata; kemudian Rasulullah shallallahu 'alaihi wasallam mengarahkan ke arah bukit Qura. Sungguh Rasulullah shallallahu 'alaihi wasallam telah diberi hadiah seorang budak hitam yang bernama Mid'am, hingga ketika mereka berada Bukit Qura. Kemudian tatkala Mid'am menurunkan pelana Rasulullah shallallahu 'alaihi wasallam tiba-tiba ia terkena anak panah dan membunuhnya. Kemudian orang-orang berkata; betapa enaknya dia mendapatkan surga. Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Tidak, demi Dzat yang jiwaku ada di tanganNya, sesungguhnya pakaian yang telah ia ambil pada saat perang Khaibar dari rampasan perang yang belum dibagi telah membakarnya.\" Kemudian tatkala mereka mendengar hal tersebut, terdapat seorang laki-laki yang datang dengan membawa satu atau dua tali sandal kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Ini adalah tali sandal dari neraka\" -atau beliau mengatakan: \"Dua tali sandal dari neraka.\""},"2272":{"ar":"حَدَّثَنَا أَبُو صَالِحٍ مَحْبُوبُ بْنُ مُوسَى قَالَ أَخْبَرَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَوْذَبٍ قَالَ حَدَّثَنِي عَامِرٌ يَعْنِي ابْنَ عَبْدِ الْوَاحِدِ عَنْ ابْنِ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَصَابَ غَنِيمَةً أَمَرَ بِلَالًا فَنَادَى فِي النَّاسِ فَيَجِيئُونَ بِغَنَائِمِهِمْ فَيَخْمُسُهُ وَيُقَسِّمُهُ فَجَاءَ رَجُلٌ بَعْدَ ذَلِكَ بِزِمَامٍ مِنْ شَعَرٍ فَقَالَ يَا رَسُولَ اللَّهِ هَذَا فِيمَا كُنَّا أَصَبْنَاهُ مِنْ الْغَنِيمَةِ فَقَالَ أَسَمِعْتَ بِلَالًا يُنَادِي ثَلَاثًا قَالَ نَعَمْ قَالَ فَمَا مَنَعَكَ أَنْ تَجِيءَ بِهِ فَاعْتَذَرَ إِلَيْهِ فَقَالَ كُنْ أَنْتَ تَجِيءُ بِهِ يَوْمَ الْقِيَامَةِ فَلَنْ أَقْبَلَهُ عَنْكَ","id":"Telah menceritakan kepada kami [Abu Shalih Mahbub bin Musa], ia berkata; telah mengabarkan kepada kami [Abu Ishaq Al Fazari], dari [Abdullah bin Syaudzab], ia berkata; telah menceritakan kepadaku ['Amir bin Abdul Wahid] dari [Ibnu Buraidah], dari [Abdullah bin 'Amr], ia berkata; Rasulullah shallallahu 'alaihi wasallam apabila mendapatkan rampasan perang beliau memerintahkan Bilal agar menyeru diantara orang-orang, kemudian mereka datang membawa rampasan perang mereka. Lalu beliau membagi lima dan membagikannya. Lalu terdapat seorang laki-laki yang datang setelah itu dengan membawa tali kekang yang terbuat dari rambut dan berkata; wahai Rasulullah, inilah yang rampasan perang yang telah kami peroleh. Kemudian beliau berkata: \"Apakah engkau telah mendengar Bilal menyeru tiga kali?\" ia berkata; ya. Beliau berkata: \"Apa yang menghalangimu untuk datang membawanya?\" kemudian ia menyampaikan alasan kepada beliau. Lalu beliau berkata: \"Datanglah dengan membawanya pada Hari Kiamat, aku tidak menerimanya darimu.\""},"2273":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ وَسَعِيدُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ قَالَ النُّفَيْلِيُّ الْأَنْدَرَاوَرْدِيُّ عَنْ صَالِحِ بْنِ مُحَمَّدِ بْنِ زَائِدَةَ قَالَ أَبُو دَاوُد وَصَالِحٌ هَذَا أَبُو وَاقِدٍقَالَ دَخَلْتُ مَعَ مَسْلَمَةَ أَرْضَ الرُّومِ فَأُتِيَ بِرَجُلٍ قَدْ غَلَّ فَسَأَلَ سَالِمًا عَنْهُ فَقَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ عُمَرَ بْنِ الْخَطَّابِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَجَدْتُمْ الرَّجُلَ قَدْ غَلَّ فَأَحْرِقُوا مَتَاعَهُ وَاضْرِبُوهُقَالَ فَوَجَدْنَا فِي مَتَاعِهِ مُصْحَفًا فَسَأَلَ سَالِمًا عَنْهُ فَقَالَ بِعْهُ وَتَصَدَّقْ بِثَمَنِهِ","id":"Telah menceritakan kepada kami [An Nufaili] dan [Sa'id bin Manshur], mereka berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad], telah berkata An Nufaili Al Andarawardi, dari [Shalih bin Muhammad bin Zaidah], Abu Daud berkata; Shalih ini adalah Abu Waqid. Ia berkata; aku masuk bersama Maslamah ke negeri Romawi, kemudian terdapat seorang laki-laki yang dihadapkan, ia telah berbuat khianat, kemudian ia bertanya kepada Salim mengenai orang tersebut, lalu [Salim] berkata; saya pernah mendengar [ayahku] menceritakan dari [Umar bin Al Khathab] dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Apabila kalian mendapatkan seorang laki-laki yang telah berkhianat, maka bakarlah barangnya dan cambuklah dia!\" Abu Waqid berkata; kemudian kami mendapati sebuah Mushhaf pada barangnya. Kemudian Maslamah bertanya kepada Salim mengenai hal tersebut, kemudian ia berkata; juallah mushaf tersebut dan sedekahkan uang hasil penjualannya. "},"2274":{"ar":"حَدَّثَنَا أَبُو صَالِحٍ مَحْبُوبُ بْنُ مُوسَى الْأَنْطَاكِيُّ قَالَ أَخْبَرَنَا أَبُو إِسْحَقَ عَنْ صَالِحِ بْنِ مُحَمَّدٍ قَالَغَزَوْنَا مَعَ الْوَلِيدِ بْنِ هِشَامٍ وَمَعَنَا سَالِمُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ وَعُمَرُ بْنُ عَبْدِ الْعَزِيزِ فَغَلَّ رَجُلٌ مَتَاعًا فَأَمَرَ الْوَلِيدُ بِمَتَاعِهِ فَأُحْرِقَ وَطِيفَ بِهِ وَلَمْ يُعْطِهِ سَهْمَهُقَالَ أَبُو دَاوُد وَهَذَا أَصَحُّ الْحَدِيثَيْنِ رَوَاهُ غَيْرُ وَاحِدٍ أَنَّ الْوَلِيدَ بْنَ هِشَامٍ أَحْرَقَ رَحْلَ زِيَادِ بْنِ سَعْدٍ وَكَانَ قَدْ غَلَّ وَضَرَبَهُ","id":"Telah menceritakan kepada kami [Abu Shalih Mahbub bin Musa Al Anthaki], ia berkata; telah mengabarkan kepada kami [Abu Ishaq] dari [Shalih bin Muhammad], ia berkata; kami pernah berperang bersama Al Walid bin Hisyam, dan bersama kami terdapat Salim bin Abdullah bin Umar, serta Umar bin Abdul Aziz. Kemudian terdapat seorang laki-laki yang berkhianat mengambil sebuah barang. Kemudian Al Walid memerintahkan agar barangnya dibakar dan orang tersebut dibawa berkeliling dan ia tidak memberikan sahamnya kepadanya. Abu Daud berkata; hadits ini adalah hadits paling shahih diantara dua hadits tersebut. Hadits tersebut telah diriwayatkan tidak hanya satu orang bahwa Al Walid bin Hisyam membakar pelana Ziyad bin Sa'd, dan ia telah berkhianat dan Al Walid mencambuknya. "},"2275":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ قَالَ حَدَّثَنَا مُوسَى بْنُ أَيُّوبَ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ حَرَّقُوا مَتَاعَ الْغَالِّ وَضَرَبُوهُقَالَ أَبُو دَاوُد وَزَادَ فِيهِ عَلِيُّ بْنُ بَحْرٍ عَنْ الْوَلِيدِ وَلَمْ أَسْمَعْهُ مِنْهُ وَمَنَعُوهُ سَهْمَهُ قَالَ أَبُو دَاوُد و حَدَّثَنَا بِهِ الْوَلِيدُ بْنُ عُتْبَةَ وَعَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ قَالَا حَدَّثَنَا الْوَلِيدُ عَنْ زُهَيْرِ بْنِ مُحَمَّدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ قَوْلَهُ وَلَمْ يَذْكُرْ عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ الْحَوْطِيُّ مَنْعَ سَهْمِهِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Auf], ia berkata; telah menceritakan kepada kami [Musa bin Ayyub], ia berkata; telah menceritakan kepada kami [Al Walid bin Muslim], ia berkata; telah menceritakan kepada kami [Zuhair bin Muhammad] dari ['Amr bin Syu'aib] dari [ayahnya], dari [kakeknya], bahwa Rasulullah shallallahu 'alaihi wasallam, Abu Bakr dan Umar telah membakar harta orang yang berkhianat dan mencambuknya. Abu Daud berkata dan menambahkan didalamnya [Ali bin Bahr] dari [Al Walid] namun saya tidak mendengar darinya kata; dan mereka melarang untuk menyerahkan bagiannya. Abu Daud berkata; dan telah menceritakan kepada kami, [Al Walid bin 'Utbah], dan [Abdul Wahhab bin Najdah], mereka berkata; telah menceritakan kepada kami [Al Walid] dari [Zuhair bin Muhammad], dari ['Amr bin Syu'aib] perkataannya; dan Abdul Wahhab bin Najdah Al Hauthi tidak menyebutkan pelarangan untuk mengambil sahamnya."},"2276":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ دَاوُدَ بْنِ سُفْيَانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ مُوسَى أَبُو دَاوُدَ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ سَعْدِ بْنِ سَمُرَةَ بْنِ جُنْدُبٍ حَدَّثَنِي خُبَيْبُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ سُلَيْمَانَ بْنِ سَمُرَةَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ قَالَأَمَّا بَعْدُ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَتَمَ غَالًّا فَإِنَّهُ مِثْلُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Daud bin Sufyan], ia berkata; telah menceritakan kepada kami [Yahya bin Hassan], ia berkata; telah menceritakan kepada kami [Sulaiman bin Musa], Abu Daud berkata; telah menceritakan kepada kami [Ja'far bin Sa'd bin Samurah bin Jundub], telah menceritakan kepadaku [Khubaib bin Sulaiman] dari [ayahnya yaitu Sulaiman bin Samurah] dari [Samurah bin Jundub], ia berkata; adapun selanjutnya, dan Rasulullah shallallahu 'alaihi wasallam pernah berkata: \"Barangsiapa yang menyembunyikan orang yang berkhianat maka ia seperti itu.\""},"2277":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عُم��رَ بْنِ كَثِيرِ بْنِ أَفْلَحَ عَنْ أَبِي مُحَمَّدٍ مَوْلَى أَبِي قَتَادَةَ عَنْ أَبِي قَتَادَةَ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي عَامِ حُنَيْنٍ فَلَمَّا الْتَقَيْنَا كَانَتْ لِلْمُسْلِمِينَ جَوْلَةٌ قَالَ فَرَأَيْتُ رَجُلًا مِنْ الْمُشْرِكِينَ قَدْ عَلَا رَجُلًا مِنْ الْمُسْلِمِينَ قَالَ فَاسْتَدَرْتُ لَهُ حَتَّى أَتَيْتُهُ مِنْ وَرَائِهِ فَضَرَبْتُهُ بِالسَّيْفِ عَلَى حَبْلِ عَاتِقِهِ فَأَقْبَلَ عَلَيَّ فَضَمَّنِي ضَمَّةً وَجَدْتُ مِنْهَا رِيحَ الْمَوْتِ ثُمَّ أَدْرَكَهُ الْمَوْتُ فَأَرْسَلَنِي فَلَحِقْتُ عُمَرَ بْنَ الْخَطَّابِ فَقُلْتُ لَهُ مَا بَالُ النَّاسِ قَالَ أَمْرُ اللَّهِ ثُمَّ إِنَّ النَّاسَ رَجَعُوا وَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ مَنْ قَتَلَ قَتِيلًا لَهُ عَلَيْهِ بَيِّنَةٌ فَلَهُ سَلَبُهُ قَالَ فَقُمْتُ ثُمَّ قُلْتُ مَنْ يَشْهَدُ لِي ثُمَّ جَلَسْتُ ثُمَّ قَالَ ذَلِكَ الثَّانِيَةَ مَنْ قَتَلَ قَتِيلًا لَهُ عَلَيْهِ بَيِّنَةٌ فَلَهُ سَلَبُهُ قَالَ فَقُمْتُ ثُمَّ قُلْتُ مَنْ يَشْهَدُ لِي ثُمَّ جَلَسْتُ ثُمَّ قَالَ ذَلِكَ الثَّالِثَةَ فَقُمْتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَكَ يَا أَبَا قَتَادَةَ قَالَ فَاقْتَصَصْتُ عَلَيْهِ الْقِصَّةَ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ صَدَقَ يَا رَسُولَ اللَّهِ وَسَلَبُ ذَلِكَ الْقَتِيلِ عِنْدِي فَأَرْضِهِ مِنْهُ فَقَالَ أَبُو بَكْرٍ الصِّدِّيقُ لَاهَا اللَّهِ إِذًا يَعْمِدُ إِلَى أَسَدٍ مِنْ أُسْدِ اللَّهِ يُقَاتِلُ عَنْ اللَّهِ وَعَنْ رَسُولِهِ فَيُعْطِيكَ سَلَبَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ فَأَعْطِهِ إِيَّاهُ فَقَالَ أَبُو قَتَادَةَ فَأَعْطَانِيهِ فَبِعْتُ الدِّرْعَ فَابْتَعْتُ بِهِ مَخْرَفًا فِي بَنِي سَلَمَةَ فَإِنَّهُ لَأَوَّلُ مَالٍ تَأَثَّلْتُهُ فِي الْإِسْلَامِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik] dari [Yahya bin Sa'id] dari [Umar bin Katsir bin Aflah], dari [Abu Muhammad], mantan budak Abu Qatadah, dari [Abu Qatadah], ia berkata; kami keluar bersama Rasulullah shallallahu 'alaihi wasallam pada tahun terjadinya perang Hunain. Kemudian tatkala kami bertemu, orang-orang muslim datang pergi. Ia berkata; kemudian saya melihat seorang laki-laki dari kalangan musyrikin telah mengalahkan seorang muslim. Ia berkata; kemudian aku mengitarinya hingga aku mendatanginya dari belakang. Kemudian aku menebasnya dengan pedang pada urat pundaknya. Kemudian ia menghadap kepadaku dan ia memelukku dan aku dapatkan darinya bau kematian. Kemudian ia mati dan melepaskanku. Lalu aku menyusul kepada Umar dan aku katakan kepadanya; bagaimana pendapat orang-orang? Ia berkata; terdapat perintah Allah. Kemudian orang-orang kembali dan Rasulullah shallallahu 'alaihi wasallam duduk. Beliau mengatakan: \"Barangsiapa yang membunuh seseorang dengan memiliki bukti maka baginya salabnya (segala yang melekat pada tubuhnya).\" Abu Qatadah berkata; lalu aku berdiri kemudian aku katakan; siapakah yang memberikan persaksian untukku? Kemudian aku duduk, lalu beliau mengatakan hal tersebut yang kedua kalinya: \"Barangsiapa yang membunuh seseorang dengan memiliki bukti, maka baginya salabnya (segala yang melekat pada tubuhnya).\" Abu Qatadah berkata; lalu aku berdiri kemudian aku katakan; siapakah yang memberikan persaksian untukku? Kemudian aku duduk, lalu beliau mengatakan hal tersebut yang ketiga kalinya. Lalu aku berdiri dan Rasulullah shallallahu 'alaihi wasallam berkata: \"Ada apa denganmu wahai Abu Qatadah?\" Abu Qatadah berkata; lalu aku ceritakan kisah tersebut kepada beliau. Lalu terdapat seseorang yang berkata; ia benar wahai Rasulullah, dan salab orang yang terbunuh tersebut ada padaku maka relakan kepadanya! Lalu Abu Bakr Ash Shiddiq berkata; tidak, demi Allah, hal tersebut tidak terjadi, jika demikian ia menjatuhkan gelar singa diantara singa Allah yang bertempur membela Allah dan RasulNya, kemudian memberimu salabnya? Maka Rasulullah shallallahu 'alaihi wasallam berkata: \"Ia benar, berikan kepadanya salab tersebut.\" Abu Qatadah berkata; kemudian beliau memberiku salab tersebut, lalu aku menjual baju zirah dan aku belikan kebun di antara Bani Salamah. Sesungguhnya hal tersebut merupakan harta pertama yang aku kumpulkan di masa Islam."},"2278":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ يَعْنِي يَوْمَ حُنَيْنٍ مَنْ قَتَلَ كَافِرًا فَلَهُ سَلَبُهُ فَقَتَلَ أَبُو طَلْحَةَ يَوْمَئِذٍ عِشْرِينَ رَجُلًا وَأَخَذَ أَسْلَابَهُمْ وَلَقِيَ أَبُو طَلْحَةَ أُمَّ سُلَيْمٍ وَمَعَهَا خِنْجَرٌ فَقَالَ يَا أُمَّ سُلَيْمٍ مَا هَذَا مَعَكِ قَالَتْ أَرَدْتُ وَاللَّهِ إِنْ دَنَا مِنِّي بَعْضُهُمْ أَبْعَجُ بِهِ بَطْنَهُ فَأَخْبَرَ بِذَلِكَ أَبُو طَلْحَةَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو دَاوُد هَذَا حَدِيثٌ حَسَنٌ قَالَ أَبُو دَاوُد أَرَدْنَا بِهَذَا الْخِنْجَرَ وَكَانَ سِلَاحَ الْعَجَمِ يَوْمَئِذٍ الْخِنْجَرُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], ia berkata; telah menceritakan kepada kami [Hammad] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata pada saat perang Hunain: \"Barangsiapa yang membunuh seorang kafir maka baginya salabnya (segala apa yang dikenakan oleh orang yang dibunuh).\" Kemudian Abu Thalhah pada saat itu telah membunuh dua puluh orang dan ia mengambil salab mereka. Dan Abu Thalhah menemui Ummu Sulaim dan bersama Ummu Sulaim terdapat sebuah khanjar (pisau besar yang memiliki dua sisi yang tajam). Lalu Abu Thalhah berkata; wahai Ummu Sulaim, apa yang engkau bawa ini? Ia berkata; demi Allah apabila salah sebagian diantara mereka mendekatiku maka aku sobek perutnya. Kemudian Abu Thalhah mengabarkan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Abu Daud berkata; hadits ini adalah hadits hasan. Abu Daud berkata; aku ingin dengan pisau ini… dan dahulu senjata orang-orang selain Arab adalah khanjar."},"2279":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنِي صَفْوَانُ بْنُ عَمْرٍو عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ قَالَخَرَجْتُ مَعَ زَيْدِ بْنِ حَارِثَةَ فِي غَزْوَةِ مُؤْتَةَ فَرَافَقَنِي مَدَدٌ مِنْ أَهْلِ الْيَمَنِ لَيْسَ مَعَهُ غَيْرُ سَيْفِهِ فَنَحَرَ رَجُلٌ مِنْ الْمُسْلِمِينَ جَزُورًا فَسَأَلَهُ الْمَدَدِيُّ طَائِفَةً مِنْ جِلْدِهِ فَأَعْطَاهُ إِيَّاهُ فَاتَّخَذَهُ كَهَيْئَةِ الدَّرْقِ وَمَضَيْنَا فَلَقِينَا جُمُوعَ الرُّومِ وَفِيهِمْ رَجُلٌ عَلَى فَرَسٍ لَهُ أَشْقَرَ عَلَيْهِ سَرْجٌ مُذْهَبٌ وَسِلَاحٌ مُذْهَبٌ فَجَعَلَ الرُّومِيُّ يُغْرِي بِالْمُسْلِمِينَ فَقَعَدَ لَهُ الْمَدَدِيُّ خَلْفَ صَخْرَةٍ فَمَرَّ بِهِ الرُّومِيُّ فَعَرْقَبَ فَرَسَهُ فَخَرَّ وَعَلَاهُ فَقَتَلَهُ وَحَازَ فَرَسَهُ وَسِلَاحَهُ فَلَمَّا فَتَحَ اللَّهُ عَزَّ وَجَلَّ لِلْمُسْلِمِينَ بَعَثَ إِلَيْهِ خَالِدُ بْنُ الْوَلِيدِ فَأَخَذَ مِنْ السَّلَبِ قَالَ عَوْفٌ فَأَتَيْتُهُ فَقُلْتُ يَا خَالِدُ أَمَا عَلِمْتَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالسَّلَبِ لِلْقَاتِلِ قَالَ بَلَى وَلَكِنِّي اسْتَكْثَرْتُهُ قُلْتُ لَتَرُدَّنَّهُ عَلَيْهِ أَوْ لَأُعَرِّفَنَّكَهَا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَبَى أَنْ يَرُدَّ عَلَيْهِ قَالَ عَوْفٌ فَاجْتَمَعْنَا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَصَصْتُ عَلَيْهِ قِصَّةَ الْمَدَدِيِّ وَمَا فَعَلَ خَالِدٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا خَالِدُ مَا حَمَلَكَ عَلَى مَا صَنَعْتَ قَالَ يَا رَسُولَ اللَّهِ لَقَدْ اسْتَكْثَرْتُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا خَالِدُ رُدَّ عَلَيْهِ مَا أَخَذْتَ مِنْهُ قَالَ عَوْفٌ فَقُلْتُ لَهُ دُونَكَ يَا خَالِدُ أَلَمْ أَفِ لَكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا ذَلِكَ فَأَخْبَرْتُهُ قَالَ فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا خَالِدُ لَا تَرُدَّ عَلَيْهِ هَلْ أَنْتُمْ تَارِكُونَ لِي أُمَرَائِي لَكُمْ صَفْوَةُ أَمْرِهِمْ وَعَلَيْهِمْ كَدَرُهُحَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ سَأَلْتُ ثَوْرًا عَنْ هَذَا الْحَدِيثِ فَحَدَّثَنِي عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal], ia berkata; telah menceritakan kepada kami [Al Walid bin Muslim], ia berkata; telah menceritakan kepadaku [Shafwan bin 'Amr] dari [Abdurrahman bin Jubair bin Nufair], dari [ayahnya] dari ['Auf bin Malik Al Asyja'i], ia berkata; aku keluar bersama Zaid bin Haritsah pada perang Muktah. Kemudian aku disertai bala bantuan dari penduduk Yaman dengan hanya membawa pedangnya. Kemudian salah seorang muslim menyembelih unta dan seorang bala bantuan meminta kulit unta tersebut, kemudian ia memberikan kepadanya. Lalu orang-orang tersebut menjadikannya seperti tameng. Dan kami berjalan dan bertemu dengan orang-orang Romawi, dan diantara mereka terdapat seorang laki-laki yang menunggang kuda berwarna blonde padanya terdapat pelana emas serta senjata yang dilapisi emas. Kemudian orang Romawi tersebut menyerang muslimin dengan tiba-tiba. Kemudian seorang bala bantuan tersebut menunggunya di balik batu besar, kemudian orang Romawi tersebut lewat, lalu orang bala bantuan tersebut memotong kaki kudanya, maka orang Romawi tersebut terjatuh dan salah seorang bala bantuan tersebut membunuhnya dan mengumpulkan kuda serta senjatanya. Kemudian tatkala Allah 'azza wajalla memenangkan untuk orang-orang muslim, khalid bin Al Walid mengirim utusan kepadanya dan mengambil sebagian dari salab tersebut. 'Auf berkata; kemudian aku mendatangi Khalid dan berkata; wahai Khalid, bukanlah engkau telah mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam memutuskan bahwa salab adalah untuk orang yang yang membunuh? Ia berkata; benar. Akan tetapi aku menganggapnya terlalu banyak. Maka aku katakan; sungguh engkau kembalikan kepadanya aku akan memberitahukanmu di hadapan Rasulullah shallallahu 'alaihi wasallam. Kemudian ia enggan untuk mengembalikannya. 'Auf berkata; kemudian kami berkumpul di sisi Rasulullah shallallahu 'alaihi wasallam, lalu aku ceritakan kisah orang bantuan tersebut kepada beliau dan apa yang dilakukan Khalid. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Wahai Khalid apa yang mendorongmu untuk melakukan apa yang telah engkau perbuat?\" ia berkata; wahai Rasulullah, sungguh aku menganggapnya sudah terlalu banyak. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Khalid, kembalikan kepadanya apa yang telah engkau ambil!\" Lalu aku katakan kepadanya; sebentar wahai Khalid, bukankah aku telah memenuhi janjiku kepadamu? Kemudian Rasulullah shallallahu 'alaihi wasallam berkata; apakah itu? Kemudian aku beritahukan kepada beliau. Kemudian Rasulullah shallallahu 'alaihi wasallam marah dan berkata: \"Wahai Khalid, jangan engkau kembalikan kepadanya! Apakah kalian akan meninggalkan para pemimpinku? Kalian mendapatkan urusan mereka yang telah bersih dan bagi mereka urusan yang masih keruh.\" Telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal], ia berkata; telah menceritakan kepada kami [Al Walid], ia berkata; saya bertanya kepada [Tsaur] mengenai hadits ini. Kemudian ia menceritakan kepadaku dari [Khalid bin Ma'dan], dari [Jubair bin Nufair] dari ['Auf bin Malik Al Asyja'i] seperti hadits tersebut. "},"2280":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ صَفْوَانَ بْنِ عَمْرٍو عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ وَخَالِدِ بْنِ الْوَلِيدِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالسَّلَبِ لِلْقَاتِلِ وَلَمْ يُخَمِّسْ السَّلَبَ","id":"Telah menceritakan kepada kami [Sa'd bin Manshur?], telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Shafwan bin 'Amr] dari [Abdurrahman bin Jubair bin Nufair] dari [ayahnya], dari ['Auf bin Malik Al Asyja'i], dan [Khalid bin Al Walid] bahwa Rasulullah shallallahu 'alaihi wasallam telah memutuskan bahwa salab adalah untuk orang yang membunuh, dan beliau tidak membagi menjadi lima bagian. "},"2281":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبَّادٍ الْأَزْدِيُّ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَنَفَّلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ بَدْرٍ سَيْفَ أَبِي جَهْلٍ كَانَ قَتَلَهُ","id":"Telah menceritakan kepada kami [Harun bin 'Abbad Al Azdi], ia berkata; telah menceritakan kepada kami [Waki'] dari [ayahnya], dari [Abu Ishaq] dari [Abu 'Ubaidah] dari [Abdullah bin Mas'ud], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah memberiku pedang Abu Jahl bagian pada saat perang Badr. Abdullah adalah orang yang telah membunuhnya. "},"2282":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ مُحَمَّدِ بْنِ الْوَلِيدِ الزّ��بَيْدِيِّ عَنْ الزُّهْرِيِّ أَنَّ عَنْبَسَةَ بْنَ سَعِيدٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يُحَدِّثُ سَعِيدَ بْنَ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ أَبَانَ بْنَ سَعِيدِ بْنِ الْعَاصِ عَلَى سَرِيَّةٍ مِنْ الْمَدِينَةِ قِبَلَ نَجْدٍ فَقَدِمَ أَبَانُ بْنُ سَعِيدٍ وَأَصْحَابُهُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِخَيْبَرَ بَعْدَ أَنْ فَتَحَهَا وَإِنَّ حُزُمَ خَيْلِهِمْ لِيفٌ فَقَالَ أَبَانُ اقْسِمْ لَنَا يَا رَسُولَ اللَّهِ فَقَالَ أَبُو هُرَيْرَةَ فَقُلْتُ لَا تَقْسِمْ لَهُمْ يَا رَسُولَ اللَّهِ فَقَالَ أَبَانُ أَنْتَ بِهَا يَا وَبْرُ تَحَدَّرُ عَلَيْنَا مِنْ رَأْسِ ضَالٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْلِسْ يَا أَبَانُ وَلَمْ يَقْسِمْ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur?], ia berkata; telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Muhammad bin Al Walid Az Zubaidi] dari [Az Zuhri], bahwa ['Anbasah bin Sa'id] telah mengabarkan kepadanya bahwa ia telah mendengar [Abu Hurairah], menceritakan kepada Sa'id bin Al 'Ash bahwa Rasulullah shallallahu 'alaihi wasallam telah mengutus Aban bin Sa'id bin Al 'Ash dalam sebuah kesatuan militer dari Madinah menuju ke Najd. Kemudian Aban bin Sa'id serta para sahabatnya datang kepada Rasulullah shallallahu 'alaihi wasallam di Khaibar setelah beliau menaklukkannya. Dan tali pengikat badan kuda mereka adalah serat. Kemudian Aban berkata; wahai Rasulullah, bagikan untuk kami! Kemudian Abu Hurairah berkata; jangan engkau bagikan untuk mereka wahai Rasulullah! Kemudian Aban berkata; engkau wahai Abu Hurairah (atas ucapanmu ini) seperti hewan kecil (seperti kucing liar) yang datang kepada kami dari puncak Dhal (nama sebuah gunung atau tempat). "},"2283":{"ar":"حَدَّثَنَا حَامِدُ بْنُ يَحْيَى الْبَلْخِيُّ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا الزُّهْرِيُّ وَسَأَلَهُ إِسْمَعِيلُ بْنُ أُمَيَّةَ فَحَدَّثَنَاهُ الزُّهْرِيُّ أَنَّهُ سَمِعَ عَنْبَسَةَ بْنَ سَعِيدٍ الْقُرَشِيَّ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَ قَالَقَدِمْتُ الْمَدِينَةَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِخَيْبَرَ حِينَ افْتَتَحَهَا فَسَأَلْتُهُ أَنْ يُسْهِمَ لِي فَتَكَلَّمَ بَعْضُ وُلْدِ سَعِيدِ بْنِ الْعَاصِ فَقَالَ لَا تُسْهِمْ لَهُ يَا رَسُولَ اللَّهِ قَالَ فَقُلْتُ هَذَا قَاتِلُ ابْنِ قَوْقَلٍ فَقَالَ سَعِيدُ بْنُ الْعَاصِ يَا عَجَبًا لِوَبْرٍ قَدْ تَدَلَّى عَلَيْنَا مِنْ قَدُومِ ضَالٍ يُعَيِّرُنِي بِقَتْلِ امْرِئٍ مُسْلِمٍ أَكْرَمَهُ اللَّهُ تَعَالَى عَلَى يَدَيَّ وَلَمْ يُهِنِّي عَلَى يَدَيْهِقَالَ أَبُو دَاوُد هَؤُلَاءِ كَانُوا نَحْوَ عَشَرَةٍ فَقُتِلَ مِنْهُمْ سِتَّةٌ وَرَجَعَ مَنْ بَقِيَ","id":"Telah menceritakan kepada kami [Hamid bin Yahya Al Balkhi], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; telah menceritakan kepada kami [Az Zuhri], dan ia ditanya Isma'il bin Umayyah kemudian Az Zuhri menceritakannya kepada kami, bahwa ia telah mendengar ['Anbasah bin Sa'id Al Qurasyi], ia menceritakan dari [Abu Hurairah], ia berkata; aku datang ke Madinah sementara Rasulullah shallallahu 'alaihi wasallam di Khaibar ketika beliau telah menaklukkannya. Kemudian aku meminta beliau untuk memberiku saham. Kemudian anak Sa'id bin Al 'Ash (Aban bin Al 'Ash) berkata; jangan engkau beri saham kepadanya wahai Rasulullah! Abu Hurairah berkata; kemudian aku katakan; ini adalah orang yang membunuh Ibnu Qauqal. Kemudian Sa'id bin Al 'Ash berkata; betapa aneh unta kecil, ia telah turun kepada kami dari Dhal dan mencelaku karena membunuh seorang muslim yang Allah ta'ala muliakan melalui diriku. Dan ia tidaklah menghinakanku di hadapannya. Abu Daud berkata; mereka berjumlah sekitar sepuluh orang, dan telah terbunuh enam orang dan kembali sisanya."},"2284":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا بُرَيْدٌ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَدِمْنَا فَوَافَقْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ افْتَتَحَ خَيْبَرَ فَأَسْهَمَ لَنَا أَوْ قَالَ فَأَعْطَانَا مِنْهَا وَمَا قَسَمَ لِأَحَدٍ غَابَ عَنْ فَتْحِ خَيْبَرَ مِنْهَا شَيْئًا إِلَّا لِمَنْ شَهِدَ مَعَهُ إِلَّا أَصْحَابَ سَفِينَتِنَا جَعْفَرٌ وَأَصْحَابُهُ فَأَسْهَمَ لَهُمْ مَعَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], ia berkata; telah menceritakan kepada kami [Abu Usamah], telah menceritakan kepada kami [Buraid] dari [Abu Burdah] dari [Abu Musa], ia berkata; kami datang dan bertepatan Rasulullah shallallahu 'alaihi wasallam berada di Khaibar. Kemudian beliau memberikan saham kepada kami. -atau ia mengatakan; dan beliau memberikan sebagiannya kepada kami. Dan beliau tidak membagikan kepada seorangpun yang tidak menghadiri penaklukan Khaibar kecuali orang yang hadir bersama beliau, kecuali para penumpang kapal kami yaitu Ja'far dan para sahabatnya. Maka beliau memberikan saham bersama mereka. "},"2285":{"ar":"حَدَّثَنَا مَحْبُوبُ بْنُ مُوسَى أَبُو صَالِحٍ أَخْبَرَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ كُلَيْبِ بْنِ وَائِلٍ عَنْ هَانِئِ بْنِ قَيْسٍ عَنْ حَبِيبِ بْنِ أَبِي مُلَيْكَةَ عَنْ ابْنِ عُمَرَ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ يَعْنِي يَوْمَ بَدْرٍ فَقَالَ إِنَّ عُثْمَانَ انْطَلَقَ فِي حَاجَةِ اللَّهِ وَحَاجَةِ رَسُولِ اللَّهِ وَإِنِّي أُبَايِعُ لَهُ فَضَرَبَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَهْمٍ وَلَمْ يَضْرِبْ لِأَحَدٍ غَابَ غَيْرَهُ","id":"Telah menceritakan kepada kami [Mahbub bin Musa Abu Shalih], telah mengabarkan kepada kami [Abu Ishaq Al Fazari], dari [Kulaib bin Wail] dari [Hani` bin Qais] dari [Habib bin Abu Mulaikah] dari [Ibnu Umar], ia berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam berdiri pada saat perang Khaibar kemudian berkata: \"Sesungguhnya Utsman pergi untuk keperluan Allah dan RasulNya, dan aku membai'at untuknya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam memberikannya saham dan tidak memberikan kepada seorangpun yang tidak hadir selainnya. "},"2286":{"ar":"حَدَّثَنَا مَحْبُوبُ بْنُ مُوسَى أَبُو صَالِحٍ حَدَّثَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ زَائِدَةَ عَنْ الْأَعْمَشِ عَنْ الْمُخْتَارِ بْنِ صَيْفِيٍّ عَنْ يَزِيدَ بْنِ هُرْمُزَ قَالَ كَتَبَ نَجْدَةُإِلَى ابْنِ عَبَّاسٍ يَسْأَلُهُ عَنْ كَذَا وَكَذَا وَذَكَرَ أَشْيَاءَ وَعَنْ الْمَمْلُوكِ أَلَهُ فِي الْفَيْءِ شَيْءٌ وَعَنْ النِّسَاءِ هَلْ كُنَّ يَخْرُجْنَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَلْ لَهُنَّ نَصِيبٌ فَقَالَ ابْنُ عَبَّاسٍ لَوْلَا أَنْ يَأْتِيَ أُحْمُوقَةً مَا كَتَبْتُ إِلَيْهِ أَمَّا الْمَمْلُوكُ فَكَانَ يُحْذَى وَأَمَّا النِّسَاءُ فَقَدْ كُنَّ يُدَاوِينَ الْجَرْحَى وَيَسْقِينَ الْمَاءَ","id":"Telah menceritakan kepada kami [Mahbub bin Musa Abu Shalih], telah menceritakan kepada kami [Abu Ishaq Al Fazari], dari [Zaidah] dari [Al A'masy] dari [Al Mukhtar bin Shaifi], dari [Yazid bin Hurmuz], ia berkata; Najdah menulis surat kepada [Ibnu Abbas] ia bertanya mengenai ini dan ini -Yazid menyebutkan beberapa hal- dan mengenai budak, apakah ia mendapatkan fai`? Dan mengenai wanita, apakah mereka keluar bersama Rasulullah shallallahu 'alaihi wasallam? Dan apakah mereka mendapatkan bagian? Kemudian Ibnu Umar berkata; seandainya ia tidak melakukan perbuatan orang-orang yang bodoh maka aku tidak akan mengirim surat kepadanya. Adapun budak maka ia diberi pemberian, dan adapun para wanita maka mereka mengobati dan memberi minum. "},"2287":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ خَالِدٍ يَعْنِي الْوَهْبِيَّ حَدَّثَنَا ابْنُ إِسْحَقَ عَنْ أَبِي جَعْفَرٍ وَالزُّهْرِيِّ عَنْ يَزِيدَ بْنِ هُرْمُزَ قَالَ كَتَبَ نَجْدَةُ الْحَرُورِيُّإِلَى ابْنِ عَبَّاسٍ يَسْأَلُهُ عَنْ النِّسَاءِ هَلْ كُنَّ يَشْهَدْنَ الْحَرْبَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَلْ كَانَ يَضْرِبُ لَهُنَّ بِسَهْمٍ قَالَ فَأَنَا كَتَبْتُ كِتَابَ ابْنِ عَبَّاسٍ إِلَى نَجْدَةَ قَدْ كُنَّ يَحْضُرْنَ الْحَرْبَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَّا أَنْ يُضْرَبَ لَهُنَّ بِسَهْمٍ فَلَا وَقَدْ كَانَ يُرْضَخُ لَهُنَّ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris], ia berkata; telah menceritakan kepada kami [Ahmad bin Khalid Al Wahbi], telah menceritakan kepada kami [Ibnu Ishaq] dari [Abu Ja'far] dan [Az Zuhri] dari [Yazid bin Hurmuz], ia berkata; [Najdah Al Haruri] menulis surat kepada [Ibnu Abbas], ia bertanya kepadanya mengenai para wanita, apakah mereka menghadiri peperangan bersama Rasulullah shallallahu 'alaihi wasallam? Dan apakah mereka diberi saham? Yazid berkata; aku yang menulis surat Ibnu Abbas kepada Najdah. Sungguh mereka telah menghadiri peperangan bersama Rasulullah shallallahu 'alaihi wasallam. Adapun mereka tidak diberi saham (bagian), dan terkadang diberi pemberian. "},"2288":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ وَغَيْرُهُ قَالَا أَخْبَرَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنَا رَافِعُ بْنُ سَلَمَةَ بْنِ زِيَادٍ حَدَّثَنِي حَشْرَجُ بْنُ زِيَادٍ عَنْ جَدَّتِهِ أُمِّ أَبِيهِأَنَّهَا خَرَجَتْ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ خَيْبَرَ سَادِسَ سِتِّ نِسْوَةٍ فَبَلَغَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ إِلَيْنَا فَجِئْنَا فَرَأَيْنَا فِيهِ الْغَضَبَ فَقَالَ مَعَ مَنْ خَرَجْتُنَّ وَبِإِذْنِ مَنْ خَرَجْتُنَّ فَقُلْنَا يَا رَسُولَ اللَّهِ خَرَجْنَا نَغْزِلُ الشَّعَرَ وَنُعِينُ بِهِ فِي سَبِيلِ اللَّهِ وَمَعَنَا دَوَاءُ الْجَرْحَى وَنُنَاوِلُ السِّهَامَ وَنَسْقِي السَّوِيقَ فَقَالَ قُمْنَ حَتَّى إِذَا فَتَحَ اللَّهُ عَلَيْهِ خَيْبَرَ أَسْهَمَ لَنَا كَمَا أَسْهَمَ لِلرِّجَالِ قَالَ قُلْتُ لَهَا يَا جَدَّةُ وَمَا كَانَ ذَلِكَ قَالَتْ تَمْرًا","id":"Telah menceritakan kepada kami [Ibrahim bin Sa'id], dan selainnya, mereka berkata; telah mengabarkan kepada kami [Zaid bin Al Hubab], ia berkata; telah menceritakan kepada kami [Rafi' bin Salamah bin Ziyad], telah menceritakan kepadaku [Hasyraj bin Ziyad], dari [neneknya yaitu ibu ayahnya], bahwa ia pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam pada waktu perang Khaibar, ia adalah wanita yang ketujuh. Kemudian hal tersebut sampai kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau mengirim utusan kepada kami. Kami melihat pada diri beliau terdapat kemarahan, beliau mengatakan; bersama siapakah kalian keluar? Dan dengan izin siapakah kalian keluar? Lalu kami katakan; wahai Rasulullah, kami keluar untuk melantunkan syair, dan dengannya kami membantu di jalan Allah, dan kami membawa obat untuk orang yang terluka, kami mengambilkan anak panah, serta memberi minum. Kemudian beliau berkata: \"Bangkitlah kalian.\" Hingga setelah Allah menaklukkan Khaibar beliau memberi kami bagian sebagaimana memberi bagian kepada para lelaki. Ia berkata; aku katakan kepadanya; wahai nenek. Apakah bagian tersebut? Ia berkata; kurma. "},"2289":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا بِشْرٌ يَعْنِي ابْنَ الْمُفَضَّلِ عَنْ مُحَمَّدِ بْنِ زَيْدٍ قَالَ حَدَّثَنِي عُمَيْرٌ مَوْلَى آبِي اللَّحْمِ قَالَشَهِدْتُ خَيْبَرَ مَعَ سَادَتِي فَكَلَّمُوا فِيَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِي فَقُلِّدْتُ سَيْفًا فَإِذَا أَنَا أَجُرُّهُ فَأُخْبِرَ أَنِّي مَمْلُوكٌ فَأَمَرَ لِي بِشَيْءٍ مِنْ خُرْثِيِّ الْمَتَاعِقَالَ أَبُو دَاوُد مَعْنَاهُ أَنَّهُ لَمْ يُسْهِمْ لَهُ قَالَ أَبُو دَاوُد وَقَالَ أَبُو عُبَيْدٍ كَانَ حَرَّمَ اللَّحْمَ عَلَى نَفْسِهِ فَسُمِّيَ آبِي اللَّحْمِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal], dari [Muhammad bin Zaid], ia berkata; telah menceritakan kepadaku [Umair] mantan budak Abu Al Lahm, ia berkata; aku pernah menghadiri perang Khaibar bersama para majikanku. Kemudian mereka berbica kepada Rasulullah shallallahu 'alaihi wasallam mengenai diriku, kemudian beliau memerintahkanku agar diberi pedang, tatkala aku menyeretnya aku memberitahukan kepadanya bahwa aku adalah seorang budak. Kemudian beliau memerintahkan agar aku diberi perabotan rumah. Abu Daud berkata; artinya bahwa beliau tidak memberikan saham kepadanya. Abu Daud berkata; dan Abu 'Ubaid berkata; ia pernah mengharamkan daging atas dirinya maka ia dinamai Abu Al Lahm. "},"2290":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَكُنْتُ أَمِيحُ أَصْحَابِي الْمَاءَ يَوْمَ بَدْرٍ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur?], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir], ia berkata; aku pernah memberi minum para sahabatku pada saat perang Badr. "},"2291":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَيَحْيَى بْنُ مَعِينٍ قَالَا حَدَّثَنَا يَحْيَى عَنْ مَالِكٍ عَنْ الْفُضَيْلِ عَنْ عَبْدِ اللَّهِ بْنِ نِيَارٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَ يَحْيَىإِنَّ رَجُلًا مِنْ الْمُشْرِكِينَ لَحِقَ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُقَاتِلَ مَعَهُ فَقَالَ ارْجِعْ ثُمَّ اتَّفَقَا فَقَالَ إِنَّا لَا نَسْتَعِينُ بِمُشْرِكٍ","id":"Telah menceritakan kepada kami [Musaddad] dan [Yahya bin Ma'in], mereka berkata; telah menceritakan kepada kami [Yahya] dari [Malik] dari [Al Fudhail] dari [Abdullah bin Niyar], dari ['Urwah] dari [Aisyah], Yahya berkata; sesungguhnya terdapat seorang musyrik yang mengikuti Rasulullah shallallahu 'alaihi wasallam untuk berperang bersama beliau. Kemudian beliau berkata; kembalilah! -kemudian mereka berdua sama lafazhnya: kemudian beliau berkata: \"Sesungguhnya kami tidak meminta bantuan kepada orang musyrik.\""},"2292":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْهَمَ لِرَجُلٍ وَلِفَرَسِهِ ثَلَاثَةَ أَسْهُمٍ سَهْمًا لَهُ وَسَهْمَيْنِ لِفَرَسِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam memberikan tiga saham kepada seseorang dan kudanya, satu saham untuknya dan dua saham untuk kudanya. "},"2293":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنِي الْمَسْعُودِيُّ حَدَّثَنِي أَبُو عَمْرَةَ عَنْ أَبِيهِ قَالَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعَةَ نَفَرٍ وَمَعَنَا فَرَسٌ فَأَعْطَى كُلَّ إِنْسَانٍ مِنَّا سَهْمًا وَأَعْطَى لِلْفَرَسِ سَهْمَيْنِحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أُمَيَّةُ بْنُ خَالِدٍ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ رَجُلٍ مِنْ آلِ أَبِي عَمْرَةَ عَنْ أَبِي عَمْرَةَ بِمَعْنَاهُ إِلَّا أَنَّهُ قَالَ ثَلَاثَةُ نَفَرٍ زَادَ فَكَانَ لِلْفَارِسِ ثَلَاثَةُ أَسْهُمٍ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdullah bin Yazid], telah menceritakan kepadaku [Al Mas'udi], telah menceritakan kepadaku [Abu 'Amrah] dari [ayahnya], ia berkata; kami telah datang kepada Rasulullah shallallahu 'alaihi wasallam berjumlah empat orang, dan kami membawa kuda. Kemudian beliau memberi setiap dari kami satu saham dan untuk kuda dua saham. Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Umayyah bin Khalid], telah menceritakan kepada kami [Al Mas'udi], dari [seorang laki-laki dari keluarga Abu 'Amrah], dari [Abu 'Amrah] seperti makna hadits tersebut hanya saja ia berkata; tiga orang. Ia menambahkan; untuk kuda tiga saham. "},"2294":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا مُجَمِّعُ بْنُ يَعْقُوبَ بْنِ مُجَمِّعِ بْنِ يَزِيدَ الْأَنْصَارِيُّ قَالَ سَمِعْتُ أَبِي يَعْقُوبَ بْنِ مُجَمِّعٍ يَذْكُرُ عَنْ عَمِّهِ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ الْأَنْصَارِيِّ عَنْ عَمِّهِ مُجَمِّعِ بْنِ جَارِيَةَ الْأَنْصَارِيِّ وَكَانَ أَحَدَ الْقُرَّاءِ الَّذِينَ قَرَءُوا الْقُرْآنَ قَالَ شَهِدْنَا الْحُدَيْبِيَةَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا انْصَرَفْنَا عَنْهَا إِذَا النَّاسُ يَهُزُّونَ الْأَبَاعِرَ فَقَالَ بَعْضُ النَّاسِ لِبَعْضٍ مَا لِلنَّاسِ قَالُوا أُوحِيَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجْنَا مَعَ النَّاسِ نُوجِفُ فَوَجَدْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاقِفًا عَلَى رَاحِلَتِهِ عِنْدَ كُرَاعِ الْغَمِيمِ فَلَمَّا اجْتَمَعَ عَلَيْهِ النَّاسُ قَرَأَ عَلَيْهِمْ إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَفَتْحٌ هُوَ قَالَ نَعَمْ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ إِنَّهُ لَفَتْحٌ فَقُسِّمَتْ خَيْبَرُ عَلَى أَهْلِ الْحُدَيْبِيَةِ فَقَسَّمَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى ثَمَانِيَةَ عَشَرَ سَهْمًا وَكَانَ الْجَيْشُ أَلْفًا وَخَمْسَ مِائَةٍ فِيهِمْ ثَلَاثُ مِائَةِ فَارِسٍ فَأَعْطَى الْفَارِسَ سَهْمَيْنِ وَأَعْطَى الرَّاجِلَ سَهْمًا قَالَ أَبُو دَاوُد حَدِيثُ أَبِي مُعَاوِيَةَ أَصَحُّ وَالْعَمَلُ عَلَيْهِ وَأَرَى الْوَهْمَ فِي حَدِيثِ مُجَمِّعٍ أَنَّهُ قَالَ ثَلَاثَ مِائَةِ فَارِسٍ وَكَانُوا مِائَتَيْ فَارِسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Isa], telah menceritakan kepada kami [Mujammi' bin Ya'qub bin Yazid Al Anshari], ia berkata; saya mendengar ayahku [Ya'qub bin Mujammi'] ia menyebutkan dari [pamannya yaitu Abdurrahman bin Yazid Al Anshari], dari [pamannya yaitu Mujammi' bin Jariyah Al Anshari], dan ia adalah salah seorang ahli Al Qur'an. Ia berkata; kami pernah menghadiri perdamaian Hudaibiyah bersama Rasulullah shallallahu 'alaihi wasallam. Kemudian tatkala kami telah pergi dari Hudaibiyah, ternyata terdapat orang-orang yang menggerakkan beberapa unta. Kemudian sebagian orang berkata kepada sebagian yang lain; ada apa dengan orang-orang? Mereka berkata; Rasulullah shallallahu 'alaihi wasallam telah diberi wahyu. Kemudian kami keluar bersama orang-orang, kami mempercepat kendaraan kami, kemudian kami dapati Nabi shallallahu 'alaihi wasallam berdiri di atas kendaraannya di Kura' Al Ghamim. Kemudian tatkala orang-orang telah berkumpul beliau membacakan kepada mereka ayat: \"Sesungguhnya Kami telah memberikan kepadamu kemenangan yang nyata.\" Kemudian terdapat seseorang yang berkata; apakah ini adalah sebuah penaklukan? Beliau berkata: \"Ya, demi Dzat yang jiwa Muhammad ada di tangannya, sesungguhnya itu adalah sebuah penaklukan.\" Kemudian Khaibar dibagikan kepada orang-orang yang menghadiri perdamaian Hudaibiyah. Rasulullah shallallahu wa'alaihi wa sallam membaginya menjadi delapan belas saham. Dan jumlah pasukan adalah seribu lima ratus, diantara mereka terdapat tiga ratus penunggang kuda. Beliau memberi dua saham kepada penunggang kuda dan satu saham kepada orang yang berjalan kaki. Abu Daud berkata; hadits Abu Mu'awiyah lebih shahih, dan menjadi dasar untuk beramal. Dan aku melihat kesalahan ada dalam hadits Mujammi', bahwa ia berkata; tiga ratus penunggang kuda, padahal mereka berjumlah dua ratus penunggang kuda. "},"2295":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ قَالَ أَخْبَرَنَا خَالِدٌ عَنْ دَاوُدَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ بَدْرٍ مَنْ فَعَلَ كَذَا وَكَذَا فَلَهُ مِنْ النَّفَلِ كَذَا وَكَذَا قَالَ فَتَقَدَّمَ الْفِتْيَانُ وَلَزِمَ الْمَشْيَخَةُ الرَّايَاتِ فَلَمْ يَبْرَحُوهَا فَلَمَّا فَتَحَ اللَّهُ عَلَيْهِمْ قَالَ الْمَشْيَخَةُ كُنَّا رِدْءًا لَكُمْ لَوْ انْهَزَمْتُمْ لَفِئْتُمْ إِلَيْنَا فَلَا تَذْهَبُوا بِالْمَغْنَمِ وَنَبْقَى فَأَبَى الْفِتْيَانُ وَقَالُوا جَعَلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنَا فَأَنْزَلَ اللَّهُ{ يَسْأَلُونَكَ عَنْ الْأَنْفَالِ قُلْ الْأَنْفَالُ لِلَّهِ وَالرَّسُولِ إِلَى قَوْلِهِ كَمَا أَخْرَجَكَ رَبُّكَ مِنْ بَيْتِكَ بِالْحَقِّ وَإِنَّ فَرِيقًا مِنْ الْمُؤْمِنِينَ لَكَارِهُونَ }يَقُولُ فَكَانَ ذَلِكَ خَيْرًا لَهُمْ فَكَذَلِكَ أَيْضًا فَأَطِيعُونِي فَإِنِّي أَعْلَمُ بِعَاقِبَةِ هَذَا مِنْكُمْحَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَوْمَ بَدْرٍ مَنْ قَتَلَ قَتِيلًا فَلَهُ كَذَا وَكَذَا وَمَنْ أَسَرَ أَسِيرًا فَلَهُ كَذَا وَكَذَا ثُمَّ سَاقَ نَحْوَهُ وَحَدِيثُ خَالِدٍ أَتَمُّ حَدَّثَنَا هَارُونُ بْنُ مُحَمَّدِ بْنِ بَكَّارِ بْنِ بِلَالٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ مَوْهَبٍ الْهَمْدَانِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ قَالَ أَخْبَرَنِي دَاوُدُ بِهَذَا الْحَدِيثِ بِإِسْنَادِهِ قَالَ فَقَسَّمَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالسَّوَاءِ وَحَدِيثُ خَالِدٍ أَتَمُّ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah], ia berkata; telah mengabarkan kepada kami [Khalid] dari [Daud], dari [Ikrimah], dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda pada saat perang Badr: \"Barangsiapa yang melakukan demikian dan demikian, maka baginya tambahan pemberian demikian dan demikian.\" Kemudian orang-orang yang muda maju sedangkan orang-orang tua menjaga bendera, dan mereka tidak meninggalkannya hingga Allah memenangkan atas mereka. Orang-orang tua berkata; kami adalah adalah penolong kalian, seandainya kalian kalah maka kalian akan bergabung kepada kami, maka janganlah kalian membawa rampasan perang sementara kami tetap di tempat dan tidak mengambilnya. Kemudian para pemuda menolak hal tersebut dan berkata; Rasulullah shallallahu 'alaihi wasallam telah menjadikannya untuk kami. Kemudian Allah menurunkan ayat: \"Mereka menanyakan kepadamu tentang (pembagian) harta rampasan perang. Katakanlah: \"Harta rampasan perang kepunyaan Allah dan Rasul….. hingga firmanNya: \"Sebagaimana Tuhanmu menyuruhmu pergi dan rumahmu dengan kebenaran, padahal sesungguhnya sebagian dari orang-orang yang beriman itu tidak menyukainya.\" Ibnu Abbas berkata berkata; maka hal tersebut menjadi sesuatu yang lebih baik bagi mereka, dan seperti itu juga; maka taatilah aku sesungguhnya aku lebih mengetahui akibat hal ini daripada kalian. Telah menceritakan kepada kami [Ziyad bin Ayyub], telah menceritakan kepada kami [Husyaim], ia berkata; telah mengabarkan kepada kami [Daud bin Abu Hindun], dari [Ikrimah], dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam berkata pada saat perang Badr: \"Barangsiapa yang membunuh satu orang, maka baginya demikian dan demikain. Dan barangsiapa yang menawan tawanan, maka baginya demikian dan demikian.\" Kemudian ia menyebutkan seperti hadits tersebut. Dan hadits Khalid lebih sempurna. Telah menceritakan kepada kami [Harun bin Muhammad bin Bakkar bin Bilal], ia berkata; telah menceritakan kepada kami [Yazid bin Khalid bin Mauhab Al Hamdani], ia berkata; telah menceritakan kepada kami [Yahya bin Zakariya bin Abu Zaidah], ia berkata; telah mengabarkan kepadaku [Daud] dengan hadits ini menggunakan sanadnya. Ia berkata; kemudian Rasulullah shallallahu 'alaihi wasallam membaginya dengan sama. Dan hadits Khalid lebih sempurna. "},"2296":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي بَكْرٍ عَنْ عَاصِمٍ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَجِئْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ بَدْرٍ بِسَيْفٍ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ قَدْ شَفَى صَدْرِي الْيَوْمَ مِنْ الْعَدُوِّ فَهَبْ لِي هَذَا السَّيْفَ قَالَ إِنَّ هَذَا السَّيْفَ لَيْسَ لِي وَلَا لَكَ فَذَهَبْتُ وَأَنَا أَقُولُ يُعْطَاهُ الْيَوْمَ مَنْ لَمْ يُبْلِ بَلَائِي فَبَيْنَمَا أَنَا إِذْ جَاءَنِي الرَّسُولُ فَقَالَ أَجِبْ فَظَنَنْتُ أَنَّهُ نَزَلَ فِيَّ شَيْءٌ بِكَلَامِي فَجِئْتُ فَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ سَأَلْتَنِي هَذَا السَّيْفَ وَلَيْسَ هُوَ لِي وَلَا لَكَ وَإِنَّ اللَّهَ قَدْ جَعَلَهُ لِي فَهُوَ لَكَ ثُمَّ قَرَأَ{ يَسْأَلُونَكَ عَنْ الْأَنْفَالِ قُلْ الْأَنْفَالُ لِلَّهِ وَالرَّسُولِ }إِلَى آخِرِ الْآيَةِقَالَ أَبُو دَاوُد قِرَاءَةُ ابْنِ مَسْعُودٍ يَسْأَلُونَكَ النَّفْلَ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] dari [Abu Bakr] dari ['Ashim] dari [Mush'ab bin Sa'd] dari [ayahnya], ia berkata; aku datang kepada Nabi shallallahu 'alaihi wasallam pada saat perang Badr dengan membawa sebuah pedang. Lalu aku katakan; wahai Rasulullah, sesungguhnya pada hari ini Allah telah mengobati dadaku dari musuh. Maka berikanlah pedang ini kepadaku. Beliau berkata: \"Sesungguhnya pedang ini bukan milikku dan bukan milikmu.\" Kemudian aku pergi dan aku katakan; pada hari ini pedang itu akan diberikan kepada orang yang tidak mendapatkan musibah seperti musibahku. Ketika aku dalam keadaan seperti itu, tiba-tiba seorang utusan datang kepadaku lalu berkata; sambutlah panggilan beliau! Lalu aku menyangka bahwa telah turun sesuatu mengenaiku karena ucapanku. Lalu aku datang dan Nabi shallallahu 'alaihi wasallam berkata kepadaku: \"Sesungguhnya engkau telah meminta pedang ini kepadaku, dan pedang tersebut bukanlah milikku dan bukan milikmu. Dan sesungguhnya Allah telah memberikannya kepadaku. Pedang tersebut untukmu.\" Kemudian beliau membacakan ayat: \"Mereka menanyakan kepadamu tentang (pembagian) harta rampasan perang. Katakanlah: \"Harta rampasan perang kepunyaan Allah dan Rasul…..\" hingga akhir ayat. Abu Daud berkata; sedangkan qira`ah (cara membaca) Ibnu Mas'ud adalah; YAS-ALUUNAKAN NAFLA. "},"2297":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ ح و حَدَّثَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ الْأَنْطَاكِيُّ قَالَ حَدَّثَنَا مُبَشَّرٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ الطَّائِيُّ أَنَّ الْحَكَمَ بْنَ نَافِعٍ حَدَّثَهُمْ الْمَعْنَى كُلُّهُمْ عَنْ شُعَيْبِ بْنِ أَبِي حَمْزَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَيْشٍ قِبَلَ نَجْدٍ وَانْبَعَثَتْ سَرِيَّةٌ مِنْ الْجَيْشِ فَكَانَ سُهْمَانُ الْجَيْشِ اثْنَيْ عَشَرَ بَعِيرًا اثْنَيْ عَشَرَ بَعِيرًا وَنَفَّلَ أَهْلَ السَّرِيَّةِ بَعِيرًا بَعِيرًا فَكَانَتْ سُهْمَانُهُمْ ثَلَاثَةَ عَشَرَ ثَلَاثَةَ عَشَرَحَدَّثَنَا الْوَلِيدُ بْنُ عُتْبَةَ الدِّمَشْقِيُّ قَالَ قَالَ الْوَلِيدُ يَعْنِي ابْنَ مُسْلِمٍ حَدَّثْتُ ابْنَ الْمُبَارَكِ بِهَذَا الْحَدِيثِ قُلْتُ وَكَذَا حَدَّثَنَا ابْنُ أَبِي فَرْوَةَ عَنْ نَافِعٍ قَالَ لَا تَعْدِلُ مَنْ سَمَّيْتَ بِمَالِكٍ هَكَذَا أَوْ نَحْوَهُ يَعْنِي مَالِكَ بْنَ أَنَسٍ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Najdah], telah menceritakan kepada kami [Al Walid bin Muslim], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Musa bin Abdurrahman Al Anthaki], ia berkata; telah menceritakan kepada kami [Mubasysyar], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Muhammad bin 'Auf Ath Tha`i], bahwa [Al Hakam bin Nafi'], telah menceritakan kepada mereka secara makna, seluruh mereka berasal dari [Syu'aib bin Abu Hamzah], dari [Nafi'], dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam mengutus kami dalam sebuah pasukan menuju Najd, kemudian diutuslah satu kesatuan militer dari pasukan tersebut, saham pasukan tersebut adalah dua belas unta, dua belas unta. Dan beliau memberikan tambahan kepada kesatuan militer satu unta, satu unta. Sehingga saham mereka adalah tiga belas. Telah menceritakan kepada kami [Al Walid bin 'Utbah Ad Dimasyqi], ia berkata; [Al Walid bin Muslim] berkata; aku menceritakan kepada Ibnu Al Mubarak dengan hadits ini. Aku katakan; demikianlah [Ibnu Abu Farwah] menceritakan kepada kami dari [Nafi'], ia berkata; orang yang telah engkau sebutkan tidak sama dengan seorang Malik, yaitu Malik bin Anas. "},"2298":{"ar":"حَدَّثَنَا هَنَّادٌ قَالَ حَدَّثَنَا عَبْدَةُ يَعْنِي ابْنَ سُلَيْمَانَ الْكِلَابِيَّ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً إِلَى نَجْدٍ فَخَرَجْتُ مَعَهَا فَأَصَبْنَا نَعَمًا كَثِيرًا فَنَفَّلَنَا أَمِيرُنَا بَعِيرًا بَعِيرًا لِكُلِّ إِنْسَانٍ ثُمَّ قَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَسَمَ بَيْنَنَا غَنِيمَتَنَا فَأَصَابَ كُلُّ رَجُلٍ مِنَّا اثْنَيْ عَشَرَ بَعِيرًا بَعْدَ الْخُمُسِ وَمَا حَاسَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالَّذِي أَعْطَانَا صَاحِبُنَا وَلَا عَابَ عَلَيْهِ بَعْدَ مَا صَنَعَ فَكَانَ لِكُلِّ رَجُلٍ مِنَّا ثَلَاثَةَ عَشَرَ بَعِيرًا بِنَفْلِهِ","id":"Telah menceritakan kepada kami [Hannad], telah menceritakan kepada kami ['Abdah bin Sulaiman Al Kilabi] dari [Muhammad bin Ishaq] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam mengutus satu kesatuan militer ke Najd, kemudian aku keluar bersama kesatuan militer tersebut dan kami mendapatkan banyak binatang ternak. Kemudian pemimpin kami memberikan tambahan satu unta, satu unta untuk setiap orang. Kemudian kami datang kepada Rasulullah shallallahu 'alaihi wasallam dan beliau membagikan rampasan perang kepada kami. Sehingga setiap kami mendapatkan dua belas unta setelah diambil seperlima. Dan Rasulullah shallallahu 'alaihi wasallam tidak menghitung apa yang telah diberikan pemimpin kami kepada kami, dan beliau tidak mencelanya setelah ia melakukan hal tersebut. Sehingga setiap kami memiliki tiga belas unta dengan tambahan tersebut. "},"2299":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ وَيَزِيدُ بْنُ خَالِدِ بْنِ مَوْهَبٍ قَالَا حَدَّثَنَا اللَّيْثُ الْمَعْنَى عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ سَرِيَّةً فِيهَا عَبْدُ اللَّهِ بْنُ عُمَرَ قِبَلَ نَجْدٍ فَغَنِمُوا إِبِلًا كَثِيرَةً فَكَانَتْ سُهْمَانُهُمْ اثْنَيْ عَشَرَ بَعِيرًا وَنُفِّلُوا بَعِيرًا بَعِيرًا زَادَ ابْنُ مَوْهَبٍ فَلَمْ يُغَيِّرْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Abdullah bin Maslamah], dan [Yazid? bin Khalid bin Mauhab], mereka berkata; telah menceritakan kepada kami [Al Laits] secara makna, dari [Nafi'] dari [Abdullah bin Umar], bahwa Rasulullah shallallahu 'alaihi wasallam telah mengirim satu kesatuan militer yang padanya terdapat Abdullah bin Umar ke arah Najd. Kemudian mereka mendapatkan rampasan unta yang banyak. Saham mereka adalah dua belas unta dan mereka diberi tambahan satu ekor, satu ekor oleh Ibnu Mauhab, dan Rasulullah shallallahu 'alaihi wasallam tidak mengubah hal tersebut. "},"2300":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ فَبَلَغَتْ سُهْمَانُنَا اثْنَيْ عَشَرَ بَعِيرًا وَنَفَّلَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعِيرًا بَعِيرًاقَالَ أَبُو دَاوُد رَوَاهُ بُرْدُ بْنُ سِنَانٍ عَنْ نَافِعٍ مِثْلَ حَدِيثِ عُبَيْدِ اللَّهِ وَرَوَاهُ أَيُّوبُ عَنْ نَافِعٍ مِثْلَهُ إِلَّا أَنَّهُ قَالَ وَنُفِّلْنَا بَعِيرًا بَعِيرًا لَمْ يَذْكُرْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah], ia berkata; telah menceritakan kepadaku [Nafi'], dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah mengutus kami dalam sebuah kesatuan militer. Dan saham mereka mencapai dua belas unta. Dan Rasulullah shallallahu 'alaihi wasallam memberikan tambahan satu unta, satu unta. Abu Daud berkata; hadits tersebut diriwayatkan oleh [Burd bin Sinan] dari [Nafi'] seperti hadits 'Ubaidullah. Dan telah diriwayatkan oleh [Ayyub] dari [Nafi'] seperti itu hanya saja ia berkata; dan kami diberi tambahan satu unta, satu unta. Dan ia tidak menyebutkan Nabi shallallahu 'alaihi wasallam. "},"2301":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ قَالَ حَدَّثَنِي أَبِي عَنْ جَدِّي ح و حَدَّثَنَا حَجَّاجُ بْنُ أَبِي يَعْقُوبَ قَالَ حَدَّثَنِي حُجَيْنٌ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ كَانَ يُنَفِّلُ بَعْضَ مَنْ يَبْعَثُ مِنْ السَّرَايَا لِأَنْفُسِهِمْ خَاصَّةَ النَّفَلِ سِوَى قَسْمِ عَامَّةِ الْجَيْشِ وَالْخُمُسُ فِي ذَلِكَ وَاجِبٌ كُلُّهُ","id":"Telah menceritakan kepada kami [Abdul Malik bin Syu'aib bin Al Laits], ia berkata; telah menceritakan kepadaku [ayahku], dari [kakekku], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Hajjaj bin Abu Ya'qub], ia berkata; telah menceritakan kepadaku [Hujain], ia berkata; telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab], dari [Salim] dari [Abdullah bin Umar], bahwa Rasulullah shallallahu 'alaihi wasallam telah memberikan tambahan kepada sebagian orang yang beliau utus dari kesatuan-kesatuan militer khusus untuk mereka selain bagian yang diberikan kepada para pasukan secara umum. Dan seperlima dalam hal tersebut adalah wajib semua. "},"2302":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنَا حُيَيٌّ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَوْمَ بَدْرٍ فِي ثَلَاثِ مِائَةٍ وَخَمْسَةَ عَشَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنَّهُمْ حُفَاةٌ فَاحْمِلْهُمْ اللَّهُمَّ إِنَّهُمْ عُرَاةٌ فَاكْسُهُمْ اللَّهُمَّ إِنَّهُمْ جِيَاعٌ فَأَشْبِعْهُمْ فَفَتَحَ اللَّهُ لَهُ يَوْمَ بَدْرٍ فَانْقَلَبُوا حِينَ انْقَلَبُوا وَمَا مِنْهُمْ رَجُلٌ إِلَّا وَقَدْ رَجَعَ بِجَمَلٍ أَوْ جَمَلَيْنِ وَاكْتَسَوْا وَشَبِعُوا","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Abdullah bin Wahb], telah menceritakan kepada kami [Huyai] dari [Abu Abdurrahman Al Hubuli], dari [Abdullah bin 'Amr], bahwa Rasulullah shallallahu 'alaihi wasallam keluar pada saat perang Badr bersama tiga ratus lima belas orang. Rasulullah shallallahu 'alaihi wasallam berdoa: \"Ya Allah, mereka adalah orang-orang yang tidak beralas kaki maka berilah mereka tunggangan, mereka adalah orang-orang yang telanjang maka berilah mereka pakaian, sesungguhnya mereka adalah orang-orang yang lapar maka kenyangkanlah mereka.\" Kemudian Allah memberi beliau kemenangan pada perang Badr. Sehingga mereka berbalik kondisi mereka, tidak ada seorangpun diantara mereka melainkan ia telah pulang dengan membawa satu atau dua ekor unta, dan mereka berpakaian serta merasa kenyang. "},"2303":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ يَزِيدَ بْنِ يَزِيدَ بْنِ جَابِرٍ الشَّامِيِّ عَنْ مَكْحُولٍ عَنْ زِيَادِ بْنِ جَارِيَةَ التَّمِيمِيِّ عَنْ حَبِيبِ بْنِ مَسْلَمَةَ الْفِهْرِيِّ أَنَّهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنَفِّلُ الثُّلُثَ بَعْدَ الْخُمُسِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], ia berkata; telah mengabarkan kepada kami [Sufyan] dari [Yazid bin Yazid bin Jabir Asy Syami], dari [Makhul] dari [Ziyad bin Jariyah At Taimi] dari [Habib bin Maslamah Al Fihri], bahwa ia berkata; Rasulullah shallallahu 'alaihi wasallam memberikan tambahan sepertiga setelah diambil seperlima. "},"2304":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ الْجُشَمِيُّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ الْعَلَاءِ بْنِ الْحَارِثِ عَنْ مَكْحُولٍ عَنْ ابْنِ جَارِيَةَ عَنْ حَبِيبِ بْنِ مَسْلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُنَفِّلُ الرُّبْعَ بَعْدَ الْخُمُسِ وَالثُّلُثَ بَعْدَ الْخُمُسِ إِذَا قَفَلَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar bin Maisarah Al Jusyami], ia berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Mu'awiyah bin Shalih] dari [Al 'Ala` bin Al Harits] dari [Makhul] dari [Ibnu Jariyah] dari [Habib bin Maslamah] bahwa Rasulullah shallallahu 'alaihi wasallam memberikan tambahan seperempat setelah diambil seperlima, dan sepertiga setelah diambil seperlima apabila berangkat. "},"2305":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَحْمَدَ بْنِ بَشِيرِ بْنِ ذَكْوَانَ وَمَحْمُودُ بْنُ خَالِدٍ الدِّمَشْقِيَّانِ الْمَعْنَى قَالَا حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا يَحْي��ى بْنُ حَمْزَةَ قَالَ سَمِعْتُ أَبَا وَهْبٍ يَقُولُ سَمِعْتُ مَكْحُولًا يَقُولُكُنْتُ عَبْدًا بِمِصْرَ لِامْرَأَةٍ مِنْ بَنِي هُذَيْلٍ فَأَعْتَقَتْنِي فَمَا خَرَجْتُ مِنْ مِصْرَ وَبِهَا عِلْمٌ إِلَّا حَوَيْتُ عَلَيْهِ فِيمَا أُرَى ثُمَّ أَتَيْتُ الْحِجَازَ فَمَا خَرَجْتُ مِنْهَا وَبِهَا عِلْمٌ إِلَّا حَوَيْتُ عَلَيْهِ فِيمَا أُرَى ثُمَّ أَتَيْتُ الْعِرَاقَ فَمَا خَرَجْتُ مِنْهَا وَبِهَا عِلْمٌ إِلَّا حَوَيْتُ عَلَيْهِ فِيمَا أُرَى ثُمَّ أَتَيْتُ الشَّامَ فَغَرْبَلْتُهَا كُلُّ ذَلِكَ أَسْأَلُ عَنْ النَّفَلِ فَلَمْ أَجِدْ أَحَدًا يُخْبِرُنِي فِيهِ بِشَيْءٍ حَتَّى لَقِيتُ شَيْخًا يُقَالُ لَهُ زِيَادُ بْنُ جَارِيَةَ التَّمِيمِيُّ فَقُلْتُ لَهُ هَلْ سَمِعْتَ فِي النَّفَلِ شَيْئًا قَالَ نَعَمْ سَمِعْتُ حَبِيبَ بْنَ مَسْلَمَةَ الْفِهْرِيَّ يَقُولُ شَهِدْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفَّلَ الرُّبُعَ فِي الْبَدْأَةِ وَالثُّلُثَ فِي الرَّجْعَةِ","id":"Telah menceritakan kepada kami [Abdullah bin Ahmad bin Basyir bin Dzakwan], serta [Mahmud bin Khalid Ad Dimasyqi] secara makna, mereka berkata; telah menceritakan kepada kami [Marwan bin Muhammad], ia berkata; telah menceritakan kepada kami [Yahya bin Hamzah], ia berkata; saya mendengar [Abu Wahb] berkata; saya telah mendegar [Makhul] berkata; dahulu aku adalah seorang budak di Mesir milik seorang wanita dari Bani Hudzail, kemudian ia membebaskanku. Tidaklah aku keluar dari Mesir dan padanya terdapat ilmu kecuali aku telah menguasainya sepengetahuanku, kemudian aku datang ke Hijaz, tidaklah aku keluar darinya dan padanya terdapat ilmu melainkan aku telah menguasainya sepengetahuanku. Kemudian aku datang ke Irak, tidaklah aku keluar darinya dan padanya terdapat ilmu melainkan aku telah menguasainya sepengetahuanku. Kemudian aku datang ke Syam lalu aku mengetahui kondisi orang-orang yang ada di sana, setiap itu semua aku bertanya mengenai nafal (tambahan yang diberikan seorang pemimpin) dan aku tidak menjumpai seseorang yang memberitahukan mengenainya hingga aku bertemu dengan seorang syekh yang bernama [Ziyad bin Jariyah At Taimi]. Kemudian aku tanyakan kepadanya; apakah engkau pernah mendengar sesuatu mengenai nafal? Ia berkata; ya. Aku pernah mendengar [Habib bin Maslamah Al Fihri] berkata; aku menyaksikan Nabi shallallahu 'alaihi wasallam memberikan tambahan seperempat ketika pergi dan sepertiga ketika kembali. "},"2306":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ إِسْحَقَ هُوَ مُحَمَّدٌ بِبَعْضِ هَذَا ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ حَدَّثَنِي هُشَيْمٌ عَنْ يَحْيَى بْنِ سَعِيدٍ جَمِيعًا عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْلِمُونَ تَتَكَافَأُ دِمَاؤُهُمْ يَسْعَى بِذِمَّتِهِمْ أَدْنَاهُمْ وَيُجِيرُ عَلَيْهِمْ أَقْصَاهُمْ وَهُمْ يَدٌ عَلَى مَنْ سِوَاهُمْ يَرُدُّ مُشِدُّهُمْ عَلَى مُضْعِفِهِمْ وَمُتَسَرِّيهِمْ عَلَى قَاعِدِهِمْ لَا يُقْتَلُ مُؤْمِنٌ بِكَافِرٍ وَلَا ذُو عَهْدٍ فِي عَهْدِهِوَلَمْ يَذْكُرْ ابْنُ إِسْحَقَ الْقَوَدَ وَالتَّكَافُؤَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Ibnu Abu Adi] dari [Ibnu Ishaq Muhammad], dengan sebagian hadits ini. Dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami ['Ubaidullah bin Umar bin Maisarah], telah menceritakan kepadaku [Husyam] dari [Yahya bin Sa'id] seluruhnya berasal dari ['Amr bin Syu'aib] dari [ayahnya], dari [kakeknya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang muslim darah mereka sederajat, orang yang paling rendah diantara mereka berjalan dengan jaminan keamanan dari mereka, orang terjauh mereka memberikan perlindungan kepada mereka dan mereka adalah satu tangan atas orang selain mereka, orang kuat mereka membantu orang lemah mereka, dan orang yang berperang atas orang yang tidak berperang. Orang yang mukmin tidak dibunuh dibunuh lantaran orang kafir, dan tidak pula dibunuh orang yang memiliki perjanjian selama dalam perjanjiannya.\" Sedangkan Ibnu Ishaq tidak menyebutkan balasan dan persamaan. "},"2307":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا عِكْرِمَةُ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ عَنْ أَبِيهِ قَالَأَغَارَ عَبْدُ الرَّحْمَنِ بْنُ عُيَيْنَةَ عَلَى إِبِلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَتَلَ رَاعِيَهَا فَخَرَجَ يَطْرُدُهَا هُوَ وَأُنَاسٌ مَعَهُ فِي خَيْلٍ فَجَعَلْتُ وَجْهِي قِبَلَ الْمَدِينَةِ ثُمَّ نَادَيْتُ ثَلَاثَ مَرَّاتٍ يَا صَبَاحَاهُ ثُمَّ اتَّبَعْتُ الْقَوْمَ فَجَعَلْتُ أَرْمِي وَأَعْقِرُهُمْ فَإِذَا رَجَعَ إِلَيَّ فَارِسٌ جَلَسْتُ فِي أَصْلِ شَجَرَةٍ حَتَّى مَا خَلَقَ اللَّهُ شَيْئًا مِنْ ظَهْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا جَعَلْتُهُ وَرَاءَ ظَهْرِي وَحَتَّى أَلْقَوْا أَكْثَرَ مِنْ ثَلَاثِينَ رُمْحًا وَثَلَاثِينَ بُرْدَةً يَسْتَخِفُّونَ مِنْهَا ثُمَّ أَتَاهُمْ عُيَيْنَةُ مَدَدًا فَقَالَ لِيَقُمْ إِلَيْهِ نَفَرٌ مِنْكُمْ فَقَامَ إِلَيَّ أَرْبَعَةٌ مِنْهُمْ فَصَعِدُوا الْجَبَلَ فَلَمَّا أَسْمَعْتُهُمْ قُلْتُ أَتَعْرِفُونِي قَالُوا وَمَنْ أَنْتَ قُلْتُ أَنَا ابْنُ الْأَكْوَعِ وَالَّذِي كَرَّمَ وَجْهَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَطْلُبُنِي رَجُلٌ مِنْكُمْ فَيُدْرِكُنِي وَلَا أَطْلُبُهُ فَيَفُوتُنِي فَمَا بَرِحْتُ حَتَّى نَظَرْتُ إِلَى فَوَارِسِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَلَّلُونَ الشَّجَرَ أَوَّلُهُمْ الْأَخْرَمُ الْأَسَدِيُّ فَيَلْحَقُ بِعَبْدِ الرَّحْمَنِ بْنِ عُيَيْنَةَ وَيَعْطِفُ عَلَيْهِ عَبْدُ الرَّحْمَنِ فَاخْتَلَفَا طَعْنَتَيْنِ فَعَقَرَ الْأَخْرَمُ عَبْدَ الرَّحْمَنِ وَطَعَنَهُ عَبْدُ الرَّحْمَنِ فَقَتَلَهُ فَتَحَوَّلَ عَبْدُ الرَّحْمَنِ عَلَى فَرَسِ الْأَخْرَمِ فَيَلْحَقُ أَبُو قَتَادَةَ بِعَبْدِ الرَّحْمَنِ فَاخْتَلَفَا طَعْنَتَيْنِ فَعَقَرَ بِأَبِي قَتَادَةَ وَقَتَلَهُ أَبُو قَتَادَةَ فَتَحَوَّلَ أَبُو قَتَادَةَ عَلَى فَرَسِ الْأَخْرَمِ ثُمَّ جِئْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمَاءِ الَّذِي جَلَّيْتُهُمْ عَنْهُ ذُو قَرَدٍ فَإِذَا نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي خَمْسِ مِائَةٍ فَأَعْطَانِي سَهْمَ الْفَارِسِ وَالرَّاجِلِ","id":"Telah menceritakan kepada kami [Harun bin Abdullah], telah menceritakan kepada kami [Hasyim bin Al Qasim], telah menceritakan kepada kami [Ikrimah], telah menceritakan kepadaku [Iyas bin Salamah] dari [ayahnya], ia berkata; Abdurrahman bin 'Uyainah telah menyerang unta Rasulullah shallallahu 'alaihi wasallam dan membunuh penggembalanya, lalu ia dan para sahabatnya menggiring unta tersebut dengan menunggang kuda. Kemudian aku arahkan wajahku menghadap ke Madinah, kemudian aku menyeru tiga kali; peringatan…! Kemudian aku mengikuti orang-orang tersebut lalu aku memanah dan membunuh tunggangan mereka. Kemudian tiba-tiba terdapat seorang penunggang kuda yang kembali ke arahku. Aku duduk bersembunyi di panggal pohon, kemudian Allah tidaklah Allah memberikan tunggangan kepada Nabi shallallahu 'alaihi wasallam melainkan aku jadikan berada di belakang punggungku. Hingga mereka melemparkan lebih dari tiga puluh tombak dan tiga puluh pakaiaan untuk memperingan darinya. Kemudian 'Uyainah memberikan bala bantuan kepada mereka. Lalu ia berkata; hendaknya ada beberapa orang diantara kalian yang bangkit menuju kepadanya! Kemudian terdapat empar orang diantara mereka yang datang kepadaku dan menaiki gunung. Kemudian tatkala mereka mendengarku aku katakan; apakah kalian mengenalku? Mereka berkata; siapa engkau? Aku katakan; aku adalah Ibnu Al Akwa'. Demi Dzat yang telah memuliakan wajah Muhammad shallallahu 'alaihi wasallam, tidak ada seorangpun dari kalian yang mencariku kemudian mampu mendapatkanku. Dan tidaklah aku mencarinya dan ia luput dariku. Dan tidak lama kemudian aku melihat para penunggang kuda Rasulullah shallallahu 'alaihi wasallam yang menyelinap diantara pepohonan. Orang pertama mereka adalah Al Akhram Al Asadi, kemudian ia mengejar Abdurrahman bin 'Uyainah, kemudian Abdurrahman berbalik kepadanya, dan tusukan mereka bergantian dua tusukan. Lalu Al Akhram membunuh tunggangannya dan Abdurrahman menusuknya hingga ia mampu membunuhnya. Kemudian Abdurrahman berpindah kepada kuda Al Akhram. Lalu Abu Qatadah mengejar Abdurrahman kemudian mereka saling bergantian dua tusukan. Abdurrahman membunuh tunggangan Abu Qatadah dan Abu Qatadah membunuhnya. Kemudian Abu Qatadah berpindah ke kuda Al Akhram. Kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam sementara beliau berada di tepi air yang aku jauhkan mereka darinya, yaitu Dzu Qarad. Ternyata Rasulullah shallallahu 'alaihi wasallam berada diantara lima ratus unta, kemudian beliau memberiku saham penunggang kuda dan pejalan kaki. "},"2308":{"ar":"حَدَّثَنَا أَبُو صَالِحٍ مَحْبُوبُ بْنُ مُوسَى أَخْبَرَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِي الْجُوَيْرِيَةِ الْجَرْمِيِّ قَالَأَصَبْتُ بِأَرْضِ الرُّومِ جَرَّةً حَمْرَاءَ فِيهَا دَنَانِيرُ فِي إِمْرَةِ مُعَاوِيَةَ وَعَلَيْنَا رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَنِي سُلَيْمٍ يُقَالُ لَهُ مَعْنُ بْنُ يَزِيدَ فَأَتَيْتُهُ بِهَا فَقَسَمَهَا بَيْنَ الْمُسْلِمِينَ وَأَعْطَانِي مِنْهَا مِثْلَ مَا أَعْطَى رَجُلًا مِنْهُمْ ثُمَّ قَالَ لَوْلَا أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا نَفْلَ إِلَّا بَعْدَ الْخُمُسِ لَأَعْطَيْتُكَ ثُمَّ أَخَذَ يَعْرِضُ عَلَيَّ مِنْ نَصِيبِهِ فَأَبَيْتُحَدَّثَنَا هَنَّادٌ عَنْ ابْنِ الْمُبَارَكِ عَنْ أَبِي عَوَانَةَ عَنْ عَاصِمِ بْنِ كُلَيْبٍ بِإِسْنَادِهِ وَمَعْنَاهُ","id":"Telah menceritakan kepada kami [Abu Shalih Mahbub bin Musa], telah mengabarkan kepada kami [Abu Ishaq Al Fazari], dari ['Ashim bin Kulaib] dari [Abu Al Juwairiyah Al Jarmi], ia berkata; aku di negeri Romawi aku mendapatkan kendi merah yang berisi uang dinar pada saat kepemimpinan Mu'awiyah. Dan kami dipimpin oleh seorang sahabat Nabi shallallahu 'alaihi wasallam dari Bani Sulaim yang dipanggil [Ma'n bin Yazid]. Lalu aku mendatanginya dengan membawa kendi tersebut, lalu ia membaginya diantara orang-orang muslim. Dan ia memberiku dari kendi tersebut seperti ia memberikan kepada salah seorang diantara mereka. Kemudian ia berkata; seandainya aku tidak mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada nafal kecuali setelah diambil seperlima niscaya aku memberimu.\" Kemudian beliau menawarkan kepadaku sebagian dari bagiannya. Lalu aku menolak. Telah menceritakan kepada kami [Hannad] dari [Ibnu Al Mubarak] dari [Abu 'Awanah] dari ['Ashim bin Kulaib] dengan sanadnya dan maknanya. "},"2309":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ عُتْبَةَ قَالَ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْعَلَاءِ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ الْأَسْوَدَ قَالَ سَمِعْتُ عَمْرَو بْنَ عَبَسَةَ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى بَعِيرٍ مِنْ الْمَغْنَمِ فَلَمَّا سَلَّمَ أَخَذَ وَبَرَةً مِنْ جَنْبِ الْبَعِيرِ ثُمَّ قَالَ وَلَا يَحِلُّ لِي مِنْ غَنَائِمِكُمْ مِثْلُ هَذَا إِلَّا الْخُمُسُ وَالْخُمُسُ مَرْدُودٌ فِيكُمْ","id":"Telah menceritakan kepada kami [Al Walid bin 'Utbah], ia berkata; telah menceritakan kepada kami [Al Walid], telah menceritakan kepada kami [Abdullah bin Al 'Ala`] bahwa ia mendengar [Abu Sallam Al Aswad], berkata; aku mendengar ['Amr bin 'Abasah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melakukan shalat bersama kami menghadap ke unta yang merupakan sebagian dari rampasan perang, kemudian beliau mengucapkan salam dan mengambil satu helai rambut dari sisi unta tersebut, kemudian beliau berkata: \"Dan tidak halal bagiku dari rampasan perang kalian seperti ini kecuali seperlima dan seperlima dikembalikan kepada kalian. "},"2310":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْغَادِرَ يُنْصَبُ لَهُ لِوَاءٌ يَوْمَ الْقِيَامَةِ فَيُقَالُ هَذِهِ غَدْرَةُ فُلَانِ بْنِ فُلَانٍ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik], dari [Abdullah bin Dinar] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang berkhianat akan dikibarkan baginya bendera pada Hari Kiamat dan dikatakan; ini adalah pengkhianatan Fulan bin Fulan.\""},"2311":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْإِمَامُ جُنَّةٌ يُقَاتَلُ بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah Al Bazzaz], ia berkata; telah menceritakan kepada kami [Abdurrahman bin Abu Az Zinad], dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang imam adalah tameng yang digunakan untuk berperang.\""},"2312":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ الْحَسَنِ بْنِ عَلِيِّ بْنِ أَبِي رَافِعٍ أَنَّ أَبَا رَافِعٍ أَخْبَرَهُ قَالَبَعَثَتْنِي قُرَيْشٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُلْقِيَ فِي قَلْبِي الْإِسْلَامُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي وَاللَّهِ لَا أَرْجِعُ إِلَيْهِمْ أَبَدًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَا أَخِيسُ بِالْعَهْدِ وَلَا أَحْبِسُ الْبُرُدَ وَلَكِنْ ارْجِعْ فَإِنْ كَانَ فِي نَفْسِكَ الَّذِي فِي نَفْسِكَ الْآنَ فَارْجِعْ قَالَ فَذَهَبْتُ ثُمَّ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمْتُقَالَ بُكَيْرٌ وَأَخْبَرَنِي أَنَّ أَبَا رَافِعٍ كَانَ قِبْطِيًّا قَالَ أَبُو دَاوُد هَذَا كَانَ فِي ذَلِكَ الزَّمَانِ فَأَمَّا الْيَوْمَ فَلَا يَصْلُحُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Abdullah bin Wahb], telah mengabarkan kepadaku ['Amr] dari [Bukair bin Al Asyajj] dari [Al Husan bin Ali bin Abu Rafi'], bahwasanya [Abu Rof'] telah mengabarkan kepadanya, ia berkata; orang-orang Quraisy telah mengutusku kepada Rasulullah shallallahu 'alaihi wasallam, kemudian tatkala aku melihat Rasulullah shallallahu 'alaihi wasallam maka terbetik dalam hatiku untuk masuk Islam. Lalu aku katakan; wahai Rasulullah, demi Allah, sesungguhnya aku tidak akan kembali kepada mereka selamanya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku tidak akan membatalkan perjanjianku, dan tidak akan menahan utusan. Akan tetapi kembalilah apabila dalam hatimu apa yang ada dalam hatimu sekarang ini maka kembalilah!\" Al Husain berkata; lalu aku kembali, kemudian aku mendatangi Nabi shallallahu 'alaihi wasallam dan masuk Islam. Bukair berkata; dan ia telah mengabarkan kepadaku bahwa Abu Rafi' adalah seorang Qibthi (orang asli Mesir). Abu Daud berkata; ini adalah pada zaman dulu, adapun sekarang maka tidak boleh. "},"2313":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ النَّمَرِيُّ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي الْفَيْضِ عَنْ سُلَيْمِ بْنِ عَامِرٍ رَجُلٌ مِنْ حِمْيَرَ قَالَكَانَ بَيْنَ مُعَاوِيَةَ وَبَيْنَ الرُّومِ عَهْدٌ وَكَانَ يَسِيرُ نَحْوَ بِلَادِهِمْ حَتَّى إِذَا انْقَضَى الْعَهْدُ غَزَاهُمْ فَجَاءَ رَجُلٌ عَلَى فَرَسٍ أَوْ بِرْذَوْنٍ وَهُوَ يَقُولُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ وَفَاءٌ لَا غَدَرَ فَنَظَرُوا فَإِذَا عَمْرُو بْنُ عَبَسَةَ فَأَرْسَلَ إِلَيْهِ مُعَاوِيَةُ فَسَأَلَهُ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَانَ بَيْنَهُ وَبَيْنَ قَوْمٍ عَهْدٌ فَلَا يَشُدُّ عُقْدَةً وَلَا يَحُلُّهَا حَتَّى يَنْقَضِيَ أَمَدُهَا أَوْ يَنْبِذَ إِلَيْهِمْ عَلَى سَوَاءٍ فَرَجَعَ مُعَاوِيَةُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar An Namiri], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Al Faidh] dari [Sulaim bin 'Amir] seorang laki-laki dari Himyar, ia berkata; dahulu antara Mu'awiyah dan Romawi terdapat perjanjian. Ia berjalan ke arah negeri mereka, kemudian setelah habis masa perjanjian ia memerangi orang-orang Romawi tersebut. Kemudian terdapat seorang laki-laki yang datang dengan menaiki kuda, ia berkata; Allahu akbar, Allahu akbar. Pemenuhan janji bukan pengkhianatan. Kemudian orang-orang melihat kepadanya dan ternyata ia adalah ['Amr bin 'Abasah], kemudian Mu'awiyah mengirimkan utusan kepadanya dan bertanya kepadanya. Kemudian ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa antara dirinya dan suatu kaum terdapat suatu perjanjian, maka janganlah ia mengencangkan ikatan dan janganlah ia melepasnya hingga habis waktunya atau ia mengembalikan perjanjian itu kepada mereka dengan cara yang jujur.\" Kemudian Mu'awiyah kembali. "},"2314":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ عُيَيْنَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَ مُعَاهِدًا فِي غَيْرِ كُنْهِهِ حَرَّمَ اللَّهُ عَلَيْهِ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Waki'] dari ['Uyainah bin Abdurrahman] dari [ayahnya] dari [Abu Bakrah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membunuh kafir mu'ahad (yang memiliki perjanjian dengan Islam) tidak pada waktunya, maka Allah mengharamkan baginya Surga.\""},"2315":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو الرَّازِيُّ حَدَّثَنَا سَلَمَةُ يَعْنِي ابْنَ الْفَضْلِ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ قَالَ كَانَ مُسَيْلِمَةُ كَتَبَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَقَدْ حَدَّثَنِي مُحَمَّدُ بْنُ إِسْحَقَ عَنْ شَيْخٍ مِنْ أَشْجَعَ يُقَالُ لَهُ سَعْدُ بْنُ طَارِقٍ عَنْ سَلَمَةَ بْنِ نُعَيْمِ بْنِ مَسْعُودٍ الْأَشْجَعِيِّ عَنْ أَبِيهِ نُعَيْمٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَهُمَا حِينَ قَرَأَ كِتَابَ مُسَيْلِمَةَ مَا تَقُولَانِ أَنْتُمَا قَالَا نَقُولُ كَمَا قَالَ قَالَ أَمَا وَاللَّهِ لَوْلَا أَنَّ الرُّسُلَ لَا تُقْتَلُ لَضَرَبْتُ أَعْنَاقَكُمَا","id":"Telah menceritakan kepada kami [Muhammad bin 'Amr Ar Razi], telah menceritakan kepada kami [Salamah bin Al Fadhl] dari [Muhammad bin Ishaq], ia berkata; dahulu Maslamah pernah menulis surat kepada Rasulullah shallallahu 'alaihi wasallam, ia berkata; telah menceritakan kepadaku Muhammad bin Ishaq dari seorang syekh dari Asyja' yang dipanggil [Sa'd bin Thariq], dari [Salamah bin Nu'aim bin Mas'ud Al Asyja'i] dari [ayahnya yaitu Nu'aim], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam berkata kepada mereka berdua ketika beliau membaca surat Musailamah: \"Bagaimana pendapat kalian berdua?\" Mereka berdua berkata; kami mengatakan seperti yang ia katakan. Beliau berkata: \"Demi Allah, seandainya utusan boleh dibunuh niscaya aku akan memenggal leher kalian berdua.\""},"2316":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ حَارِثَةَ بْنِ مُضَرِّبٍأَنَّهُ أَتَى عَبْدَ اللَّهِ فَقَالَ مَا بَيْنِي وَبَيْنَ أَحَدٍ مِنْ الْعَرَبِ حِنَةٌ وَإِنِّي مَرَرْتُ بِمَسْجِدٍ لِبَنِي حَنِيفَةَ فَإِذَا هُمْ يُؤْمِنُونَ بِمُسَيْلِمَةَ فَأَرْسَلَ إِلَيْهِمْ عَبْدَ اللَّهِ فَجِيءَ بِهِمْ فَاسْتَتَابَهُمْ غَيْرَ ابْنِ النَّوَّاحَةِ قَالَ لَهُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْلَا أَنَّكَ رَسُولٌ لَضَرَبْتُ عُنُقَكَ فَأَنْتَ الْيَوْمَ لَسْتَ بِرَسُولٍ فَأَمَرَ قَرَظَةَ بْنَ كَعْبٍ فَضَرَبَ عُنُقَهُ فِي السُّوقِ ثُمَّ قَالَ مَنْ أَرَادَ أَنْ يَنْظُرَ إِلَى ابْنِ النَّوَّاحَةِ قَتِيلًا بِالسُّوقِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Abu Ishaq] dari [Haritsah bin Mudharrib], bahwa ia datang kepada [Abdullah] dan berkata; tidak ada antara diriku dengan salah seorang Arab permusuhan, dan aku pernah melewati masjid Bani Hanifah, ternyata mereka adalah orang-orang yang beriman kepada Musailamah. Kemudian Abdullah mengutus utusan kepada mereka, kemudian mereka dihadapkan kepadanya. Lalu ia meminta mereka untuk bertaubat selain Ibnu An Nawwahah. Abdullah berkata kepadanya; saya mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Seandainya engkau bukanlah seorang utusan niscaya aku memenggal lehermu.\" Pada saat ini engkau bukanlah seorang utusan. Kemudian ia memerintahkan Qarazhah bin Ka'bin untuk memenggalnya, lalu ia memenggal lehernya di pasar. Kemudian ia berkata; siapa yang ingin melihat Ibnu An Nawwahah terbunuh di pasar? "},"2317":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عِيَاضُ بْنُ عَبْدِ اللَّهِ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَ حَدَّثَتْنِي أُمُّ هَانِئٍ بِنْتُ أَبِي طَالِبٍأَنَّهَا أَجَارَتْ رَجُلًا مِنْ الْمُشْرِكِينَ يَوْمَ الْفَتْحِ فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ ذَلِكَ لَهُ فَقَالَ قَدْ أَجَرْنَا مَنْ أَجَرْتِ وَأَمَّنَّا مَنْ أَمَّنْتِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku ['Iyadh bin Abdullah] dari [Makhramah bin Sulaiman], dari [Kuraib] dari [Ibnu Abbas], ia berkata; telah menceritakan kepadaku [Ummu Hani` binti Abu Thalib] bahwa ia telah melindungi seorang laki-laki musyrik pada saat penaklukan Mekkah. Kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepadanya. Kemudian beliau berkata: \"Kami telah melindungi orang yang engkau lindungi, dan kami memberi keamanan orang yang telah engkau beri keamanan.\""},"2318":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْإِنْ كَانَتْ الْمَرْأَةُ لَتُجِيرُ عَلَى الْمُؤْمِنِينَ فَيَجُوزُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Sufyan bin 'Uyainah], dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah], ia berkata; apabila seorang wanita melindungi orang-orang mukmin, maka hal tersebut adalah boleh. "},"2319":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ أَنَّ مُحَمَّدَ بْنَ ثَوْرٍ حَدَّثَهُمْ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمَنَ الْحُدَيْبِيَةِ فِي بِضْعَ عَشْرَةَ مِائَةً مِنْ أَصْحَابِهِ حَتَّى إِذَا كَانُوا بِذِي الْحُلَيْفَةِ قَلَّدَ الْهَدْيَ وَأَشْعَرَهُ وَأَحْرَمَ بِالْعُمْرَةِ وَسَاقَ الْحَدِيثَ قَالَ وَسَارَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كَانَ بِالثَّنِيَّةِ الَّتِي يَهْبِطُ عَلَيْهِمْ مِنْهَا بَرَكَتْ بِهِ رَاحِلَتُهُ فَقَالَ النَّاسُ حَلْ حَلْ خَلَأَتْ الْقَصْوَاءُ مَرَّتَيْنِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا خَلَأَتْ وَمَا ذَلِكَ لَهَا بِخُلُقٍ وَلَكِنْ حَبَسَهَا حَابِسُ الْفِيلِ ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَا يَسْأَلُونِي الْيَوْمَ خُطَّةً يُعَظِّمُونَ بِهَا حُرُمَاتِ اللَّهِ إِلَّا أَعْطَيْتُهُمْ إِيَّاهَا ثُمَّ زَجَرَهَا فَوَثَبَتْ فَعَدَلَ عَنْهُمْ حَتَّى نَزَلَ بِأَقْصَى الْحُدَيْبِيَةِ عَلَى ثَمَدٍ قَلِيلِ الْمَاءِ فَجَاءَهُ بُدَيْلُ بْنُ وَرْقَاءَ الْخُزَاعِيُّ ثُمَّ أَتَاهُ يَعْنِي عُرْوَةَ بْنَ مَسْعُودٍ فَجَعَلَ يُكَلِّمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكُلَّمَا كَلَّمَهُ أَخَذَ بِلِحْيَتِهِ والْمُغِيَرةُ بْنُ شُعْبَةَ قَائِمٌ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ السَّيْفُ وَعَلَيْهِ الْمِغْفَرُ فَضَرَبَ يَدَهُ بِنَعْلِ السَّيْفِ وَقَالَ أَخِّرْ يَدَكَ عَنْ لِحْيَتِهِ فَرَفَعَ عُرْوَةُ رَأْسَهُ فَقَالَ مَنْ هَذَا قَالُوا الْمُغِيرَةُ بْنُ شُعْبَةَ فَقَالَ أَيْ غُدَرُ أَوَلَسْتُ أَسْعَى فِي غَدْرَتِكَ وَكَانَ الْمُغِيرَةُ صَحِبَ قَوْمًا فِي الْجَاهِلِيَّةِ فَقَتَلَهُمْ وَأَخَذَ أَمْوَالَهُمْ ثُمَّ جَاءَ فَأَسْلَمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا الْإِسْلَامُ فَقَدْ قَبِلْنَا وَأَمَّا الْمَا��ُ فَإِنَّهُ مَالُ غَدْرٍ لَا حَاجَةَ لَنَا فِيهِ فَذَكَرَ الْحَدِيثَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اكْتُبْ هَذَا مَا قَاضَى عَلَيْهِ مُحَمَّدٌ رَسُولُ اللَّهِ وَقَصَّ الْخَبَرَ فَقَالَ سُهَيْلٌ وَعَلَى أَنَّهُ لَا يَأْتِيكَ مِنَّا رَجُلٌ وَإِنْ كَانَ عَلَى دِينِكَ إِلَّا رَدَدْتَهُ إِلَيْنَا فَلَمَّا فَرَغَ مِنْ قَضِيَّةِ الْكِتَابِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ قُومُوا فَانْحَرُوا ثُمَّ احْلِقُوا ثُمَّ جَاءَ نِسْوَةٌ مُؤْمِنَاتٌ مُهَاجِرَاتٌ الْآيَةَ فَنَهَاهُمْ اللَّهُ أَنْ يَرُدُّوهُنَّ وَأَمَرَهُمْ أَنْ يَرُدُّوا الصَّدَاقَ ثُمَّ رَجَعَ إِلَى الْمَدِينَةِ فَجَاءَهُ أَبُو بَصِيرٍ رَجُلٌ مِنْ قُرَيْشٍ يَعْنِي فَأَرْسَلُوا فِي طَلَبِهِ فَدَفَعَهُ إِلَى الرَّجُلَيْنِ فَخَرَجَا بِهِ حَتَّى إِذْ بَلَغَا ذَا الْحُلَيْفَةِ نَزَلُوا يَأْكُلُونَ مِنْ تَمْرٍ لَهُمْ فَقَالَ أَبُو بَصِيرٍ لِأَحَدِ الرَّجُلَيْنِ وَاللَّهِ إِنِّي لَأَرَى سَيْفَكَ هَذَا يَا فُلَانُ جَيِّدًا فَاسْتَلَّهُ الْآخَرُ فَقَالَ أَجَلْ قَدْ جَرَّبْتُ بِهِ فَقَالَ أَبُو بَصِيرٍ أَرِنِي أَنْظُرْ إِلَيْهِ فَأَمْكَنَهُ مِنْهُ فَضَرَبَهُ حَتَّى بَرَدَ وَفَرَّ الْآخَرُ حَتَّى أَتَى الْمَدِينَةَ فَدَخَلَ الْمَسجِدَ يَعْدُو فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ رَأَى هَذَا ذُعْرًا فَقَالَ قَدْ قُتِلَ وَاللَّهِ صَاحِبِي وَإِنِّي لَمَقْتُولٌ فَجَاءَ أَبُو بَصِيرٍ فَقَالَ قَدْ أَوْفَى اللَّهُ ذِمَّتَكَ فَقَدْ رَدَدْتَنِي إِلَيْهِمْ ثُمَّ نَجَّانِي اللَّهُ مِنْهُمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيْلَ أُمِّهِ مِسْعَرَ حَرْبٍ لَوْ كَانَ لَهُ أَحَدٌ فَلَمَّا سَمِعَ ذَلِكَ عَرَفَ أَنَّهُ سَيَرُدُّهُ إِلَيْهِمْ فَخَرَجَ حَتَّى أَتَى سَيْفَ الْبَحْرِ وَيَنْفَلِتُ أَبُو جَنْدَلٍ فَلَحِقَ بِأَبِي بَصِيرٍ حَتَّى اجْتَمَعَتْ مِنْهُمْ عِصَابَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid] bahwa [Muhammad bin Tsaur] telah menceritakan kepada mereka, dari [Ma'mar] dari [Az Zuhri] dari ['Urwah bin Az Zubair] dari [Al Miswar bin Makhramah], ia berkata; Nabi shallallahu 'alaihi wasallam pernah keluar pada waktu terjadinya perdamaian Hudaibiyah bersama seratus tiga belas sahabatnya hingga ketika sampai di Dzul Hulaifah, beliau mengalungi hewan kurban dan memberinya tanda serta berihram untuk melakukan umrah. Al Miswar menyebutkan hadits tersebut, dan ia berkata; dan Nabi shallallahu 'alaihi wasallam berjalan hingga setelah berada di Ats Tsaniyyah yang darinya beliau turun kepada mereka, unta beliau menderum. Kemudian orang-orang berkata; hus, hus.. Al Qaswa` berhernti dua kali. Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Demi Dzat yang jiwaku ada di tanganNya, Al Qashwaa` tidak berhenti dan hal itu bukanlah tabi'atnya, akan tetapi ia tertahan oleh sesuatu yang menahan gajah (yang hendak menghancurkan Ka'bah).\" Kemudian beliau berkata: \"Demi Dzat yang jiwaku ada di tangannya, tidaklah pada hari ini mereka meminta sebuah kondisi yang dengannya mereka mengagungkan bulan-bulan haram (dengan tidak melakukan peperangan) melainkan aku akan memberikannya kepada mereka.\" Kemudian beliu menggertak untanya hingga berdiri, lalu beliau pergi dari mereka hingga beliau singgah di bagian Hudaibiyyah yang paling jauh, berada di atas lubang yang memilliki sedikit air. Kemudian Budail bin Warqa` Al Khuza'i datang kepada beliau kemudian 'Urwah bin Mas'ud datang kepadanya, dan berbicara dengan Nabi shallallahu 'alaihi wasallam, setiap kali ia berbicara dengan beliau ia memegang jenggot beliau. Sementara Al Mughirah bin Syu'bah berdiri di samping Nabi shallallahu 'alaihi wasallam dengan memegang pedang, dan memakai penutup kepala. Kemudian ia memukulkan tangannya pada gagang pedang, dan ia berkata; jauhkan tanganmu dari jenggot beliau! Kemudian 'Urwah mengangkat kepalanya dan berkata; siapakah ini? Mereka berkata; Al Mughirah bin Syu'bah. Kemudian ia berkata; wahai orang yang suka mengingkari janji, bukankah aku telah berusaha menolak keburukan sifat ingkar janjimu? Dahulu Al Mughirah pernah menyertai beberapa orang (dari Tsaqif) pada masa jahiliyah kemudan ia membunuh mereka dan mengambil harta mereka. Kemudian ia datang dan masuk Islam. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Adapun (jika) masuk Islam, maka kami menerima, sedangkan harta tersebut adalah harta hasil dari pengkhianatan, kami tidak butuh kepadanya.\" kemudian ia menyebutkan hadits tersebut. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Tulislah, ini adalah yang diputuskan Muhammad Rasulullah.\" Kemudian ia menyebutkan kisah tersebut. Kemudian Suhail berkata; dan dengan syarat bahwa tidak ada seorangpun diantara kami yang datang kepadamu walaupun ia berada di atas agamu melainkan engkau kembalikan kepada kami. Kemudian tatkala telah selesai dari urusan tulisan tersebut Nabi shallallahu 'alaihi wasallam bersabda kepada para sahabatnya: \"Bangkitlah, lalu sembelihlah kurban kemudian bercukurlah!\" kemudian para wanita mukmi yang berhijrah datang, sebagaimana yang terdapat dalam ayat. Kemudian Allah melarang mereka untuk mengembalikan para wanita tersebut dan memerintahkan agar mereka mengembalikan mahar (kepada mantan suami mereka). Kemudian beliau kembali ke Madinah, kemudian beliau di datangi seorang laki-laki Quraisy. Lalu orang-orang Quraisy mengirimkan utusan untuk mencarinya, kemudian beliau menyerahkannya kepada dua orang. Kemudian kedua orang tersebut keluar dengan membawanya, hingga tatkala mereka sampai di Dzul Hulaifah, mereka singgah dan makan sebagian kurma mereka. Lalu Abu Bashir berkata kepada salah seorang dari mereka; demi Allah, sungguh aku melihat pedangmu ini bagus wahai Fulan. Kemudian orang yang lain menghunusnya dan berkata; benar. Sungguh aku telah mencobanya. Lalu Abu Bashir bekata; perlihatkan kepadaku! aku akan melihatnya. Kemudian orang tersebut menyerahkan pedang tersebut kepadanya. lalu Abu Bashir menebasnya hingga mati, dan yang lain melarikan diri hingga datang ke Madinah, lalu ia memasuki masjid. Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Sungguh orang ini telah melihat rasa takut.\" Kemudian orang tersebut berkata; demi Allah, sahabatku telah terbunuh, dan aku akan dibunuh. Lalu Abu Bashir datang dan berkata; sungguh Allah telah memenuhi perlindunganmu, anda telah mengembalikanku kepada mereka kemudian Allah menyelamatkanku dari mereka. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Mengherankan, ia akan mengobarkan api peperangan apabila ia memiliki teman yang menolongnya.\" Kemudian tatkala Abu Bashir mendengar hal tersebut maka ia mengerti bahwa beliau akan mengembalikannya kepada mereka. Maka ia keluar hingga sampai di tepi laut, dan Abu Jundal hilang dan bergabung dengan Abu Bashir hingga terkumpul dari mereka sekelompok orang (berjumlah empat puluh atau lebih). "},"2320":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ إِدْرِيسَ قَالَ سَمِعْتُ ابْنَ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ وَمَرْوَانَ بْنِ الْحَكَمِأَنَّهُمْ اصْطَلَحُوا عَلَى وَضْعِ الْحَرْبِ عَشْرَ سِنِينَ يَأْمَنُ فِيهِنَّ النَّاسُ وَعَلَى أَنَّ بَيْنَنَا عَيْبَةً مَكْفُوفَةً وَأَنَّهُ لَا إِسْلَالَ وَلَا إِغْلَالَ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], telah menceritakan kepada kami [Ibnu Idris], ia berkata; saya mendengar [Ibnu Ishaq] dari [Az Zuhri], dari ['Urwah bin Az Zubair] dari [Al Miswar bin Makhramah], dan [Marwan bin Al Hakam] bahwa mereka berdamai untuk mengadakan gencatan senjata selama sepuluh tahun. Pada waktu tersebut orang-orang merasakan keamanan, dan mereka saling menahan peperangan, dan tidak ada pencurian dan tidak ada pengkhianatan. "},"2321":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ قَالَ مَالَ مَكْحُولٌ وَابْنُ أَبِي زَكَرِيَّاءَ إِلَى خَالِدِ بْنِ مَعْدَانَ وَمِلْتُ مَعَهُمَا فَحَدَّثَنَا عَنْ جُبَيْرِ بْنِ نُفَيْرٍقَالَ قَالَ جُبَيْرٌ انْطَلِقْ بِنَا إِلَى ذِي مِخْبَرٍ رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْنَاهُ فَسَأَلَهُ جُبَيْرٌ عَنْ الْهُدْنَةِ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَتُصَالِحُونَ الرُّومَ صُلْحًا آمِنًا وَتَغْزُونَ أَنْتُمْ وَهُمْ عَدُوًّا مِنْ وَرَائِكُمْ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Isa bin Yunus], telah menceritakan kepada kami [Al Auza'i], dari [Hassan bin 'Athiyyah], ia berkata; Makhul dan Ibnu Zakariya` pergi kepada [Khalid bin Ma'dan] dan aku ikut bersama mereka berdua. Kemudian ia menceritakan kepada kami dari [Jubair bin Nufair], ia berkata; Jubair berkata; pergilah bersama kami ke [Dzu Mikhbar] seorang sahabat Nabi shallallahu 'alaihi wasallam, kemudian kami datang kepadanya. Kemudian Jubair bertanya kepadanya mengenai perjanjian damai. Kemudian ia berkata; aku telah mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Kalian akan mengadakan perjanjian damai dengan orang-orang Romawi, dan kalian bersama mereka akan menyerang musuh di belakang kalian.\""},"2322":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لِكَعْبِ بْنِ الْأَشْرَفِ فَإِنَّهُ قَدْ آذَى اللَّهَ وَرَسُولَهُ فَقَامَ مُحَمَّدُ بْنُ مَسْلَمَةَ فَقَالَ أَنَا يَا رَسُولَ اللَّهِ أَتُحِبُّ أَنْ أَقْتُلَهُ قَالَ نَعَمْ قَالَ فَأْذَنْ لِي أَنْ أَقُولَ شَيْئًا قَالَ نَعَمْ قُلْ فَأَتَاهُ فَقَالَ إِنَّ هَذَا الرَّجُلَ قَدْ سَأَلَنَا الصَّدَقَةَ وَقَدْ عَنَّانَا قَالَ وَأَيْضًا لَتَمَلُّنَّهُ قَالَ اتَّبَعْنَاهُ فَنَحْنُ نَكْرَهُ أَنْ نَدَعَهُ حَتَّى نَنْظُرَ إِلَى أَيِّ شَيْءٍ يَصِيرُ أَمْرُهُ وَقَدْ أَرَدْنَا أَنْ تُسْلِفَنَا وَسْقًا أَوْ وَسْقَيْنِ قَالَ كَعْبٌ أَيَّ شَيْءٍ تَرْهَنُونِي قَالَ وَمَا تُرِيدُ مِنَّا قَالَ نِسَاءَكُمْ قَالُوا سُبْحَانَ اللَّهِ أَنْتَ أَجْمَلُ الْعَرَبِ نَرْهَنُكَ نِسَاءَنَا فَيَكُونُ ذَلِكَ عَارًا عَلَيْنَا قَالَ فَتَرْهَنُونِي أَوْلَادَكُمْ قَالُوا سُبْحَانَ اللَّهِ يُسَبُّ ابْنُ أَحَدِنَا فَيُقَالُ رُهِنْتَ بِوَسْقٍ أَوْ وَسْقَيْنِ قَالُوا نَرْهَنُكَ اللَّأْمَةَ يُرِيدُ السِّلَاحَ قَالَ نَعَمْ فَلَمَّا أَتَاهُ نَادَاهُ فَخَرَجَ إِلَيْهِ وَهُوَ مُتَطَيِّبٌ يَنْضَحُ رَأْسُهُ فَلَمَّا أَنْ جَلَسَ إِلَيْهِ وَقَدْ كَانَ جَاءَ مَعَهُ بِنَفَرٍ ثَلَاثَةٍ أَوْ أَرْبَعَةٍ فَذَكَرُوا لَهُ قَالَ عِنْدِي فُلَانَةُ وَهِيَ أَعْطَرُ نِسَاءِ النَّاسِ قَالَ تَأْذَنُ لِي فَأَشُمَّ قَالَ نَعَمْ فَأَدْخَلَ يَدَهُ فِي رَأْسِهِ فَشَمَّهُ قَالَ أَعُودُ قَالَ نَعَمْ فَأَدْخَلَ يَدَهُ فِي رَأْسِهِ فَلَمَّا اسْتَمْكَنَ مِنْهُ قَالَ دُونَكُمْ فَضَرَبُوهُ حَتَّى قَتَلُوهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Sufyan] dari ['Amr bin Dinar] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapakah yang bersedia membunuh Ka'b bin Al Asyraf? Karena sesungguhnya ia telah mengganggu Allah dan RasulullahNya.\" Kemudian Muhammad bin Maslamah berdiri dan berkata; saya wahai Rasulullah. Apakah engkau ingin aku membunuhnya? Beliau berkata: \"Ya.\" Ia berkata; izinkan saya untuk mengatakan sesuatu! Beliau berkata: \"Ya.\" Kemudian ia datang kepada Ka'b dan berkata; sesungguhnya orang ini telah meminta sedekah kepada kami dan telah memberatkan kami. Ia berkata; dan juga niscaya engkau akan merasa bosan dengannya. Ia berkata; kami mengikutinya sementara kami tidak ingin meninggalkannya hingga kami melihat ke manakah urusannya akan berakhir. Sungguh kami ingin agar engkau memberi kami hutang satu wasaq atau dua wasaq. Ka'b berkata; apakah yang akan kalian gadaikan kepadaku? ia berkata; apa yang engkau inginkan dari kami? Ia berkata; para wanita kalian. Mereka berkata; subhanallah, engkau adalah orang Arab yang paling tampan, apakah kami akan menggadaikan para wanita kami kepadamu, hingga hal tersebut menjadi sebuah cela atas kami? Ia berkata; kalian gadaikan kepadaku anak-anak kalian. Mereka berkata; subhanallah, anak salah seorang dari kami akan dicela. Kemudian dikatakan; akan digadaikan kepadamu satu atau dua wasaq. Mereka berkata; kami akan menggadaikan senjata kepadamu. Ia bekata; ya. kemudian tatkala Muhammad bin Maslamah datang kepadanya, maka ia memanggilnya. Lalu ia keluar dengan memakai minyak wangi, kepalanya menebarkan bau wangi. Kemudian tatkala ia datang kepadanya sementara Muhammad bin Maslamah telah datang bersama tiga atau empat orang. Kemudian mereka menyebutkan hal tersebut kepadanya, ia berkata; aku memiliki Fulanah, ia adalah wanita yang paling wangi. Muhammad bin Maslamah berkata; apakah engkau menizinkanku untuk mencium? Ia berkata; ya. kemudian ia memasukkan tangannya ke kepalannya dan menciumnya. Ia berkata; apakah aku boleh mengulangi? Ia berkata; ya. kemudian ia memasukkan tangannya ke dalam kelapanya. Kemudian tatkala Muhammad bin Maslamah memungkinkan untuk membunuhnya ia berkata; tangkaplah dia! Kemudian mereka menebasnya hingga mereka membunuh Ka'b. "},"2323":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُزَابَةَ حَدَّثَنَا إِسْحَقُ يَعْنِي ابْنَ مَنْصُورٍ حَدَّثَنَا أَسْبَاطٌ الْهَمْدَانِيُّ عَنْ السُّدِّيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْإِيمَانُ قَيَّدَ الْفَتْكَ لَا يَفْتِكُ مُؤْمِنٌ","id":"Telah menceritakan kepada kami [Muhammad bin Huzabah], telah menceritakan kepada kami [Ishaq bin Manshur?], telah menceritakan kepada kami [Asbath Al Hamdani], dari [As Suddi] dari [ayahnya], dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam, beliau berkata; keimanan menghalangi pembunuhan, seorang mukmin tidak boleh membunuh. "},"2324":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَفَلَ مِنْ غَزْوٍ أَوْ حَجٍّ أَوْ عُمْرَةٍ يُكَبِّرُ عَلَى كُلِّ شَرَفٍ مِنْ الْأَرْضِ ثَلَاثَ تَكْبِيرَاتٍ وَيَقُولُ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ آيِبُونَ تَائِبُونَ عَابِدُونَ سَاجِدُونَ لِرَبِّنَا حَامِدُونَ صَدَقَ اللَّهُ وَعْدَهُ وَنَصَرَ عَبْدَهُ وَهَزَمَ الْأَحْزَابَ وَحْدَهُ","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam apabila kembali dari peperangan atau haji atau umrah beliau bertakbir di atas setiap dataran tinggi sebanyak tiga kali takir, beliau mengucapkan: LAA ILAAHA ILLALLAAHU WAHDAHU LAA SYARIIKALAH, LAHUL MULKU WA LAHUL HAMDU WA HUWA 'ALAA KULLI SYAI-IN QADIIR. AAYIBUUNA, TAAIBUUNA 'AABIDUUNA SAAJIDUUNA, LIRABBINAA HAAMIDUUN, SHADAQALLAHU WA'DAHU WA NASHARA 'ABDAHU WA HAZAMAL AHZAABA WAHDAH (Tidak ada tuhan yang berhak disembah kecuali Allah semata, tidak ada sekutu bagiNya, milikNya semua kerajaan dan bagiNya seluruh pujian, dan Dia Maha Mampu melakukan segala sesuatu AAYIBUUNA INSYAA ALLAAH, TAAIBUUNA 'AABIDUUNA LIRABBINAA HAAMIDUUN\" (Kami kembali insya Allah, kami bertaubat, ka0mi menyembah, dan kepada Tuhan kami, kami memuji, Allah menepati janji, menolong hambaNya, dan mengalahkan musuh yang berkelompok-kelompok..). "},"2325":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ لَا يَسْتَأْذِنُكَ الَّذِينَ يُؤْمِنُونَ بِاللَّهِ وَالْيَوْمِ الْآخِرِ }الْآيَةَ نَسَخَتْهَا الَّتِي فِي النُّورِ{ إِنَّمَا الْمُؤْمِنُونَ الَّذِينَ آمَنُوا بِاللَّهِ وَرَسُولِهِ إِلَى قَوْلِهِ غَفُورٌ رَحِيمٌ }","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Tsabit Al Marwazi], telah menceritakan kepadaku [Ali bin Husain], dari [ayahnya], dari [Yazid An Nahwi], dari [Ikrimah], dari [Ibnu Abbas], ia berkata; \"Orang-orang yang beriman kepada Allah dan hari kemudian, tidak akan meminta izin……\" ayat tersebut digantikan oleh yang ada dalam Surat An Nur yang berbunyi: Sesungguhnya yang sebenar-benar orang mukmin ialah orang-orang yang beriman kepada Allah dan Rasul-Nya……hingga: \"Sesungguhnya Allah Maha Pengampun lagi Maha Penyayang.\""},"2326":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا عِيسَى عَنْ إِسْمَعِيلَ عَنْ قَيْسٍ عَنْ جَرِيرٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا تُرِيحُنِي مِنْ ذِي الْخَلَصَةِ فَأَتَاهَا فَحَرَّقَهَا ثُمَّ بَعَثَ رَجُلًا مِنْ أَحْمَسَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُبَشِّرُهُ يُكْنَى أَبَا أَرْطَاةَ","id":"Telah menceritakan kepada kami [Abu Taubah Ar Rabi' bin Nafi'], telah menceritakan kepada kami [Isa] dari [Isma'il] dari [Qais] dari [Jarir], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Tidakkah engkau menenangkanku dari Dzul Khalashah?\" kemudian terdapat seseorang yang mendatanginya dan membakarnya. Kemudian mengirim seseorang dari Ahmas kepada Nabi shallallahu 'alaihi wasallam untuk memberikan kabar gembiran kepada beliau. Orang tersebut diberi kunyah Abu Arthah. "},"2327":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبٍ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَدِمَ مِنْ سَفَرٍ بَدَأَ بِالْمَسْجِدِ فَرَكَعَ فِيهِ رَكْعَتَيْنِ ثُمَّ جَلَسَ لِلنَّاسِ وَقَصَّ ابْنُ السَّرْحِ الْحَدِيثَ قَالَ وَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْلِمِينَ عَنْ كَلَامِنَا أَيُّهَا الثَّلَاثَةُ حَتَّى إِذَا طَالَ عَلَيَّ تَسَوَّرْتُ جِدَارَ حَائِطِ أَبِي قَتَادَةَ وَهُوَ ابْنُ عَمِّي فَسَلَّمْتُ عَلَيْهِ فَوَاللَّهِ مَا رَدَّ عَلَيَّ السَّلَامَ ثُمَّ صَلَّيْتُ الصُّبْحَ صَبَاحَ خَمْسِينَ لَيْلَةً عَلَى ظَهْرِ بَيْتٍ مِنْ بُيُوتِنَا فَسَمِعْتُ صَارِخًا يَا كَعْبَ بْنَ مَالِكٍ أَبْشِرْ فَلَمَّا جَاءَنِي الَّذِي سَمِعْتُ صَوْتَهُ يُبَشِّرُنِي نَزَعْتُ لَهُ ثَوْبَيَّ فَكَسَوْتُهُمَا إِيَّاهُ فَانْطَلَقْتُ حَتَّى إِذَا دَخَلْتُ الْمَسْجِدَ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ فَقَامَ إِلَيَّ طَلْحَةُ بْنُ عُبَيْدِ اللَّهِ يُهَرْوِلُ حَتَّى صَافَحَنِي وَهَنَّأَنِي","id":"Telah menceritakan kepada kami [Ibnu As Sarh] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] ia berkata; telah mengabarkan kepadaku [Abdurrahman bin Abdullah bin Ka'b bin Malik], bahwa [Abdullah bin Ka'b] berkata; aku mendengar [Ka'b bin Malik] beliau berkata: Nabi shallallahu 'alaihi wasallam apabila datang dari safar beliau memulai dengan mendatangi masjid, kemudian melakukan shalat dua raka'at, dan duduk untuk memenuhi hajat orang-orang. Ibnu As Sarh berkata; dan Rasulullah shallallahu 'alaihi wasallam melarang orang-orang muslim untuk berbicara dengan kami bertiga. Hingga tatkala hal tersebut terasa lama bagiku, aku menaiki dinding kebun Abu Qatadah, ia adalah anak pamanku. Kemudian aku mengucapkan salam kepadanya. demi Allah, ia tidak membalas salamku. Kemudian aku melakukan Shalat Subuh pada hari kelima puluh, di atas rumah diantara rumah-rumah kami. Kemudian aku mendengar seseorang berteriak; wahai Ka'b bin Malik, bergembiralah. Kemudian tatkala orang yang aku dengan suaranya untuk memberikan kabar gembiera telah datang kepadaku, maka aku lepaskan pakaianku dan aku berikan kepadanya. kemudian aku pergi hingga tatkala aku memasuki masjid, ternyata Rasulullah shallallahu 'alaihi wasallam sedang duduk. Kemudian Thalhah berdiri untuk menyambutku dengan berlari-lari kecil, hingga ia menyalami dan mengucapkan selamat kepadaku. "},"2328":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ أَبِي بَكْرَةَ بَكَّارِ بْنِ عَبْدِ الْعَزِيزِ أَخْبَرَنِي أَبِي عَبْدُ الْعَزِيزِ عَنْ أَبِي بَكْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ إِذَا جَاءَهُ أَمْرُ سُرُورٍ أَوْ بُشِّرَ بِهِ خَرَّ سَاجِدًا شَاكِرًا لِلَّهِ","id":"Telah menceritakan kepada kami [Makhlad bin Khalid], telah menceritakan kepada kami [Abu 'Ashim] dari [Abu Bakrah Bakkar bin Abdul Aziz], telah mengabarkan kepadaku [Ayahku yaitu Abdul Aziz] dari [Abu Bakrah] dari Nabi shallallahu 'alaihi wasallam bahwa apabila terdapat perkara perkara yang menyenangkan atau beliau dibei kabar gembira maka beliau bersujud untuk bersyukur kepada Allah. "},"2329":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنِي مُوسَى بْنُ يَعْقُوبَ عَنْ ابْنِ عُثْمَانَ قَالَ أَبُو دَاوُد وَهُوَ يَحْيَى بْنُ الْحَسَنِ بْنِ عُثْمَانَ عَنْ الْأَشْعَثِ بْنِ إِسْحَقَ بْنِ سَعْدٍ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَكَّةَ نُرِيدُ الْمَدِينَةَ فَلَمَّا كُنَّا قَرِيبًا مِنْ عَزْوَرَا نَزَلَ ثُمَّ رَفَعَ يَدَيْهِ فَدَعَا اللَّهَ سَاعَةً ثُمَّ خَرَّ سَاجِدًا فَمَكَثَ طَوِيلًا ثُمَّ قَامَ فَرَفَعَ يَدَيْهِ فَدَعَا اللَّهَ سَاعَةً ثُمَّ خَرَّ سَاجِدًا فَمَكَثَ طَوِيلًا ثُمَّ قَامَ فَرَفَعَ يَدَيْهِ سَاعَةً ثُمَّ خَرَّ سَاجِدًا ذَكَرَهُ أَحْمَدُ ثَلَاثًا قَالَ إِنِّي سَأَلْتُ رَبِّي وَشَفَعْتُ لِأُمَّتِي فَأَعْطَانِي ثُلُثَ أُمَّتِي فَخَرَرْتُ سَاجِدًا شُكْرًا لِرَبِّي ثُمَّ رَفَعْتُ رَأْسِي فَسَأَلْتُ رَبِّي لِأُمَّتِي فَأَعْطَانِي ثُلُثَ أُمَّتِي فَخَرَرْتُ سَاجِدًا لِرَبِّي شُكْرًا ثُمَّ رَفَعْتُ رَأْسِي فَسَأَلْتُ رَبِّي لِأُمَّتِي فَأَعْطَانِي الثُّلُثَ الْآخِرَ فَخَرَرْتُ سَاجِدًا لِرَبِّيقَالَ أَبُو دَاوُد أَشْعَثُ بْنُ إِسْحَقَ أَسْقَطَهُ أَحْمَدُ بْنُ صَالِحٍ حِينَ حَدَّثَنَا بِهِ فَحَدَّثَنِي بِهِ عَنْهُ مُوسَى بْنُ سَهْلٍ الرَّمْلِيُّ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Abu Fudaik], telah menceritakan kepadaku [Musa bin Ya'qub] dari [Ibnu Utsman]. Abu Daud berkata; ia adalah Yahya bin Al Hasan bin Utsman dari [Al Asy'ats bin Ishaq bin Sa'd] dari ['Amir bin Sa'd] dari [ayahnya], ia berkata; kami keluar besama Rasulullah shallallahu 'alaihi wasallam dari Mekkah henda menuju Madinah. Kemudian tatkala kami telah mendeati 'Azwara, beliau turun kemudian mengangkat kedua tangannyaa dan berdoa kepada Allah sesaat, kemudian beliau bersujud. Beliau lama berada dalam keadaan demikian kemudian bangkit dan mengangkat kedua tangannya, dan berdoa kepada Allah sesaat, kemudian beliau bersujud. Beliau lama berada dalam keadaan demikian kemudian bangkit dan mengangkat kedua tangannya, dan berdoa kepada Allah sesaat, kemudian beliau bersujud. Ahmad menyebutkan hal tersebut sebanyak tiga kali. Beliau berkata: \"Aku memohon kepada Tuhanku dan memintakan syafa'at untuk umatku. Kemudian Allah memberiku sepertiga umatku, lalu aku bersujud sebagai rasa syukur kepada Tuhanku. Kemudian aku mengangkat kepalaku dan memohonkan untuk umatku. Kemudian Allah memberiku sepertiga umatku, lalu aku bersujud sebagai rasa syukur kepada Tuhanku. Kemudian aku mengangkat kepalaku dan memohonkan untuk umatku. Kemudian Allah memberiku sepertiga yang lainnya, lalu aku bersujud untuk Tuhanku.\" Abu Daud berkata; Asy'ats bin Ishaq telah digugurkan oleh Ahmad bin Shalih, ketika ia menceritakan hadits tersebut. Musa bin Sahl Ar Ramli menceritakan hadits tersebut darinya. "},"2330":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْرَهُ أَنْ يَأْتِيَ الرَّجُلُ أَهْلَهُ طُرُوقًا","id":"Telah menceritakan kepada kami [Hafsh bin Umar], dan [Muslim bin Ibrahim], mereka berkata; telah menceritakan kepada kami [Syu'ba] dari [Muharib bin Ditsar], dari [Jabir bin Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam tidak menyukai seseorang mendatangi keluarganya pada malam hari. "},"2331":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مُغِيرَةَ عَنْ الشَّعْبِيِّ عَنْ جَابِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَحْسَنَ مَا دَخَلَ الرَّجُلُ عَلَى أَهْلِهِ إِذَا قَدِمَ مِنْ سَفَرٍ أَوَّلَ اللَّيْلِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Jarir] dari [Mughirah] dari [Asy Sya'bi] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya sebaik-baik waktu seseorang menemui keluarganya apabila ia datang dari sebuah safar adalah awal malam.\""},"2332":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا سَيَّارٌ عَنْ الشَّعْبِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَلَمَّا ذَهَبْنَا لِنَدْخُلَ قَالَ أَمْهِلُوا حَتَّى نَدْخُلَ لَيْلًا لِكَيْ تَمْتَشِطَ الشَّعِثَةُ وَتَسْتَحِدَّ الْمُغِيبَةُقَالَ أَبُو دَاوُد قَالَ الزُّهْرِيُّ الطُّرُوقُ بَعْدَ الْعِشَاءِ قَالَ أَبُو دَاوُد وَبَعْدَ الْمَغْرِبِ لَا بَأْسَ بِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Husyaim], telah mengabarkan kepada kami [Sayyar] dari [Asy Sya'bi], dari [Jabir bin Abdullah], ia berkata; dahulu kami bersama Nabi shallallahu 'alaihi wasallam dalam sebuah safar, kemudian tatkala kami pergi untuk menemui keluarga kami beliau berkata: \"Tundalah hingga kita masuk pada malam hari, agar wanita yang rambutnya acak-acakan bersisir, dan wanita yang ditinggal suaminya membersihkan bulu kemaluannya.\" Abu Daud berkata; Az Zuhri berkata; Thuruq adalah setelah 'Isya`. Abu Daud berkata; sedangkan setelah Maghrib tidak mengapa. "},"2333":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ السَّائِبِ بْنِ يَزِيدَ قَالَلَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ مِنْ غَزْوَةِ تَبُوكَ تَلَقَّاهُ النَّاسُ فَلَقِيتُهُ مَعَ الصِّبْيَانِ عَلَى ثَنِيَّةِ الْوَدَاعِ","id":"Telah menceritakan kepada kami [Ibnu As Sarh], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri], dari [As Saib bin Yazid], ia berkata; tatkala Nabi shallallahu 'alaihi wasallam datang ke Madinah dari perang Tabuk, orang-orang menemui beliau, sementara aku menemui beliau bersama anak-anak kecil di atas Tsaniyah Al Wada'. "},"2334":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ الْبُنَانِيُّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ فَتًى مِنْ أَسْلَمَ قَالَ يَا رَسُولَ اللَّهِ إِنِّي أُرِيدُ الْجِهَادَ وَلَيْسَ لِي مَالٌ أَتَجَهَّزُ بِهِ قَالَ اذْهَبْ إِلَى فُلَانٍ الْأَنْصَارِيِّ فَإِنَّهُ كَانَ قَدْ تَجَهَّزَ فَمَرِضَ فَقُلْ لَهُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقْرِئُكَ السَّلَامَ وَقُلْ لَهُ ادْفَعْ إِلَيَّ مَا تَجَهَّزْتَ بِهِ فَأَتَاهُ فَقَالَ لَهُ ذَلِكَ فَقَالَ لِامْرَأَتِهِ يَا فُلَانَةُ ادْفَعِي لَهُ مَا جَهَّزْتِنِي بِهِ وَلَا تَحْبِسِي مِنْهُ شَيْئًا فَوَاللَّهِ لَا تَحْبِسِينَ مِنْهُ شَيْئًا فَيُبَارِكَ اللَّهُ فِيهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami [Tsabit Al Bunani], dari [Anas bin Malik], bahwa seorang pemuda Aslam berkata; wahai Rasulullah, aku ingin berjihad dan aku tidak memiliki harta yang perlu aku persiapkan. Beliau berkata: \"Pergilah kepada Fulan Al Anshari, sesungguhnya ia telah bersiap-siap lalu sakit. Katakan kepadanya; sesungguhnya Rasulullah shallallahu 'alaihi wasallam menyampaikan salam kepadamu. Dan katakan kepadanya; serahkan kepadaku apa yang telah engkau persiapkan!\" kemudian pemuda tersebut datang kepadanya hal tersebut. Lalu orang anshar tersebut berkata kepada isterinya; wahai Fulanah, serahkan kepadanya apa yang telah aku persiapkan, dan jangan engkau tahan sedikitpun darinya! Demi Allah, tidak mungkin engkau menahan sedikitpun darinya kemudian Allah memberi berkah. "},"2335":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُتَوَكِّلِ الْعَسْقَلَانِيُّ وَالْحَسَنُ بْنُ عَلِيٍّ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنِي ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ عَبْدِ اللَّهِ بْنِ كَعْبٍ وَعَمِّهِ عُبَيْدِ اللَّهِ بْنِ كَعْبٍ عَنْ أَبِيهِمَا كَعْبِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَقْدَمُ مِنْ سَفَرٍ إِلَّا نَهَارًا قَالَ الْحَسَنُ فِي الضُّحَى فَإِذَا قَدِمَ مِنْ سَفَرٍ أَتَى الْمَسْجِدَ فَرَكَعَ فِيهِ رَكْعَتَيْنِ ثُمَّ جَلَسَ فِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutawakkil Al 'Asqalani] dan [Al Hasan bin Ali], mereka berkata; telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ibnu Juraij], ia berkata; telah mengabarkan kepadaku [Ibnu Syihab], ia berkata; telah mengabarkan kepadaku [Abdurrahman bin Abdullah bin Ka'b bin Malik], dari [ayahnya yaitu Abdullah bin Ka'b] dan [pamannya yaitu 'Ubaidullah bin Ka'b] dari [ayah mereka berdua yaitu Ka'b bin Malik], bahwa Nabi shallallahu 'alaihi wasallam tidak datang dari bepergian kecuali pada siang hari. Al Hasan berkata; pada waktu Dhuha. Apabila beliau datang dari bepergian maka beliau datang ke masjid, dan melakukan shalat dua raka'at kemudian duduk."},"2336":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَنْصُورٍ الطُّوسِيُّ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَقْبَلَ مِنْ حَجَّتِهِ دَخَلَ الْمَدِينَةَ فَأَنَاخَ عَلَى بَابِ مَسْجِدِهِ ثُمَّ دَخَلَهُ فَرَكَعَ فِيهِ رَكْعَتَيْنِ ثُمَّ انْصَرَفَ إِلَى بَيْتِهِقَالَ نَافِعٌ فَكَانَ ابْنُ عُمَرَ كَذَلِكَ يَصْنَعُ","id":"Telah menceritakan kepada kami [Muhammad bin Manshur Ath Thusi], telah menceritakan kepada kami [Ya'qub], telah menceritakan kepada kami [ayahku], dari [Ibnu Ishaq], telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam ketika datang dari hajinya beliau masuk ke masjid, dan menderumkan untanya di depan pintu masjid, kemudian beliau pergi ke rumahnya. Nafi' berkata; Ibnu Umar melakukan demikian. "},"2337":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ التِّنِّيسِيُّ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنَا الزَّمْعِيُّ عَنْ الزُّبَيْرِ بْنِ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ سُرَاقَةَ أَنَّ مُحَمَّدَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ أَخْبَرَهُ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِيَّاكُمْ وَالْقُسَامَةَ قَالَ فَقُلْنَا وَمَا الْقُسَامَةُ قَالَ الشَّيْءُ يَكُونُ بَيْنَ النَّاسِ فَيَجِيءُ فَيَنْتَقِصُ مِنْهُحَدَّثَنَا عَبْدُ اللَّهِ الْقَعْنَبِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ شَرِيكٍ يَعْنِي ابْنَ أَبِي نَمِرٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ الرَّجُلُ يَكُونُ عَلَى الْفِئَامِ مِنْ النَّاسِ فَيَأْخُذُ مِنْ حَظِّ هَذَا وَحَظِّ هَذَا","id":"Telah menceritakan kepada kami [Ja'far bin Musafir At Tinnisi], telah menceritakan kepada kami [Ibnu Abu Fudaik], telah menceritakan kepada kami [Az Zam'i], dari [Az Zubair bin Utsman bin Abdullah bin Suraqah], bahwa [Muhammad bin Abdurrahman bin Tsauban], telah mengabarkan kepadanya bahwa [Abu Sa'id Al Khudri] telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: hendaklah kalian menjauhi qosamah. Ia berkatal lalu kami berkata; apakah qosamah itu? Beliau bersabda: suatu (pembunuhan tanpa bukti) yang terjadi di antara manusia kemudian (keluarganya) datang dan minta diadakan qishas darinya. Telah menceritakan kepada kami [Abdullah Al Qo'nabi] telah menceritakan kepada kami [Abdul Aziz yaitu Ibnu Muhammad] dari [Syarik yaitu Ibnu Abi Namir] dari ['Atha` bin Yasar] dari Nabi shallallahu 'alaihi wasallam seperti itu. Perawi berkata; seorang laki-laki yang berada di tengah-tengah perkumpulan manusia kemudian meminta tuntutan dari perkara ini dan perkara ini. "},"2338":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ سَلَّامٍ عَنْ زَيْدٍ يَعْنِي ابْنَ سَلَّامٍ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ يَقُولُ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ سَلْمَانَأَنَّ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُ قَالَ لَمَّا فَتَحْنَا خَيْبَرَ أَخْرَجُوا غَنَائِمَهُمْ مِنْ الْمَتَاعِ وَالسَّبْيِ فَجَعَلَ النَّاسُ يَتَبَايَعُونَ غَنَائِمَهُمْ فَجَاءَ رَجُلٌ حِينَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ لَقَدْ رَبِحْتُ رِبْحًا مَا رَبِحَ الْيَوْمَ مِثْلَهُ أَحَدٌ مِنْ أَهْلِ هَذَا الْوَادِي قَالَ وَيْحَكَ وَمَا رَبِحْتَ قَالَ مَا زِلْتُ أَبِيعُ وَأَبْتَاعُ حَتَّى رَبِحْتُ ثَلَاثَ مِائَةِ أُوقِيَّةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا أُنَبِّئُكَ بِخَيْرِ رَجُلٍ رَبِحَ قَالَ مَا هُوَ يَا رَسُولَ اللَّهِ قَالَ رَكْعَتَيْنِ بَعْدَ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Ar Rabi' bin Nafi'], telah menceritakan kepada kami [Mu'awiyah bin Sallam] dari [Zaid bin Sallam] bahwa ia mendengar [Abu Sallam] berkata; telah menceritakan kepadaku ['Ubaidullah bin Salman] bahwa [seorang sahabat] Nabi shallallahu 'alaihi wasallam telah menceritakan kepadanya, ia berkata; tatkala kami menaklukkan Khaibar mereka mengeluarkan rampasan perang dari barang dan tawanan perang. Kemudian orang-orang menjual rampasan perang mereka. Lalu terdapat seorang laki-laki yang datang ketika Rasulullah shallallahu 'alaihi wasallam telah melakukan shalat dan berkata; wahai Rasulullah, sungguh aku telah mendapatkan keuntungan yang tidak ada seorangpun penghuni bukit ini yang mendapatkan keuntungan seperti itu hari ini. Beliau mengatakan; keuntungan apa yang telah engkau dapatkan? Ia berkata; aku terus berjual beli hingga mendapatkan keuntungan tiga ratus uqiyah. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku akan memberitahukan kepadamu mengenai orang mendapatkan keuntungan yang terbaik.\" Ia berkata; apakah itu wahai Rasulullah? Beliau berkata: \"Shalat dua raka'at setelah melakukan shalat.\""},"2339":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ أَخْبَرَنِي أَبِي عَنْ أَبِي إِسْحَقَ عَنْ ذِي الْجَوْشَنِ رَجُلٍ مِنْ الضِّبَابِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ أَنْ فَرَغَ مِنْ أَهْلِ بَدْرٍ بِابْنِ فَرَسٍ لِي يُقَالُ لَهَا الْقَرْحَاءُ فَقُلْتُ يَا مُحَمَّدُ إِنِّي قَدْ جِئْتُكَ بِابْنِ الْقَرْحَاءِ لِتَتَّخِذَهُ قَالَ لَا حَاجَةَ لِي فِيهِ وَإِنْ شِئْتَ أَنْ أَقِيضَكَ بِهِ الْمُخْتَارَةَ مِنْ دُرُوعِ بَدْرٍ فَعَلْتُ قُلْتُ مَا كُنْتُ أَقِيضُهُ الْيَوْمَ بِغُرَّةٍ قَالَ فَلَا حَاجَةَ لِي فِيهِ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Isa bin Yunus], telah mengabarkan kepadaku [ayahku] dari [Abu Ishaq] dari [Dzul Jausyan] seorang laki-laki dari daerah yang banyak terdapat biawaknya. Aku datang kepada Nabi shallallahu 'alaihi wasallam dengan membawa anak kuda yang bernama Al Qarha` setelah beliau selesai menemui ahli Badr, kemudian aku katakan; wahai Muhammad, aku datang kepadamu dengan membawa anak Al Qarha` agar engkau gunakan. Beliau berkata: \"Aku tidak butuh kepadanya, apabila engkau mau, aku akan menggantimu dengan baju zirah pilihan dari Badr maka aku akan melakukannya.\" Aku katakan; aku tidak akan menukarnya dengan kuda pada hari ini (bagaimana aku menukarnya dengan sesuatu yang lebih rendah nilainya?). Beliau berkata: \"Aku tidak butuh kepadanya.\""},"2340":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ دَاوُدَ بْنِ سُفْيَانَ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ أَخْبَرَنَا سُلَيْمَانُ بْنُ مُوسَى أَبُو دَاوُدَ حَدَّثَنَا جَعْفَرُ بْنُ سَعْدِ بْنِ سَمُرَةَ بْنِ جُنْدُبٍ حَدَّثَنِي خُبَيْبُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ سُلَيْمَانَ بْنِ سَمُرَةَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍأَمَّا بَعْدُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَامَعَ الْمُشْرِكَ وَسَكَنَ مَعَهُ فَإِنَّهُ مِثْلُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Daud bin Sufyan], telah menceritakan kepada kami [Yahya bin Hassan], telah mengabarkan kepada kami [Sulaiman bin Musa Abu Daud], telah menceritakan kepada kami [Ja'far bin Sa'd bin Samurah bin Jundub], telah menceritakan kepadaku [Khubaib bin Sulaiman] dari [ayahnya yaitu Sulaiman bin Samurah] dari [Samurah bin Jundub], adapun selanjutnya, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menggauli (menikahi) orang musyrik dan tinggal bersamanya, maka ia adalah sepertinya.\""},"2341":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ ح و حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا بِشْرٌ عَنْ عَبْدِ اللَّهِ بْنِ عَوْنٍ عَنْ عَامِرٍ أَبِي رَمْلَةَ قَالَ أَخْبَرَنَا مِخْنَفُ بْنُ سُلَيْمٍ قَالَوَنَحْنُ وُقُوفٌ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَاتٍ قَالَ يَا أَيُّهَا النَّاسُ إِنَّ عَلَى كُلِّ أَهْلِ بَيْتٍ فِي كُلِّ عَامٍ أُضْحِيَّةً وَعَتِيرَةً أَتَدْرُونَ مَا الْعَتِيرَةُ هَذِهِ الَّتِي يَقُولُ النَّاسُ الرَّجَبِيَّةُقَالَ أَبُو دَاوُد الْعَتِيرَةُ مَنْسُوخَةٌ هَذَا خَبَرٌ مَنْسُوخٌ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yazid], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Humaid bin Mas'adah], telah menceritakan kepada kami [Bisyr] dari [Abdullah bin 'Aun] dari ['Amir Abu Ramlah], ia berkata; telah mengabarkan kepada kami [Mikhnaf bin Sulaim], ketika kami sedang berwukuf bersama Rasulullah shallallahu 'alaihi wasallam di 'Arafah beliau berkata: \"Wahai umat manusia, sesungguhnya kewajiban setiap penghuni rumah pada setiap tahun untuk menyembelih kurban serta 'atirah, tahukah kalian apakah 'atirah? Yaitu yang orang-orang menyebutnya rajabiyyah (menyembelih hewan pada sepuluh hari pertama).\" Abu Daud berkata; 'atirah telah dihapuskan dan hadits ini adalah hadits yang telah terhapus. "},"2342":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي أَيُّوبَ حَدَّثَنِي عَيَّاشُ بْنُ عَبَّاسٍ الْقِتْبَانِيُّ عَنْ عِيسَى بْنِ هِلَالٍ الصَّدَفِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْتُ بِيَوْمِ الْأَضْحَى عِيدًا جَعَلَهُ اللَّهُ عَزَّ وَجَلَّ لِهَذِهِ الْأُمَّةِ قَالَ الرَّجُلُ أَرَأَيْتَ إِنْ لَمْ أَجِدْ إِلَّا أُضْحِيَّةً أُنْثَى أَفَأُضَحِّي بِهَا قَالَ لَا وَلَكِنْ تَأْخُذُ مِنْ شَعْرِكَ وَأَظْفَارِكَ وَتَقُصُّ شَارِبَكَ وَتَحْلِقُ عَانَتَكَ فَتِلْكَ تَمَامُ أُضْحِيَّتِكَ عِنْدَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Harun bin Abdullah], telah menceritakan kepada kami [Abdullah bin Yazid], telah menceritakan kepadaku [Sa'id bin Abu Ayyub], telah menceritakan kepadaku ['Ayyasy bin 'Abbas Al Qatbani], dari [Isa bin Hilal Ash Shudafi], dari [Abdullah bin 'Amr bin Al 'Ash], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Aku diperintahkan pada hari Kurban untuk menjadikannya sebagai hari raya, Allah 'azza wajalla telah menjadikannya untuk umat ini.\" Seseorang berkata; bagaimana pendapat anda jika aku hanya mendapatkan hewan kurban betina? Apakah aku boleh berkurban dengannya? Beliau berkata: \"Tidak, akan tetapi engkau ambil sebagian rambutmu dan kukumu, serta engkau gunting kumismu dan engkau cukur bulu kemaluanmu. Maka itulah kurbanmu yang sempurna di sisi Allah 'azza wajalla.\""},"2343":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي الْحَسْنَاءِ عَنْ الْحَكَمِ عَنْ حَنَشٍ قَالَرَأَيْتُ عَلِيًّا يُضَحِّي بِكَبْشَيْنِ فَقُلْتُ لَهُ مَا هَذَا فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْصَانِي أَنْ أُضَحِّيَ عَنْهُ فَأَنَا أُضَحِّي عَنْهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Syarik] dari [Abu Al Hasna`] dari [Al Hakam] dari [Hanasy], ia berkata; aku melihat [Ali] berkurban dengan dua kambing. Kemudian aku katakan kepadanya; apa ini? Lalu ia berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah berwasiat kepadaku agar berkurban untuknya, maka aku berkurban untuknya. "},"2344":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو حَدَّثَنَا عَمْرُو بْنُ مُسْلِمٍ اللَّيْثِيُّ قَالَ سَمِعْتُ سَعِيدَ بْنَ الْمُسَيِّبِ يَقُولُ سَمِعْتُ أُمَّ سَلَمَةَ تَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ لَهُ ذِبْحٌ يَذْبَحُهُ فَإِذَا أَهَلَّ هِلَالُ ذِي الْحِجَّةِ فَلَا يَأْخُذَنَّ مِنْ شَعْرِهِ وَلَا مِنْ أَظْفَارِهِ شَيْئًا حَتَّى يُضَحِّيَقَالَ أَبُو دَاوُد اخْتَلَفُوا عَلَى مَالِكٍ وَعَلَى مُحَمَّدِ بْنِ عَمْرٍو فِي عَمْرِو بْنِ مُسْلِمٍ قَالَ بَعْضُهُمْ عُمَرُ وَأَكْثَرُهُمْ قَالَ عَمْرٌو قَالَ أَبُو دَاوُد وَهُوَ عَمْرُو بْنُ مُسْلِمِ بْنِ أُكَيْمَةَ اللَّيْثِيُّ الْجُنْدُعِيُّ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz], telah menceritakan kepada kami [ayahku], telah menceritakan kepada kami [Muhammad bin 'Amr], telah menceritakan kepada kami ['Amr bin Muslim Al Laitsi], ia berkata; saya mendengar [Sa'id bin Al Musayyab] berkata; saya mendengar [Ummu Salamah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang memiliki hewan sembelihan yang akan ia sembelih, apabila telah muncul hilal Bulan Dzul Hijjah maka janganlah ia mengambil sedikitpun dari rambut, serta kukunya hingga ia menyembelih.\" Abu Daud berkata; mereka menyelisihi Malik dan Muhammad bin 'Amr mengenai 'Amr bin Muslim. Sebagian mereka berkata; ia adalah Umar, dan kebanyakan mereka mengatakan; 'Amr. Abu Daud berkata; ia adalah 'Amr bin Muslim bin Ukaimah Al Laitsi Al Jundu'i. "},"2345":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي حَيْوَةُ حَدَّثَنِي أَبُو صَخْرٍ عَنْ ابْنِ قُسَيْطٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِكَبْشٍ أَقْرَنَ يَطَأُ فِي سَوَادٍ وَيَنْظُرُ فِي سَوَادٍ وَيَبْرُكُ فِي سَوَادٍ فَأُتِيَ بِهِ فَضَحَّى بِهِ فَقَالَ يَا عَائِشَةُ هَلُمِّي الْمُدْيَةَ ثُمَّ قَالَ اشْحَذِيهَا بِحَجَرٍ فَفَعَلَتْ فَأَخَذَهَا وَأَخَذَ الْكَبْشَ فَأَضْجَعَهُ وَذَبَحَهُ وَقَالَ بِسْمِ اللَّهِ اللَّهُمَّ تَقَبَّلْ مِنْ مُحَمَّدٍ وَآلِ مُحَمَّدٍ وَمِنْ أُمَّةِ مُحَمَّدٍ ثُمَّ ضَحَّى بِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Abdullah bin Wahb], telah mengabarkan kepadaku [Haiwah], telah menceritakan kepadaku [Abu Shakhr] dari [Ibnu Qusaith] dari ['Urwah bin Az Zubair] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk menyembelih domba yang bertanduk, berkaki hitam, sekitar matanya hitam, dan perutnya hitam. Kemudian beliau diberi kambing seperti itu, lalu beliau berkurban dengannya. Beliau berkata: \"Wahai Aisyah, berikan pisau.\" Kemudian beliau berkata: \"Tajamkan pisau tersebut dengan batu!\" kemudian ia melakukannya, lalu Rasulullah shallallahu 'alaihi wasallam mengambilnya dan mengambil domba tersebut serta membaringkan dan menyembelihnya. Beliau mengucapkan: \"BISMILLAAH, ALLAAHUMMA TAQABBAL MIN MUHAMMADIN WA AALI MUHAMMAD, WA MIN UMMATI MUHAMMAD (Dengan nama Allah, ya Allah, terimalah dari Muhammad dan keluarga Muhammad serta Ummat Muhammad). Kemudian beliau shallallahu 'alaihi wasallam berkurban dengannya. "},"2346":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وَهْبٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحَرَ سَبْعَ بَدَنَاتٍ بِيَدِهِ قِيَامًا وَضَحَّى بِالْمَدِينَةِ بِكَبْشَيْنِ أَقْرَنَيْنِ أَمْلَحَيْنِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Wahb] dari [Ayyub], dari [Abu Qilabah], dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam menyembelih tujuh unta dengan tangannya dalam keadaan berdiri, dan beliau di Madinah berkurban dengan dua domba yang bertanduk dan berwarna abu-Abu. "},"2347":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَحَّى بِكَبْشَيْنِ أَقْرَنَيْنِ أَمْلَحَيْنِ يَذْبَحُ وَيُكَبِّرُ وَيُسَمِّي وَيَضَعُ رِجْلَهُ عَلَى صَفْحَتِهِمَا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam berkurban dengan dua domba yang bertanduk dan berwarna abu-Abu. Beliau menyembelih, bertakbir dan membaca bismilah, serta beliau meletakkan kakinya di atas sebelah kepalanya. "},"2348":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ حَدَّثَنَا عِيسَى حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي عَيَّاشٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَذَبَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الذَّبْحِ كَبْشَيْنِ أَقْرَنَيْنِ أَمْلَحَيْنِ مُوجَأَيْنِ فَلَمَّا وَجَّهَهُمَا قَالَ إِنِّي وَجَّهْتُ وَجْهِيَ لِلَّذِي فَطَرَ السَّمَوَاتِ وَالْأَرْضَ عَلَى مِلَّةِ إِبْرَاهِيمَ حَنِيفًا وَمَا أَنَا مِنْ الْمُشْرِكِينَ إِنَّ صَلَاتِي وَنُسُكِي وَمَحْيَايَ وَمَمَاتِي لِلَّهِ رَبِّ الْعَالَمِينَ لَا شَرِيكَ لَهُ وَبِذَلِكَ أُمِرْتُ وَأَنَا مِنْ الْمُسْلِمِينَ اللَّهُمَّ مِنْكَ وَلَكَ وَعَنْ مُحَمَّدٍ وَأُمَّتِهِ بِاسْمِ اللَّهِ وَاللَّهُ أَكْبَرُ ثُمَّ ذَبَحَ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi], telah menceritakan kepada kami [Isa], telah menceritakan kepada kami [Muhammad bin Ishaq], dari [Yazid bin Abu Habib], dari [Abu 'Ayyasy] dari [Jabir bin Abdullah], ia berkata; Nabi shallallahu 'alaihi wasallam pada hari Kurban menyembelih dua domba yang bertanduk dan berwarna abu-abu yang terkebiri. Kemudian tatkala beliau telah menghadapkan keduanya beliau mengucapkan: \"INNII WAJJAHTU WAJHIYA LILLADZII FATHARAS SAMAAWAATI WAL ARDHA 'ALAA MILLATI IBRAAHIIMA HANIIFAN WA MAA ANA MINAL MUSYRIKIIN, INNA SHALAATII WA NUSUKII WA MAHYAAYA WA MAMAATII LILLAAHI RABBIL 'AALAMIIN, LAA SYARIIKA LAHU WA BIDZAALIKA UMIRTU WA ANA MINAL MUSLIMIIN. ALLAAHUMMA MINKA WA LAKA WA 'AN MUHAMMADIN WA UMMATIHI. BISMILLAAHI WALLAHU AKBAR\" (Sesungguhnya aku telah menghadapkan wajahku kepada Dzat yang telah menciptakan langit dan bumi di atas agama Ibrahim dengan lurus, dan aku bukan termsuk orang-orang yang berbuat syirik. Sesungguhnya shalatku, dan sembelihanku serta hidup dan matiku adalah untuk Allah Tuhan semesta alam, tidak ada sekutu bagiNya, dengan itu aku diperintahkan, dan aku termasuk orang-orang yang berserah diri. Ya Allah, ini berasal dariMu dan untukMu, dari Muhammad dan ummatnya. Dengan Nama Allah, dan Allah Maha Besar). "},"2349":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا حَفْصٌ عَنْ جَعْفَرٍ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ قَالَكَانَ رَسُولُ اللَّهِ يُضَحِّي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَبْشٍ أَقْرَنَ فَحِيلٍ يَنْظُرُ فِي سَوَادٍ وَيَأْكُلُ فِي سَوَادٍ وَيَمْشِي فِي سَوَادٍ","id":"Telah menceritakan kepada kami [Yahya bin Ma'in], telah menceritakan kepada kami [Hafsh] dari [Ja'far], dari [ayahnya], dari [Abu Sa'id], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkurban dengan seekor domba yang bertanduk yang sempurna tubuhnya, sekitar matanya hitam, dan perutnya hitam, serta berkaki hitam. "},"2350":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ الْحَرَّانِيُّ حَدَّثَنَا زُهَيْرُ بْنُ مُعَاوِيَةَ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَذْبَحُوا إِلَّا مُسِنَّةً إِلَّا أَنْ يَعْسُرَ عَلَيْكُمْ فَتَذْبَحُوا جَذَعَةً مِنْ الضَّأْنِ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Syu'aib Al Harrani], telah menceritakan kepada kami [Zuhair bin Mu'awiyah], telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menyembelih kecuali domba yang berumur tiga tahun, kecuali kalian kesulitan mendapatkannya maka sembelihlah domba yang berumur satu tahun.\""},"2351":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ صُدْرَانَ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ حَدَّثَنِي عُمَارَةُ بْنُ عَبْدِ اللَّهِ بْنِ طُعْمَةَ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَصْحَابِهِ ضَحَايَا فَأَعْطَانِي عَتُودًا جَذَعًا قَالَ فَرَجَعْتُ بِهِ إِلَيْهِ فَقُلْتُ لَهُ إِنَّهُ جَذَعٌ قَالَ ضَحِّ بِهِ فَضَحَّيْتُ بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Shudran], telah menceritakan kepada kami [Abdul A'la bin Abdul A'la], telah menceritakan kepada kami [Muhammad bin Ishaq], telah menceritakan kepadaku ['Umarah bin Abdullah bin Thu'mah], dari [Sa'id bin Al Musayyab], dari [Zaid bin Khalid Al Juhani], ia berkata; Rasulullah shallallahu 'alaihi wasallam membagikan kurban beliau kepada para sahabatnya, beliau memberiku kambing kecil yang berumur satu tahun. Kemudian aku membawanya kembali kepada beliau dan aku katakan kepadanya; kambing itu adalah kambing yang berumur satu tahun. Kemudian beliau berkata: \"Berkurbanlah dengannya!\" kemudian aku berkurban dengannya. "},"2352":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا الثَّوْرِيُّ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ قَالَكُنَّا مَعَ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لَهُ مُجَاشِعٌ مِنْ بَنِي سُلَيْمٍ فَعَزَّتْ الْغَنَمُ فَأَمَرَ مُنَادِيًا فَنَادَى أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ إِنَّ الْجَذَعَ يُوَفِّي مِمَّا يُوَفِّي مِنْهُ الثَّنِيُّقَالَ أَبُو دَاوُد وَهُوَ مُجَاشِعُ بْنُ مَسْعُودٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdurrazzaq], telah menceritakan kepada kami [Ats Tsauri] dari ['Ashim bin Kulaib], dari [ayahnya], ia berkata; kami pernah bersama seorang sahabat Nabi shallallahu 'alaihi wasallam yang bernama [Mujasyi'] dari Bani Sulaim. Dan jumlah kambing sedikit. Kemudian ia memerintahkan seseorang untuk menyeru bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Sesungguhnya kambing yang berumur satu tahun adalah cukup sebagaimana yang genap dua tahun masuk tiga tahun.\" Abu Daud berkata; ia adalah Mujasyi' bin Mas'ud. "},"2353":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا مَنْصُورٌ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ بَعْدَ الصَّلَاةِ فَقَالَ مَنْ صَلَّى صَلَاتَنَا وَنَسَكَ نُسُكَنَا فَقَدْ أَصَابَ النُّسُكَ وَمَنْ نَسَكَ قَبْلَ الصَّلَاةِ فَتِلْكَ شَاةُ لَحْمٍ فَقَامَ أَبُو بُرْدَةَ بْنُ نِيَارٍ فَقَالَ يَا رَسُولَ اللَّهِ وَاللَّهِ لَقَدْ نَسَكْتُ قَبْلَ أَنْ أَخْرُجَ إِلَى الصَّلَاةِ وَعَرَفْتُ أَنَّ الْيَوْمَ يَوْمُ أَكْلٍ وَشُرْبٍ فَتَعَجَّلْتُ فَأَكَلْتُ وَأَطْعَمْتُ أَهْلِي وَجِيرَانِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ شَاةُ لَحْمٍ فَقَالَ إِنَّ عِنْدِي عَنَاقًا جَذَعَةً وَهِيَ خَيْرٌ مِنْ شَاتَيْ لَحْمٍ فَهَلْ تُجْزِئُ عَنِّي قَالَ نَعَمْ وَلَنْ تُجْزِئَ عَنْ أَحَدٍ بَعْدَكَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu Al Ahwash], telah menceritakan kepada kami [Manshur], dari [Asy Sya'bi], dari [Al Bara`], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada kami pada hari penyembelihan ('idul Adhha) setelah melakukan shalat. Beliau berkata: \"Barangsiapa yang melakukan shalat seperti shalat kami dan menyembelih sembelihan kami maka sungguh ia telah telah melakukan kurban, dan barang siapa yang menyembelih sebelum shalat maka hal itu adalah kambing daging (untuk dimakan dagingnya saja).\" Kemudian Abu Burdah bin Diyar berdiri dan berkata; wahai Rasulullah, aku telah menyembelih sebelum keluar untuk melakukan shalat, dan aku telah mengetahui bahwa hari ini adalah hari makan dan minum, maka aku segerekan penyembelihan tersebut, lalu aku makan dan memberi makan keluarga serta tetanggaku. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itu adalah kambing untuk dimakan dagingnya saja.\" Kemudian beliau bersabda: \"Sesungguhnya bagiku kambing yang berumur satu tahun lebih baik daripada dua kambing daging (yang dimakan dagingnya saja).\" Al Bara` berkata: \"Apakah sah bagiku? Ia berkata; ya. Dan tidak sah untuk seorang pun setelahmu.\""},"2354":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدٌ عَنْ مُطَرِّفٍ عَنْ عَامِرٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَضَحَّى خَالٌ لِي يُقَالُ لَهُ أَبُو بُرْدَةَ قَبْلَ الصَّلَاةِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاتُكَ شَاةُ لَحْمٍ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ عِنْدِي دَاجِنًا جَذَعَةً مِنْ الْمَعْزِ فَقَالَ اذْبَحْهَا وَلَا تَصْلُحُ لِغَيْرِكَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Khalid], dari [Mutharrif], dari ['Amir], dari [Al Bara` bin 'Azib], ia berkata; pamanku yang bernama Abu Burdah berkurban sebelum melakukan shalat. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Kambingmu adalah kambing daging (yang dimakan dagingnya saja).\""},"2355":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ النَّمَرِيُّ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عُبَيْدِ بْنِ فَيْرُوزَ قَالَسَأَلْتُ الْبَرَاءَ بْنَ عَازِبٍ مَا لَا يَجُوزُ فِي الْأَضَاحِيِّ فَقَالَ قَامَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصَابِعِي أَقْصَرُ مِنْ أَصَابِعِهِ وَأَنَامِلِي أَقْصَرُ مِنْ أَنَامِلِهِ فَقَالَ أَرْبَعٌ لَا تَجُوزُ فِي الْأَضَاحِيِّ فَقَالَ الْعَوْرَاءُ بَيِّنٌ عَوَرُهَا وَالْمَرِيضَةُ بَيِّنٌ مَرَضُهَا وَالْعَرْجَاءُ بَيِّنٌ ظَلْعُهَا وَالْكَسِيرُ الَّتِي لَا تَنْقَى قَالَ قُلْتُ فَإِنِّي أَكْرَهُ أَنْ يَكُونَ فِي السِّنِّ نَقْصٌ قَالَ مَا كَرِهْتَ فَدَعْهُ وَلَا تُحَرِّمْهُ عَلَى أَحَدٍقَالَ أَبُو دَاوُد لَيْسَ لَهَا مُخٌّ","id":"Telah menceritakan kepada kami [Hafsh bin Umar An Namari], telah menceritakan kepada kami [Syu'bah] dari [Sulaiman bin Abdurrahman], dari ['Ubaid bin Fairuz], ia berkata; aku pernah bertanya kepada [Al Bara` bin 'Azib]; sesuatu apakah yang tidak diperbolehkan dalam hewan kurban? Kemudian ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah berdiri diantara kami, jari-jariku lebih pendek daripada jari-jarinya dan ruas-ruas jariku lebih pendek dari ruas-ruas jarinya, kemudian beliau berkata: \"Empat perkara yang tidak boleh ada di dalam hewan-hewan kurban.\" Kemudian belaiu berkata; yaitu; buta sebelah matanya yang jelas kebutaannya, pincang yang jelas pincangnya, sakit yang jelas sakitnya, dan pecah kakinya yang tidak memiliki sumsum. 'Ubaid berkata; aku katakan kepada Al Bara`; tidak suka pada giginya terdapat aib. Ia berkata; apa yang tidak engkau sukai maka tinggalkan dan janganlah engkau mengharamkannya kepada seseorang. Abu Daud berkata; tidak ada otak padanya. "},"2356":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ قَالَ أَخْبَرَنَا ح و حَدَّثَنَا عَلِيُّ بْنُ بَحْرِ بْنِ بَرِيٍّ حَدَّثَنَا عِيسَى الْمَعْنَى عَنْ ثَوْرٍ حَدَّثَنِي أَبُو حُمَيْدٍ الرُّعَيْنِيُّ أَخْبَرَنِي يَزِيدُ ذُو مِصْرَ قَالَأَتَيْتُ عُتْبَةَ بْنَ عَبْدٍ السُّلَمِيَّ فَقُلْتُ يَا أَبَا الْوَلِيدِ إِنِّي خَرَجْتُ أَلْتَمِسُ الضَّحَايَا فَلَمْ أَجِدْ شَيْئًا يُعْجِبُنِي غَيْرَ ثَرْمَاءَ فَكَرِهْتُهَا فَمَا تَقُولُ قَالَ أَفَلَا جِئْتَنِي بِهَا قُلْتُ سُبْحَانَ اللَّهِ تَجُوزُ عَنْكَ وَلَا تَجُوزُ عَنِّي قَالَ نَعَمْ إِنَّكَ تَشُكُّ وَلَا أَشُكُّ إِنَّمَا نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُصْفَرَّةِ وَالْمُسْتَأْصَلَةِ وَالْبَخْقَاءِ وَالْمُشَيَّعَةِ وَكِسَرَا وَالْمُصْفَرَّةُ الَّتِي تُسْتَأْصَلُ أُذُنُهَا حَتَّى يَبْدُوَ سِمَاخُهَا وَالْمُسْتَأْصَلَةُ الَّتِي اسْتُؤْصِلَ قَرْنُهَا مِنْ أَصْلِهِ وَالْبَخْقَاءُ الَّتِي تُبْخَقُ عَيْنُهَا وَالْمُشَيَّعَةُ الَّتِي لَا تَتْبَعُ الْغَنَمَ عَجَفًا وَضَعْفًا وَالْكَسْرَاءُ الْكَسِيرَةُ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi], ia berkata; dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ali bin Bahr bin Bari], telah menceritakan kepada kami [Isa] secara makna, dari [Tsaur], telah menceritakan kepadaku [Abu Humaid Ar Ru'aini], telah mengabarkan kepadaku [Yazid Dzu Mishr], ia berkata; aku datang kepada ['Utbah bin Abdussulami], kemudian aku katakan; wahai Abu Al Walid, sesungguhnya aku keluar mencari kurban, dan aku tidak mendapatkan sesuatu yang menarik bagiku selain tsarma` (yang telah tanggal gigi seri dan gigi taring). Lalu aku tidak menyukainya, maka bagaimana pendapatmu? Ia berkata; tidakkah engkau membawanya kepadaku? Aku katakan; subhanallah, tidak cukup bagimu dan tidak cukup bagiku? Ia berkata; ya. Karena engkau ragu dan aku tidak ragu. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam hanya melarang dari mushfarrah, musta`shalah, bakhqa`, musyayya'ah dan kasra`. Mushfarrah adalah yang terpotong telinganya hingga nampak lubangnya, sedangkan musta`shalah adalah yang patah tanduknya pangkalnya, bakhqa` adalah yang buta matanya, dan musyayya'ah adalah yang kurus dan lemah, dan kasra` adalah yang retak (tulangnya)."},"2357":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ شُرَيْحِ بْنِ النُّعْمَانِ وَكَانَ رَجُلَ صِدْقٍ عَنْ عَلِيٍّ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَسْتَشْرِفَ الْعَيْنَ وَالْأُذُنَيْنِ وَلَا نُضَحِّي بِعَوْرَاءَ وَلَا مُقَابَلَةٍ وَلَا مُدَابَرَةٍ وَلَا خَرْقَاءَ وَلَا شَرْقَاءَقَالَ زُهَيْرٌ فَقُلْتُ لِأَبِي إِسْحَقَ أَذَكَرَ عَضْبَاءَ قَالَ لَا قُلْتُ فَمَا الْمُقَابَلَةُ قَال يُقْطَعُ طَرَفُ الْأُذُنِ قُلْتُ فَمَا الْمُدَابَرَةُ قَالَ يُقْطَعُ مِنْ مُؤَخَّرِ الْأُذُنِ قُلْتُ فَمَا الشَّرْقَاءُ قَالَ تُشَقُّ الْأُذُنُ قُلْتُ فَمَا الْخَرْقَاءُ قَالَ تُخْرَقُ أُذُنُهَا لِلسِّمَةِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Abu Ishaq], dari [Syuraih bin An Nu'man], dan ia adalah orang yang jujur, dari [Ali], ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami agar memeriksa mata, dan telinga serta agar kami tidak berkurban dengan 'aura`, muqabalah, mudabarah, kharqa` dan syarqa`. Zuhair berkata; aku katakan kepada Abu Ishaq; apakah beliau menyebutkan 'Adhba`? ia berkata; tidak. Aku katakan; apakah Muqabalah? Ia berkata; yang terpotong ujung telingannya. Aku katakan; apakah mudabarah? Ia berkata; yang terpotong belakang telingannya. Aku katakan; apakah syarqa`? Ia berkata; yang telingannya sobek. Aku katakan; apakah kharqa`? Ia berkata; yang telinganya dilubangi sebagai tanda. "},"2358":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامُ بْنُ أَبِي عَبْدِ اللَّهِ الدَّسْتُوَائِيُّ وَيُقَالُ لَهُ هِشَامُ بْنُ سَنْبَرٍ عَنْ قَتَادَةَ عَنْ جُرَيِّ بْنِ كُلَيْبٍ عَنْ عَلِيٍّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ ي��ضَحَّى بِعَضْبَاءِ الْأُذُنِ وَالْقَرْنِقَالَ أَبُو دَاوُد جُرَيٌّ سَدُوسِيٌّ بَصْرِيٌّ لَمْ يُحَدِّثْ عَنْهُ إِلَّا قَتَادَةُ حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ قَالَ قُلْتُ لِسَعِيدِ بْنِ الْمُسَيِّبِ مَا الْأَعْضَبُ قَالَ النِّصْفُ فَمَا فَوْقَهُ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Hisyam bin Abu Abdullah Ad Dastuwai], dan ia dipanggil Hisyam bin Sanbar, dari [Qatadah], dari [Jurai bin Kulaib], dari [Ali], bahwa Nabi shallallahu 'alaihi wasallam melarang berkurban dengan dengan hewan yang sobek telinganya dan pecah tanduknya. Abu Daud berkata; Jurai Sadusi Bashri tidak ada yang meriwayatkan darinya selain Qatadah. Telah menceritakan kepada kami Musaddad, telah menceritakan kepada kami Yahya, telah menceritakan kepada kami Hisyam dari Qatadah, ia berkata; aku katakan kepada Sa'id bin Al Musayyab, apakah a'dhab itu? Ia berkata; setengah atau lebih. "},"2359":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا نَتَمَتَّعُ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَذْبَحُ الْبَقَرَةَ عَنْ سَبْعَةٍ وَالْجَزُورَ عَنْ سَبْعَةٍ نَشْتَرِكُ فِيهَا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Husyaim], telah menceritakan kepada kami [Abdul Malik], dari ['Atho`], dari [Jabir bin Abdullah], ia berkata; dahulu kami melakukan haji tamattu' pada zaman Rasulullah shallallahu 'alaihi wasallam, kami menyembelih sapi untuk tujuh orang dan unta untuk tujuh orang, kami bersekutu dalam kurban tersebut. "},"2360":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ قَيْسٍ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَقَرَةُ عَنْ سَبْعَةٍ وَالْجَزُورُ عَنْ سَبْعَةٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Qais] dari ['Atha`], dari [Jabir bin Abdullah], bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Satu ekor sapi untuk tujuh orang, dan satu ekor unta untuk tujuh orang.\""},"2361":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي الزُّبَيْرِ الْمَكِّيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّهُ قَالَنَحَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحُدَيْبِيَّةِ الْبَدَنَةَ عَنْ سَبْعَةٍ وَالْبَقَرَةَ عَنْ سَبْعَةٍ","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik], dari [Abu Az Zubair Al Makki], dari [Jabir bin Abdullah], bahwa ia berkata; kami menyembelih satu ekor unta bersama Rasulullah shallallahu 'alaihi wasallam di Hudaibiyah untuk tujuh orang dan seekor sapi untuk tujuh ekor. "},"2362":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي الْإِسْكَنْدَرَانِيَّ عَنْ عَمْرٍو عَنْ الْمُطَّلِبِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَشَهِدْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَضْحَى بِالْمُصَلَّى فَلَمَّا قَضَى خُطْبَتَهُ نَزَلَ مِنْ مِنْبَرِهِ وَأُتِيَ بِكَبْشٍ فَذَبَحَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ وَقَالَ بِسْمِ اللَّهِ وَاللَّهُ أَكْبَرُ هَذَا عَنِّي وَعَمَّنْ لَمْ يُضَحِّ مِنْ أُمَّتِي","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Ya'qub Al Iskandari], dari ['Amr] dari [Al Muththalib] dari [Jabir bin Abdullah], ia berkata; saya menyaksikan bersama Rasulullah shallallahu 'alaihi wasallam Shalat Adha di lapangan, kemudian tatkala menyelesaikan khutbahnya beliau turun dari mimbarnya, dan beliau diberi satu ekor domba kemudian Rasulullah shallallahu 'alaihi wasallam menyembelihnya, dan mengucapkan: \"BISMILLAAHI WALLAAHU AKBAR, HAADZA 'ANNII WA 'AN MAN LAM YUDHAHHI MIN UMMATI\" (Dengan nama Allah, Allah Maha Besar, ini (kurban) dariku dan orang-orang yang belum berkurban dari umatku). "},"2363":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ أَنَّ أَبَا أُسَامَةَ حَدَّثَهُمْ عَنْ أُسَامَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَذْبَحُ أُضْحِيَّتَهُ بِالْمُصَلَّىوَكَانَ ابْنُ عُمَرَ يَفْعَلُهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], bahwa [Abu Usamah] telah menceritakan kepada mereka dari [Usamah] dari [Nafi'] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam menyembelih kurbannya di lapangan, dan Ibnu Umar melakukan hal tersebut. "},"2364":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ قَالَتْ سَمِعْتُ عَائِشَةَ تَقُولُدَفَّ نَاسٌ مِنْ أَهْلِ الْبَادِيَةِ حَضْرَةَ الْأَضْحَى فِي زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادَّخِرُوا الثُّلُثَ وَتَصَدَّقُوا بِمَا بَقِيَ قَالَتْ فَلَمَّا كَانَ بَعْدُ ذَلِكَ قِيلَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رَسُولَ اللَّهِ لَقَدْ كَانَ النَّاسُ يَنْتَفِعُونَ مِنْ ضَحَايَاهُمْ وَيَجْمُلُونَ مِنْهَا الْوَدَكَ وَيَتَّخِذُونَ مِنْهَا الْأَسْقِيَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا ذَاكَ أَوْ كَمَا قَالَ قَالُوا يَا رَسُولَ اللَّهِ نَهَيْتَ عَنْ إِمْسَاكِ لُحُومِ الضَّحَايَا بَعْدَ ثَلَاثٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا نَهَيْتُكُمْ مِنْ أَجْلِ الدَّافَّةِ الَّتِي دَفَّتْ عَلَيْكُمْ فَكُلُوا وَتَصَدَّقُوا وَادَّخِرُوا","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik], dari [Abdullah bin Abu Bakr], dari ['Amrah binti Abdurrahman], ia berkata; saya mendengar [Aisyah] berkata; orang-orang bersegera menghadiri shalat 'Idul Adhha pada zaman Rasulullah shallallahu 'alaihi wasallam, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Simpanlah sepertiga, dan sedekahkan sisanya!\" Aisyah berkata; kemudian setelah itu Rasulullah shallallahu 'alaihi wasallam ditanya; wahai Rasulullah, dahulu orang-orang mendapatkan manfaat dari kurban mereka dan mereka mencairkan lemak, dan membuat tempat minum dari kulitnya, kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Ada apa dengan hal tersebut?\" Mereka berkata; wahai Rasulullah, engkautelah melarang dari memakan daging kurban setelah tiga hari. Kemudian beliau berkata: \"Sesungguhnya aku melarang hal tersebut, karena sekelompok orang yang terburu-buru datang kepada kalian. Makanlah, sedekahkan, serta simpanlah!\""},"2365":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي الْمَلِيحِ عَنْ نُبَيْشَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا كُنَّا نَهَيْنَاكُمْ عَنْ لُحُومِهَا أَنْ تَأْكُلُوهَا فَوْقَ ثَلَاثٍ لِكَيْ تَسَعَكُمْ فَقَدْ جَاءَ اللَّهُ بِالسَّعَةِ فَكُلُوا وَادَّخِرُوا وَاتَّجِرُوا أَلَا وَإِنَّ هَذِهِ الْأَيَّامَ أَيَّامُ أَكْلٍ وَشُرْبٍ وَذِكْرِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yazid bin Zurai'], telah menceritakan kepada kami [Khalid Al Hadzdza`] dari [Abu Al Malih], dari [Nubaisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dahulu kami telah melarang kalian dari memakan daging kurban di atas tiga hari agar mencukupi kalian. Allah telah memberikan keluasan, maka dan simpanlah serta juallah! Ketahuilah bahwa hari-hari ini adalah hari-hari makan dan minum serta berdzikir kepada Allah 'azza wajalla.\""},"2366":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ الْخَيَّاطُ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ أَبِي الزَّاهِرِيَّةِ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ ثَوْبَانَ قَالَضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا ثَوْبَانُ أَصْلِحْ لَنَا لَحْمَ هَذِهِ الشَّاةِ قَالَ فَمَا زِلْتُ أُطْعِمُهُ مِنْهَا حَتَّى قَدِمْنَا الْمَدِينَةَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Hammad bin Khalid Al Khayyath], ia berkata; telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Abu Az Zahiriyyah], dari [Jubair bin Nufair], dari [Tsauban], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkurban kemudian berkata: \"Wahai Tsauban, persiapkan daging kambing ini untuk kami!\" Aku terus memberi beliau makan dari daging tersebut hingga kami datang ke Madinah. "},"2367":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ عَنْ شَدَّادِ بْنِ أَوْسٍ قَالَخَصْلَتَانِ سَمِعْتُهُمَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ كَتَبَ الْإِحْسَانَ عَلَى كُلِّ شَيْءٍ فَإِذَا قَتَلْتُمْ فَأَحْسِنُوا قَالَ غَيْرُ مُسْلِمٍ يَقُولُ فَأَحْسِنُوا الْقِتْلَةَ وَإِذَا ذَبَحْتُمْ فَأَحْسِنُوا الذَّبْحَ وَلْيُحِدَّ أَحَدُكُمْ شَفْرَتَهُ وَلْيُرِحْ ذَبِيحَتَهُ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Syu'bah] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Abu Al Asy'ats] dari [Syaddad bin Aus], ia berkata; dua sifat yang aku dengar dari Rasulullah shallallahu wa'alaihi wa sallam: \"Sesungguhnya Allah telah mewajibkan bersikap baik terhadap segala sesuatu, apabila kalian membunuh maka bersikaplah yang baik!\" selain Muslim mengatakan mengatakan: maka bunuhlah dengan baik, dan apabila kalian menyembelih maka sembelihlah dengan baik, dan hendaknya salah seorang dari kalian menajamkan pisaunya dan memberikan kenyamanan kepada hewan sembelihannya.\""},"2368":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ زَيْدٍ قَالَدَخَلْتُ مَعَ أَنَسٍ عَلَى الْحَكَمِ بْنِ أَيُّوبَ فَرَأَى فِتْيَانًا أَوْ غِلْمَانًا قَدْ نَصَبُوا دَجَاجَةً يَرْمُونَهَا فَقَالَ أَنَسٌ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُصْبَرَ الْبَهَائِمُ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi], telah menceritakan kepada kami [Syu'bah], dari [Hisyam bin Zaid], ia berkata; aku bersama Anas menemui Al Hakam bin Ayyub, kemudian ia melihat beberapa pemuda atau anak-anak yang memasang ayam dan mereka melemparinya. Kemudian [Anas] berkata; Rasulullah shallallahu 'alaihi wasallam telah melarang dari menjadikan hewan sebagai sasaran. "},"2369":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ فَكُلُوا مِمَّا ذُكِرَ اسْمُ اللَّهِ عَلَيْهِ }{ وَلَا تَأْكُلُوا مِمَّا لَمْ يُذْكَرْ اسْمُ اللَّهِ عَلَيْهِ }فَنُسِخَ وَاسْتَثْنَى مِنْ ذَلِكَ فَقَالَ{ وَطَعَامُ الَّذِينَ أُوتُوا الْكِتَابَ حِلٌّ لَكُمْ وَطَعَامُكُمْ حِلٌّ لَهُمْ }","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Tsabit Al Marwazi], telah menceritakan kepadaku [Ali bin Husain] dari [ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; ayat \"Makanlah apa yang telah disebutkan nama Allah padanya, \" \"Dan jangan kalian makan apa yang yang belum disebutkan nama Allah padanya.\" Kemudian hal tersebut dihapuskan dan Allah mengecualihan dari hal tersebut, Allah berfirman: \"Dan makanan orang-orang ahli kitab adalah halal bagimu dan makananmu adalah halal bagi mereka.\""},"2370":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا سِمَاكٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ وَإِنَّ الشَّيَاطِينَ لَيُوحُونَ إِلَى أَوْلِيَائِهِمْ }يَقُولُونَ مَا ذَبَحَ اللَّهُ فَلَا تَأْكُلُوا وَمَا ذَبَحْتُمْ أَنْتُمْ فَكُلُوا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَلَا تَأْكُلُوا مِمَّا لَمْ يُذْكَرْ اسْمُ اللَّهِ عَلَيْهِ }","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Israil], telah menceritakan kepada kami [Simak], dari [Ikrimah] dari [Ibnu Abbas], mengenai firman Allah: \"Sesungguhnya syaitan itu membisikkan kepada kawan-kawannya.\" Mereka mengatakan; apa yang Allah sembelih janganlah kalian makan dan apa yang kalian sembelih makanlah! Kemudian Allah 'azza wajalla menurunkan ayat: \"Dan jangan kalian makan apa yang yang belum disebutkan nama Allah padanya.\""},"2371":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عِمْرَانُ بْنُ عُيَيْنَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَتْ الْيَهُودُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا نَأْكُلُ مِمَّا قَتَلْنَا وَلَا نَأْكُلُ مِمَّا قَتَلَ اللَّهُ فَأَنْزَلَ اللَّهُ{ وَلَا تَأْكُلُوا مِمَّا لَمْ يُذْكَرْ اسْمُ اللَّهِ عَلَيْهِ }إِلَى آخِرِ الْآيَةِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Imran bin 'Uyainah], dari ['Atha` bin As Saib], dari [Sa'id bin Jubair], dari [Ibnu Abbas], ia berkata; orang-orang yahudi telah datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; kami maka apa yang kami bunuh, dna kami tidak makan apa yang Allah bunuh. Kemudian Allah menurunkan ayat: \"Dan jangan kalian makan apa yang yang belum disebutkan nama Allah padanya.\" Hinngga akhir ayat. "},"2372":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ عَنْ عَوْفٍ عَنْ أَبِي رَيْحَانَةَ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ مُعَاقَرَةِ الْأَعْرَابِقَالَ أَبُو دَاوُد اسْمُ أَبِي رَيْحَانَةَ عَبْدُ اللَّهِ بْنُ مَطَرٍ وَغُنْدَرٌ أَوْقَفَهُ عَلَى ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Harun bin Abdullah], telah menceritakan kepada kami [Hammad bin Mas'adah], dari ['Auf], dari [Abu Raihanah], dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah melarang dari sikap berbangga orang-orang badui. "},"2373":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا سَعِيدُ بْنُ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا نَلْقَى الْعَدُوَّ غَدًا وَلَيْسَ مَعَنَا مُدًى أَفَنَذْبَحُ بِالْمَرْوَةِ وَشِقَّةِ الْعَصَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرِنْ أَوْ أَعْجِلْ مَا أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ عَلَيْهِ فَكُلُوا مَا لَمْ يَكُنْ سِنًّا أَوْ ظُفْرًا وَسَأُحَدِّثُكُمْ عَنْ ذَلِكَ أَمَّا السِّنُّ فَعَظْمٌ وَأَمَّا الظُّفْرُ فَمُدَى الْحَبَشَةِ وَتَقَدَّمَ بِهِ سَرْعَانٌ مِنْ النَّاسِ فَتَعَجَّلُوا فَأَصَابُوا مِنْ الْغَنَائِمِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي آخِرِ النَّاسِ فَنَصَبُوا قُدُورًا فَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْقُدُورِ فَأَمَرَ بِهَا فَأُكْفِئَتْ وَقَسَمَ بَيْنَهُمْ فَعَدَلَ بَعِيرًا بِعَشْرِ شِيَاهٍ وَنَدَّ بَعِيرٌ مِنْ إِبِلِ الْقَوْمِ وَلَمْ يَكُنْ مَعَهُمْ خَيْلٌ فَرَمَاهُ رَجُلٌ بِسَهْمٍ فَحَبَسَهُ اللَّهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِهَذِهِ الْبَهَائِمِ أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَمَا فَعَلَ مِنْهَا هَذَا فَافْعَلُوا بِهِ مِثْلَ هَذَا","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu Al Ahwash], telah menceritakan kepada kami [Sa'id bin Masruq], dari ['Abayah bin Rifa'ah] dari [ayahnya], dari [kakeknya yaitu Rafi' bin Khadij], ia berkata; aku datang kepada Rasulullah shallallahu 'alaihi wasallam lalu aku katakan; wahai Rasulullah, sesungguhnya kita akan bertemu musuh besok, dan kita tidak memiliki pisau. Bolehkah kami menyembelih menggunakan marwah (batu putih yang dibuat seperti pisau) dan belahan tongkat? Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Percepat dan segeralah, apa yang dapat mengalirkan darah dan telah disebutkan nama Allah, maka makanlah, selama bukan gigi atau kuku dan akan saya ceritakan mengenai hal tersebut; adapun gigi maka itu adalah tulang, adapun kuku maka itu adalah pisau orang-orang Habasyah.\" Kemudian orang-orang terdepan maju dan cepat-cepat mereka menyembelih kambing, sementara Rasulullah shallallahu 'alaihi wasallam berada di belakang orang-orang. Kemudian mereka meletakkan bejana-bejana mereka. Kemudian Rasulullah shallallahu 'alaihi wasallam melewati bejana-bejana tersebut dan memerintahkan untuk dipenuhi dan beliau membagikan daging tersebut diantara mereka. Beliau menyetarakan satu ekor unta sama dengan sepuluh kambing. Kemudian salah satu unta orang-orang tersebut kabur, dan mereka tidak membawa kuda. Kemudian seseorang memanahnya dan Allah menghentikannya. Lalu Nabi shallallahu 'alaihi wasallam berkata: \"Sesungguhnya hewan-hewan ternak ini memiliki hewan-hewan yang menjadi liar seperti liarnya hewan yang liar, apa yang dilakukan orang ini terhadapnya (unta yang kabur tersebut), maka lakukanlah seperti ini!\""},"2374":{"ar":"حَدَّثَنَا مُسَدَّدٌ أَنَّ عَبْدَ الْوَاحِدِ بْنِ زِيَادٍ وَحَمَّادًا حَدَّثَاهُمْ الْمَعْنَى وَاحِدٌ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ مُحَمَّدِ بْنِ صَفْوَانَ أَوْ صَفْوَانَ بْنِ مُحَمَّدٍ قَالَاصَّدْتُ أَرْنَبَيْنِ فَذَبَحْتُهُمَا بِمَرْوَةٍ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْهُمَا فَأَمَرَنِي بِأَكْلِهِمَا","id":"Telah menceritakan kepada kami [Musaddad], bahwa [Abdul Wahid bin Ziyad] dan [Hammad], telah menceritakan kepada mereka, dan maknanya adalah satu, dari ['Ashim] dari [Asy Sya'bi], dari [Muhammad bin Shafwan atau Shafwan bin Muhammad], ia berkata; aku telah berburu dua ekor kelinci, kemudian aku menyembelihnya menggunakan batu, lalu aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai kedua kelinci tersebut, lalu beliau memerintahkanku agar memakannya. "},"2375":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رَجُلٍ مِنْ بَنِي حَارِثَةَأَنَّهُ كَانَ يَرْعَى لِقْحَةً بِشِعْبٍ مِنْ شِعَابِ أُحُدٍ فَأَخَذَهَا الْمَوْتُ فَلَمْ يَجِدْ شَيْئًا يَنْحَرُهَا بِهِ فَأَخَذَ وَتِدًا فَوَجَأَ بِهِ فِي لَبَّتِهَا حَتَّى أُهَرِيقَ دَمُهَا ثُمَّ جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِذَلِكَ فَأَمَرَهُ بِأَكْلِهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Ya'qub] dari [Zaid bin Aslam], dari ['Atha` bin Yasar] dari [seorang laki-laki dari Bani Haritsah], bahwa ia pernah menggembala unta yang bersusu dan hampir melahirkan di sebuah jalan Uhud. Kemudian unta tersebut hampir mati dan ia tidak mendapatkan sesuatu untuk menyembelihnya, lalu ia mengambil pasak dan ia tusukkan pada dadanya hingga mengeluarkan darah, kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam lalu mengabarkan tentang hal itu, maka beliau memerintahkan untuk memakannya. "},"2376":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ مُرَيِّ بْنِ قَطَرِيٍّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ أَحَدُنَا أَصَابَ صَيْدًا وَلَيْسَ مَعَهُ سِكِّينٌ أَيَذْبَحُ بِالْمَرْوَةِ وَشِقَّةِ الْعَصَا فَقَالَ أَمْرِرْ الدَّمَ بِمَا شِئْتَ وَاذْكُرْ اسْمَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], dari [Simak bin Harb], dari [Murai bin Qothary], dari [Adi bin Hatim], dia berkata; aku berkata; wahai Rasulullah bagaimana menurut engkau jika salah seorang diantara kami mendapat hewan buruan sedangkan dia tidak mempunyai pisau, apakah (boleh) dia menyembelih dengan batu yang tajam? Maka beliau bersabda: \"alirkanlah darah (hewan itu) dengan apa yang kamu punyai dan sebutlah nama Allah 'azza wajalla\". "},"2377":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي الْعُشَرَاءِ عَنْ أَبِيهِ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ أَمَا تَكُونُ الذَّكَاةُ إِلَّا مِنْ اللَّبَّةِ أَوْ الْحَلْقِ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ طَعَنْتَ فِي فَخِذِهَا لَأَجْزَأَ عَنْكَقَالَ أَبُو دَاوُد وَهَذَا لَا يَصْلُحُ إِلَّا فِي الْمُتَرَدِّيَةِ وَالْمُتَوَحِّشِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Hammad bin Salamah], dari [Abu Al 'Usyara`] dari [ayahnya], bahwa ia berkata; wahai Rasulullah, apakah menyembelih itu harus dari labbah (leher bagian bawah) atau tenggorokan? Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Seandainya engkau tusuk pada pahanya niscaya sah bagimu.\" Abu Daud berkata; dan hal ini tidak boleh dilakukan kecuali pada hewan yang terjatuh dari atas dan hewan yang menjadi liar. "},"2378":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ وَالْحَسَنُ بْنُ عِيسَى مَوْلَى ابْنِ الْمُبَارَكِ عَنْ ابْنِ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ عَمْرِو بْنِ عَبْدِ اللَّهِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ زَادَ ابْنُ عِيسَى وَأَبِي هُرَيْرَةَ قَالَانَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ شَرِيطَةِ الشَّيْطَانِ زَادَ ابْنُ عِيسَى فِي حَدِيثِهِ وَهِيَ الَّتِي تُذْبَحُ فَيُقْطَعُ الْجِلْدُ وَلَا تُفْرَى الْأَوْدَاجُ ثُمَّ تُتْرَكُ حَتَّى تَمُوتَ","id":"Telah menceritakan kepada kami [Hannad bin As Sari], dan [Al Hasan bin Isa] mantan budak Ibnu Al Mubarak, dari [Ibnu Al Mubarak] dari [Ma'mar] dari ['Amr bin Abdullah], dari [Ikrimah] dari [Ibnu Abbas], Ibnu Isa menambahkan; dan dari [Abu Hurairah] mereka berdua mengatakan; Rasulullah shallallahu 'alaihi wasallam melarang dari syarithatu syaithan (hewan yang ketika disembelih urat lehernya tidak terpotong dengan sempurna), Ibnu Isa menambahkan dalam haditsnya; yaitu yang disembelih dengan memotong kulit dan urat-urat leher tidak dipotong kemudian dibiarkan hingga mati. "},"2379":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا ابْنُ الْمُبَارَكِ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا هُشَيْمٌ عَنْ مُجَالِدٍ عَنْ أَبِي الْوَدَّاكِ عَنْ أَبِي سَعِيدٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجَنِينِ فَقَالَ كُلُوهُ إِنْ شِئْتُمْ وَقَالَ مُسَدَّدٌ قُلْنَا يَا رَسُولَ اللَّهِ نَنْحَرُ النَّاقَةَ وَنَذْبَحُ الْبَقَرَةَ وَالشَّاةَ فَنَجِدُ فِي بَطْنِهَا الْجَنِينَ أَنُلْقِيهِ أَمْ نَأْكُلُهُ قَالَ كُلُوهُ إِنْ شِئْتُمْ فَإِنَّ ذَكَاتَهُ ذَكَاةُ أُمِّهِ","id":"Telah menceritakan kepada kami [Al Qa'nabi], telah menceritakan kepada kami [Ibnu Al Mubarak], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Husyaim] dari [Mujalid] dari [Abu Al Waddak] dari [Abu Sa'id], ia berkata; saya bertanya kepada Rasulullah shallallahu wa'alaihi wa sallam mengenai janin hewan, kemudian beliau berkata: \"Makanlah apabila kalian menghendaki!\" Musaddad berkata; maka kami katakan; wahai Rasulullah, kami menyembelih unta, sapi dan kambing, kemudian kami dapatkan janin dalam perutnya, apakah kami membuangnya atau kami boleh memakannya? Beliau berkata: \"Makanlah apabila kalian menghendaki! Sesungguhnya penyembelihannya adalah dengan menyembelih induknya\""},"2380":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنِي إِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ رَاهَوَيْهِ حَدَّثَنَا عَتَّابُ بْنُ بَشِيرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي زِيَادٍ الْقَدَّاحُ الْمَكِّيُّ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَكَاةُ الْجَنِينِ ذَكَاةُ أُمِّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris], telah menceritakan kepadaku [Ishaq bin Ibrahim bin Rahawaih], telah menceritakan kepada kami ['Attab bin Basyir], telah menceritakan kepada kami ['Ubaidullah bin Abu Al Qaddah Al Makki], dari [Abu Az Zubair], dari [Jabir bin Abdullah], dari Rasulullah shallallahu 'alaihi wasallam, beliau berkata: \"Penyembelihan janin adalah dengan menyembelih induknya.\""},"2381":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ ح و حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا سُلَيْمَانُ بْنُ حَيَّانَ وَمُحَاضِرٌ الْمَعْنَى عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَة�� وَلَمْ يَذْكُرَا عَنْ حَمَّادٍ وَمَالِكٍ عَنْ عَائِشَةَ أَنَّهُمْ قَالُوايَا رَسُولَ اللَّهِ إِنَّ قَوْمًا حَدِيثُو عَهْدٍ بِالْجَاهِلِيَّةِ يَأْتُونَ بِلُحْمَانٍ لَا نَدْرِي أَذَكَرُوا اسْمَ اللَّهِ عَلَيْهَا أَمْ لَمْ يَذْكُرُوا أَفَنَأْكُلُ مِنْهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمُّوا اللَّهَ وَكُلُوا","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik], dan telah diriwayatkan dari jalur yang lain: Dan telah menceritakan kepada kami [Yusuf bin Musa], telah menceritakan kepada kami [Sulaiman bin Hayyan], serta [Muhadhir] secara makna, dari [Hisyam bin 'Urwah] dari [ayahnya], dari [Aisyah], dan mereka berdua tidak menyebutkan dari Hammad, dan Malik, dari Aisyah. Bahwa mereka berkata; wahai Rasulullah, sesungguhnya orang-orang yang belum lama meninggalkan masa jahiliyah datang membawa daging, kami tidak mengetahui apakah mereka menyebutkan nama Allah padanya atau belum. Apakah kami boleh memakan sebagian darinya? Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebutlah nama Allah dan makanlah!\""},"2382":{"ar":"حَدَّثَنَا مُسَدَّدٌ ح و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ عَنْ بِشْرِ بْنِ الْمُفَضَّلِ الْمَعْنَى حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمَلِيحِ قَالَ قَالَ نُبَيْشَةُنَادَى رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا كُنَّا نَعْتِرُ عَتِيرَةً فِي الْجَاهِلِيَّةِ فِي رَجَبٍ فَمَا تَأْمُرُنَا قَالَ اذْبَحُوا لِلَّهِ فِي أَيِّ شَهْرٍ كَانَ وَبَرُّوا اللَّهَ عَزَّ وَجَلَّ وَأَطْعِمُوا قَالَ إِنَّا كُنَّا نُفْرِعُ فَرَعًا فِي الْجَاهِلِيَّةِ فَمَا تَأْمُرُنَا قَالَ فِي كُلِّ سَائِمَةٍ فَرَعٌ تَغْذُوهُ مَاشِيَتَكَ حَتَّى إِذَا اسْتَحْمَلَ قَالَ نَصْرٌ اسْتَحْمَلَ لِلْحَجِيجِ ذَبَحْتَهُ فَتَصَدَّقْتَ بِلَحْمِهِ قَالَ خَالِدٌ أَحْسَبَهُ قَالَ عَلَى ابْنِ السَّبِيلِ فَإِنَّ ذَلِكَ خَيْرٌقَالَ خَالِدٌ قُلْتُ لِأَبِي قِلَابَةَ كَمْ السَّائِمَةُ قَالَ مِائَةٌ","id":"Telah menceritakan kepada kami [Musaddad], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Nashr bin Ali], dari [Bisyr bin Al Mufadhdhal] secara makna, telah menceritakan kepada kami [Khalid Al Hadzdza`], dari [Abu Qilabah], dari [Abu Al Malih], ia berkata; [Nubaisy] berkata; seorang laki-laki memanggil Rasulullah shallallahu 'alaihi wasallam; sesungguhnya kami dahulu menyembelih hewan pada sepuluh pertama Bulan Rajab pada masa jahiliyah, maka apakah yang anda perintahkan kepada kami? Beliau berkata: \"Sembelihlah karena Allah pada bulan apa saja, dan berbaktilah kepada Allah 'azza wajalla, serta berilah makan!\" orang tersebut berkata; sesungguhnya kami dahulu kami menyembelih anak hewan pertama pada masa jahiliyah, maka apakah yang anda perintahkan kepada kami? Beliau berkata: \"Pada setiap hewan yang telah digembala lebih dari satu tahun terdapat anak pertama yang kalian yang diberi makan oleh hewan ternakmu, hingga apabila ia siap untuk dibebani -Nashr mengatakan; siap untuk dibebani orang-orang yang berhaji- maka engkau menyembelihnya dan bersedekah dengan dagingnya.\" Khalid berkata; aku katakan kepada Abu Qilabah; berapakah hewan saimah (yang digembala lebih dari satu tahun) (yang diperintahkan Rasulullah shallallahu 'alaihi wasallam untuk disembelih anak pertamanya?) ia berkata; seratus. "},"2383":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَخْبَرَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا فَرَعَ وَلَا عَتِيرَةَ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah], telah mengabarkan kepada kami [Sufyan] dari [Az Zuhri], dari [Sa'id] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Tidak ada fara' (menyembelih anak hewan yang pertama) dan tidak ada 'atirah (menyembelih hewan yang disembelih pada sepuluh pertama Bulan Rajab).\""},"2384":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ قَالَالْفَرَعُ أَوَّلُ النَّتَاجِ كَانَ يُنْتَجُ لَهُمْ فَيَذْبَحُونَهُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar], dari [Az Zuhri] dari [Sa'id], ia berkata; fara' adalah anak hewan pertama, dahulu mereka hewan mereka melahirkan kemudian mereka menyembelihnya. "},"2385":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ حَفْصَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ كُلِّ خَمْسِينَ شَاةً شَاةٌقَالَ أَبُو دَاوُد قَالَ بَعْضُهُمْ الْفَرَعُ أَوَّلُ مَا تُنْتِجُ الْإِبِلُ كَانُوا يَذْبَحُونَهُ لِطَوَاغِيتِهِمْ ثُمَّ يَأْكُلُونَهُ وَيُلْقَى جِلْدُهُ عَلَى الشَّجَرِ وَالْعَتِيرَةُ فِي الْعَشْرِ الْأُوَلِ مِنْ رَجَبٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Abdullah bin Utsman bin Khutsaim] dari [Yusuf bin Mahak], dari [Hafshah binti Abdurrahman] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk dikeluarkan zakat dari setiap lima puluh kambing satu ekor kambing. Abu Daud berkata; sebagian mereka mengatakan; fara' adalah anak unta yang pertama, dahulu mereka menyembelihnya untuk para berhala mereka, kemudian mereka memakannya, dan kulitnya dilemparkan ke pohon, sedangkan 'atirah ada pada sepuluh hari pertama pada Bulan Rajab. "},"2386":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءٍ عَنْ حَبِيبَةَ بِنْتِ مَيْسَرَةَ عَنْ أُمِّ كُرْزٍ الْكَعْبِيَّةِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَنْ الْغُلَامِ شَاتَانِ مُكَافِئَتَانِ وَعَنْ الْجَارِيَةِ شَاةٌقَالَ أَبُو دَاوُد سَمِعْت أَحْمَدَ قَالَ مُكَافِئَتَانِ أَيْ مُسْتَوِيَتَانِ أَوْ مُقَارِبَتَانِ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Sufyan] dari ['Amr bin Dinar], dari ['Atho`], dari [Habibah binti Maisarah], dari [Ummu Kurz Al Ka'biyyah], ia berkata; saya mendengar Rasulullah shallallahu wa'alaihi wa sallam bersabda: \"Untuk anak laki-laki dua kambing yang sama dan untuk anak perempuan satu kambing.\" Abu Daud berkata; saya mendengar Ahmad, ia berkata; mukafiatani yaitu yang sama atau saling berdekatan. "},"2387":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ أَبِيهِ عَنْ سِبَاعِ بْنِ ثَابِتٍ عَنْ أُمِّ كُرْزٍ قَالَتْسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَقِرُّوا الطَّيْرَ عَلَى مَكِنَاتِهَا قَالَتْ وَسَمِعْتُهُ يَقُولُ عَنْ الْغُلَامِ شَاتَانِ وَعَنْ الْجَارِيَةِ شَاةٌ لَا يَضُرُّكُمْ أَذُكْرَانًا كُنَّ أَمْ إِنَاثًا","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Sufyan] dari ['Ubaidullah bin Abu Yazid], dari [ayahnya] dari [Siba' bin Tsabit], dari [Ummu Kurz], ia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam berkata: \"Biarkan burung berada pada tempatnya!\" Aisyah berkata; dan saya mendengar beliau berkata: \"Untuk anak laki-laki dua kambing yang sama dan untuk anak perempuan satu kambing tidak bermasalah bagi kalian apakah jantan atau betina.\""},"2388":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ سِبَاعِ بْنِ ثَابِتٍ عَنْ أُمِّ كُرْزٍ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْغُلَامِ شَاتَانِ مِثْلَانِ وَعَنْ الْجَارِيَةِ شَاةٌقَالَ أَبُو دَاوُد هَذَا هُوَ الْحَدِيثُ وَحَدِيثُ سُفْيَانَ وَهْمٌ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Hammad bin Zaid], dari ['Ubaidullah bin Abu Yazid], dari [Siba' bin Tsabit], dari [Ummu Kurz], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Untuk anak laki-laki dua kambing yang sama dan untuk anak perempuan satu kambing.\" Abu Daud berkata; ini adalah hadits yang benar sedangkan hadits Sufyan adalah salah. "},"2389":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ النَّمَرِيُّ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ الْحَسَنِ عَنْ سَمُرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ غُلَامٍ رَهِينَةٌ بِعَقِيقَتِهِ تُذْبَحُ عَنْهُ يَوْمَ السَّابِعِ وَيُحْلَقُ رَأْسُهُ وَيُدَمَّىفَكَانَ قَتَادَةُ إِذَا سُئِلَ عَنْ الدَّمِ كَيْفَ يُصْنَعُ بِهِ قَالَ إِذَا ذَبَحْتَ الْعَقِيقَةَ أَخَذْتَ مِنْهَا صُوفَةً وَاسْتَقْبَلْتَ بِهِ أَوْدَاجَهَا ثُمَّ تُوضَعُ عَلَى يَافُوخِ الصَّبِيِّ حَتَّى يَسِيلَ عَلَى رَأْسِهِ مِثْلَ الْخَيْطِ ثُمَّ يُغْسَلُ رَأْسُهُ بَعْدُ وَيُحْلَقُ قَالَ أَبُو دَاوُد وَهَذَا وَهْمٌ مِنْ هَمَّامٍ وَيُدَمَّى قَالَ أَبُو دَاوُد خُولِفَ هَمَّامٌ فِي هَذَا الْكَلَامِ وَهُوَ وَهْمٌ مِنْ هَمَّامٍ وَإِنَّمَا قَالُوا يُسَمَّى فَقَالَ هَمَّامٌ يُدَمَّى قَالَ أَبُو دَاوُد وَلَيْسَ يُؤْخَذُ بِهَذَا","id":"Telah menceritakan kepada kami [Hafsh bin Umar An Namari], telah menceritakan kepada kami [Hammam], telah menceritakan kepada kami [Qatadah], dari [Al Hasan] dari [Samurah] dari Rasulullah shallallahu wa'alaihi wa sallam, beliau berkata: \"Setiap anak tergadaikan dengan aqiqahnya, disembelih untuknya pada hari ketujuh dan rambutnya dicukur, dan dilumuri dengan darah aqiqah.\" Qatadah apabila ditanya mengenai darah bagaimana dilakukan dengannya? Ia berkata; apabila engkau menyembelih aqiqah, maka engkau mengambil darinya satu bulu wol, dan engkau bawa ke arah urat-urat lehernya kemudian diletakkan pada pertengahan kepala anak kecil tersebut hingga mengalir di atas kelapa tersebut darah seperti benang, kemudian dicuci kepalanya setelah itu, dan dicukur. Abu Daud berkata; dan ini adalah kesalahan dari Hammam, yaitu kata; wa yudamma. Abu Daud berkata; Hammam diselisihi dalam perkataan ini, dan hal tersebut adalah kesalahan dari Hammam. Sesungguhnya mereka mengatakan; yusamma (diberi nama), namun Hammam berkata; wa yudamma (dan dilumuri darah). Abu Daud berkata; dan hadits tersebut tidak diambil dengan hal ini. "},"2390":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ غُلَامٍ رَهِينَةٌ بِعَقِيقَتِهِ تُذْبَحُ عَنْهُ يَوْمَ سَابِعِهِ وَيُحْلَقُ وَيُسَمَّىقَالَ أَبُو دَاوُد وَيُسَمَّى أَصَحُّ كَذَا قَالَ سَلَّامُ بْنُ أَبِي مُطِيعٍ عَنْ قَتَادَةَ وَإِيَاسُ ابْنُ دَغْفَلٍ وَأَشْعَثُ عَنْ الْحَسَنِ قَالَ وَيُسَمَّى وَرَوَاهُ أَشْعَثُ عَنْ الْحَسَنِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيُسَمَّى","id":"Telah menceritakan kepada kami [Ibnu Al Mutsanna], telah menceritakan kepada kami [Ibnu Abu Adi], dari [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub] bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Setiap anak tergadaikan dengan aqiqahnya, disembelihkan untuknya pada hari ketujuhnya, dicukur rambutnya dan diberi nama.\" Abu Daud berkata; dan kata yusamma (diberi nama) adalah lebih benar. Demikianlah yang dikatakan [Sallam bin Abu Muthi'] dari [Qatadah] serta [Iyas bin Daghfal], dan [Asy'ats], dari [Al Hasan], ia berkata; dan diberi nama. Dan hadits tersebut diriwayatkan oleh Asy'ats dari Al Hasan dari Nabi shallallahu 'alaihi wasallam dan ia diberi nama. "},"2391":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ الرَّبَابِ عَنْ سَلْمَانَ بْنِ عَامِرٍ الضَّبِّيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ الْغُلَامِ عَقِيقَتُهُ فَأَهْرِيقُوا عَنْهُ دَمًا وَأَمِيطُوا عَنْهُ الْأَذَى","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdurrazzaq], telah menceritakan kepada kami [Hisyam bin Hassan] dari [Hafshah binti Sirin] dari [Ar Robab] dari [Salman bin 'Amir Adh Dhabbi], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada (setiap) anak laki-laki (yang lahir) harus diaqiqahi, maka sembelihlah (aqiqah) untuknya dan hilangkan gangguan darinya.\""},"2392":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا هِشَامٌ عَنْ الْحَسَنِ أَنَّهُ كَانَ يَقُولُإِمَاطَةُ الْأَذَى حَلْقُ الرَّأْسِ","id":"Telah menceritakan kepada kami [Yahya bin Khalaf], telah menceritakan kepada kami [Abdul A'la], telah menceritakan kepada kami [Hisyam], dari [Al Hasan], bahwa ia pernah berkata; menghilangkan gangguan adalah mencukur rambut kepala. "},"2393":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ عَبْدُ اللَّهِ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَقَّ عَنْ الْحَسَنِ وَالْحُسَيْنِ كَبْشًا كَبْشًا","id":"Telah menceritakan kepada kami [Abu Ma'mar Abdullah bin 'Amr], telah menceritakan kepada kami [Abdul Warits], telah menceritakan kepada kami [Ayyub] dari [Ikrimah] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam menyembelih aqiqah untuk Al Hasan dan Al Husain satu domba, satu domba. "},"2394":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا دَاوُدُ بْنُ قَيْسٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا عَبْدُ الْمَلِكِ يَعْنِي ابْنَ عَمْرٍو عَنْ دَاوُدَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ أُرَاهُ عَنْ جَدِّهِ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْعَقِيقَةِ فَقَالَ لَا يُحِبُّ اللَّهُ الْعُقُوقَ كَأَنَّهُ كَرِهَ الِاسْمَ وَقَالَ مَنْ وُلِدَ لَهُ وَلَدٌ فَأَحَبَّ أَنْ يَنْسُكَ عَنْهُ فَلْيَنْسُكْ عَنْ الْغُلَامِ شَاتَانِ مُكَافِئَتَانِ وَعَنْ الْجَارِيَةِ شَاةٌ وَسُئِلَ عَنْ الْفَرَعِ قَالَ وَالْفَرَعُ حَقٌّ وَأَنْ تَتْرُكُوهُ حَتَّى يَكُونَ بَكْرًا شُغْزُبًّا ابْنَ مَخَاضٍ أَوْ ابْنَ لَبُونٍ فَتُعْطِيَهُ أَرْمَلَةً أَوْ تَحْمِلَ عَلَيْهِ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ أَنْ تَذْبَحَهُ فَيَلْزَقَ لَحْمُهُ بِوَبَرِهِ وَتَكْفَأَ إِنَاءَكَ وَتُولِهُ نَاقَتَكَ","id":"Telah menceritakan kepada kami [Al Qa'nabi], telah menceritakan kepada kami [Daud bin Qais], dari ['Amr bin Syu'aib], bahwa Nabi shallallahu 'alaihi wasallam, dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari], telah menceritakan kepada kami [Abdul Malik bin 'Amr], dari [Daud] dari ['Amr bin Syu'aib] dari [ayahnya], aku diberitahu dari [kakeknya], ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya mengenai aqiqah, kemudian beliau berkata: \"Allah tidak menyukai tindakkan durhaka.\" Sepertinya beliau tidak menyukai nama tersebut. Dan beliau berkata: \"Barangsiapa yang anaknya telah dilahirkan dan ia ingin menyembelih untuknya maka hendaknya ia menyembelih untuk anak laki-laki dua ekor kambing yang sama dan untuk anak wanita satu ekor kambing.\" Dan beliau ditanya mengenai fara' (anak unta yang pertama kali lahir). Beliau berkata: \"Dan fara' adalah hak, sedangkan kalian membiarkannya hingga menjadi dewasa kuat berumur satu tahun masuk dua tahun atau berumur dua tahun masuk tiga tahun kemudian engkau berikan kepada seorang janda atau engkau bebani di jalan Allah adalah lebih baik daripada engkau menyembelihnya sehingga dagingnya menempel dengan bulunya, dan engkau penuhi bejanamu dan engkau kagetkan untamu dengan kematian anaknya.\""},"2395":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ حَدَّثَنِي أَبِي حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ قَالَ سَمِعْتُ أَبِي بُرَيْدَةَ يَقُولُكُنَّا فِي الْجَاهِلِيَّةِ إِذَا وُلِدَ لِأَحَدِنَا غُلَامٌ ذَبَحَ شَاةً وَلَطَخَ رَأْسَهُ بِدَمِهَا فَلَمَّا جَاءَ اللَّهُ بِالْإِسْلَامِ كُنَّا نَذْبَحُ شَاةً وَنَحْلِقُ رَأْسَهُ وَنُلَطِّخُهُ بِزَعْفَرَانٍ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Tsabit], telah menceritakan kepada kami [Ali bin Al Husain], telah menceritakan kepadaku [ayahku] telah menceritakan kepada kami [Abdullah bin Buraidah], ia berkata; saya mendengar [ayahku yaitu Buraidah] berkata; dahulu kami pada masa jahiliyah apabila salah seorang diantara kami terlahirkan anak laki-lakinya maka ia menyembelih seekor kambing dan melumuri kepalanya dengan darahnya. Kemudian tatkala Allah datang membawa Islam maka kami menyembelih seekor kambing dan mencukur rambutnya serta melumurinya dengan za'faran. "},"2396":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اتَّخَذَ كَلْبًا إِلَّا كَلْبَ مَاشِيَةٍ أَوْ صَيْدٍ أَوْ زَرْعٍ انْتَقَصَ مِنْ أَجْرِهِ كُلَّ يَوْمٍ قِيرَاطٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar], dari [Az Zuhri], dari [Abu Salamah], dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Barangsiapa yang memelihara anjing kecuali anjing penjaga binatang ternak atau anjing pemburu, atau penjaga tanaman maka pahalanya berkurang satu Qirath setiap hari.\""},"2397":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا أَنَّ الْكِلَابَ أُمَّةٌ مِنْ الْأُمَمِ لَأَمَرْتُ بِقَتْلِهَا فَاقْتُلُوا مِنْهَا الْأَسْوَدَ الْبَهِيمَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yazid], telah menceritakan kepada kami [Yunus], dari [Al Hasan], dari [Abdullah bin Mughaffal], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya anjing itu tidak termasuk salah satu umat diantara berbagai umat, niscaya aku diperintahkan untuk membunuhnya. Bunuhlah anjing yang hitam pekat.\""},"2398":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَأَمَرَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَتْلِ الْكِلَابِ حَتَّى إِنْ كَانَتْ الْمَرْأَةُ تَقْدَمُ مِنْ الْبَادِيَةِ يَعْنِي بِالْكَلْبِ فَنَقْتُلُهُ ثُمَّ نَهَانَا عَنْ قَتْلِهَا وَقَالَ عَلَيْكُمْ بِالْأَسْوَدِ","id":"Telah menceritakan kepada kami [Yahya bin Khalaf], telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij], ia berkata; telah mengabarkan kepadaku [Abu Az Zubair] dari [Jabir], ia berkata; Nabi shallallahu 'alaihi wasallam memerintahkan untuk membunuh seluruh anjing hingga seorang wanita datang dari pelosok dengan membawa anjing, lalu kami membunuhnya. Kemudian beliau melarang kami dari membunuh anjing dan berkata: \"Bunuhlah yang hitam!\""},"2399":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ إِنِّي أُرْسِلُ الْكِلَابَ الْمُعَلَّمَةَ فَتُمْسِكُ عَلَيَّ أَفَآكُلُ قَالَ إِذَا أَرْسَلْتَ الْكِلَابَ الْمُعَلَّمَةَ وَذَكَرْتَ اسْمَ اللَّهِ فَكُلْ مِمَّا أَمْسَكْنَ عَلَيْكَ قُلْتُ وَإِنْ قَتَلْنَ قَالَ وَإِنْ قَتَلْنَ مَا لَمْ يَشْرَكْهَا كَلْبٌ لَيْسَ مِنْهَا قُلْتُ أَرْمِي بِالْمِعْرَاضِ فَأُصِيبُ أَفَآكُلُ قَالَ إِذَا رَمَيْتَ بِالْمِعْرَاضِ وَذَكَرْتَ اسْمَ اللَّهِ فَأَصَابَ فَخَرَقَ فَكُلْ وَإِنْ أَصَابَ بِعَرْضِهِ فَلَا تَأْكُلْ","id":"Telah menceritakan kepada kami [Muhammad bin Isa], telah menceritakan kepada kami [Jarir], dari [Manshur?] dari [Ibrahim], dari [Hammam], dari [Adi bin Hatim], ia berkata; aku bertanya kepada Nabi shallallahu 'alaihi wasallam, aku katakan; sesungguhnya aku telah melepaskan anjing-anjingku yang terlatih kemudian anjing tersebut menangkap buruan untukku, apa aku boleh memakannya? Beliau berkata: \"Apabila engkau melepas anjingmu yang terlatih dan engkau sebut nama Allah, maka makanlah apa yang mereka tangkap untukmu!\" aku katakan; walaupun anjing-anjing tersebut telah membunuh buruan tersebut? Beliau berkata: \"Walaupun mereka telah membunuh, selama tidak ada anjing lain yang menyertainya.\" Aku katakan; aku memanah menggunakan panah tumpul, kemudian aku mengenai buruan, apakah aku boleh memakannya? Beliau berkata: \"Apabila engkau memanah menggunakan panah tumpul dan engkau sebut nama Allah kemudian mengenai dan menusuk (hewan sasaran), maka makanlah dan apabila mengenai dengan sisi lebarnya (bukan ujungnya), maka jangan engkau makan!\""},"2400":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ بَيَانٍ عَنْ عَامِرٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ إِنَّا نَصِيدُ بِهَذِهِ الْكِلَابِ فَقَالَ لِي إِذَا أَرْسَلْتَ كِلَابَكَ الْمُعَلَّمَةَ وَذَكَرْتَ اسْمَ اللَّهِ عَلَيْهَا فَكُلْ مِمَّا أَمْسَكْنَ عَلَيْكَ وَإِنْ قَتَلَ إِلَّا أَنْ يَأْكُلَ الْكَلْبُ فَإِنْ أَكَلَ الْكَلْبُ فَلَا تَأْكُلْ فَإِنِّي أَخَافُ أَنْ يَكُونَ إِنَّمَا أَمْسَكَهُ عَلَى نَفْسِهِ","id":"Telah menceritakan kepada kami [Hannad bin As Sari], telah menceritakan kepada kami [Ibnu Fudhail] dari [Bayan] dari ['Amir] dari [Adi bin Hatim], ia berkata; aku bertanya kepada Nabi shallallahu 'alaihi wasallam, aku katakan; sesungguhnya kami berburu dengan anjing- anjing ini. Kemudian beliau berkata kepadaku: \"Apabila engkau melepas anjingmu yang terlatih dan engkau sebut nama Allah, maka makanlah apa yang mereka tangkap untukmu! Walaupun anjing-anjing tersebut telah membunuh buruan, kecuali apabila ada anjing (lain) yang makan. Apabila ada anjing (lain) yang makan maka jangan engkau makan, karena sesungguhnya aku khawatir anjing tersebut menangkap untuk dirinya sendiri.\""},"2401":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَمَيْتَ بِسَهْمِكَ وَذَكَرْتَ اسْمَ اللَّهِ فَوَجَدْتَهُ مِنْ الْغَدِ وَلَمْ تَجِدْهُ فِي مَاءٍ وَلَا فِيهِ أَثَرٌ غَيْرُ سَهْمِكَ فَكُلْ وَإِذَا اخْتَلَطَ بِكِلَابِكَ كَلْبٌ مِنْ غَيْرِهَا فَلَا تَأْكُلْ لَا تَدْرِي لَعَلَّهُ قَتَلَهُ الَّذِي لَيْسَ مِنْهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], dari ['Ashim Al Ahwal] dari [Asy Sya'bi], dari [Adi bin Hatim] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila engkau memanah dengan anak panahmu dan engkau sebutkan nama Allah, kemudian engkau mendapatinya keesokan hari dan engkau tidak mendapatinya di air serta tidak ada padanya bekas selain anak panahmu maka makanlah. Dan apabila bercampur anjingmu bercampur dengan anjing yang lain, maka jangan engkau maka. Engkau tidak tahu, bisa jadi buruan tersebut dibunuh anjing yang lain.\""},"2402":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ أَخْبَرَنِي عَاصِمٌ الْأَحْوَلُ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَقَعَتْ رَمِيَّتُكَ فِي مَاءٍ فَغَرِقَ فَمَاتَ فَلَا تَأْكُلْ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris], telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Yahya bin Zakariya bin Abu Zaidah], telah mengabarkan kepadaku ['Ashim Al Ahwal], dari [Asy Sya'bi] dari [Adi bin Hatim], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila buruan yang engkau panah terjatuh dalam air kemudian tenggelam dan mati, janganlah engkau makan!\""},"2403":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا مُجَالِدٌ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا عَلَّمْتَ مِنْ كَلْبٍ أَوْ بَازٍ ثُمَّ أَرْسَلْتَهُ وَذَكَرْتَ اسْمَ اللَّهِ فَكُلْ مِمَّا أَمْسَكَ عَلَيْكَ قُلْتُ وَإِنْ قَتَلَ قَالَ إِذَا قَتَلَهُ وَلَمْ يَأْكُلْ مِنْهُ شَيْئًا فَإِنَّمَا أَمْسَكَهُ عَلَيْكَقَالَ أَبُو دَاوُد الْبَازُ إِذَا أَكَلَ فَلَا بَأْسَ بِهِ وَالْكَلْبُ إِذَا أَكَلَ كُرِهَ وَإِنْ شَرِبَ الدَّمَ فَلَا بَأْسَ بِهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], Telah menceritakan kepada kami [Abdullah bin Numair], telah menceritakan kepada kami [Mujalid], dari [Asy Sya'bi], dari [Adi bin Hatim], bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Anjing atau rajawali yang engkau latih kemudian engkau lepaskan dan engkau sebutkan nama Allah, maka makanlah apa yang ia tangkap untukmu!\" Aku katakan; apabila ia membunuh buruan? Beliau berkata: \"Apabila ia membunuhnya dan tidak makan sedikitpun darinya, maka sesungguhnya ia menangkap untukmu.\" Abu Daud berkata; rajawali apabila maka maka tidak mengapa, dan anjing apabila makan maka tidak disukai, dan apabila minum darah maka tidak mengapa. "},"2404":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا دَاوُدُ بْنُ عَمْرٍو عَنْ بُسْرِ بْنِ عُبَيْدِ اللَّهِ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَيْدِ الْكَلْبِ إِذَا أَرْسَلْتَ كَلْبَكَ وَذَكَرْتَ اسْمَ اللَّهِ فَكُلْ وَإِنْ أَكَلَ مِنْهُ وَكُلْ مَا رَدَّتْ عَلَيْكَ يَدَاكَ","id":"Telah menceritakan kepada kami [Muhammad bin Isa], telah menceritakan kepada kami [Husyaim], telah menceritakan kepada kami [Daud bin 'Amr], dari [Busr bin 'Ubaidullah], dari [Abu Idris Al Khaulani] dari [Abu Tsa'labah Al Khusyani], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda mengenai buruan anjing: \"Apabila engkau melepas anjingmu dan engkau sebutkan nama Allah maka makanlah, dan walaupun ia makan sebagian darinya, dan makanlah apa yang dibawa kembali kedua tanganmu kepadamu!\""},"2405":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ مُعَاذِ بْنِ خُلَيْفٍ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا دَاوُدُ عَنْ عَامِرٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ أَحَدُنَا يَرْمِي الصَّيْدَ فَيَقْتَفِي أَثَرَهُ الْيَوْمَيْنِ وَالثَّلَاثَةَ ثُمَّ يَجِدُهُ مَيِّتًا وَفِيهِ سَهْمُهُ أَيَأْكُلُ قَالَ نَعَمْ إِنْ شَاءَ أَوْ قَالَ يَأْكُلُ إِنْ شَاءَ","id":"Telah menceritakan kepada kami [Al Husain bin Mu'adz bin Khulaif], telah menceritakan kepada kami [Abdul A'laa], telah menceritakan kepada kami [Daud] dari ['Amir], dari [Adi bin Hatim], bahwa ia berkata; wahai Rasulullah, salah seorang diantara kami memanah hewan buruan, kemudian ia mengikuti jejaknya selama dua dan tiga hari, kemudian ia mendapatinya telah mati dan padanya terdapat anak panahnya, apakah ia boleh memakannya? Beliau berkata: \"Ya, apabila ia menghendaki.\" Atau beliau berkata: \"Ia boleh memakannya apabila ia menghendaki.\""},"2406":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ قَالَ قَالَ عَدِيُّ بْنُ حَاتِمٍسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمِعْرَاضِ فَقَالَ إِذَا أَصَابَ بِحَدِّهِ فَكُلْ وَإِذَا أَصَابَ بِعَرْضِهِ فَلَا تَأْكُلْ فَإِنَّهُ وَقِيذٌ قُلْتُ أُرْسِلُ كَلْبِي قَالَ إِذَا سَمَّيْتَ فَكُلْ وَإِلَّا فَلَا تَأْكُلْ وَإِنْ أَكَلَ مِنْهُ فَلَا تَأْكُلْ فَإِنَّمَا أَمْسَكَ لِنَفْسِهِ فَقَالَ أُرْسِلُ كَلْبِي فَأَجِدُ عَلَيْهِ كَلْبًا آخَرَ فَقَالَ لَا تَأْكُلْ لِأَنَّكَ إِنَّمَا سَمَّيْتَ عَلَى كَلْبِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Abu As Safar], dari [Asy Sya'bi], ia berkata; [Adi bin Hatim] berkata; aku bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai anak panah yang tumpul. Kemudian beliau berkata: \"Apabila mengenai dengan bagian tajamnya maka makanlah dan apabila mengenai dengan pagian lebarnya maka jangan engkau makan, karena itu adalah hewan yang mati karena terkena benda tumpul.\" Aku katakan; aku melepaskan anjingku. Beliau berkata: \"Apabila engkau menyebut nama Allah maka makanlah, jika tidak maka jangan engkau makan. Dan jika ia makan sebagian darinya maka jangan engkau makan, karena sesungguhnya ia menangkap untuk dirinya sendiri.\" Kemudian Adi berkata; aku melepaskan anjingku dan aku mendapati anjing lain padanya. Maka beliau berkata: \"Jangan engkau makan, karena engkau hanya menyebutkan nama Allah hanya pada anjngmu.\""},"2407":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ ابْنِ الْمُبَارَكِ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ قَالَ سَمِعْتُ رَبِيعَةَ بْنَ يَزِيدَ الدِّمَشْقِيَّ يَقُولُ أَخْبَرَنِي أَبُو إِدْرِيسَ الْخَوْلَانِيُّ عَائِذُ اللَّهِ قَالَ سَمِعْتُ أَبَا ثَعْلَبَةَ الْخُشَنِيَّ يَقُولُ قُلْتُيَا رَسُولَ اللَّهِ إِنِّي أَصِيدُ بِكَلْبِي الْمُعَلَّمِ وَبِكَلْبِي الَّذِي لَيْسَ بِمُعَلَّمٍ قَالَ مَا صِدْتَ بِكَلْبِكَ الْمُعَلَّمِ فَاذْكُرْ اسْمَ اللَّهِ وَكُلْ وَمَا أَصَّدْتَ بِكَلْبِكَ الَّذِي لَيْسَ بِمُعَلَّمٍ فَأَدْرَكْتَ ذَكَاتَهُ فَكُلْ","id":"Telah menceritakan kepada kami [Hannad bin As Sari], dari [Ibnu Al Mubarak] dari [Haiwah bin Syuraih], ia berkata; saya mendengar [Rabi'ah bin Yazid Ad Dimasyqi] berkata; telah mengabarkan kepadaku [Abu Idris Al Khaulani 'Aidzullah], ia berkata; saya mendengar [Abu Tsa'labah Al Khusyani] berkata; aku katakan; wahai Rasulullah, sesungguhnya aku berburu dengan anjingku yang terlatih serta anjingku yang tidak terlatih. Beliau berkata: \"Apa yang engkau buru dengan anjingmu yang terlatih maka sebutlah nama Allah dan makanlah! Dan apa yang engkau buru dengan anjingmu yang tidak terlatih dan engkau sempat menyembelihnya maka makanlah!\""},"2408":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمِنْهَالِ الضَّرِيرُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا حَبِيبٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ أَعْرَابِيًّا يُقَالُ لَهُ أَبُو ثَعْلَبَةَ قَالَ يَا رَسُولَ اللَّهِ إِنَّ لِي كِلَابًا مُكَلَّبَةً فَأَفْتِنِي فِي صَيْدِهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ لَكَ كِلَابٌ مُكَلَّبَةٌ فَكُلْ مِمَّا أَمْسَكْنَ عَلَيْكَ قَالَ ذَكِيًّا أَوْ غَيْرَ ذَكِيٍّ قَالَ نَعَمْ قَالَ فَإِنْ أَكَلَ مِنْهُ قَالَ وَإِنْ أَكَلَ مِنْهُ فَقَالَ يَا رَسُولَ اللَّهِ أَفْتِنِي فِي قَوْسِي قَالَ كُلْ مَا رَدَّتْ عَلَيْكَ قَوْسُكَ قَالَ ذَكِيًّا أَوْ غَيْرَ ذَكِيٍّ قَالَ وَإِنْ تَغَيَّبَ عَنِّي قَالَ وَإِنْ تَغَيَّبَ عَنْكَ مَا لَمْ يَضِلَّ أَوْ تَجِدْ فِيهِ أَثَرًا غَيْرَ سَهْمِكَ قَالَ أَفْتِنِي فِي آنِيَةِ الْمَجُوسِ إِنْ اضْطُرِرْنَا إِلَيْهَا قَالَ اغْسِلْهَا وَكُلْ فِيهَا","id":"Telah menceritakan kepada kami [Muhammad bin Al Minhal Adh Dharir], telah menceritakan kepada kami [Yazid? bin Zurai'], telah menceritakan kepada kami [Habib Al Mu'allim] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya], bahwa seorang badui yang dipanggil Abu Tsa'labah berkata; wahai Rasulullah, sesungguhnya aku memiliki anjing yang terlatih, maka berilah aku fatwa mengenai buruannya. Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Apabila engkau memiliki anjing yang terlatih maka makanlah apa yang mereka tangkap untukmu!\" Ia berkata; disembelih ataupun tidak disembelih? Beliau berkata: \"Ya.\" Ia berkata; \"Walaupun anjing tersebut telah makan sebagian darinya?\" beliau berkata: \"Walaupun anjing tersebut telah makan sebagian darinya.\" Kemuidan ia berkata; wahai Rasulullah, berilah aku fatwa mengenai busurku! Beliau berkata: \"Makanlah apa yang dibawa kembali oleh busurmu kepadamu!\" Beliau berkata; \"Disembelih maupun tidak disembelih.\" Ia berkata; walaupun tak terlihat dariku? Beliau berkata: \"Walaupun tak terlihat darimu, selama tidak hilang atau engkau dapati padanya bekas selain anak panahmu.\" Ia berkata; berilah aku fatwa mengenai bejana orang-orang majusi apabila kami terpaksa menggunakannya? Beliau berkata: \"Cucilah dan makanlah padanya!\""},"2409":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي وَاقِدٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قُطِعَ مِنْ الْبَهِيمَةِ وَهِيَ حَيَّةٌ فَهِيَ مَيْتَةٌ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Hasyim bin Al Qasim], telah menceritakan kepada kami [Abdurrahman bin Abdullah bin Dinar], dari [Zaid bin Aslam], dari ['Atha` bin Yasar] dari [Abu Waqid], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Apa yang dipotong dari binatang dalam keadaan hidup, maka sesuatu tersebut adalah bangkai.\""},"2410":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي أَبُو مُوسَى عَنْ وَهْبِ بْنِ مُنَبِّهٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ مَرَّةً سُفْيَانُوَلَا أَعْلَمُهُ إِلَّا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَكَنَ الْبَادِيَةَ جَفَا وَمَنْ اتَّبَعَ الصَّيْدَ غَفَلَ وَمَنْ أَتَى السُّلْطَانَ افْتُتِنَحَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا الْحَسَنُ بْنُ الْحَكَمِ النَّخَعِيُّ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ شَيْخٍ مِنْ الْأَنْصَارِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى مُسَدَّدٍ قَالَ وَمَنْ لَزِمَ السُّلْطَانَ افْتُتِنَ زَادَ وَمَا ازْدَادَ عَبْدٌ مِنْ السُّلْطَانِ دُنُوًّا إِلَّا ازْدَادَ مِنْ اللَّهِ بُعْدًا","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya] dari [Sufyan], telah menceritakan kepadaku [Abu Musa] dari [Wahb bin Munabbih] dari [Ibnu Abbas], dari Nabi shallallahu 'alaihi wasallam, suatu kali Sufyan mengatakan; dan aku tidak mengetahuinya kecuali dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Barangsiapa yang tinggal di pelosok (pedalaman), maka ia akan menjadi keras, dan barangsiapa yang mengikuti hewan buruan maka ia akan lalai, dan barangsiapa yang datang kepada penguasa maka ia akan terkena fitnah.\" Telah menceritakan kepada kami [Muhammad bin Isa], telah menceritakan kepada kami [Muhammad bin 'Ubaid], telah menceritakan kepada kami [Al Hasan bin Al Hakam An Nakha'i], dari [Adi bin Tsabit] dari [seorang syekh dari kalangan anshor], dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dengan makna hadits Musaddad, beliau bersabda: \"Barangsiapa yang terus menyertai penguasa, maka ia terfitnah.\" Ia menambahkan: \"Dan tidaklah seorang hamba bertambah dekat kepada penguasa melainkan ia akan bertambah jauh dari Allah.\""},"2411":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ الْخَيَّاطُ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَمَيْتَ الصَّيْدَ فَأَدْرَكْتَهُ بَعْدَ ثَلَاثِ لَيَالٍ وَسَهْمُكَ فِيهِ فَكُلْهُ مَا لَمْ يُنْتِنْ","id":"Telah menceritakan kepada kami [Yahya bin Ma'in], Telah menceritakan kepada kami [Hammad bin Khalid Al Khayyath], dari [Mu'awiyah bin Shalih] dari [Abdurrahman bin Jubair bin Nufair], dari [ayahnya], dari [Tsa'labah Al Khusyani], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila engkau memanah hewan buruan kemudian engkau mendapatinya setelah tiga malam dan anak panahmu ada padanya, maka makanlah selama belum membusuk!\""},"2412":{"ar":"حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ يَعْنِي ابْنَ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا حَقُّ امْرِئٍ مُسْلِمٍ لَهُ شَيْءٌ يُوصِي فِيهِ يَبِيتُ لَيْلَتَيْنِ إِلَّا وَوَصِيَّتُهُ مَكْتُوبَةٌ عِنْدَهُ","id":"Telah menceritakan kepada kami [Musaddad bin Masarhad], telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah], telah menceritakan kepadaku [Nafi'] dari [Abdullah bin Umar] dari Rasulullah shallallahu 'alaihi wasallam, beliau berkata: \"Tidaklah hak seorang muslim yang memiliki sesuatu yang diwasiatkan untuk bermalam selama dua malam melainkan wasiatnya telah tertulis di sisinya.\""},"2413":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَمُحَمَّدُ بْنُ الْعَلَاءِ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْمَا تَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِينَارًا وَلَا دِرْهَمًا وَلَا بَعِيرًا وَلَا شَاةً وَلَا أَوْصَى بِشَيْءٍ","id":"Telah menceritakan kepada kami [Musaddad] dan [Muhammad bin Al 'Ala`], mereka berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Wail], dari [Masruq] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam tidak meninggalkan dinar, dirham, unta serta kambing dan beliau tidak berwasiat dengan sesuatupun. "},"2414":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَابْنُ أَبِي خَلَفٍ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَمَرِضَ مَرَضًا قَالَ ابْنُ أَبِي خَلَفٍ بِمَكَّةَ ثُمَّ اتَّفَقَا أَشْفَى فِيهِ فَعَادَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ لِي مَالًا كَثِيرًا وَلَيْسَ يَرِثُنِي إِلَّا ابْنَتِي أَفَأَتَصَدَّقُ بِالثُّلُثَيْنِ قَالَ لَا قَالَ فَبِالشَّطْرِ قَالَ لَا قَالَ فَبِالثُّلُثِ قَالَ الثُّلُثُ وَالثُّلُثُ كَثِيرٌ إِنَّكَ أَنْ تَتْرُكَ وَرَثَتَكَ أَغْنِيَاءَ خَيْرٌ مِنْ أَنْ تَدَعَهُمْ عَالَةً يَتَكَفَّفُونَ النَّاسَ وَإِنَّكَ لَنْ تُنْفِقَ نَفَقَةً إِلَّا أُجِرْتَ بِهَا حَتَّى اللُّقْمَةُ تَرْفَعُهَا إِلَى فِي امْرَأَتِكِ قُلْتُ يَا رَسُولَ اللَّهِ أَتَخَلَّفُ عَنْ هِجْرَتِي قَالَ إِنَّكَ إِنْ تُخَلَّفْ بَعْدِي فَتَعْمَلَ عَمَلًا صَالِحًا تُرِيدُ بِهِ وَجْهَ اللَّهِ لَا تَزْدَادُ بِهِ إِلَّا رِفْعَةً وَدَرَجَةً لَعَلَّكَ أَنْ تُخَلَّفَ حَتَّى يَنْتَفِعَ بِكَ أَقْوَامٌ وَيُضَرَّ بِكَ آخَرُونَ ثُمَّ قَالَ اللَّهُمَّ أَمْضِ لِأَصْحَابِي هِجْرَتَهُمْ وَلَا تَرُدَّهُمْ عَلَى أَعْقَابِهِمْ لَكِنْ الْبَائِسُ سَعْدُ بْنُ خَوْلَةَ يَرْثِي لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ مَاتَ بِمَكَّةَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], serta [Ibnu Abu Khalaf], mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri], dari [Amir bin Sa'd], dari [ayahnya], ia berkata; Sa'd terkena suatu penyakit, Ibnu Abu Khalaf berkata; di Mekkah. Kemudian lafazh mereka sama; hampir meninggal karena penyakit tersebut, kemudian Rasulullah shallallahu 'alaihi wasallam menjenguknya, lalu ia berkata; wahai Rasulullah, sesungguhnya saya memiliki harta yang banyak, dan tidak ada yang mewarisiku selain anak perempuanku, apakah aku boleh bersedekah dengan dua pertiga? Beliau bersabda: \"Tidak.\" Ia berkata; setengah? Beliau bersabda: \"Tidak.\" Ia berkata; sepertiga? Beliau bersabda: \"Ya, sepertiga. Dan sepertiga adalah banyak. Sesungguhnya engkau meninggalkan para pewarismu dalam keadaan kaya adalah lebih baik daripada engkau meninggalkan mereka dalam keadaan kekurangan, mereka meminta-minta kepada manusia. Dan sesungguhnya tidaklah engkau berinfak dengan suatu nafkah melainkan engkau diberi pahala karenanya, hingga suapan yang engkau berikan kepada isterimu.\" Aku katakan; wahai Rasulullah, apakah aku akan tinggal di Mekkah? Beliau berkata: \"Sesungguhnya seandainya engkau tertinggal setelahku kemudian engkau beramal shalih dengan mengharapkan wajah Allah niscaya engkau pasti akan bertambah tinggi derajatmu, kemungkinan engkau akan berumur panjang hingga orang-orang mengambil manfaat dengan keberadaanmu, dan orang yang lain akan mendapatkan madharat.\" Kemudian beliau berkata kepada para sahabatnya: \"Ya Allah, sempurnakanlah hijrah para sahabatku, dan jangan Engkau kembalikan mereka kepada kekafiran, akan tetapi Sa'd bin Khaulah akan meninggal di Mekkah.\" Beliau merasa kasihan terhadapnya. "},"2415":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا عُمَارَةُ بْنُ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَجُلٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رَسُولَ اللَّهِ أَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ أَنْ تَصَدَّقَ وَأَنْتَ صَحِيحٌ حَرِيصٌ تَأْمُلُ الْبَقَاءَ وَتَخْشَى الْفَقْرَ وَلَا تُمْهِلَ حَتَّى إِذَا بَلَغَتْ الْحُلْقُومَ قُلْتَ لِفُلَانٍ كَذَا وَلِفُلَانٍ كَذَا وَقَدْ كَانَ لِفُلَانٍ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abdul Wahid bin Ziyad], telah menceritakan kepada kami ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah bin 'Amr bin Jarir], dari [Abu Hurairah], ia berkata; seseorang berkata kepada Nabi shallallahu 'alaihi wasallam; wahai Rasulullah, sedekah apakah yang paling utama? Beliau berkata: \"Engkau bersedekah dalam keadaan sehat, bersemangat dan mengharapkan tetap hidup, serta khawatir mengalami kekurangan, dan engkau tidak menunda hingga setelah nyawa telah sampai di tenggorokan engkau mengatakan; untuk Fulan sekian dan untuk Fulan sekian. Dan sungguh harta tersebut telah menjadi milik Fulan.\""},"2416":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ أَخْبَرَنِي ابْنُ أَبِي ذِئْبٍ عَنْ شُرَحْبِيلَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَأَنْ يَتَصَدَّقَ الْمَرْءُ فِي حَيَاتِهِ بِدِرْهَمٍ خَيْرٌ لَهُ مِنْ أَنْ يَتَصَدَّقَ بِمِائَةِ دِرْهَمٍ عِنْدَ مَوْتِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Abu Fudaik], telah mengabarkan kepadaku [Ibnu Abi Dzi`b] dari [Syurahbil], dari [Abu Sa'id Al Khudri], bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Sungguh seseorang bersedekah pada waktu hidupnya dengan satu dirham adalah lebih baik baginya daripada ia bersedekah dengan seratus dirham ketika akan meninggal.\""},"2417":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ أَخْبَرَنَا عَبْدُ الْصَّمَدِ حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْحُدَّانِيُّ حَدَّثَنَا الْأَشْعَثُ بْنُ جَابِرٍ حَدَّثَنِي شَهْرُ بْنُ حَوْشَبٍ أَنَّ أَبَا هُرَيْرَةَ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الرَّجُلَ لَيَعْمَلُ وَالْمَرْأَةُ بِطَاعَةِ اللَّهِ سِتِّينَ سَنَةً ثُمَّ يَحْضُرُهُمَا الْمَوْتُ فَيُضَارَّانِ فِي الْوَصِيَّةِ فَتَجِبُ لَهُمَا النَّارُقَالَ وَقَرَأَ عَلَيَّ أَبُو هُرَيْرَةَ مِنْ هَا هُنَا{ مِنْ بَعْدِ وَصِيَّةٍ يُوصَى بِهَا أَوْ دَيْنٍ غَيْرَ مُضَارٍّ حَتَّى بَلَغَ ذَلِكَ الْفَوْزُ الْعَظِيمُ }قَالَ أَبُو دَاوُد هَذَا يَعْنِي الْأَشْعَثَ بْنَ جَابِرٍ جَدَّ نَصْرِ بْنِ عَلِيٍّ","id":"Telah menceritakan kepada kami ['Abdah bin Abdullah], telah mengabarkan kepada kami [Abdushshamad], telah menceritakan kepada kami [Nashr bin Ali Al Huddani], telah menceritakan kepada kami [Al Asy'ats bin Jabir], telah menceritakan kepadaku [Syahr bin Hausyab], bahwa [Abu Hurairah] telah menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ada seorang laki-laki dan wanita yang beramal dengan ketaatan kepada Allah selama enam puluh tahun kemudian kematian menghampiri mereka berdua, lalu mereka menyulitkan (para pewaris) dalam berwasiat sehingga neraka adalah wajib bagi mereka.\" Kemudian Abu Hurairah membacakan ayat kepadaku dari sini: \"Sesudah dipenuhi wasiat yang dibuat olehnya atau sesudah dibayar hutangnya dengan tidak memberi mudharat (kepada ahli waris) …..\" hingga sampai firmanNya: \"dan itulah kemenangan yang besar.\" Abu Daud berkata; orang ini yaitu Al Asy'ats bin Jabir adalah kakek Nashr bin Ali. "},"2418":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ الْمُقْرِئُ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ سَالِمِ بْنِ أَبِي سَالِمٍ الْجَيْشَانِيِّ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا ذَرٍّ إِنِّي أَرَاكَ ضَعِيفًا وَإِنِّي أُحِبُّ لَكَ مَا أُحِبُّ لِنَفْسِي فَلَا تَأَمَّرَنَّ عَلَى اثْنَيْنِ وَلَا تَوَلَّيَنَّ مَالَ يَتِيمٍقَالَ أَبُو دَاوُد تَفَرَّدَ بِهِ أَهْلُ مِصْرَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abu Abdurrahman Al Muqri`], telah menceritakan kepada kami [Sa'id bin Abu Ayyub], dari ['Ubaidullah bin Abu Ja'far], dari [Salim bin Abu Salim Al Jaisyani], dari [ayahnya], dari [Abu Dzar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Wahai Abu Dzar, aku melihat engkau adalah orang yang lemah dan aku mencintai sesuatu untukmu sebagaimana yang aku cintai untuk diriku. Maka janganlah engkau memimpin dua orang dan jangan engkau mengurusi harta anak yatim.\" Abu Daud berkata; hadits tersebut hanya diriwayatkan penduduk Mesir. "},"2419":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنِ بْنِ وَاقِدٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ{ إِنْ تَرَكَ خَيْرًا الْوَصِيَّةُ لِلْوَالِدَيْنِ وَالْأَقْرَبِينَ }فَكَانَتْ الْوَصِيَّةُ كَذَلِكَ حَتَّى نَسَخَتْهَا آيَةُ الْمِيرَاثِ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi], telah menceritakan kepadaku [Ali bin Husain bin Waqid], dari [ayahnya], dari [Yazid An Nahwi], dari [Ikrimah] dari [Ibnu Abbas], \"Jika ia meninggalkan harta yang banyak, berwasiat untuk ibu-bapak dan karib kerabatnya.\" Maka wasiat adalah demikian hingga dihapus oleh ayat warisan. "},"2420":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا ابْنُ عَيَّاشٍ عَنْ شُرَحْبِيلَ بْنِ مُسْلِمٍ سَمِعْتُ أَبَا أُمَامَةَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ قَدْ أَعْطَى كُلَّ ذِي حَقٍّ حَقَّهُ فَلَا وَصِيَّةَ لِوَارِثٍ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Najdah], telah menceritakan kepada kami [Ibnu 'Ayyasy], dari [Syurahbil bin Muslim], saya mendengar [Abu Umamah], saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah telah memberikan hak kepada setiap yang memiliki hak, maka tidak ada wasiat bagi pewaris.\""},"2421":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ عَطَاءٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَلَا تَقْرَبُوا مَالَ الْيَتِيمِ إِلَّا بِالَّتِي هِيَ أَحْسَنُ }وَ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }الْآيَةَ انْطَلَقَ مَنْ كَانَ عِنْدَهُ يَتِيمٌ فَعَزَلَ طَعَامَهُ مِنْ طَعَامِهِ وَشَرَابَهُ مِنْ شَرَابِهِ فَجَعَلَ يَفْضُلُ مِنْ طَعَامِهِ فَيُحْبَسُ لَهُ حَتَّى يَأْكُلَهُ أَوْ يَفْسُدَ فَاشْتَدَّ ذَلِكَ عَلَيْهِمْ فَذَكَرُوا ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَيَسْأَلُونَكَ عَنْ الْيَتَامَى قُلْ إِصْلَاحٌ لَهُمْ خَيْرٌ وَإِنْ تُخَالِطُوهُمْ فَإِخْوَانُكُمْ }فَخَلَطُوا طَعَامَهُمْ بِطَعَامِهِ وَشَرَابَهُمْ بِشَرَابِهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Jarir] dari ['Atho`], dari [Sa'id bin Jubair], dari [Ibnu Abbas], ia berkata; tatkala Allah 'azza wajalla menurunkan ayat: \"Dan janganlah kamu dekati harta anak yatim, kecuali dengan cara yang lebih bermanfaat.\" Dan \"Sesungguhnya orang-orang yang memakan harta anak yatim secara zalim…..\" Maka orang yang memiliki anak yatim pergi dan menjauhkan makanannya makanannya dan minumannya dari minumannya. Maka makanan anak yatim tersebut tersisa kemudian disimpan hingga ia memakannya atau menjadi rusak. Maka hal tersebut terasa berat atas mereka, kemudian mereka meceritakan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Lalu Allah 'azza wajalla menurunkan ayat: \"Dan mereka bertanya kepadamu tentang anak yatim, katakalah: \"Mengurus urusan mereka secara patut adalah baik, dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu.\" Kemudian mereka mencampur makanan mereka dengan makanannya dan minuman mereka dengan minumannya. "},"2422":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ أَنَّ خَالِدَ بْنَ الْحَارِثِ حَدَّثَهُمْ حَدَّثَنَا حُسَيْنٌ يَعْنِي الْمُعَلِّمَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي فَقِيرٌ لَيْسَ لِي شَيْءٌ وَلِي يَتِيمٌ قَالَ فَقَالَ كُلْ مِنْ مَالِ يَتِيمِكَ غَيْرَ مُسْرِفٍ وَلَا مُبَادِرٍ وَلَا مُتَأَثِّلٍ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah], bahwa [Khalid bin Al Harits] telah menceritakan kepada mereka; telah menceritakan kepada kami [Husain Al Mu'allim] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya], bahwa seseorang datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; aku adalah orang fakir yang tidak memiliki sesuatupun, sementara aku memiliki anak yatim. Kemudian beliau bersabda: \"Makanlah sebagian dari harta anak yatimmu, tetapi janganlah berlebihan, tidak menggunakannya secara mubadzir, dan tidak mengambi harta pokoknya..\""},"2423":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا يَحْيَى بْنُ مُحَمَّدٍ الْمَدِينِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ خَالِدِ بْنِ سَعِيدِ بْنِ أَبِي مَرْيَمَ عَنْ أَبِيهِ عَنْ سَعِيدِ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ رُقَيْشٍ أَنَّهُ سَمِعَ شُيُوخًا مِنْ بَنِي عَمْرِو بْنِ عَوْفٍ وَمِنْ خَالِهِ عَبْدِ اللَّهِ بْنِ أَبِي أَحْمَدَ قَالَ قَالَ عَلِيُّ بْنُ أَبِي طَالِبٍحَفِظْتُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُتْمَ بَعْدَ احْتِلَامٍ وَلَا صُمَاتَ يَوْمٍ إِلَى اللَّيْلِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Yahya bin Muhammad Al Madini] telah menceritakan kepada kami [Abdullah bin Khalid bin Sa'id bin Abu Maryam] dari [ayahnya], dari [Sa'id bin Abdurrahman bin Yazid bin Ruqaisy] bahwa ia mendengar beberapa syekh dari Bani 'Amr bin 'Auf serta dari pamannya yaitu [Abdullah bin Abu Ahmad], ia berkata; [Ali bin Abu Thalib] berkata; aku telah hafal dari Rasulullah shallallahu 'alaihi wasallam: \"Tidak ada yatim setelah baligh, dan tidak ada sikap diam satu hari hingga malam hari.\""},"2424":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الْهَمْدَانِيُّ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ عَنْ ثَوْرِ بْنِ زَيْدٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اجْتَنِبُوا السَّبْعَ الْمُوبِقَاتِ قِيلَ يَا رَسُولَ اللَّهِ وَمَا هُنَّ قَالَ الشِّرْكُ بِاللَّهِ وَالسِّحْرُ وَقَتْلُ النَّفْسِ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَأَكْلُ الرِّبَا وَأَكْلُ مَالِ الْيَتِيمِ وَالتَّوَلِّي يَوْمَ الزَّحْفِ وَقَذْفُ الْمُحْصَنَاتِ الْغَافِلَاتِ الْمُؤْمِنَاتِقَالَ أَبُو دَاوُد أَبُو الْغَيْثِ سَالِمٌ مَوْلَى ابْنِ مُطِيعٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ الْجُوْزَجَانِيُّ حَدَّثَنَا مُعَاذُ بْنُ هَانِئٍ حَدَّثَنَا حَرْبُ بْنُ شَدَّادٍ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ سِنَانٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ أَبِيهِ أَنَّهُ حَدَّثَهُ وَكَانَتْ لَهُ صُحْبَةٌ أَنَّ رَجُلًا سَأَلَهُ فَقَالَ يَا رَسُولَ اللَّهِ مَا الْكَبَائِرُ فَقَالَ هُنَّ تِسْعٌ فَذَكَرَ مَعْنَاهُ زَادَ وَعُقُوقُ الْوَالِدَيْنِ الْمُسْلِمَيْنِ وَاسْتِحْلَالُ الْبَيْتِ الْحَرَامِ قِبْلَتِكُمْ أَحْيَاءً وَأَمْوَاتًا","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Al Hamdani], telah menceritakan kepada kami [Ibnu Wahb] dari [Sulaiman bin Bilal] dari [Tsaur bin Zaid] dari [Abu Al Ghaits] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jauhilah tujuh perkara yang membinasakan!\" Beliau ditanya; wahai Rasulullah, apakah perkara tersebut? Beliau berkata: \"\"Mensekutukan Allah, sihir, membunuh jiwa yang Allah haramkan kecuali dengan haq, memakan riba, memakan harta anak yatim, lari dari peperangan, menuduh seorang wanita mukmin yang suci dan baik berbuat zina.\" Abu Daud berkata; Abu Al Ghaits Salim adalah mantan budak Ibnu Muthi'. Telah menceritakan kepada kami [Ibrahim bin Ya'qub Al Juzajani], telah menceritakan kepada kami [Mu'adz bin Hani`], telah menceritakan kepada kami [Harb bin Syaddad], telah menceritakan kepada kami [Yahya bin Abu Katsir], dari [Abdul Hamid bin Sinan] dari ['Ubaid bin 'Umair], dari [ayahnya], bahwa ia telah menceritakan kepadanya, dan ia pernah menyertai Rasulullah shallallahu 'alaihi wasallam. Bahwa seorang laki-laki pernah bertanya kepada Nabi shallallahu 'alaihi wasallam, ia berkata; wahai Rasulullah, apakah dosa-dosa besar itu? Kemudian beliau berkata: \"Dosa-dosa besar tersebut ada sembilan.\" Kemudian ia menyebutkan maknanya, dan ia tambahkan; dan durhaka kepada kedua orang tua muslim, dan menghalalkan hal-hal yang haram dilakukan di Baitul Haram kiblat kalian (seperti berburu, memotoh pepohonan), baik yang hidup maupun yang mati. "},"2425":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ خَبَّابٍ قَالَمُصْعَبُ بْنُ عُمَيْرٍ قُتِلَ يَوْمَ أُحُدٍ وَلَمْ تَكُنْ لَهُ إِلَّا نَمِرَةٌ كُنَّا إِذَا غَطَّيْنَا بِهَا رَأْسَهُ خَرَجَتْ رِجْلَاهُ وَإِذَا غَطَّيْنَا رِجْلَيْهِ خَرَجَ رَأْسُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَطُّوا بِهَا رَأْسَهُ وَاجْعَلُوا عَلَى رِجْلَيْهِ مِنْ الْإِذْخِرِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Wail], dari [Khabbab], ia berkata; Mush'ab bin 'Umair telah terbunuh pada saat perang Uhud, dan ia hanya memiliki sehelai kain, apabila kami menutup kepalanya maka kedua kakinya keluar, dan apabila kami tutup kedua kakinya maka keluar kepalanya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tutuplah kepalanya menggunakan kain tersebut dan letakkan idzkhir di atas kedua kakinya!\""},"2426":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَطَاءٍ عَنْ عَبْدِ اللَّهِ بَنِ بُرَيْدَةَ عَنْ أَبِيهِ بُرَيْدَةَأَنَّ امْرَأَةً أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كُنْتُ تَصَدَّقْتُ عَلَى أُمِّي بِوَلِيدَةٍ وَإِنَّهَا مَاتَتْ وَتَرَكَتْ تِلْكَ الْوَلِيدَةَ قَالَ قَدْ وَجَبَ أَجْرُكِ وَرَجَعَتْ إِلَيْكِ فِي الْمِيرَاثِ قَالَتْ وَإِنَّهَا مَاتَتْ وَعَلَيْهَا صَوْمُ شَهْرٍ أَفَيُجْزِئُ أَوْ يَقْضِي عَنْهَا أَنْ أَصُومَ عَنْهَا قَالَ نَعَمْ قَالَتْ وَإِنَّهَا لَمْ تَحُجَّ أَفَيُجْزِئُ أَوْ يَقْضِي عَنْهَا أَنْ أَحُجَّ عَنْهَا قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Abdullah bin 'Atha`], dari [Abdullah bin Buraidah], dari [ayahnya], bahwa seorang wanita datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; dahulu aku bersedekah kepada ibuku dengan memberikan seorang budak wanita, dan beliau meninggal serta meninggalkan budak tersebut. Beliau berkata: \"Telah tetap pahalamu dan budak tersebut kembali kepadamu diantara harta warisan.\" Wanita tersebut berkata; beliau meninggal dalam keadaan memiliki kewajiban berpuasa satu bulan. Apakah sah atau dapat menunaikan untuknya apabila aku berpuasa untuknya? Beliau berkata: \"Ya.\" Wanita tersebtu berkata; sesungguhnya beliau belum berhaji, apakah sah atau dapat menunaikan untuknya apabila aku berhaji untuknya? Beliau berkata: \"Ya.\""},"2427":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ عَوْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَأَصَابَ عُمَرُ أَرْضًا بِخَيْبَرَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَصَبْتُ أَرْضًا لَمْ أُصِبْ مَالًا قَطُّ أَنْفَسَ عِنْدِي مِنْهُ فَكَيْفَ تَأْمُرُنِي بِهِ قَالَ إِنْ شِئْتَ حَبَّسْتَ أَصْلَهَا وَتَصَدَّقْتَ بِهَا فَتَصَدَّقَ بِهَا عُمَرُ أَنَّهُ لَا يُبَاعُ أَصْلُهَا وَلَا يُوهَبُ وَلَا يُوَرَّثُ لِلْفُقَرَاءِ وَالْقُرْبَى وَالرِّقَابِ وَفِي سَبِيلِ اللَّهِ وَابْنِ السَّبِيلِ وَزَادَ عَنْ بِشْرٍ وَالضَّيْفِ ثُمَّ اتَّفَقُوا لَا جُنَاحَ عَلَى مَنْ وَلِيَهَا أَنْ يَأْكُلَ مِنْهَا بِالْمَعْرُوفِ وَيُطْعِمَ صَدِيقًا غَيْرَ مُتَمَوِّلٍ فِيهِ زَادَ عَنْ بِشْرٍ قَالَ وَقَالَ مُحَمَّدٌ غَيْرَ مُتَأَثِّلٍ مَالًاحَدَّثَنَا سُلَيْمَانُ بِنُ دَاوُدَ الْمَهْرِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ صَدَقَةِ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ قَالَ نَسَخَهَا لِي عَبْدُ الْحَمِيدِ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ بْنِ الْخَطَّابِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ هَذَا مَا كَتَبَ عَبْدُ اللَّهِ عُمَرُ فِي ثَمْغٍ فَقَصَّ مِنْ خَبَرِهِ نَحْوَ حَدِيثِ نَافِعٍ قَالَ غَيْرَ مُتَأَثِّلٍ مَالًا فَمَا عَفَا عَنْهُ مِنْ ثَمَرِهِ فَهُوَ لِلسَّائِلِ وَالْمَحْرُومِ قَالَ وَسَاقَ الْقِصَّةَ قَالَ وَإِنْ شَاءَ وَلِيُّ ثَمْغٍ اشْتَرَى مِنْ ثَمَرِهِ رَقِيقًا لِعَمَلِهِ وَكَتَبَ مُعَيْقِيبٌ وَشَهِدَ عَبْدُ اللَّهِ بْنُ الْأَرْقَمِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ هَذَا مَا أَوْصَى بِهِ عَبْدُ اللَّهِ عُمَرُ أَمِيرُ الْمُؤْمِنِينَ إِنْ حَدَثَ بِهِ حَدَثٌ أَنَّ ثَمْغًا وَصِرْمَةَ بْنَ الْأَكْوَعِ وَالْعَبْدَ الَّذِي فِيهِ وَالْمِائَةَ سَهْمٍ الَّتِي بِخَيْبَرَ وَرَقِيقَهُ الَّذِي فِيهِ وَالْمِائَةَ الَّتِي أَطْعَمَهُ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْوَادِي تَلِيهِ حَفْصَةُ مَا عَاشَتْ ثُمَّ يَلِيهِ ذُو الرَّأْيِ مِنْ أَهْلِهَا أَنْ لَا يُبَاعَ وَلَا يُشْتَرَى يُنْفِقُهُ حَيْثُ رَأَى مِنْ السَّائِلِ وَالْمَحْرُومِ وَذَوِي الْقُرْبَى وَلَا حَرَجَ عَلَى مَنْ وَلِيَهُ إِنْ أَكَلَ أَوْ آكَلَ أَوْ اشْتَرَى رَقِيقًا مِنْهُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yazid? bin Zurai'], dan telah diriwayatkan dari jalur yang lain: dan telah mencerityakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya] dari [Ibnu 'Aun], dari [Nafi'] dari [Ibnu Umar], ia berkata; Umar mendapatkan tanah Khaibar, kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; aku telah mendapatkan tanah dan belum pernah mendapatkan harta yang lebih berharga menurutku daripadanya. Apakah yang anda perintahkan kepadaku? Beliau berkata: \"Apabila engkau mau, maka engkau tahan pokoknya dan bersedekah dengannya.\" Kemudian Umar bersedekah dengannya, dengan syarat bahwa pokoknya tidka dijual, dan tidak diberikan, serta tidak diwariskan untuk orang-orang faqir, para kaum kerabat, serta para budak. Dan dengan syarat di jalan Allah, serta ibnu Sabil. Dan ia menambahkan dari Bisyr; serta tamu. Kemudian lafazh mereka sama: \"Tidak mengapa bagi orang yang mengurusnya untuk memakan sebagian darinya dengan cara yang baik. Memberi makan teman, tanpa mengembangkannya.\" Dan Muhammad mengatakan; tidak mengumpulkan dan menjadikannya harta pokok. Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri], telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Al Laits], dari [Yahya bin Sa'id] mengenai sedekah Umar bin Al Khathab radliallahu 'anhu, ia berkata; [Abdul Hamid bin Abdullah bin Umar bin Al Khathab] menyalinnya untukku; bismillahirrahmanirrahim, ini adalah yang ditulis hamba Allah [Umar] apabila terjadi sesuatu padanya, bahwa Tsamgh, dan Shirmah bin Al Akwa' (dua harta milik Umar di Madinah) serta budak yang ada padanya, dan seratus saham yang ada di Khaibar, budak yang ada padanya, serta seratus (wasaq) yang telah Muhammad shallallahu 'alaihi wasallam berikan kepadanya di sebuah bukit akan diurus oleh Hafshah selama ia masih hidup, kemudian orang-orang yang memiliki pemikiran yang baik dari kalangan keluarganya. Tidak boleh dijual, dan tidak boleh dibeli, ia nafkahkan ke tempat yang ia pandang baik, kepada orang yang meminta, dan orang miskin yang tidak mendapat bagian, para kaum kerabat, dan tidak mengapa orang yang mengurusnya untuk makan atau memberi makan, atau membeli budak darinya. "},"2428":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ الْمُؤَذِّنُ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ سُلَيْمَانَ يَعْنِي ابْنَ بِلَالٍ عَنْ الْعَلاَءِ بْنِ عَبْدِ الرَّحْمَنِ أُرَاهُ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا مَاتَ الْإِنْسَانُ انْقَطَعَ عَنْهُ عَمَلُهُ إِلَّا مِنْ ثَلَاثَةِ أَشْيَاءَ مِنْ صَدَقَةٍ جَارِيَةٍ أَوْ عِلْمٍ يُنْتَفَعُ بِهِ أَوْ وَلَدٍ صَالِحٍ يَدْعُو لَهُ","id":"Telah menceritakan kepada kami [Ar Rabi' bin Sulaiman Al Muadzdzin], telah menceritakan kepada kami [Ibnu Wahb] dari [Sulaiman bin Bilal] dari [Al 'Ala` bin Abdurrahman], dari [ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seorang muslim meninggal, maka amalannya terputus kecuali dari tiga perkara; sedekah jariyah, ilmu yang bermanfaat, atau anak shalih yang mendoakannya.\""},"2429":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ امْرَأَةً قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أُمِّي افْتُلِتَتْ نَفْسُهَا وَلَوْلَا ذَلِكَ لَتَصَدَّقَتْ وَأَعْطَتْ أَفَيُجْزِئُ أَنْ أَتَصَدَّقَ عَنْهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ فَتَصَدَّقِي عَنْهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Hisyam], dari [ayahnya], dari [Aisyah], bahwa seorang wanita berkata; wahai Rasulullah, sesungguhnya ibuku meninggal tiba-tiba, jika tidak terjadi hal tersebut niscaya ia telah bersedekah dan memberi. Apakah sah saya bersedekah untuknya? Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Ya, bersedekahlah untuknya.\""},"2430":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا زَكَرِيَّا بْنُ إِسْحَقَ أَخْبَرَنَا عَمْرُو بْنُ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ إِنَّ أُمِّي تُوُفِّيَتْ أَفَيَنْفَعُهَا إِنْ تَصَدَّقْتُ عَنْهَا فَقَالَ نَعَمْ قَالَ فَإِنَّ لِي مَخْرَفًا وَإِنِّي أُشْهِدُكَ أَنِّي قَدْ تَصَدَّقْتُ بِهِ عَنْهَا","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Rauh bin 'Ubadah], telah menceritakan kepada kami [Zakariya bin Ishaq], telah mengabarkan kepada kami ['Amr bin Dinar], dari [Ikrimah] dari [Ibnu Abbas], bahwa seorang laki-laki berkata; wahai Rasulullah, sesungguhnya ibuku meninggal apakah akan memberikan manfaat baginya apabila aku bersedekah untuknya? Kemudian beliau berkata: \"Ya.\" Orang tersebut berkata; sesungguhnya saya memiliki kebun kurma dan saya meminta persaksian anda bahwa saya telah mensedekahkannya untuknya. "},"2431":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ بْنِ مَزْيَدٍ أَخْبَرَنِي أَبِي حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي حَسَّانُ بْنُ عَطِيَّةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ الْعَاصَ بْنَ وَائِلٍ أَوْصَى أَنْ يُعْتِقَ عَنْهُ مِائَةُ رَقَبَةٍ فَأَعْتَقَ ابْنُهُ هِشَامٌ خَمْسِينَ رَقَبَةً فَأَرَادَ ابْنُهُ عَمْرٌو أَنْ يُعْتِقَ عَنْهُ الْخَمْسِينَ الْبَاقِيَةَ فَقَالَ حَتَّى أَسْأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أَبِي أَوْصَى بِعَتْقِ مِائَةِ رَقَبَةٍ وَإِنَّ هِشَامًا أَعْتَقَ عَنْهُ خَمْسِينَ وَبَقِيَتْ عَلَيْهِ خَمْسُونَ رَقَبَةً أَفَأُعْتِقُ عَنْهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَوْ كَانَ مُسْلِمًا فَأَعْتَقْتُمْ عَنْهُ أَوْ تَصَدَّقْتُمْ عَنْهُ أَوْ حَجَجْتُمْ عَنْهُ بَلَغَهُ ذَلِكَ","id":"Telah menceritakan kepada kami [Al Abbas bin Al Walid bin Mazyad], telah mengabarkan kepadaku [ayahku], telah menceritakan kepada kami [Al Aza'i], telah menceritakan kepadaku [Hassan bin 'Athiyyah], dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Al 'Ash bin Wail telah memberikan wasiat dibebaskan untuknya seratus unta. Kemudian anaknya yaitu Hisyam membebaskan lima puluh budak, dan anaknya yang bernama 'Amr hendak membebaskan lima puluh yang lainnya. Kemudian ia berkata; tunggulah hingga aku bertanya kepada Rasulullah, kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, sesungguhnya ayahku telah berwasiat agar membebaskan seratus budak. Dan sesungguhnya Hisyam telah membebaskan lima puluh dan tersisa lima puluh budak, apakah saya boleh membebaskan untuknya? Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya apabila ia adalah seorang muslim kemudian kalian membebaskan budak untuknya atau bersedekah untuknya atau berhaji untuknya, maka hal tersebut sampai kepadanya.\""},"2432":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَنَّ شُعَيْبَ بْنَ إِسْحَقَ حَدَّثَهُمْ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّهُ أَخْبَرَهُأَنَّ أَبَاهُ تُوُفِّيَ وَتَرَكَ عَلَيْهِ ثَلَاثِينَ وَسْقًا لِرَجُلٍ مِنْ يَهُودَ فَاسْتَنْظَرَهُ جَابِرٌ فَأَبَى فَكَلَّمَ جَابِرٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَشْفَعَ لَهُ إِلَيْهِ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَلَّمَ الْيَهُودِيَّ لِيَأْخُذَ ثَمَرَ نَخْلِهِ بِالَّذِي لَهُ عَلَيْهِ فَأَبَى عَلَيْهِ وَكَلَّمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُنْظِرَهُ فَأَبَى وَسَاقَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] bahwa [Syu'aib bin Ishaq] telah menceritakan kepada mereka dari [Hisyam bin 'Urwah] dari [Wahb bin Kaisan], dari [Jabir bin Abdullah], bahwa ia telah mengabarkan kepadanya bahwa ayahnya telah meninggal dan meninggalkan untuknya hutang tiga puluh wasaq kepada seorang yahudi. Kemudian Jabir meminta penangguhan kepadanya, dan orang yahudi tersebut menolak. Lalu Jabir berbicara kepada Nabi shallallahu 'alaihi wasallam agar beliau menjadi perantaranya kepada orang yahudi tersebut dan berbicara kepada orang yahudi agar ia mengambil buah pohon kurmanya untuk menggantikan apa yang menjadi kewajibannya kepada orang yahudi tersebut. Dan Rasulullah shallallahu 'alaihi wasallam berbicara kepadanya agar memberinya tangguhan, namun orang yahudi tersebut menolak. Dan ia pun menyebutkan hadits tersebut. "},"2433":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْروِ بْنِ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ زِيَادٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ رَافِعٍ التَّنُوخِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعِلْمُ ثَلَاثَةٌ وَمَا سِوَى ذَلِكَ فَهُوَ فَضْلٌ آيَةٌ مُحْكَمَةٌ أَوْ سُنَّةٌ قَائِمَةٌ أَوْ فَرِيضَةٌ عَادِلَةٌ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amr bin As Sarh], telah mengabarkan kepada kami [Ibnu Wahb], telah menceritakan kepadaku [Abdurrahman bin Ziyad] dari [Abdurrahman bin Rafi' At Tanukhi], dari [Abdullah bin 'Amr bin Al 'Ash], bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Ilmu ada tiga, dan yang selain itu adalah kelebihan, yaitu; ayat muhkamah (yang jelas penjelasannya dan tidak dihapuskan), atau sunah yang shahih, atau faraidh (pembagian warisan) yang adil.\""},"2434":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ ابْنَ الْمُنْكَدِرِ أَنَّهُ سَمِعَ جَابِرًا يَقُولُمَرِضْتُ فَأَتَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي هُوَ وَأَبُو بَكْرٍ مَاشِيَيْنِ وَقَدْ أُغْمِيَ عَلَيَّ فَلَمْ أُكَلِّمْهُ فَتَوَضَّأَ وَصَبَّهُ عَلَيَّ فَأَفَقْتُ فَقُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ أَصْنَعُ فِي مَالِي وَلِي أَخَوَاتٌ قَالَ فَنَزَلَتْ آيَةُ الْمَوَارِيثِ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Sufyan], ia berkata; saya mendengar [Ibnu Al Munkadir], bahwa ia mendengar [Jabir] berkata; aku pernah sakit, kemudian Nabi shallallahu 'alaihi wasallam datang mengunjungiku bersama Abu Bakr dengan berjalan kaki, sementara aku dalam keadaan pingsan dan belum berbicara dengannya. Kemudian beliau berwudhu dan memercikkan air kepadaku hingga aku sadar. Lalu aku katakan; wahai Rasulullah, apa yang aku lakakukan pada hartaku sementara aku memiliki beberapa orang saudara wanita. Kemudian turunlah ayat mengenai warisan: \"Mereka meminta fatwa kepadamu tentang kalalah (orang yang mati tidak meninggalkan ayah dan anak).\""},"2435":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا كَثِيرُ بْنُ هِشَامٍ حَدَّثَنَا هِشَامٌ يَعْنِي الدَّسْتُوَائِيَّ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَاشْتَكَيْتُ وَعِنْدِي سَبْعُ أَخَوَاتٍ فَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَفَخَ فِي وَجْهِي فَأَفَقْتُ فَقُلْتُ يَا رَسُولَ اللَّهِ أَلَا أُوصِي لِأَخَوَاتِي بِالثُّلُثِ قَالَ أَحْسِنْ قُلْتُ الشَّطْرُ قَالَ أَحْسِنْ ثُمَّ خَرَجَ وَتَرَكَنِي فَقَالَ يَا جَابِرُ لَا أُرَاكَ مَيِّتًا مِنْ وَجَعِكَ هَذَا وَإِنَّ اللَّهَ قَدْ أَنْزَلَ فَبَيَّنَ الَّذِي لِأَخَوَاتِكَ فَجَعَلَ لَهُنَّ الثُّلُثَيْنِقَالَ فَكَانَ جَابِرٌ يَقُولُ أُنْزِلَتْ هَذِهِ الْآيَةُ فِيَّ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Katsir bin Hisyam], telah menceritakan kepada kami [Hisyam Ad Dastuwai], dari [Abu Az Zubair], dari [Jabir], ia berkata; aku sedang sakit sementara aku memiliki tujuh orang saudara perempuan, kemudian Rasulullah shallallahu 'alaihi wasallam mendatangiku dan meniup pada wajahku kemudian aku tersadar, lalu aku katakan; wahai Rasulullah, bolehkah aku berwasiat sepertiga untuk para saudara wanita? Beliau berkata: \"Berikan yang lebih baik!\" Aku katakan; setengah? Beliau berkata: \"Berikan yang lebih baik!\" kemudian beliau keluar dan meninggalkanku. Lalu beliau berkata; wahai Jabir, aku yakin engkau tidak meninggal karena sakitmu. Sesungguhnya Allah telah menurunkan ayat dan menjelaskan bagian untuk saudara-saudara wanitamu. Allah memberikan untuk mereka dua pertiga. Jabir berkata; ayat ini turun mengenai diriku: \"Mereka meminta fatwa kepadamu tentang kalalah (orang mati yang tidak meninggalkan ayah dan anak).\""},"2436":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَآخِرُ آيَةٍ نَزَلَتْ فِي الْكَلَالَةِ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Syu'bah], dari [Abu Ishaq], dari [Al Bara` bin 'Azib], ia berkata; ayat terakhir yang turun adalah mengenai kalalah: \"Mereka meminta fatwa kepadamu tentang kalalah (orang mati yang tidak meninggalkan ayah dan anak).\""},"2437":{"ar":"حَدَّثَنَا مَنْصُورُ بْنُ أَبِي مُزَاحِمٍ حَدَّثَنَا أَبُو بَكْرٍ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ يَسْتَفْتُونَكَ فِي الْكَلَالَةِ فَمَا الْكَلَالَةُ قَالَ تُجْزِيكَ آيَةُ الصَّيْفِفَقُلْتُ لِأَبِي إِسْحَقَ هُوَ مَنْ مَاتَ وَلَمْ يَدَعْ وَلَدًا وَلَا وَالِدًا قَالَ كَذَلِكَ ظَنُّوا أَنَّهُ كَذَلِكَ","id":"Telah menceritakan kepada kami [Manshur bin Abu Muzahim], telah menceritakan kepada kami [Abu Bakr], dari [Abu Ishaq], dari [Al Bara` bin 'Azib], ia berkata; seorang laki-laki datang kepada kepada Nabi shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, mereka meminta fatwa kepada engkau mengenai kalalah, apakah kalalah itu? Beliau berkata: \"Cukup bagimu ayat yang turun pada musim panas.\" Kemudian aku katakan kepada Abu Ishaq; ia adalah orang yang mati dan tidak meninggalkan anak dan ayah, ia berkata; demikianlah mereka meyakini."},"2438":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي قَيْسٍ الْأَوْدِيِّ عَنْ هُزَيْلِ بْنِ شُرَحْبِيلَ الْأَوْدِيِّ قَالَجَاءَ رَجُلٌ إِلَى أَبِي مُوسَى الْأَشْعَرِيِّ وَسَلْمَانَ بْنِ رَبِيعَةَ فَسَأَلَهُمَا عَنْ ابْنَةٍ وَابْنَةِ ابْنٍ وَأُخْتٍ لِأَبٍّ وَأُمٍّ فَقَالَا لِابْنَتِهِ النِّصْفُ وَلِلْأُخْتِ مِنْ الْأَبِ وَالْأُمِّ النِّصْفُ وَلَمْ يُوَرِّثَا ابْنَةَ الِابْنِ شَيْئًا وَأْتِ ابْنَ مَسْعُودٍ فَإِنَّهُ سَيُتَابِعُنَا فَأَتَاهُ الرَّجُلُ فَسَأَلَهُ وَأَخْبَرَهُ بِقَوْلِهِمَا فَقَالَ لَقَدْ ضَلَلْتُ إِذًا وَمَا أَنَا مِنْ الْمُهْتَدِينَ وَلَكِنِّي سَأَقْضِي فِيهَا بِقَضَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِابْنَتِهِ النِّصْفُ وَلِابْنَةِ الِابْنِ سَهْمٌ تَكْمِلَةُ الثُّلُثَيْنِ وَمَا بَقِيَ فَلِلْأُخْتِ مِنْ الْأَبِ وَالْأُمِّ","id":"Telah menceritakan kepada kami [Abdullah bin 'Amir bin Zurarah], telah menceritakan kepada kami [Ali bin Mushir] dari [Al A'masy] dari [Abu Qais Al Audi] dari [Hudzail bin Syurahbil Al Audi], ia berkata; seorang laki-laki telah datang kepada Abu Musa Al Asy'ari dan Salman bin Rabi'ah, kemudian bertanya kepada mereka berdua mengenai anak perempuan, anak perempuan dari anak laki-laki dan saudara perempuan seayah serta seorang ibu. Kemudian mereka berdua mengatakan; untuk anak wanita setengah bagian, untuk saudara wanita seayah serta ibu adalah setengah bagian. Dan mereka berdua tidak memberikan warisan kepada anak perempuan dari anak laki-laki sedikitpun. Datanglah kepada [Ibnu Mas'ud], sesungguhnya ia akan mengoreksi kami, kemudian orang tersebut datang kepadanya dan bertanya, kemudian Ibnu Mas'ud memberitahu kepadanya dengan perkataan mereka berdua. Kemudian ia berkata; sungguh aku telah sesat dan aku bukan termasuk orang-orang yang mendapat petunjuk. Akan tetapi aku akan memutuskan padanya dengan keputusan Nabi shallallahu 'alaihi wasallam. Untuk anak wanitanya setengah dan untuk anak wanita dari anak laki-laki mendapatkan saham (bagian) sebagai penyempuraan dua pertiga, dan sisanya adalah untuk saudara wanita seayah serta untuk ibu. "},"2439":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى جِئْنَا امْرَأَةً مِنْ الْأَنْصَارِ فِي الْأَسْوَاقِ فَجَاءَتْ الْمَرْأَةُ بِابْنَتَيْنِ لَهَا فَقَالَتْ يَا رَسُولَ اللَّهِ هَاتَانِ بِنْتَا ثَابِتِ بْنِ قَيْسٍ قُتِلَ مَعَكَ يَوْمَ أُحُدٍ وَقَدْ اسْتَفَاءَ عَمُّهُمَا مَالَهُمَا وَمِيرَاثَهُمَا كُلَّهُ فَلَمْ يَدَعْ لَهُمَا مَالًا إِلَّا أَخَذَهُ فَمَا تَرَى يَا رَسُولَ اللَّهِ فَوَاللَّهِ لَا تُنْكَحَانِ أَبَدًا إِلَّا وَلَهُمَا مَالٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْضِي اللَّهُ فِي ذَلِكَ قَالَ وَنَزَلَتْ سُورَةُ النِّسَاءِ{ يُوصِيكُمُ اللَّهُ فِي أَوْلَادِكُمْ }الْآيَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْعُوا لِي الْمَرْأَةَ وَصَاحِبَهَا فَقَالَ لِعَمِّهِمَا أَعْطِهِمَا الثُّلُثَيْنِ وَأَعْطِ أُمَّهُمَا الثُّمُنَ وَمَا بَقِيَ فَلَكَقَالَ أَبُو دَاوُد أَخْطَأَ بِشْرٌ فِيهِ إِنَّمَا هُمَا ابْنَتَا سَعْدِ بْنِ الرَّبِيعِ وَثَابِتُ بْنُ قَيْسٍ قُتِلَ يَوْمَ الْيَمَامَةِ حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي دَاوُدُ بْنُ قَيْسٍ وَغَيْرُهُ مِنْ أَهْلِ الْعِلْمِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّ امْرَأَةَ سَعْدِ بْنِ الرَّبِيعِ قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ سَعْدًا هَلَكَ وَتَرَكَ ابْنَتَيْنِ وَسَاقَ نَحْوَهُ قَالَ أَبُو دَاوُد وَهَذَا هُوَ أَصَحُّ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal], telah menceritakan kepada kami [Abdullah bin Muhammad bin 'Aqil], dari [Jabir bin Abdullah], ia berkata; kami keluar bersama Rasulullah shallallahu 'alaihi wasallam hingga kami sampai pada seorang wanita anshar di beberapa pasar kemudian wanita tersebut datang dengan membawa dua orang anak wanitanya dan berkata; wahai Rasulullah, ini adalah dua anak wanita Tsabit bin Qais, ia terbunuh bersama engkau pada saat perang Uhud. Dan pamannya telah mengambil seluruh harta dan warisan mereka berdua, dan tidaklah Tsabit meninggalkan harta untuk mereka berdua melainkan ia telah mengambilnya. Bagaimana pendapat engkau wahai Rasulullah? Demi Allah, mereka berdua tidaklah dinikahkan selamanya kecuali mereka memiliki harta. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah akan memutuskan dalam perkara tersebut.\" Jabir berkata; dan turunlah Surat An Nisa`: \"Allah mensyari'atkan bagimu tentang (pembagian pusaka untuk) anak-anakmu.\" Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Panggilkan wanita tersebut sahabatnya (paman kedua anak tersebut)!\" kemudian beliau berkata kepada paman kedua anak tersebut: \"Berikan kepada keduanya dua pertiga, dan berikan seperdelapan kepada ibu mereka, dan sisanya adalah untukmu.\" Abu Daud berkata; Bisyr telah salah dalam hal tersebut. Sesungguhnya mereka berdua adalah anak wanita Sa'd bin Ar Rabi', sedangkan Tsabit bin Qais terbunuh pada perang Yamamah. Telah menceritakan kepada kami [Ibnu As Sarh], telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Daud bin Qais], dan yang lainnya dari kalangan ahli ilmu, dari [Abdullah bin Muhammad bin 'Aqil], dari [Jabir bin Abdullah], bahwa isteri Sa'd bin Ar Rabi' berkata; wahai Rasulullah, sesungguhnya Sa'd telah mati dan meninggalkan dua anak wanita, kemudian Ibnu As Sarh menyebutkan hadits seperti hadits tersebut. Abu Daud berkata; dan hadits ini lebih shahih. "},"2440":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ حَدَّثَنَا قَتَادَةُ حَدَّثَنِي أَبُو حَسَّانَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَأَنَّ مُعَاذَ بْنَ جَبَلٍ وَرَّثَ أُخْتًا وَابْنَةً فَجَعَلَ لِكُلِّ وَاحِدَةٍ مِنْهُمَا النِّصْفَ وَهُوَ بِالْيَمَنِ وَنَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ حَيٌّ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Aban], telah menceritakan kepada kami [Qatadah], telah menceritakan kepadaku [Abu Hassan] dari [Al Aswad bin Yazid?] bahwa [Mu'adz bin Jabarl], telah memberikan warisan kepada seorang saudara wanita dan anak wanita. Ia memberikan setiap mereka setengah bagian, pada saat ia berada di Yaman, sedang Nabi shallallahu 'alaihi wasallam pada saat itu masih hidup. "},"2441":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُثْمَانَ بْنِ إِسْحَقَ بْنِ خَرَشَةَ عَنْ قَبِيصَةَ بْنِ ذُؤَيْبٍ أَنَّهُ قَالَجَاءَتْ الْجَدَّةُ إِلَى أَبِي بَكْرٍ الصِّدِّيقِ تَسْأَلُهُ مِيرَاثَهَا فَقَالَ مَا لَكِ فِي كِتَابِ اللَّهِ تَعَالَى شَيْءٌ وَمَا عَلِمْتُ لَكِ فِي سُنَّةِ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا فَارْجِعِي حَتَّى أَسْأَلَ النَّاسَ فَسَأَلَ النَّاسَ فَقَالَ الْمُغِيرَةُ بْنُ شُعْبَةَ حَضَرْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَاهَا السُّدُسَ فَقَالَ أَبُو بَكْرٍ هَلْ مَعَكَ غَيْرُكَ فَقَامَ مُحَمَّدُ بْنُ مَسْلَمَةَ فَقَالَ مِثْلَ مَا قَالَ الْمُغِيرَةُ بْنُ شُعْبَةَ فَأَنْفَذَهُ لَهَا أَبُو بَكْرٍ ثُمَّ جَاءَتْ الْجَدَّةُ الْأُخْرَى إِلَى عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ تَسْأَلُهُ مِيرَاثَهَا فَقَالَ مَا لَكِ فِي كِتَابِ اللَّهِ تَعَالَى شَيْءٌ وَمَا كَانَ الْقَضَاءُ الَّذِي قُضِيَ بِهِ إِلَّا لِغَيْرِكِ وَمَا أَنَا بِزَائِدٍ فِي الْفَرَائِضِ وَلَكِنْ هُوَ ذَلِكَ السُّدُسُ فَإِنْ اجْتَمَعْتُمَا فِيهِ فَهُوَ بَيْنَكُمَا وَأَيَّتُكُمَا خَلَتْ بِهِ فَهُوَ لَهَا","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Ibnu Syihab], dari [Utsman bin Ishaq bin Kharasyah], dari [Qabishah bin Dzuaib], bahwa ia berkata; telah datang seorang nenek kepada Abu Bakr Ash Shiddiq, ia bertanya kepadanya mengenai warisannya. Kemudian ia berkata; engkau tidak mendapatkan sesuatupun dalam Kitab Allah Ta'ala, dan aku tidak mengetahui sesuatu untukmu dalam sunnah Nabi shallallahu 'alaihi wasallam. Kembalilah hingga aku bertanya kepada orang-orang. Kemudian Abu Bakr bertanya kepada orang-orang, lalu [Al Mughirah bin Syu'bah] berkata; aku menyaksikan Rasulullah shallallahu 'alaihi wasallam telah memberikan kepadanya seperenam. Kemudian Abu Bakr berkata; apakah ada orang (yang menyaksikan) selainmu? Kemudian [Muhammad bin Maslamah] berdiri dan berkata seperti apa yang dikatakan Al Mughirah bin Syu'bah. Lalu Abu Bakr menerapkannya dan berkata; engkau tidak mendapatkan sesuatupun dalam Kitab Allah Ta'ala, dan keputusan yang telah diputuskan adalah untuk selainmu, dan aku tidak akan menambahkan dalam perkara faraidl, akan tetapi hal itu adalah seperenam. Apabila kalian berdua dalam seperenam tersebut maka seperenam itu dibagi di antara kalian berdua. Siapapun di antara kalian berdua yang melepaskannya maka seperenam tersebut adalah miliknya. "},"2442":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي رِزْمَةَ أَخْبَرَنِي أَبِي حَدَّثَنَا عُبَيْدُ اللَّهِ أَبُو الْمُنِيبِ الْعَتَكِيِّ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَعَلَ لِلْجَدَّةِ السُّدُسَ إِذَا لَمْ يَكُنْ دُونَهَا أُمٌّ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Aziz bin Abu Rizmah], telah mengabarkan kepadaku [ayahku], telah menceritakan kepada kami ['Ubaidullah Abu Al Munib Al 'Ataki], dari [Ibnu Buraidah] dari [ayahnya], bahwa Nabi shallallahu 'alaihi wasallam telah memberikan nenek bagian seperenam apabila tidak ada ibu bersamanya. "},"2443":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنًأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ ابْنَ ابْنِي مَاتَ فَمَا لِي مِنْ مِيرَاثِهِ فَقَالَ لَكَ السُّدُسُ فَلَمَّا أَدْبَرَ دَعَاهُ فَقَالَ لَكَ سُدُسٌ آخَرُ فَلَمَّا أَدْبَرَ دَعَاهُ فَقَالَ إِنَّ السُّدُسَ الْآخَرَ طُعْمَةٌقَالَ قَتَادَةُ فَلَا يَدْرُونَ مَعَ أَيِّ شَيْءٍ وَرَّثَهُ قَالَ قَتَادَةُ أَقَلُّ شَيْءٍ وَرِثَ الْجَدُّ السُّدُسُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Hammam], dari [Qatadah] dari [Al Hasan] dari [Imran bin Hushain], bahwa seorang laki-laki telah datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; sesungguhnya cucu laki-laki saya meninggal, maka berapakah warisan untuk saya? Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Engkau mendapatkan seperenam.\" Kemudian tatkala laki-laki tersebut pergi beliau berkata: \"Engkau mendapat seperenam yang lain.\" Kemudian tatkala orang tersebut pergi beliau berkata: \"Seperenam yang lain adalah makanan.\" Qatadah berkata; mereka tidak mengetahui bersama siapakah beliau memberinya warisan tersebut. Qatadah berkata; bagian minimal yang diperoleh seorang kakek adalah seperenam. "},"2444":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ عَنْ يُونُسَ عَنْ الْحَسَنِأَنْ عُمَرَ قَالَ أَيُّكُمْ يَعْلَمُ مَا وَرَّثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَدَّ فَقَالَ مَعْقِلُ بْنُ يَسَارٍ أَنَا وَرَّثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السُّدُسَ قَالَ مَعَ مَنْ قَالَ لَا أَدْرِي قَالَ لَا دَرَيْتَ فَمَا تُغْنِي إِذًا","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah], dari [Khalid] dari [Yunus], dari [Al Hasan] bahwa Umar berkata; siapakah di antara kalian yang mengetahui berapakah Rasulullah shallallahu 'alaihi wasallam memberikan warisan seorang kakek? Kemudian [Ma'qil bin Yasar] berkata; saya, Rasulullah shallallahu 'alaihi wasallam memberinya seperenam. Umar berkata; bersama siapa? Ma'qil berkata; aku tidak tahu. Umar berkata; engkau tidak tahu, kalau demikian engkau tidak cukup (dalam memberikan persaksian). "},"2445":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ وَمخْلَدُ بْنُ خَالِدٍ وَهَذَا حَدِيثُ مَخْلَدٍ وَهُوَ الْأَشْبَعُ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْسِمْ الْمَالَ بَيْنَ أَهْلِ الْفَرَائِضِ عَلَى كِتَابِ اللَّهِ فَمَا تَرَكَتْ الْفَرَائِضُ فَلِأَوْلَى ذَكَرٍ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], dan [Makhlad bin Khalid], dan ini adalah hadits Makhlad dan hadits tersebut lebih bagus (patut diterima). Mereka berdua mengatakan; telah menceritakan kepada kami [Abdurrazzaq], telah menceritakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [ayahnya] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata: \"Bagikan harta diantara para pemilik faraidl (bagian harta waris) berdasarkan Kitab Allah. Maka bagian harta yang tersisa setelah pembagian tersebut, lebih utama diberikan kepada (ahli waris) laki-laki.\""},"2446":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ بُدَيْلٍ عَنْ عَلِيِّ بْنِ أَبِي طَلْحَةَ عَنْ رَاشِدِ بْنِ سَعْدٍ عَنْ أَبِي عَامِرٍ الْهَوْزَنِيِّ عَبْدِ اللَّهِ بْنِ لُحَيٍّ عَنْ الْمِقْدَامِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَرَكَ كَلًّا فَإِلَيَّ وَرُبَّمَا قَالَ إِلَى اللَّهِ وَإِلَى رَسُولِهِ وَمَنْ تَرَكَ مَالًا فَلِوَرَثَتِهِ وَأَنَا وَارِثُ مَنْ لَا وَارِثَ لَهُ أَعْقِلُ لَهُ وَأَرِثُهُ وَالْخَالُ وَارِثُ مَنْ لَا وَارِثَ لَهُ يَعْقِلُ عَنْهُ وَيَرِثُهُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar], telah menceritakan kepada kami [Syu'bah] dari [Budail] dari [Ali bin Abu Thalhah], dari [Rasyid bin Sa'd], dari [Abu 'Amir Al Hauzani Abdullah bin Luhai] dari [Al Miqdam], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang meninggalkan kall (keluarga dan hutang) maka menjadi tanggunganku.\" Dan terkadang beliau mengatakan: \"Menjadi tanggungan Allah dan rasulNya.\" \"Dan barangsiapa yang meninggalkan harta maka untuk para pewarisnya, dan aku adalah pewaris orang yang tidak memiliki pewaris. Aku menanggung diyatnya dan mewarisinya. Paman (dari pihak ibu) adalah pewaris orang yang tidak memiliki pewaris, ia menanggung diyatnya dan mewarisinya.\""},"2447":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ فِي آخَرِينَ قَالُوا حَدَّثَنَا حَمَّادٌ عَنْ بُدَيْلٍ يَعْنِي ابْنَ مَيْسَرَةَ عَنْ عَلِيِّ بْنِ أَبِي طَلْحَةَ عَنْ رَاشِدِ بْنِ سَعْدٍ عَنْ أَبِي عَامِرٍ الْهَوْزَنِيِّ عَنْ الْمِقْدَامِ الْكِنْدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا أَوْلَى بِكُلِّ مُؤْمِنٍ مِنْ نَفْسِهِ فَمَنْ تَرَكَ دَيْنًا أَوْ ضَيْعَةً فَإِلَيَّ وَمَنْ تَرَكَ مَالًا فَلِوَرَثَتِهِ وَأَنَا مَوْلَى مَنْ لَا مَوْلَى لَهُ أَرِثُ مَالَهُ وَأَفُكُّ عَانَهُ وَالْخَالُ مَوْلَى مَنْ لَا مَوْلَى لَهُ يَرِثُ مَالَهُ وَيَفُكُّ عَانَهُقَالَ أَبُو دَاوُد رَوَاهُ الزُّبَيْدِيُّ عَنْ رَاشِدِ بْنِ سَعْدٍ عَنْ ابْنِ عَائِذٍ عَنْ الْمِقْدَامِ وَرَوَاهُ مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ رَاشِدٍ قَالَ سَمِعْتُ الْمِقْدَامَ قَالَ أَبُو دَاوُد يَقُولُ الضَّيْعَةُ مَعْنَاهُ عِيَالٌ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] di antara para syekh yang lain, mereka berkata; telah menceritakan kepada kami [Hammad], dari [Budail bin Maisarah], dari [Ali bin Abu Thalhah], dari [Rasyid bin Sa'd] dari [Abu Amir Al Hauzani], dari [Al Miqdam Al Kindi], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku adalah orang yang paling berhak (menanggung) terhadap seorang mukmin daripada dirinya. Barangsiapa yang meninggalkan hutang atau keluarga maka menjadi tanggunganku, dan barangsiapa yang meninggalkan harta maka untuk para pewarisnya, aku adalah pewaris orang yang tidak memiliki pewaris, aku warisi hartanya dan aku bebaskan tanggungannya.\" Abu Daud berkata; hadits tersebut diriwayatkan oleh [Az Zubaidi], dari [Rasyid bin Sa'd], dari [Ibnu 'Aidz] dari [Al Miqdam], dan telah diriwayatkan oleh [Mu'awiyah bin Shalih] dari [Rasyid], ia berkata; saya mendengar [Al Miqdam], ia berkata; Abu Daud berkata; dha'ah adalah keluarga. "},"2448":{"ar":"حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ عَتِيقٍ الدِّمَشْقِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ يَزِيدَ بْنِ حُجْرٍ عَنْ صَالِحِ بْنِ يَحْيَى بْنِ الْمِقْدَامِ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَنَا وَارِثُ مَنْ لَا وَارِثَ لَهُ أَفُكُّ عَانِيَهُ وَأَرِثُ مَالَهُ وَالْخَالُ وَارِثُ مَنْ لَا وَارِثَ لَهُ يَفُكُّ عَانِيَهُ وَيَرِثُ مَالَهُ","id":"Telah menceritakan kepada kami [Abdussalam bin 'Atiq Ad Dimasyqi], telah menceritakan kepada kami [Muhammad bin Al Mubarak], telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Yazid? bin Hujr] dari [Shalih bin Yahya bin Al Miqdam] dari [ayahnya], dari [kakeknya], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku adalah pewaris orang yang tidak memiliki pewaris, aku bebaskan tanggungannya dan mewarisi hartanya. Paman (dari pihak ibu) adalah pewaris orang yang tidak memiliki pewaris yang akan membebaskan tanggungannya dan mewarisi hartanya.\""},"2449":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ عَنْ سُفْيَانَ جَمِيعًا عَنْ ابْنِ الْأَصْبَهَانِيِّ عَنْ مُجَاهِدِ بْنِ وَرْدَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ مَوْلًى لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاتَ وَتَرَكَ شَيْئًا وَلَمْ يَدَعْ وَلَدًا وَلَا حَمِيمًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطُوا مِيرَاثَهُ رَجُلًا مِنْ أَهْلِ قَرْيَتِهِقَالَ أَبُو دَاوُد وَحَدِيثُ سُفْيَانَ أَتَمُّ و قَالَ مُسَدَّدٌ قَالَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَاهُنَا أَحَدٌ مَنْ أَهْلِ أَرْضِهِ قَالُوا نَعَمْ قَالَ فَأَعْطُوهُ مِيرَاثَهُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya], telah menceritakan kepada kami [Syu'bah], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Utsman Ibnu Abu Syaibah?], telah menceritakan kepada kami [Waki' bin Al Jarrah], dari [Sufyan], semuanya berasal dari [Ibnu Al Ashbahani], dari [Muhajid bin Wardan], dari ['Urwah] dari [Aisyah] radliallahu 'anha, bahwa mantan budak Nabi shallallahu 'alaihi wasallam meninggal dan ia tidak meninggalkan sesuatupun, dan tidak meninggalkan anak serta kerabat. Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Berikan warisannya kepada seseorang yang merupakan penduduk kampungnya.\" Abu Daud berkata; dan hadits Sufyan lebih sempurna. Musaddad berkata; Nabi shallallahu 'alaihi wasallam berkata: \"Apakah di sini terdapat seseorang yang berasal dari penduduk negerinya?\" Mereka berkata; Iya. Beliau bersabda: \"Berikan warisan tersebut kepadanya!\""},"2450":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ الْكِنْدِيُّ حَدَّثَنَا الْمُحَارِبِيُّ عَنْ جِبْرِيلَ بْنِ أَحْمَرَ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ إِنَّ عِنْدِي مِيرَاثَ رَجُلٍ مِنْ الْأَزْدِ وَلَسْتُ أَجِدُ أَزْدِيًّا أَدْفَعُهُ إِلَيْهِ قَالَ اذْهَبْ فَالْتَمِسْ أَزْدِيًّا حَوْلًا قَالَ فَأَتَاهُ بَعْدَ الْحَوْلِ فَقَالَ يَا رَسُولَ اللَّهِ لَمْ أَجِدْ أَزْدِيًّا أَدْفَعُهُ إِلَيْهِ قَالَ فَانْطَلِقْ فَانْظُرْ أَوَّلَ خُزَاعِيٍّ تَلْقَاهُ فَادْفَعْهُ إِلَيْهِ فَلَمَّا وَلَّى قَالَ عَلَيَّ الرَّجُلُ فَلَمَّا جَاءَهُ قَالَ انْظُرْ كُبْرَ خُزَاعَةَ فَادْفَعْهُ إِلَيْهِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id Al Kindi], telah menceritakan kepada kami [Al Muharibi], dari [Jibril bin Ahmar] dari [Abdullah bin Buraidah] dari [ayahnya], ia berkata; terdapat seorang laki-laki yang datang kepada Nabi shallallahu 'alaihi wasallam kemudian berkata; sesungguhnya aku memiliki warisan seseorang yang berasal dari Azd, dan aku tidak mendapatkan seseorang yang berasal dari Azd yang dapat aku serahkan warisan tersebut kepadanya. Beliau berkata: \"Pergilah dan carilah orang yang berasal dari Azd selama satu tahun.\" Buraidah berkata; kemudian orang tersebut datang kepada beliau setelah satu tahun, kemudian ia berkata; wahai Rasulullah, aku belum mendapatkan orang Azd yang dapat aku serahkan warisan tersebut kepadanya. Beliau berkata: \"Pergilah dan lihatlah orang Khuza'ah pertama yang engkau temui, kemudian serahkan warisan tersebut kepadanya!\" kemudian tatkala orang tersebut telah pergi beliau berkata: \"Hadirkan orang tersebut!\" kemudian tatkala orang tersebut telah datang kepadanya beliau berkata: \"Lihatlah orang Khuza'ah yang paling tua, kemudian serahkan warisan tersebut kepadanya! '"},"2451":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ أَسْوَدَ الْعِجْلِيُّ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا شَرِيكٌ عَنْ جِبْرِيلَ بْنِ أَحْمَرَ أَبِي بَكْرٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَمَاتَ رَجُلٌ مِنْ خُزَاعَةَ فَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِيرَاثِهِ فَقَالَ الْتَمِسُوا لَهُ وَارِثًا أَوْ ذَا رَحِمٍ فَلَمْ يَجِدُوا لَهُ وَارِثًا وَلَا ذَا رَحِمٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطُوهُ الْكُبْرَ مِنْ خُزَاعَةَ وَقَالَ يَحْيَى قَدْ سَمِعْتُهُ مَرَّةً يَقُولُ فِي هَذَا الْحَدِيثِ انْظُرُوا أَكْبَرَ رَجُلٍ مِنْ خُزَاعَةَ","id":"Telah menceritakan kepada kami [Husain bin Aswad Al 'Ijli], telah menceritakan kepada kami [Yahya bin Adam], telah menceritakan kepada kami [Syarik], dari [Jibril bin Ahmar Abu Bakr], dari [Ibnu Buraidah] dari [ayahnya], ia berkata; terdapat seorang laki-laki yang meninggal kemudian Nabi shallallahu 'alaihi wasallam diberi warisannya. Kemudian beliau bersabda: \"Carikan pewarisnya atau kerabatnya!\" kemudian mereka tidak mendapatkan pewaris dan kerabatnya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berikan warisan tersebut kepada orang tertua dari Khuza'ah.\" Yahya berkata; pernah suatu kali aku mendengar beliau dalam hadits ini berkata: \"Lihatlah orang Khuza'ah yang paling tua!\""},"2452":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا عَمْرُو بْنُ دِينَارٍ عَنْ عَوْسَجَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا مَاتَ وَلَمْ يَدَعْ وَارِثًا إِلَّا غُلَامًا لَهُ كَانَ أَعْتَقَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَهُ أَحَدٌ قَالُوا لَا إِلَّا غُلَامًا لَهُ كَانَ أَعْتَقَهُ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِيرَاثَهُ لَهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami ['Amr bin Dinar], dari ['Ausajah], dari [Ibnu Abbas] bahwa seorang laki-laki meninggal dan tidak meninggalkan pewaris kecuali seorang budak yang telah ia bebaskan. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah ia memiliki seseorang?\" Mereka berkata; tidak, kecuali seorang budak yang telah ia bebaskan. Kemudian Rasulullah shallallahu 'alaihi wasallam memberikan warisannya untuk mantan budak tersebut. "},"2453":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنِي عُمَرُ بْنُ رُؤْبَةَ التَّغْلِبِيُّ عَنْ عَبْدِ الْوَاحِدِ بْنِ عَبْدِ اللَّهِ النَّصْرِيِّ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَرْأَةُ تُحْرِزُ ثَلَاثَةَ مَوَارِيثَ عَتِيقَهَا وَلَقِيطَهَا وَوَلَدَهَا الَّذِي لَاعَنَتْ عَنْهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi], telah menceritakan kepada kami [Muhammad bin Harb], telah menceritakan kepadaku [Umar bin Ru`bah At Taghlibi], dari [Abdul Wahid bin Abdullah An Nashri], dari [Watsilah bin Al Asqa'] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Seorang wanita menjaga tiga orang yang mewarisi; budak yang ia bebaskan, anak temuannya, dan anaknya yang karenanya ia melakukan li'an.\""},"2454":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ وَمُوسَى بْنُ عَامِرٍ قَالَا حَدَّثَنَا الْوَلِيدُ أَخْبَرَنَا ابْنُ جَابِرٍ حَدَّثَنَا مَكْحُولٌ قَالَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِيرَاثَ ابْنِ الْمُلَاعَنَةِ لِأُمِّهِ وَلِوَرَثَتِهَا مِنْ بَعْدِهَاحَدَّثَنَا مُوسَى بْنُ عَامِرٍ حَدَّثَنَا الْوَلِيدُ أَخْبَرَنِي عِيسَى أَبُو مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ الْحَارِثِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid], dan [Musa bin 'Amir], mereka berkata; telah menceritakan kepada kami [Al Walid], telah mengabarkan kepada kami [Ibnu Jabir], telah menceritakan kepada kami [Makhul], Ia berkata; Rasulullah shallallahu 'alaihi wasallam memberikan warisan anak wanita yang melakukan li'an kepada ibunya serta para pewaris ibunya setelahnya. Telah menceritakan kepada kami [Musa bin Amir], telah menceritakan kepada kami [Al Walid], telah mengabarkan kepadaku [Isa Abu Muhammad] dari [Al 'Ala` bin Al Harits] dari ['Amr bin Syu'aib] dari [ayahnya], dari [kakeknya] dari Nabi shallallahu 'alaihi wasallam seperti itu. "},"2455":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَرِثُ الْمُسْلِمُ الْكَافِرَ وَلَا الْكَافِرُ الْمُسْلِمَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Ali bin Husain] dari ['Amr bin Utsman] dari [Usamah bin Zaid] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang muslim tidak mewarisi orang kafir, dan orang kafir tidak mewarisi orang muslim.\""},"2456":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيْنَ تَنْزِلُ غَدًا فِي حِجَّتِهِ قَالَ وَهَلْ تَرَكَ لَنَا عَقِيلٌ مَنْزِلًا ثُمَّ قَالَ نَحْنُ نَازِلُونَ بِخَيْفِ بَنِي كِنَانَةَ حَيْثُ تَقَاسَمَتْ قُرَيْشٌ عَلَى الْكُفْرِ يَعْنِي الْمُحَصَّبِ وَذَاكَ أَنَّ بَنِي كِنَانَةَ حَالَفَتْ قُرَيْشًا عَلَى بَنِي هَاشِمٍ أَنْ لَا يُنَاكِحُوهُمْ وَلَا يُبَايِعُوهُمْ وَلَا يُؤْوُوهُمْقَالَ الزُّهْرِيُّ وَالْخَيْفُ الْوَادِي","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ali bin Husain], dari ['Amr bin Utsman] dari [Usamah bin Zaid], ia berkata; aku katakan; wahai Rasulullah, dimanakah kita singgah besok? Yaitu pada waktu haji beliau. Beliau berkata: \"Apakah 'Aqil telah meninggalkan untuk kita tempat persinggahan?\" kemudian beliau berkata: \"Kita akan singgah di Khaif Bani Kinanah dimana orang-orang Quraisy saling bersumpah di atas kekafiran.\" Yaitu di Al Muhashshab, hal tersebut karena Bani Kinanah telah bersumpah kepada orang-orang Quraisy untuk memusuhi Bani Hasyim yang tidak saling menikahkan dengan mereka, dan tidak memberi tempat perlindungan kepada mereka. Az Zuhri berkata; Khaif adalah nama sebuah bukit. "},"2457":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ حَبِيبٍ الْمُعَلِّمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ عَمْروٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَتَوَارَثُ أَهْلُ مِلَّتَيْنِ شَتَّى","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Habib Al Mu'allim], dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya yaitu Abdullah bin 'Amr], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pemeluk dua agama yang berbeda tidak saling mewarisi.\""},"2458":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَمْرِو بْنِ أَبِي حَكِيمٍ الْوَاسِطِيِّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَأَنَّ أَخَوَيْنِ اخْتَصَمَا إِلَى يَحْيَى بْنِ يَعْمَرَ يَهُودِيٌّ وَمُسْلِمٌ فَوَرَّثَ الْمُسْلِمَ مِنْهُمَا وَقَالَ حَدَّثَنِي أَبُو الْأَسْوَدِ أَنَّ رَجُلًا حَدَّثَهُ أَنَّ مُعَاذًا حَدَّثَهُ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْإِسْلَامُ يَزِيدُ وَلَا يَنْقُصُ فَوَرَّثَ الْمُسْلِمَحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ أَبِي حَكِيمٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ أَبِي الْأَسْوَدِ الدِّيلِيِّ أَنَّ مُعَاذًا أُتِيَ بِمِيرَاثِ يَهُودِيٍّ وَارِثُهُ مُسْلِمٌ بِمَعْنَاهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Warits] dari ['Amr bin Abu Hakim Al Wasithi], telah menceritakan kepada kami [Abdullah bin Buraidah] bahwa dua orang yang bersaudara seorang yahudi dan muslim saling memperkarakan kepada Yahya bin Ya'mar kemudian ia memberikan warisan kepada orang muslim. Dan [Yahya] berkata; telah menceritakan kepadaku [Abu Al Aswad bin Amir] bahwa [seorang laki-laki] telah menceritakan kepadanya bahwa [Mu'adz] telah menceritakan kepadanya ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Islam bertambah dan tidak berkurang.\" Kemudian beliau memberikan warisan kepada seorang muslim. Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [Amru bin Abi Hakim] dari [Abdullah bin Buraidah] dari [Yahya bin Ya'mar] dari [Abu Al Aswad Ad Dili] bahwa [Mu'adz] diberi warisan seorang yahudi sementara pewarisnya adalah seorang muslim. Ia menyebutkan hadits tersebut dengan maknanya dari Nabi shallallahu 'alaihi wasallam. "},"2459":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ أَبِي يَعْقُوبَ حَدَّثَنَا مُوسَى بْنُ دَاوُدَ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي الشَّعْثَاءِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ قَسْمٍ قُسِمَ فِي الْجَاهِلِيَّةِ فَهُوَ عَلَى مَا قُسِمَ لَهُ وَكُلُّ قَسْمٍ أَدْرَكَهُ الْإِسْلَامُ فَهُوَ عَلَى قَسْمِ الْإِسْلَامِ","id":"Telah menceritakan kepada kami [Hajjaj bin Abu Ya'qub], telah menceritakan kepada kami [Musa bin Daud], telah menceritakan kepada kami [Muhammad bin Muslim], dari ['Amr bin Dinar], dari [Asy Sya'tsa`] dari [Ibnu Abbas], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Setiap pembagian yang dibagikan pada masa jahiliyah adalah sesuai dengan aturan pembagian yang berlaku (pada masa itu), dan setiap pembagian yang dilakukan pada masa Islam adalah sesuai dengan pembagian menurut aturan Islam.\""},"2460":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ قُرِئَ عَلَى مَالِكٍ وَأَنَا حَاضِرٌ قَالَ مَالِكٌ عَرَضَ عَلَيَّ نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أُمَّ الْمُؤْمِنِينَ أَرَادَتْ أَنْ تَشْتَرِيَ جَارِيَةً تَعْتِقُهَا فَقَالَ أَهْلُهَا نَبِيعُكِهَا عَلَى أَنَّ وَلَاءَهَا لَنَا فَذَكَرَتْ عَائِشَةُ ذَاكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا يَمْنَعُكِ ذَلِكَ فَإِنَّ الْوَلَاءَ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], ia berkata; telah dibacakan riwayat kepada Malik sementara aku menyaksikannya. [Malik] berkata; [Nafi'] telah memaparkan kepadaku dari [Ibnu Umar], bahwa Aisyah radliallahu 'anha ummul mukminin hendak membeli seorang budak wanita yang akan ia merdekakan. Kemudian tuannya berkata; kami akan menjualnya kepadamu dengan syarat perwaliaannya adalah milik kami. Kemudian Aisyah menceritakan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam, kemudian beliau berkata: \"Hal tersebut tidaklah menghalangimu, sesungguhnya perwalian adalah untuk orang yang membebaskan.\""},"2461":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلَاءُ لِمَنْ أَعْطَى الثَّمَنَ وَوَلِيَ النِّعْمَةَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Waki' bin Al Jarrah], dari [Sufyan Ats Tsauri] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perwalian adalah milik orang yang memberikan harga dan membebaskan.\""},"2462":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ أَبِي الْحَجَّاجِ أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رِئَابَ بْنَ حُذَيْفَةَ تَزَوَّجَ امْرَأَةً فَوَلَدَتْ لَهُ ثَلَاثَةَ غِلْمَةٍ فَمَاتَتْ أُمُّهُمْ فَوَرَّثُوهَا رِبَاعَهَا وَوَلَاءَ مَوَالِيهَا وَكَانَ عَمْرُو بْنُ الْعَاصِ عَصَبَةَ بَنِيهَا فَأَخْرَجَهُمْ إِلَى الشَّامِ فَمَاتُوا فَقَدَّمَ عَمْرُو بْنُ الْعَاصِ وَمَاتَ مَوْلًى لَهَا وَتَرَكَ مَالًا لَهُ فَخَاصَمَهُ إِخْوَتُهَا إِلَى عُمَرَ بْنِ الْخَطَّابِ فَقَالَ عُمَرُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَحْرَزَ الْوَلَدُ أَوْ الْوَالِدُ فَهُوَ لِعَصَبَتِهِ مَنْ كَانَ قَالَ فَكَتَبَ لَهُ كِتَابًا فِيهِ شَهَادَةُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَزَيْدِ بْنِ ثَابِتٍ وَرَجُلٍ آخَرَ فَلَمَّا اسْتُخْلِفَ عَبْدُ الْمَلِكِ اخْتَصَمُوا إِلَى هِشَامِ بْنِ إِسْمَعِيلَ أَوْ إِلَى إِسْمَعِيلَ بْنِ هِشَامٍ فَرَفَعَهُمْ إِلَى عَبْدِ الْمَلِكِ فَقَالَ هَذَا مِنْ الْقَضَاءِ الَّذِي مَا كُنْتُ أَرَاهُ قَالَ فَقَضَى لَنَا بِكِتَابِ عُمَرَ بْنِ الْخَطَّابِ فَنَحْنُ فِيهِ إِلَى السَّاعَةِ","id":"Telah menceritakan kepada kami [Abdullah bin 'Amr bin Abu Al Hajjaj Abu Ma'mar], telah menceritakan kepada kami [Abdul Warits] dari [Husain Al Mu'allim], dari ['Amr bin Syu'aib], dari [ayahnya], dari [kakeknya], bahwa Ri`ab bin Hudzaifah telah menikah dengan seorang wanita kemudian ia melahirkan tiga orang anak. Kemudian ibu mereka meninggal. Kemudian mereka mewarisi tempat tinggalnya dan perwalian mantan budaknya. Dan 'Amr bin Al 'Ash adalah 'ashabah (orang yang mendapat sisa dari pembagian warisan) anak-anak wanita tersebut, kemudian ia mengeluarkan mereka ke Syam, dan mereka meninggal. Kemudian 'Amr bin Al 'Ash datang dan mantan budak wanita tersebut dan meninggalkan harta untuknya. Kemudian para saudara wanita tersebut mempermasalahkannya kepada Umar bin Al Khathab, kemudian [Umar] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang dijaga seorang anak atau orang tua adalah untuk 'ashabahnya, siapapun dia.\" Ia berkata; kemudian Umar menulis untuknya sebuah surat yang berisi persaksian Abdurrahman bin 'Auf, dan Zaid bin Tsabit serta seorang laki-laki yang lain. Kemudian tatkala Abdul Malik ditunjuk menjadi Khalifah mereka memperselisihkannya kepada Hisyam bin Isma'il, atau kepada Isma'il bin Hisyam. Kemudian ia melaporkannya kepada Abdul Malik. Kemudian ia berkata; ini termasuk keputusan yang telah aku lihat. Ia berkata; kemudian Abdul Malik memutuskan untuk kami dengan surat Umar bin Al Khathab, dan kami dalam keputusan tersebut hingga saat ini."},"2463":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ مَوْهَبٍ الرَّمْلِيُّ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا يَحْيَى قَالَ أَبُو دَاوُد وَهُوَ ابْنُ حَمْزَةَ عَنْ عَبْدِ الْعَزِيزِ بْنِ عُمَرَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَوْهَبٍ يُحَدِّثُ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ عَنْ قَبِيصَةَ بْنِ ذُؤَيْبٍ قَالَ هِشَامٌ عَنْ تَمِيمٍ الدَّارِيِّ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ وَقَالَ يَزِيدُ إِنَّ تَمِيمًا قَالَ يَا رَسُولَ اللَّهِ مَا السُّنَّةُ فِي الرَّجُلِ يُسْلِمُ عَلَى يَدَيْ الرَّجُلِ مِنْ الْمُسْلِمِينَ قَالَ هُوَ أَوْلَى النَّاسِ بِمَحْيَاهُ وَمَمَاتِهِ","id":"Telah menceritakan kepada kami [Yazid? bin Khalid bin Mauhib Ar Ramli], dan [Hisyam bin 'Ammar], mereka berkata; telah menceritakan kepada kami [Yahya], Abu Daud berkata; ia adalah Ibnu Hamzah, dari [Abdul Aziz bin Umar], ia berkata; saya mendengar [Abdullah bin Mauhib] menceritakan kepada Umar bin Abdul Aziz, dari [Qabishah bin Dzuaib], Hisyam berkata; dari [Tamim Ad Dari], bahwa ia berkata; wahai Rasulullah, -sedangkan Yazid? berkata; sesungguhnya Tamim berkata; wahai Rasulullah, apakah sunnah bagi seorang laki-laki yang masuk Islam di hadapan seorang muslim? Beliau bersabda: \"Ia adalah yang lebih layak untuk membela muslim tersebut dikala hidup dan matinya.\""},"2464":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْوَلَاءِ وَعَنْ هِبَتِهِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar], telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Dinar], dari [Ibnu Umar] radliallahu 'anhuma, ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menjual perwalian dan menghibahkannya. "},"2465":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُعَاذٍ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ إِسْحَقَ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اسْتَهَلَّ الْمَوْلُودُ وُرِّثَ","id":"Telah menceritakan kepada kami [Husain bin Muadz], telah menceritakan kepada kami [Abdul A'la], telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Yazid? bin Abdullah bin Qusaith] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila anak yang lahir (dalam keadaan) menangis, maka ia diwarisi.\""},"2466":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ{ وَالَّذِينَ عَاقَدَتْ أَيْمَانُكُمْ فَآتُوهُمْ نَصِيبَهُمْ }كَانَ الرَّجُلُ يُحَالِفُ الرَّجُلَ لَيْسَ بَيْنَهُمَا نَسَبٌ فَيَرِثُ أَحَدُهُمَا الْآخَرَ فَنَسَخَ ذَلِكَ الْأَنْفَالُ فَقَالَ تَعَالَى{ وَأُولُو الْأَرْحَامِ بَعْضُهُمْ أَوْلَى بِبَعْضٍ }","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Tsabit], telah menceritakan kepadaku [Ali bin Husain], dari [ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma, ia berkata; firman Allah: \"Dan (jika ada) orang-orang yang kamu telah bersumpah setia dengan mereka, maka berilah kepada mereka bagiannya.\" Dahulu seorang laki-laki saling bersumpah dengan orang lain yang tidak memiliki nasab dengannya, kemudian yang satu mewarisi yang lainnya. Kemudian hal tersebut dihapuskan oleh Surat Al Anfal: \"Orang-orang yang mempunyai hubungan kerabat itu sebagiannya lebih berhak terhadap sesamanya (daripada yang bukan kerabat) \""},"2467":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنِي إِدْرِيسُ بْنُ يَزِيدَ حَدَّثَنَا طَلْحَةُ بْنُ مُصَرِّفٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ تَعَالَى{ وَالَّذِينَ عَاقَدَتْ أَيْمَانُكُمْ فَآتُوهُمْ نَصِيبَهُمْ }قَالَ كَانَ الْمُهَاجِرُونَ حِينَ قَدِمُوا الْمَدِينَةَ تُوَرَّثُ الْأَنْصَارَ دُونَ ذَوِي رَحِمِهِ لِلْأُخُوَّةِ الَّتِي آخَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمْ فَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَلِكُلٍّ جَعَلْنَا مَوَالِيَ مِمَّا تَرَكَ }قَالَ نَسَخَتْهَا{ وَالَّذِينَ عَقَدَتْ أَيْمَانُكُمْ فَآتُوهُمْ نَصِيبَهُمْ }مِنْ النَّصْرِ وَالنَّصِيحَةِ وَالرِّفَادَةِ وَيُوصِي لَهُ وَقَدْ ذَهَبَ الْمِيرَاثُ","id":"Telah menceritakan kepada kami [Harun bin Abdullah], telah menceritakan kepada kami [Abu Usamah], telah menceritakan kepadaku [Idris bin Yazid?], telah menceritakan kepada kami [Thalhah bin Musharrif] dari [Sa'id bin Jubair], dari [Ibnu Abbas] mengenai firman Allah ta'ala: \"Dan (jika ada) orang-orang yang kamu telah bersumpah setia dengan mereka, maka berilah kepada mereka bagiannya.\" Ia berkata; dahulu orang-orang muhajirin ketika datang ke Madinah, orang-orang anshar diwarisi selain orang-orang yang memiliki hubungan kekerabatan dengannya karena persaudaraan yang telah Allah perintahkan diantara mereka. Kemudian tatkala turun ayat ini: \"Bagi tiap-tiap harta peninggalan dari harta yang ditinggalkan…..\" ia berkata; ayat tersebut dihapus ayat: \"Dan (jika ada) orang-orang yang kamu telah bersumpah setia dengan mereka, maka berilah kepada mereka bagiannya.\" Yaitu berupa pertolongan, nasehat, serta bantuan, berwasiat kepadanya dan warisan telah pergi. "},"2468":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَعَبْدُ الْعَزِيزِ بْنُ يَحْيَى الْمَعْنَى قَالَ أَحْمَدُ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ ابْنِ إِسْحَقَ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ قَالَكُنْتُ أَقْرَأُ عَلَى أُمِّ سَعْدٍ بِنْتِ الرَّبِيعِ وَكَانَتْ يَتِيمَةً فِي حِجْرِ أَبِي بَكْرٍ فَقَرَأْتُ{ وَالَّذِينَ عَقَدَتْ أَيْمَانُكُمْ }فَقَالَتْ لَا تَقْرَأْ{ وَالَّذِينَ عَقَدَتْ أَيْمَانُكُمْ }إِنَّمَا نَزَلَتْ فِي أَبِي بَكْرٍ وَابْنِهِ عَبْدِ الرَّحْمَنِ حِينَ أَبَى الْإِسْلَامَ فَحَلَفَ أَبُو بَكْرٍ أَلَّا يُوَرِّثَهُ فَلَمَّا أَسْلَمَ أَمَرَ اللَّهُ تَعَالَى نَبِيَّهُ عَلَيْهِ السَّلَام أَنْ يُؤْتِيَهُ نَصِيبَهُ زَادَ عَبْدُ الْعَزِيزِ فَمَا أَسْلَمَ حَتَّى حُمِلَ عَلَى الْإِسْلَامِ بِالسَّيْفِقَالَ أَبُو دَاوُد مَنْ قَالَ عَقَدَتْ جَعَلَهُ حِلْفًا وَمَنْ قَالَ عَاقَدَتْ جَعَلَهُ حَالِفًا قَالَ وَالصَّوَابُ حَدِيثُ طَلْحَةَ عَاقَدَتْ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Abdul Aziz bin Yahya] secara makna, Ahmad berkata; telah menceritakan kepada kami [Muhammad bin Salamah], dari [Ibnu Ishaq] dari [Daud bin Al Hushain], ia berkata; dahulu aku membacakan riwayat kepada [Ummu Sa'd binti Ar Rabi'] dan ia dahulu adalah seorang yatim di dalam asuhan Abu Bakr, kemudian aku membaca: WALLADZIINA 'AQADAT AIMAANUKUM \"Dan (jika ada) orang-orang yang kamu telah bersumpah setia dengan mereka……\" Kemudian Ummu Sa'd berkata; janganlah engkau membaca; WALLADZIINA 'AQADAT AIMAANUKUM \"Dan (jika ada) orang-orang yang kamu telah bersumpah setia dengan mereka..\" sesungguhnya ayat tersebut turun mengenai Abu Bakr dan anaknya yaitu Abdurrahman ketika ia menolak masuk Islam, kemudian Abu Bakr bersumpah bahwa ia tidak akan memberinya warisan. Kemudian tatkala Abdurrahman telah masuk Islam, maka Allah Ta'ala memerintahkan NabiNya shallallahu 'alaihi wasallam agar memberikan kepadanya bagiannya. Abdul Aziz menambahkan; tidaklah ia masuk Islam hingga ia didorong masuk Islam dengan acungan pedang. Abu Daud berkata; barangsiapa yang mengucapkan 'aqadat maka ia menjadikan sebuah sumpah, sedangkan orang yang mengatakan; 'aaqadat maka ia menjadikannya orang yang bersumpah. Ia berkata; dan yang benar adalah hadits Thalhah yaitu: 'aaqadat. "},"2469":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ{ وَالَّذِينَ آمَنُوا وَهَاجَرُوا }{ وَالَّذِينَ آمَنُوا وَلَمْ يُهَاجِرُوا }فَكَانَ الْأَعْرَابِيُّ لَا يَرِثُ الْمُهَاجِرَ وَلَا يَرِثُهُ الْمُهَاجِرُ فَنَسَخَتْهَا فَقَالَ{ وَأُولُو الْأَرْحَامِ بَعْضُهُمْ أَوْلَى بِبَعْضٍ }","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah menceritakan kepada kami [Ali bin Husain], dari [ayahnya], dari [Yazid? An Nahwi], dari [Ikrimah], dari [Ibnu Abbas]: \"Dan orang-orang yang beriman dan berhijrah…\" serta \"Dan orang-orang yang beriman dan belum berhijrah….\" Dahulu orang badui tidak mewarisi orang muhajir dan ia tidak diwarisi orang muhajir, kemudian ayat tersebut dihapus, Allah berfirman: \"Orang-orang yang mempunyai hubungan kerabat itu sebagiannya lebih berhak terhadap sesamanya (daripada yang bukan kerabat).\""},"2470":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ وَابْنُ نُمَيْرٍ وَأَبُو أُسَامَةَ عَنْ زَكَرِيَّا عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِيهِ عَنْ جُبَيْرِ بْنِ مُطْعِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حِلْفَ فِي الْإِسْلَامِ وَأَيُّمَا حِلْفٍ كَانَ فِي الْجَاهِلِيَّةِ لَمْ يَزِدْهُ الْإِسْلَامُ إِلَّا شِدَّةً","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Muhammad bin Bisyr] dan [Ibnu Numair] serta [Abu Usamah] dari [Zakariya] dari [Sa'd bin Ibrahim] dari [ayahnya] dari [Jubair bin Muth'im], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada perjanjian (melakukan hal-hal yang dilarang syariat) dalam Islam, apapun bentuk bentuk perjanjian yang telah dilakukan pada masa jahiliyah (berkenaan dengan hal-hal kebaikan) maka Islam akan mengukuhkan dan menguatkannya.\""},"2471":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ الْأَحْوَلِ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُحَالَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الْمُهَاجِرِينَ وَالْأَنْصَارِ فِي دَارِنَا فَقِيلَ لَهُ أَلَيْسَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حِلْفَ فِي الْإِسْلَامِ فَقَالَ حَالَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الْمُهَاجِرِينَ وَالْأَنْصَارِ فِي دَارِنَا مَرَّتَيْنِ أَوْ ثَلَاثًا","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Sufyan] dari ['Ashim Al Ahwal] ia berkata; saya mendengar [Anas bin Malik] berkata; Rasulullah shallallahu 'alaihi wasallam mempersaudarakan antara orang-orang muhajirin dan anshar di rumah kami. Kemudian dikatakan kepadanya; bukankah Rasulullah shallallahu 'alaihi wasallam telah mengatakan: \"Tidak ada perjanjian dalam Islam?\" Kemudian ia berkata; Rasulullah shallallahu 'alaihi wasallam mempersaudarakan antara orang-orang muhajirin dan anshar di rumah kami. Ia mengucapkannya dua atau tiga kali. "},"2472":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ قَالَكَانَ عُمَرُ بْنُ الْخَطَّابِ يَقُولُ الدِّيَةُ لِلْعَاقِلَةِ وَلَا تَرِثُ الْمَرْأَةُ مِنْ دِيَةِ زَوْجِهَا شَيْئًا حَتَّى قَالَ لَهُ الضَّحَّاكُ بْنُ سُفْيَانَ كَتَبَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أُوَرِّثَ امْرَأَةَ أَشْيَمَ الضِّبَابِيِّ مِنْ دِيَةِ زَوْجِهَا فَرَجَعَ عُمَرُقَالَ أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ بِهَذَا الْحَدِيثِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ وَقَالَ فِيهِ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَهُ عَلَى الْأَعْرَابِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id] ia berkata; dahulu Umar bin Al Khathab berkata; diyat adalah untuk 'aqilah ('ashabah serta kerabat dari pihak ayah), dan wanita tidak mewarisi sedikitpun dari diyat suaminya, hingga [Adh Dhahhak bin Sufyan] berkata kepadanya, Rasulullah shallallahu 'alaihi wasallam telah menulis surat kepadaku agar aku memberikan warisan kepada isteri Asyyam Adhdhabbi dari diyat suaminya. Kemudian Umar kembali, Ahmad bin Shalih berkata; telah menceritakan kepada kami [Abdurrazzaq] dengan hadits ini dari [Ma'mar] dari [Az Zuhri] dari [Sa'id], ia berkata; padanya. Dan Nabi shallallahu 'alaihi wasallam mengangkatnya untuk mengurusi orang-orang badui. "},"2473":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا كُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِ فَالْأَمِيرُ الَّذِي عَلَى النَّاسِ رَاعٍ عَلَيْهِمْ وَهُوَ مَسْئُولٌ عَنْهُمْ وَالرَّجُلُ رَاعٍ عَلَى أَهْلِ بَيْتِهِ وَهُوَ مَسْئُولٌ عَنْهُمْ وَالْمَرْأَةُ رَاعِيَةٌ عَلَى بَيْتِ بَعْلِهَا وَوَلَدِهِ وَهِيَ مَسْئُولَةٌ عَنْهُمْ وَالْعَبْدُ رَاعٍ عَلَى مَالِ سَيِّدِهِ وَهُوَ مَسْئُولٌ عَنْهُ فَكُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah], dari [Malik] dari [Abdullah bin Dinar], dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam berkata: Ketahuilah bahwa setiap dari kalian adalah pemimpin dan setiap dari kalian akan dimintai pertanggung jawaban atas kepemimpinannya, seorang pemimpin umat manusia adalah pemimpin bagi mereka dan ia bertanggung jawab dengan kepemimpinannya atas mereka, seorang laki-laki adalah pemimpin bagi keluarganya dan ia bertanggung jawab atas mereka, seorang wanita adalah pemimpin bagi rumah suaminya dan anaknya, dan ia bertanggung jawab atas mereka. Seorang budak adalah pemimpin bagi harta tuannya, dan ia bertanggung jawab atasnya. Maka setiap dari kalian adalah adalah pemimpin yang bertanggung jawab atas kepemimpinannya.\""},"2474":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يُونُسُ وَمَنْصُورٌ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ الرَّحْمَنِ بْنَ سَمُرَةَ لَا تَسْأَلْ الْإِمَارَةَ فَإِنَّكَ إِذَا أُعْطِيتَهَا عَنْ مَسْأَلَةٍ وُكِلْتَ فِيهَا إِلَى نَفْسِكَ وَإِنْ أُعْطِيتَهَا عَنْ غَيْرِ مَسْأَلَةٍ أُعِنْتَ عَلَيْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah Al Bazzaz], telah menceritakan kepada kami [Husyaim], telah mengabarkan kepada kami [Yunus] dan [Manshur] dari [Al Hasan] dari [Abdurrahman bin Samurah], ia berkata; Nabi shallallahu 'alaihi wasallam berkata kepadaku: \"Wahai Abdurrahman, janganlah engkau meminta kepemimpinan, sesungguhnya apabila engkau diberi kepemimpinan karena memintanya maka engkau diserahi kepemimpinan itu (sepenuhnya) kepada dirimu, dan apabila engkau diberinya bukan karena meminta maka engkau akan diberi pertolongan.\""},"2475":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ حَدَّثَنَا خَالِدٌ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ أَخِيهِ عَنْ بِشْرِ بْنِ قُرَّةَ الْكَلْبِيِّ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَانْطَلَقْتُ مَعَ رَجُلَيْنِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَشَهَّدَ أَحَدُهُمَا ثُمَّ قَالَ جِئْنَا لِتَسْتَعِينَ بِنَا عَلَى عَمَلِكَ وَقَالَ الْآخَرُ مِثْلَ قَوْلِ صَاحِبِهِ فَقَالَ إِنَّ أَخْوَنَكُمْ عِنْدَنَا مَنْ طَلَبَهُ فَاعْتَذَرَ أَبُو مُوسَى إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ لَمْ أَعْلَمْ لِمَا جَاءَا لَهُ فَلَمْ يَسْتَعِنْ بِهِمَا عَلَى شَيْءٍ حَتَّى مَاتَ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah], telah menceritakan kepada kami [Khalid], dari [Isma'il bin Abu Khalid], dari [saudaranya], dari [Bisyr bin Qurrah Al Kalbi], dari [Abu Burdah], dari [Abu Musa], ia berkata; aku pergi bersama dua orang laki-laki kepada Nabi shallallahu 'alaihi wasallam, kemudian salah seorang diantara mereka bersaksi (memohon), kemudian berkata; kami datang agar engkau mempekerjakan kami untuk mengurusi pekerjaan engkau. Dan yang lain berkata; seperti perkataan sahabatnya. Kemudian beliau berkata; sesungguhnya saudara-saudara kalian di sisi kami (paling banyak melakukan khianat) yang meminta pekerjaan. Abu Musa meminta maaf kepada Nabi shallallahu 'alaihi wasallam dan berkata; aku tidak mengetahui kenapa mereka datang, dan beliau tidak mempekerjakan mereka mengurusi sesuatupun, hingga beliau meninggal. "},"2476":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْمُخَرَّمِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عِمْرَانُ الْقَطَّانُ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَخْلَفَ ابْنَ أُمِّ مَكْتُومٍ عَلَى الْمَدِينَةِ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah Al Mukharrami], telah menceritakan kepada kami [Abdurrahman bin Mahdi], telah menceritakan kepada kami [Imran Al Qaththan] dari [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam menunjuk Ibnu Ummi Maktum menggantikan beliau di Madinah dua kali. "},"2477":{"ar":"حَدَّثَنَا مُوسَى بْنُ عَامِرٍ الْمُرِّيُّ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ اللَّهُ بِالْأَمِيرِ خَيْرًا جَعَلَ لَهُ وَزِيرَ صِدْقٍ إِنْ نَسِيَ ذَكَّرَهُ وَإِنْ ذَكَرَ أَعَانَهُ وَإِذَا أَرَادَ اللَّهُ بِهِ غَيْرَ ذَلِكَ جَعَلَ لَهُ وَزِيرَ سُوءٍ إِنْ نَسِيَ لَمْ يُذَكِّرْهُ وَإِنْ ذَكَرَ لَمْ يُعِنْهُ","id":"Telah menceritakan kepada kami [Musa bin 'Amir Al Murri], telah menceritakan kepada kami [Al Walid] telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Abdurrahman bin Al Qasim], dari [ayahnya], dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata: \"Apabila Allah menghendaki kebaikan pada diri pemimpin maka Allah akan menjadikan baginya menteri yang jujur, apabila ia lupa maka ia akan mengingatkannya dan apabila ia ingat maka ia akan membantunya. Dan apabila Allah menghendaki selain itu (keburukan) pada diri seorang pemimpin maka Allah jadikan baginya menteri (pembantu) yang buruk, apabila ia lupa maka ia tidak mengingatakannya, dan apabila ia ingat maka ia tidak membantunya.\""},"2478":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ أَبِي سَلَمَةَ سُلَيْمَانَ بْنِ سُلَيْمٍ عَنْ يَحْيَى بْنِ جَابِرٍ عَنْ صَالِحِ بْنِ يَحْيَى بْنِ الْمِقْدَامِ عَنْ جَدِّهِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَرَبَ عَلَى مَنْكِبِهِ ثُمَّ قَالَ لَهُ أَفْلَحْتَ يَا قُدَيْمُ إِنْ مُتَّ وَلَمْ تَكُنْ أَمِيرًا وَلَا كَاتِبًا وَلَا عَرِيفًا","id":"Telah menceritakan kepada kami ['Amru bin Utsman], telah menceritakan kepada kami [Muhammad bin Harb], dari [Abu Salamah Sulaiman bin Sulaim], dari [Yahya bin Jabir] dari [Shalih bin Yahya bin Al Miqdam] dari [kakeknya yaitu Al Miqdam bin Ma'dikarib] bahwa Rasulullah shallallahu 'alaihi wasallam menepuk pundaknya kemudian berkata kepadanya: \"Engkau telah beruntung wahai Qudaim, apabila engkau meninggal dan tidak menjadi seorang pemimpin, sekretaris, dan 'arif (orang yang bertugas mengatur permasalahan dan kemaslahatan umat).\""},"2479":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا غَالِبٌ الْقَطَّانُ عَنْ رَجُلٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّهُمْ كَانُوا عَلَى مَنْهَلٍ مِنْ الْمَنَاهِلِ فَلَمَّا بَلَغَهُمْ الْإِسْلَامُ جَعَلَ صَاحِبُ الْمَاءِ لِقَوْمِهِ مِائَةً مِنْ الْإِبِلِ عَلَى أَنْ يُسْلِمُوا فَأَسْلَمُوا وَقَسَمَ الْإِبِلَ بَيْنَهُمْ وَبَدَا لَهُ أَنْ يَرْتَجِعَهَا مِنْهُمْ فَأَرْسَلَ ابْنَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ ائْتِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْ لَهُ إِنَّ أَبِي يُقْرِئُكَ السَّلَامَ وَإِنَّهُ جَعَلَ لِقَوْمِهِ مِائَةً مِنْ الْإِبِلِ عَلَى أَنْ يُسْلِمُوا فَأَسْلَمُوا وَقَسَمَ الْإِبِلَ بَيْنَهُمْ وَبَدَا لَهُ أَنْ يَرْتَجِعَهَا مِنْهُمْ أَفَهُوَ أَحَقُّ بِهَا أَمْ هُمْ فَإِنْ قَالَ لَكَ نَعَمْ أَوْ لَا فَقُلْ لَهُ إِنَّ أَبِي شَيْخٌ كَبِيرٌ وَهُوَ عَرِيفُ الْمَاءِ وَإِنَّهُ يَسْأَلُكَ أَنْ تَجْعَلَ لِي الْعِرَافَةَ بَعْدَهُ فَأَتَاهُ فَقَالَ إِنَّ أَبِي يُقْرِئُكَ السَّلَامَ فَقَالَ وَعَلَيْكَ وَعَلَى أَبِيكَ السَّلَامُ فَقَالَ إِنَّ أَبِي جَعَلَ لِقَوْمِهِ مِائَةً مِنْ الْإِبِلِ عَلَى أَنْ يُسْلِمُوا فَأَسْلَمُوا وَحَسُنَ إِسْلَامُهُمْ ثُمَّ بَدَا لَهُ أَنْ يَرْتَجِعَهَا مِنْهُمْ أَفَهُوَ أَحَقُّ بِهَا أَمْ هُمْ فَقَالَ إِنْ بَدَا لَهُ أَنْ يُسْلِمَهَا لَهُمْ فَلْيُسْلِمْهَا وَإِنْ بَدَا لَهُ أَنْ يَرْتَجِعَهَا فَهُوَ أَحَقُّ بِهَا مِنْهُمْ فَإِنْ هُمْ أَسْلَمُوا فَلَهُمْ إِسْلَامُهُمْ وَإِنْ لَمْ يُسْلِمُوا قُوتِلُوا عَلَى الْإِسْلَامِ فَقَالَ إِنَّ أَبِي شَيْخٌ كَبِيرٌ وَهُوَ عَرِيفُ الْمَاءِ وَإِنَّهُ يَسْأَلُكَ أَنْ تَجْعَلَ لِي الْعِرَافَةَ بَعْدَهُ فَقَالَ إِنَّ الْعِرَافَةَ حَقٌّ وَلَا بُدَّ لِلنَّاسِ مِنْ الْعُرَفَاءِ وَلَكِنَّ الْعُرَفَاءَ فِي النَّارِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal], telah menceritakan kepada kami [Ghalib Al Qaththan] dari [seorang laki-laki] dari [ayahnya] dari [kakeknya] bahwa mereka berada di atas tempat minum diantara beberapa tempat minum. Kemudian tatkala Islam telah sampai kepada mereka maka pemilik air tersebut akan memberikan kepada kaumnya seratus ekor unta dengan syarat mereka masuk Islam. Kemudian mereka masuk Islam. Dan ia membagikan unta tersebut diantara mereka. Kemudian ia berfikiran untuk mengambil kembali unta-unta tersebut dari mereka. Kemudian ia mengutus anaknya kepada Nabi shallallahu 'alaihi wasallam. Ia berkata kepada anaknya; datanglah kepada Nabi shallallahu 'alaihi wasallam dan katakan; sesungguhnya ayahku mengucapkan salam kepada anda. Dan ia telah memberi kaumnya seratus ekor unta dengan syarat mereka masuk Islam. Kemudian mereka masuk Islam, dan ia membagikan unta tersebut diantara mereka. Dan ia berfikiran untuk mengambil kembali unta tersebut dari mereka. Apakah ia berhak atas unta tersebut ataukah mereka yang lebih berhak? Apabila beliau mengatakan: \"Ya.\" atau \"Tidak\" maka katakan kepada beliau; sesungguhnya ayahku adalah orang yang telah tua dan ia adalah seorang 'arif (orang yang bertugas mengatur permasalahan dan kemaslahatan umat) yang mengatur air, dan ia meminta agar engkau menjadikan saya pekerjaan 'arif setelahnya. Kemudian anak tersebut datang kepada beliau kemudian mengatakan; sesungguhnya ayahku mengucapkan salam kepada engkau. Kemudian beliau menjawab: \"WA 'ALAIKA WA 'ALA ABIIKAS SALAAM\" (semoga keselamatan terlimpahkan kepadamu dan kepada ayahmu). Kemudian ia berkata; sesungguhnya ayahku memberi kaumnya dengan syarat mereka masuk Islam, lalu mereka masuk Islam dan telah baik keislaman mereka. Kemudian ia berfikiran untuk mengambil kembali unta tersebut dari mereka. Apakah ia lebih berhak terhadap unta tersebut atau mereka lebih berhak? Kemudian beliau bersabda: \"Apabila ia berfikiran untuk memberikan unta tersebut kepada mereka maka silahkan ia memberikannya kepada mereka, dan apabila ia berfikiran untuk mengambil kembali unta tersebut dari mereka maka ia lebih berhak terhadap unta tersebut daripada mereka. Dan apabila mereka telah masuk Islam maka bagi mereka keislaman mereka dan apabia mereka tidak masuk Islam maka mereka diperangi atas nama Islam.\" Kemudian ia berkata; sesungguhnya ayahku adalah orang yang telah tua dan ia adalah 'arif (pengatur) pembagian air, dan ia mohon kepada anda agar anda memberiku pekerajaan instruktur yang mengurusi air setelahnya. Kemudian beliau berkata: \"Sesungguhnya pekerjaan sebagai 'arif (pengatur) adalah sesuatu yang hak dan orang-orang memerlukan para pengatur, akan tetapi para pengatur akan berada di neraka.\""},"2480":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا نُوحُ بْنُ قَيْسٍ عَنْ يَزِيدَ بْنِ كَعْبٍ عَنْ عَمْرِو بْنِ مَالِكٍ عَنْ أَبِي الْجَوْزَاءِ عَنْ ابْنِ عَبَّاسٍ قَالَالسِّجِلُّ كَاتِبٌ كَانَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Nuh bin Qais], dari [Yazid? bin Ka'b], dari ['Amr bin Malik], dari [Abu Al Jauza`] dari [Ibnu Abbas] ia berkata; sijil adalah sekretaris Nabi shallallahu 'alaihi wasallam. "},"2481":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ الْأَسْبَاطِيُّ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْعَامِلُ عَلَى الصَّدَقَةِ بِالْحَقِّ كَالْغَازِي فِي سَبِيلِ اللَّهِ حَتَّى يَرْجِعَ إِلَى بَيْتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ibrahim Al Asbathi], telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Muhammad bin Ishaq] dari ['Ashim bin Umar bin Qatadah] dari [Mahmud bin Labid] dari [Rafi' bin Khadij], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam berkata; penunggu zakat yang benar seperti orang yang berperang di jalan Allah hingga ia kembali ke rumahnya. "},"2482":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِمَاسَةَ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَدْخُلُ الْجَنَّةَ صَاحِبُ مَكْسٍ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Muhammad bin Maslamah], dari [Muhammad bin Ishaq], dari [Yazid? bin Abu Habib] dari [Abdurrahman bin Syimasah] dari ['Uqbah bin 'Amir], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam berkata: Tidak akan masuk surga orang yang mengambil pajak secara zhalim. "},"2483":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْقَطَّانُ عَنْ ابْنِ مَغْرَاءَ عَنْ ابْنِ إِسْحَقَ قَالَالَّذِي يَعْشُرُ النَّاسَ يَعْنِي صَاحِبَ الْمَكْسِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah Al Qaththan] dari [Ibnu Maghra`], dari [Ibnu Ishaq] ia berkata; orang yang mengambil sepersepuluh dari orang-orang maka adalah mengambil pajak secara zhalim. "},"2484":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ دَاوُدَ بْنِ سُفْيَانَ وَسَلَمَةُ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ عُمَرُإِنِّي إِنْ لَا أَسْتَخْلِفْ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَسْتَخْلِفْ وَإِنْ أَسْتَخْلِفْ فَإِنَّ أَبَا بَكْرٍ قَدْ اسْتَخْلَفَ قَالَ فَوَاللَّهِ مَا هُوَ إِلَّا أَنْ ذَكَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ فَعَلِمْتُ أَنَّهُ لَا يَعْدِلُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدًا وَأَنَّهُ غَيْرُ مُسْتَخْلِفٍ","id":"Telah menceritakan kepada kami [Muhammad bin Daud bin Sufyan] dan [Salamah], mereka berdua mengatakan; telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar], ia berkata; [Umar] berkata; sesungguhnya aku apabila tidak menunjuk seseorang menjadi khalifah, karena Rasulullah shallallahu 'alaihi wasallam tidak menunjuk khalifah. Dan apabila aku menunjuk seseorang sebagai khalifah maka sesunguhnya Abu Bakr telah menunjuk seseorang menjadi khalifah. Ia berkata; ia hanya menyebutkan Rasulullah shallallahu 'alaihi wasallam dan Abu Bakr, maka aku mengetahui bahwa tidak ada seorangpun yang sebanding dengan beliau sementara beliau tidak menunjuk seorang khalifah. "},"2485":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَكُنَّا نُبَايِعُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ وَيُلَقِّنُنَا فِيمَا اسْتَطَعْتَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar], telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Dinar], dari [Ibnu Umar], ia berkata; dahulu kami membai'at Nabi shallallahu 'alaihi wasallam untuk mendengar dan mentaati, dan beliau membisikkan: \"Semampumu!\""},"2486":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَخْبَرَتْهُعَنْ بَيْعَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النِّسَاءَ قَالَتْ مَا مَسَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَ امْرَأَةٍ قَطُّ إِلَّا أَنْ يَأْخُذَ عَلَيْهَا فَإِذَا أَخَذَ عَلَيْهَا فَأَعْطَتْهُ قَالَ اذْهَبِي فَقَدْ بَايَعْتُكِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Wahb], telah menceritakan kepadaku [Malik], dari [Ibnu Syihab] dari ['Urwah] bahwa [Aisyah] radliallahu 'anha telah mengabarkan kepadanya mengenai bai'at Rasulullah shallallahu 'alaihi wasallam kepada para wanita. Ia berkata; tidaklah Rasulullah shallallahu 'alaihi wasallam menyentuh tangan wanita sama sekali kecuali beliau mengambil sumpah atasnya, maka apabila beliau telah mengambil sumpah atasnya beliau berkata: \"Pergilah, aku telah membaiat kalian!\""},"2487":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ حَدَّثَنِي أَبُو عَقِيلٍ زَهْرَةُ بْنُ مَعْبَدٍ عَنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ هِشَامٍوَكَانَ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَهَبَتْ بِهِ أُمُّهُ زَيْنَبُ بِنْتُ حُمَيْدٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ بَايِعْهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ صَغِيرٌ فَمَسَحَ رَأْسَهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar bin Maisarah], telah menceritakan kepada kami [Abdullah bin Yazid?], telah menceritakan kepada kami [Sa'id bin Abu Ayyub], telah menceritakan kepadaku [Abu 'Aqil Zahrah bin Ma'bad], dari [kakeknya yaitu Abdullah bin Hisyam], dan ia pernah bertemu dengan Nabi shallallahu 'alaihi wasallam, ibunya yaitu Zainab binti Humaid telah membawanya kepada Rasulullah shallallahu 'alaihi wasallam, kemudian berkata; wahai Rasulullah, bai'atlah dia! Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Ia masih kecil.\" Kemudian beliau mengusap kepalanya. "},"2488":{"ar":"حَدَّثَنَا زَيْدُ بْنُ أَخْزَمَ أَبُو طَالِبٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ عَبْدِ الْوَارِثِ بْنِ سَعِيدٍ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اسْتَعْمَلْنَاهُ عَلَى عَمَلٍ فَرَزَقْنَاهُ رِزْقًا فَمَا أَخَذَ بَعْدَ ذَلِكَ فَهُوَ غُلُولٌ","id":"Telah menceritakan kepada kami [Zaid bin Akhzam Abu Thalib], telah menceritakan kepada kami [Abu 'Ashim] dari [Abdul Warits bin Sa'id] dari [Husain Al Mu'allim] dari [Abdullah bin Buraidah], dari [ayahnya], dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa yang kami beri jabatan untuk mengurusi suatu pekerjaan kemudian kami berikan kepadanya suatu pemberian (gaji), maka apa yang ia ambil setelah itu (selain gaji) adalah suatu bentuk pengkhianatan.\""},"2489":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا لَيْثٌٌ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ ابْنِ السَّاعِدِيِّ قَالَاسْتَعْمَلَنِي عُمَرُ عَلَى الصَّدَقَةِ فَلَمَّا فَرَغْتُ أَمَرَ لِي بِعُمَالَةٍ فَقُلْتُ إِنَّمَا عَمِلْتُ لِلَّهِ قَالَ خُذْ مَا أُعْطِيتَ فَإِنِّي قَدْ عَمِلْتُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَمَّلَنِي","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi], telah menceritakan kepada kami [Laits] dari [Bukair bin Abdullah bin Al Asyjj], dari [Busr bin Sa'id], dari [Ibnu As Sa'idi], ia berkata; [Umar] memberiku jabatan untuk mengurusi zakat, lalu tatkala saya telah selesai mengurusinya, ia memerintahkan agar saya diberi uang, maka saya katakan; sesungguhnya saya bekerja hanya untuk Allah. Ia berkata; ambillah apa yang telah diberikan kepadamu, karena sesungguhnya saya telah bekerja pada masa? Rasulullah shallallahu 'alaihi wasallam dan beliau memberiku uang. "},"2490":{"ar":"حَدَّثَنَا مُوسَى بْنُ مَرْوَانَ الرَّقِّيُّ حَدَّثَنَا الْمُعَافَى حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الْحَارِثِ بْنِ يَزِيدَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ الْمُسْتَوْرِدِ بْنِ شَدَّادٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَانَ لَنَا عَامِلًا فَلْيَكْتَسِبْ زَوْجَةً فَإِنْ لَمْ يَكُنْ لَهُ خَادِمٌ فَلْيَكْتَسِبْ خَادِمًا فَإِنْ لَمْ يَكُنْ لَهُ مَسْكَنٌ فَلْيَكْتَسِبْ مَسْكَنًاقَالَ قَالَ أَبُو بَكْرٍ أُخْبِرْتُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اتَّخَذَ غَيْرَ ذَلِكَ فَهُوَ غَالٌّ أَوْ سَارِقٌ","id":"Telah menceritakan kepada kami [Musa bin Marwan Ar Raqqi], telah menceritakan kepada kami [Al Mu'afi], telah menceritakan kepada kami [Al Auza'i], dari [Al Harits bin Yazid], dari [Jubair bin Nufair] dari [Al Mustaurid bin Syaddad], ia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menjadi pegawai kami maka hendaknya ia mencari seorang isteri, apabila ia tidak memiliki pembantu maka hendaknya ia mencari pembantu, dan apabila ia tidak memiliki tempat tinggal maka hendaknya ia mencari tempat tinggal!\" Abu Bakr berkata; aku diberi khabar bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Barangsiapa yang mengambil selain itu, maka ia adalah pengkhianat atau pencuri.\""},"2491":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ وَابْنُ أَبِي خَلَفٍ لَفْظَهُ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَ رَجُلًا مِنْ الْأَزْدِ يُقَالُ لَهُ ابْنُ اللُّتْبِيَّةِ قَالَ ابْنُ السَّرْحِ ابْنُ الْأُتْبِيَّةِ عَلَى الصَّدَقَةِ فَجَاءَ فَقَالَ هَذَا لَكُمْ وَهَذَا أُهْدِيَ لِي فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَقَالَ مَا بَالُ الْعَامِلِ نَبْعَثُهُ فَيَجِيءُ فَيَقُولُ هَذَا لَكُمْ وَهَذَا أُهْدِيَ لِي أَلَا جَلَسَ فِي بَيْتِ أُمِّهِ أَوْ أَبِيهِ فَيَنْظُرَ أَيُهْدَى لَهُ أَمْ لَا لَا يَأْتِي أَحَدٌ مِنْكُمْ بِشَيْءٍ مِنْ ذَلِكَ إِلَّا جَاءَ بِهِ يَوْمَ الْقِيَامَةِ إِنْ كَانَ بَعِيرًا فَلَهُ رُغَاءٌ أَوْ بَقَرَةً فَلَهَا خُوَارٌ أَوْ شَاةً تَيْعَرُ ثُمَّ رَفَعَ يَدَيْهِ حَتَّى رَأَيْنَا عُفْرَةَ إِبِطَيْهِ ثُمَّ قَالَ اللَّهُمَّ هَلْ بَلَّغْتُ اللَّهُمَّ هَلْ بَلَّغْتُ","id":"Telah menceritakan kepada kami [Ibnu As Sarh], dan [Ibnu Abu Khalaf], dengan lafazhnya, mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Urwah], dari [Abu Humaid As Sa'idi], bahwa Nabi shallallahu 'alaihi wasallam mengangkat seorang laki-laki dari Azd yang bernama Ibnu Al Lutbiyyah sebagai pegawai. -Ibnu As Sarh berkata; Ibnu Al Utbiyyah-. Untuk mengurusi zakat, kemudian ia datang dan berkata; ini yang menjadi untuk anda dan yang ini dihadiahkan kepadaku. Kemudian Nabi shallallahu 'alaihi wasallam berdiri di atas mimbar lalu memuji Allah dan bersabda: \"Bagaimana dengan seorang pekerja yang kami utus, kemudian datang dan berkata; ini untuk anda dan ini dihadiahkan kepadaku. Tidakkah sekiranya ia duduk di rumah ayah atau ibunya kemudian menunggu, apakah ia akan diberi hadiah atau tidak? Tidaklah seseorang diantara kalian mengambil sesuatupun dari hal tersebut kecuali pada Hari Kiamat ia datang dengan membawanya pada lehernya, apabila sesuatu tersebut adalah unta maka unta tersebut bersuara unta, apabila atau sapi maka sapi tersebut bersuara sapi, dan kambing yang mengembik.\" Kemudian Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya hingga kami melihat putih kedua ketiaknya. Kemudian beliau mengucapkan: \"Ya Allah, bukankah aku telah menyampaikan? Ya Allah, bukankah aku telah menyampaikan?\""},"2492":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مُطَرِّفٍ عَنْ أَبِي الْجَهْمِ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَبَعَثَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاعِيًا ثُمَّ قَالَ انْطَلِقْ أَبَا مَسْعُودٍ وَلَا أُلْفِيَنَّكَ يَوْمَ الْقِيَامَةِ تَجِيءُ وَعَلَى ظَهْرِكَ بَعِيرٌ مِنْ إِبِلِ الصَّدَقَةِ لَهُ رُغَاءٌ قَدْ غَلَلْتَهُ قَالَ إِذًا لَا أَنْطَلِقُ قَالَ إِذًا لَا أُكْرِهُكَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Jarir], dari [Mutharrif] dari [Abu Al Jahm] dari [Abu Mas'ud Al Anshari] ia berkata; Nabi shallallahu 'alaihi wasallam mengutusku sebagai petugas pengambil zakat, kemudian beliau berkata: \"Pergilah wahai Abu Mas'ud dan jangan sampai aku mendapatimu pada Hari Kiamat datang sementara di atas punggungmu terdapat unta dari unta-unta zakat yang memiliki suara unta yang telah engkau ambil sebagai suatu pengkhiatan.\" Ia berkata; kalau demikian aku tidak akan pergi. Beliau berkata: \"Kalau demikian aku tidak akan memaksa.\""},"2493":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ الدِّمَشْقِيُّ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنِي ابْنُ أَبِي مَرْيَمَ أَنَّ الْقَاسِمَ بْنَ مُخَيْمِرَةَ أَخْبَرَهُ أَنَّ أَبَا مَرْيَمَ الْأَزْدِيَّ أَخْبَرَهُ قَالَدَخَلْتُ عَلَى مُعَاوِيَةَ فَقَالَ مَا أَنْعَمَنَا بِكَ أَبَا فُلَانٍ وَهِيَ كَلِمَةٌ تَقُولُهَا الْعَرَبُ فَقُلْتُ حَدِيثًا سَمِعْتُهُ أُخْبِرُكَ بِهِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ وَلَّاهُ اللَّهُ عَزَّ وَجَلَّ شَيْئًا مِنْ أَمْرِ الْمُسْلِمِينَ فَاحْتَجَبَ دُونَ حَاجَتِهِمْ وَخَلَّتِهِمْ وَفَقْرِهِمْ احْتَجَبَ اللَّهُ عَنْهُ دُونَ حَاجَتِهِ وَخَلَّتِهِ وَفَقْرِهِقَالَ فَجَعَلَ رَجُلًا عَلَى حَوَائِجِ النَّاسِ","id":"Telah menceritakan kepada kami [Sulaiman bin Abdurrahman Ad Dimasyqi], telah menceritakan kepada kami [Yahya bin Hamzah], telah menceritakan kepadaku [Ibnu Abu Maryam] bahwa [Al Qasim bin Mukhaimirah] telah mengabarkan kepadanya bahwa [Abu Maryam Al Azdi] telah mengabarkan kepadanya; ia berkata; aku menemui Mu'awiyah, kemudian ia berkata; -kenikmatan apakah yang diberikan kepada kami melaluimu wahai Abu Fulan? Hal itu merupakan perkataan yang biasa diucapkan orang-orang Arab-. Kemudian aku katakan; sebuah hadits yang aku dengar, aku akan mengabarkannya kepadamu, aku telah mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Barangsiapa yang Allah 'azza wajalla serahkan kepadanya sebagian urusan orang muslim kemudian ia menutup diri dari melayani kebutuhan mereka dan keperluan mereka, maka Allah menutup diri darinya dan tidak melayani kebutuhannya, serta keperluannya.\" Abu Maryam berkata; kemudian Mu'awiyah menjadikan seseorang untuk mengurusi kebutuhan-kebutuhan manusia. "},"2494":{"ar":"حَدَّثَنَا سَلَمَةُ بْنُ شَبِيبٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا بِهِ أَبُو هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أُوتِيكُمْ مِنْ شَيْءٍ وَمَا أَمْنَعُكُمُوهُ إِنْ أَنَا إِلَّا خَازِنٌ أَضَعُ حَيْثُ أُمِرْتُ","id":"Telah menceritakan kepada kami [Salamah bin Syabib], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih], ia berkata; ini adalah apa yang diceritakan [Abu Hurairah] kepada kami, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku tidak memberi sesuatu kepada kalian dan aku tidak menahannya. Aku hanyalah orang yang menampung (perintah) dan melaksankannya sesuai yang diperintahkan kepadaku.\""},"2495":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ قَالَذَكَرَ عُمَرُ بْنُ الْخَطَّابِ يَوْمًا الْفَيْءَ فَقَالَ مَا أَنَا بِأَحَقَّ بِهَذَا الْفَيْءِ مِنْكُمْ وَمَا أَحَدٌ مِنَّا بِأَحَقَّ بِهِ مِنْ أَحَدٍ إِلَّا أَنَّا عَلَى مَنَازِلِنَا مِنْ كِتَابِ اللَّهِ عَزَّ وَجَلَّ وَقَسْمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَالرَّجُلُ وَقِدَمُهُ وَالرَّجُلُ وَبَلَاؤُهُ وَالرَّجُلُ وَعِيَالُهُ وَالرَّجُلُ وَحَاجَتُهُ","id":"Telah menceritakan kepada kami [An Nufaili], telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Muhammad bin 'Amr bin 'Atho`] dari [Malik bin Aus bin Al Hadatsan], ia berkata; pada suatu hari [Umar] menyebutkan fai`, kemudian ia berkata; aku bukanlah orang yang lebih berhak terhadap fai` ini daripada kalian, dan tidak ada seorang pun diantara kita yang lebih berhak terhadapnya dari pada orang yang lain, hanya saja kita berada pada posisi yang telah dijelaskan dari Kitab Allah 'azza wajalla serta pembagian Rasulullah shallallahu 'alaihi wasallam. Maka seseorang bagiannya sesuai dengan cepatnya ia masuk Islam, dan seseorang bagiannya sesuai dengan musibah yang menimpanya, sesuai dengan orang yang menjadi tanggungannya dan seseorang bagiannya sesuai dengan kebutuhannya. "},"2496":{"ar":"حَدَّثَنَا هَارُونُ بْنُ زَيْدِ بْنِ أَبِي الزَّرْقَاءِ حَدَّثَنَا أَبِي حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَأَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ دَخَلَ عَلَى مُعَاوِيَةَ فَقَالَ حَاجَتَكَ يَا أَبَا عَبْدِ الرَّحْمَنِ فَقَالَ عَطَاءُ الْمُحَرَّرِينَ فَإِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلَ مَا جَاءَهُ شَيْءٌ بَدَأَ بِالْمُحَرَّرِينَ","id":"Telah menceritakan kepada kami [Harun bin Zaid bin Abu Az Zarqa`], telah menceritakan kepada kami [ayahku], telah menceritakan kepada kami [Hisyam bin Sa'd], dari [Zaid bin Aslam] bahwa [Abdullah bin Umar] menemui Mu'awiyah dan berkata; apa keperluanmu wahai Abdurrahman? 'Atho` berkata; ia berkata; memberikan pemberian kepada budak-budak yang telah dibebaskan. Sesungguhnya aku telah melihat Rasulullah shallallahu 'alaihi wasallam sesuatu pertama yang beliau lakukan adalah beliau memulai dari budak-budak yang telah dimerdekakan. "},"2497":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عِيسَى حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْقَاسِمِ بْنِ عَبَّاسٍ عَنْ عَبْدِ اللَّهِ بْنِ نِيَارٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِظَبْيَةٍ فِيهَا خَرَزٌ فَقَسَمَهَا لِلْحُرَّةِ وَالْأَمَةِقَالَتْ عَائِشَةُ كَانَ أَبِي رَضِيَ اللَّهُ عَنْهُ يَقْسِمُ لِلْحُرِّ وَالْعَبْدِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi], telah mengabarkan kepada kami [Isa], telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Al Qasim bin 'Abbas] dari [Abdullah bin Niyar] dari ['Urwah] dari [Aisyah] radliallahu 'anha, bahwa Nabi shallallahu 'alaihi wasallam diberi kendi kecil yang berisi manik-manik, kemudian beliau membaginya untuk wanita merdeka dan budak. Aisyah berkata; dahulu ayahku radliallahu 'anhu membagikan untuk orang yang merdeka dan budak. "},"2498":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ ح و حَدَّثَنَا ابْنُ الْمُصَفَّى قَالَ حَدَّثَنَا أَبُو الْمُغِيرَةِ جَمِيعًا عَنْ صَفْوَانَ بْنِ عَمْرٍو عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ عَوْفِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ ع��لَيْهِ وَسَلَّمَ كَانَ إِذَا أَتَاهُ الْفَيْءُ قَسَمَهُ فِي يَوْمِهِ فَأَعْطَى الْآهِلَ حَظَّيْنِ وَأَعْطَى الْعَزَبَ حَظًّا زَادَ ابْنُ الْمُصَفَّى فَدُعِينَا وَكُنْتُ أُدْعَى قَبْلَ عَمَّارٍ فَدُعِيتُ فَأَعْطَانِي حَظَّيْنِ وَكَانَ لِي أَهْلٌ ثُمَّ دُعِيَ بَعْدِي عَمَّارُ بْنُ يَاسِرٍ فَأَعْطَى لَهُ حَظًّا وَاحِدًا","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Abdullah bin Al Mubarak], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ibnu Al Mushaffa], ia berkata; telah menceritakan kepada kami [Abu Al Mughirah] seluruhnya dari [Shafwan bin 'Amr], dari [Abdurrahman bin Jubair bin Nufair] dari [ayahnya] dari ['Auf bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam apabila terdapat fa` yang datang kepadanya maka beliau membaginya pada hari itu, beliau memberi orang yang telah berkeluarga dua bagian dan orang yang bujang satu bagian. Ibnu Al Mushaffa menambahkan; kemudian aku dipanggil 'Ammar, aku dipanggil kemudian beliau memberiku dua bagian, dan aku adalah orang yang telah berkeluarga, kemudian 'Ammar bin Yasir dipanggil setelahku, lalu beliau memberinya satu bagian. "},"2499":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ جَعْفَرٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَنَا أَوْلَى بِالْمُؤْمِنِينَ مِنْ أَنْفُسِهِمْ مَنْ تَرَكَ مَالًا فَلِأَهْلِهِ وَمَنْ تَرَكَ دَيْنًا أَوْ ضَيَاعًا فَإِلَيَّ وَعَلَيَّ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Ja'far] dari [ayahnya], dari [Jabir bin Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata: \"Aku adalah orang yang lebih utama (lebih berhak) terhadap orang-orang mukmin daripada diri mereka sendiri, barangsiapa yang meninggalkan harta maka untuk keluarganya, dan barangsiapa yang meninggalkan hutang dan keluarga maka kembalinya kepadaku dan menjadi tanggunganku.\""},"2500":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَرَكَ مَالًا فَلِوَرَثَتِهِ وَمَنْ تَرَكَ كَلًّا فَإِلَيْنَا","id":"Telah menceritakan kepada kami [Hafsh bin Umar], telah menceritakan kepada kami [Syu'bah], dari [Adi bin Tsabit] dari [Abu Hazim], dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang meninggalkan harta maka untuk para pewarisnya, dan barang siapa yang meninggalkan keluarga maka kembalinya kepadaku.\""}};
